window.BEAUBIRD_BIRD_PROFILE_SHARDS["shard-052.json"] = [{"name":"苍头薮雀","english_name":"Pale-headed Brushfinch","scientific_name":"Atlapetes pallidiceps","overview":"苍头薮雀（英文名：Pale-headed Brushfinch，学名：Atlapetes pallidiceps），是雀形目雀鹀科薮雀属的鸟类。仅分布于厄瓜多尔南部安第斯山脉的狭窄地带。以苍白色的头部和喉部，面部暗斑及翼上的白色斑点为显著特征。该鸟种几乎全部群体生活在圣伊莎贝尔镇上方的Yunguilla保护区及其周边。","appearance":"苍头薮雀体型约16.5厘米，上体呈棕灰色，翼上有明显白色斑点。仅年长雄鸟头部几乎全白，具栗棕色至浅褐色的“角”状羽毛覆盖鼻孔，中冠和后冠两侧有细条纹。雌鸟及年轻雄鸟颜色较暗淡，上体更偏向棕色，下体淡黄色，头部色泽多变，尤其是眼区、脸颊和后冠两侧。幼鸟全身更偏棕色，胸部和侧身有轻微条纹，头部灰暗，眼周区域近乎黑色。","habits":"栖息于干旱山谷底部与湿润高坡之间的过渡带，偏好干燥森林和灌木丛生的环境，有时会在地面觅食。在Yunguilla保护区内的喂食器附近有时也能发现它们的身影。","breeding":"关于繁殖习性的详细信息有限，但在密集管理下，苍头薮雀的种群数量有所增加。然而，牛鸟寄生可能仍然限制了其种群的增长。","identification":"与白翅薮雀相似，但体型更大，喙部比例较大，头部图案不同，无部分白化斑点。年长雄鸟头部的白色和“角”状羽毛是重要辨识特征。","protection":"IUCN：EN（濒危）","distribution":"分布局限于厄瓜多尔南部阿苏艾省的Yunguilla山谷，主要在Girón附近。目前仅在单一地点被确认，95%的现存113对苍头薮雀位于为保护它们而设立的保护区中。"},{"name":"棕冠薮雀","english_name":"Bay-crowned Brushfinch","scientific_name":"Atlapetes seebohmi","overview":"棕冠薮雀（英文名：Bay-crowned Brushfinch，学名：Atlapetes seebohmi），是雀形目雀鹀科薮雀属的鸟类。分布于秘鲁西北部安第斯山与厄瓜多尔西南部的大型薮雀，以锈红色冠羽与全黑面罩为显著特征。它栖于海拔1150–2800米的干燥灌丛及矮树林，繁殖期在雨季，以种子与昆虫为食。","appearance":"全长约16–17厘米，体型粗壮，嘴厚长有力。成鸟头顶至后颈深栗红色，与全黑面罩及前额形成鲜明对比；喉及须纹区白色，颏黑色并延伸为短黑髭纹，仅达喉侧半段；上体橄榄灰色，翼与尾略深，折翼时具白色翼缘；胸带浅灰色，中央最淡，向下延伸至胁部并转为橄榄灰；下腹及腹部白色，尾下覆羽淡黄褐色；虹膜暗红褐，嘴黑色，脚灰色。两性同色。幼鸟上体较褐色，喉与腹淡黄褐，胸胁具不明显纵纹。亚种simonsi前额亦栗红，整体暗灰，具小白眉斑；celicae体型较小，前额仅少量黑色，喉部带黄褐洗羽。","call":"鸣唱为急促的“chew-chew wit-chew”或更短的“chew-chew’trrrrr”。叫声为尖锐高音“tsiip”，受惊时发出急促重复的“piit”或“put”。","habits":"留鸟。栖息于干燥区的低矮山地林下层及灌丛山坡，植被高度仅及胸高。通常成对或小群活动，紧贴地面觅食，亦降至地面翻扒枯叶。食物包括大型昆虫、种子及果实。","breeding":"已知繁殖期为雨季，约3–5月，其余繁殖信息缺乏。","identification":"与锈腹薮雀区别在于冠羽栗红而非黑色，腹部灰色而非黄褐。与重叠分布的白翅薮雀相比，本种体型明显较大，冠纹色深且缺白色翼斑。亚种间差异主要体现在前额颜色、整体羽色深浅及体型大小。","protection":"IUCN: LC（无危）","distribution":"繁殖区：厄瓜多尔西南部洛哈省西部（celica亚种）、中南部及东部洛哈省—秘鲁通贝斯地区（simonsi亚种）；秘鲁西北部安第斯山太平洋坡南至安卡什省（指名亚种seebohmi）。非繁殖区：无迁徙，全年留居上述区域。","other":"曾被认为与灰蓝薮雀或锈腹薮雀同种。亚种celicae仅凭单一标本描述，或为simonsi的异常个体。"},{"name":"锈腹薮雀","english_name":"Rusty-bellied Brushfinch","scientific_name":"Atlapetes nationi","overview":"锈腹薮雀（英文名：Rusty-bellied Brushfinch，学名：Atlapetes nationi），是雀形目雀鹀科薮雀属的独特鸟类。秘鲁西部安第斯山脉高海拔地区特有的薮雀。它以黑色头部、淡黄褐色腹部及明显的“白髭”状侧喉纹为标志，是唯一在秘鲁境内具此组合的薮雀。主要栖息于海拔2100–4000米的干燥灌丛及疏林坡地，为留鸟。","appearance":"全长约17厘米，体重40.5–43.4克，体型较大，嘴厚重而长。成鸟雌雄同色：额、脸全黑，头顶在多数光线下看似黑色，近看略泛暗橄榄褐，少数个体头顶散生白色羽；喉及髭区白色，颏黑色并向下延伸为半侧喉短黑纹；上体铅灰色，翼和尾略深，翼弯处具小白缘；胸有宽阔灰色胸带，将肉桂黄褐色的腹部与喉部明显分隔；虹膜暗红褐，嘴黑色，脚灰褐。幼鸟上体带褐，喉至中腹淡黄，胸胁具黄褐纵纹。亚种brunneiceps较指名亚种色淡，上体略带橄榄灰，面侧及冠部常具白斑，下体灰带极淡，腹肉桂色更浅并上延至喉侧，使喉部呈黄褐洗染。","call":"歌声尚未被录音记录。常见叫声为响亮而硬的“tchip”或高音的“ti”；另有一种可能是乞食声的重复鼻音“zzppp”。","habits":"留鸟，不迁徙。成对或三五小群在地面或近地面灌丛中觅食，食物组成尚无详细资料。典型生境为安第斯山西坡的干燥灌丛及零散林地，海拔2000–4000米。","breeding":"繁殖资料稀少。仅在6月于利马地区记录到幼鸟，其余繁殖细节未知。","identification":"在秘鲁境内，锈腹薮雀是唯一具黑色头与黄褐色腹部的薮雀，与色彩更鲜明的棕冠薮雀近似但色更暗，冠纹极不明显。亚种brunneiceps比指名亚种色淡，冠及面侧具白斑，胸带模糊，腹肉桂色更浅且上延至喉，易于区分。","protection":"IUCN: LC（无危）","distribution":"繁殖区：秘鲁西部安第斯山，指名亚种分布于利马省，brunneiceps亚种分布于伊卡、阿亚库乔南至阿雷基帕省。非繁殖区：全年留居上述区域，无迁徙记录。","other":"曾与灰蓝薮雀或棕冠薮雀被视为同一种，现已独立为有效种，包含两个亚种。"},{"name":"灰脸薮雀","english_name":"Cuzco Brushfinch","scientific_name":"Atlapetes canigenis","overview":"灰脸薮雀（英文名：Cuzco Brushfinch，学名：Atlapetes canigenis），是雀形目雀鹀科薮雀属的鸟类。但在分布区内常见。灰蓝薮雀全身深灰色，脸部两侧呈黑色，头顶带有暗锈色条纹。分子数据显示，与灰耳薮雀和圣河薮雀的关系更近，而非曾被认为是其亚种的灰蓝薮雀。","appearance":"灰蓝薮雀是一种中等体型、长尾的雀鸟，全身几乎均匀地覆盖着烟灰色羽毛，头部两侧黑色，头顶有一条暗锈色带。腹部颜色略浅，翼和尾部呈黑色，初级飞羽边缘略显灰色。雄鸟和雌鸟外观极为相似，仅雌鸟体型略小。","call":"灰蓝薮雀发出一系列尖锐的吱吱声，被描述为“尖锐的颤音后跟着啾啾啾的连续音”。它们的晨歌由雄鸟单独发出，通常在黎明时分，不同于二重唱叫声，有时包含拉长的响亮音符。","habits":"灰蓝薮雀主要栖息在秘鲁安第斯山脉的湿润山地森林边缘和灌木丛，海拔高度在2,300至3,600米之间。它们倾向于居住在山地的湿润地带。关于饮食，虽然记录不多，但推测会食用地面无脊椎动物、种子和小型果实。它们属于次冠层觅食者群体，已观察到它们食用树上的种子。","breeding":"关于灰蓝薮雀的巢穴和卵的信息非常有限，但假设其巢为杯状。在2,300至3,600米的高海拔地区，它们表现出积极的繁殖行为，可能意味着它们在常规栖息地中繁殖。","identification":"灰蓝薮雀与灰蓝薮雀相似，但后者前额和头部两侧为黑色，眉斑白色，喉咙和颊纹亦为白色。灰蓝薮雀的灰度强度在下体上有显著变化，有些个体下体几乎统一的深灰色，而另一些则是淡灰色腹部。","protection":"IUCN：LC（无危）","distribution":"灰蓝薮雀主要分布在秘鲁南部安第斯山脉的库斯科地区，海拔高度介于2,300至3,600米之间。","other":"灰蓝薮雀曾一度被视为灰蓝薮雀的一个亚种，但最近的研究将其分类为独立物种。"},{"name":"黄胸灰耳薮雀","english_name":"Vilcabamba Brushfinch","scientific_name":"Atlapetes terborghi","overview":"黄胸灰耳薮雀（英文名：Vilcabamba Brushfinch，学名：Atlapetes terborghi），是雀形目雀鹀科薮雀属的鸟类。首次被发现是在1966至1970年间，由约翰·特博格和约翰·韦斯克领导的探险队在秘鲁南部中央的未开发的维卡班巴山脉顶峰。栖息于海拔2520-3520米的湿润山地森林和矮林中。","appearance":"黄胸灰耳薮雀是一种中等体型的长尾鸣禽，具有暗绿色背部，翅膀和尾巴更黑，两侧脸上的黑色面罩与红褐色的冠部和颈背形成鲜明对比。它的下体呈鲜艳的黄色，两胁带有橄榄色的洗染。成鸟的性别相似，头部前冠、冠部和颈背为红褐色，背部黑色，带有橄榄绿色晕染。虹膜为丰富的棕色，喙为黑色，跗蹠和脚趾为深棕色。","habits":"黄胸灰耳薮雀主要栖息在秘鲁西北部库斯科地区的湿润安第斯森林中。它们在非繁殖季节通常会集群活动，而在繁殖季节则在地面或灌木丛中筑造碗状巢穴。","identification":"黄胸灰耳薮雀在其分布区域内没有其他物种与其外观相似，尤其是没有其他具有红褐色冠部和黄色下体的物种。地理上，它被南部的黑脸薮雀所取代，后者具有显著不同的黑色喉部，较暗淡的黄色胸部和腹部，以及广泛的暗斑点。","protection":"IUCN：NT（近危）","distribution":"黄胸灰耳薮雀的分布局限于秘鲁西北部库斯科地区的维卡班巴山脉，栖息在该地区的湿润安第斯森林中。"},{"name":"灰耳薮雀","english_name":"Grey-eared Brushfinch","scientific_name":"Atlapetes melanolaemus","overview":"灰耳薮雀（英文名：Grey-eared Brushfinch，学名：Atlapetes melanolaemus），是雀形目雀鹀科薮雀属的鸟类。最显著的外部特征是暗灰色的脸部和上体，带有黄褐色的下体和锈红色的冠羽。分布于南美洲安第斯山脉的湿润森林中，从秘鲁库斯科至玻利维亚拉巴斯一带。","appearance":"灰耳薮雀是一种长尾、类似麻雀的鸟类，具有暗灰色的面部和上体，下体呈淡黄褐色，头部有醒目的锈红色冠羽。与范围内的其他薮雀相比，它结合了黄色腹部和红色冠羽的特点，比相似的栗头绿雀更鲜艳，后者背部呈橄榄黄色。雌雄幼鸟的羽毛细节和大小变化需进一步观察研究。","call":"灰耳薮雀发出简单的哨声歌曲和高亢、尖锐的叫声。","habits":"灰耳薮雀栖息在海拔较高的山地森林和灌木丛中，活动范围广泛。它们倾向于在地面附近觅食，以昆虫和其他小型无脊椎动物为食。","breeding":"繁殖期主要集中在7月至12月，筑巢高峰期在10月。巢为开放式的杯状，主要由厚草和Chusquea竹叶构成，内部铺有细干草，通常隐藏在草丛、蕨类植物或灌木中，离地面平均高度约为0.9米。每窝产卵2枚，卵呈奶油粉色，带有红棕色斑点，集中在较大端。孵化期大约为14至15天，雏鸟孵化后约13至14天离巢。雏鸟出生时体重约为3.24克，皮肤粉红，头背有灰色绒毛，嘴部内侧红色，腿色粉灰，爪尖黄色，喙黑色，嘴角黄色。","identification":"与同属的薮雀相比，灰耳薮雀可通过其独特的颜色组合——黄色腹部和红色冠羽来区分。此外，它的下体颜色较深，更偏橄榄色，且喉部黑色。","protection":"IUCN：LC（无危）","distribution":"灰耳薮雀分布于南美洲的秘鲁库斯科东南部至相邻的玻利维亚西部拉巴斯地区。","other":"灰耳薮雀有时被认为是红颈薮雀的一个亚种，尽管其脸部并不比许多近亲更黑，而所谓的灰“耳”往往不易察觉。"},{"name":"棕枕薮雀","english_name":"Bolivian Brushfinch","scientific_name":"Atlapetes rufinucha","overview":"棕枕薮雀（英文名：Bolivian Brushfinch，学名：Atlapetes rufinucha），是雀形目雀鹀科薮雀属的独特鸟类，主要分布在南美洲的玻利维亚境内。在玻利维亚中部和北部安第斯山脉东坡的中高海拔地带，湿润的山地森林中尤为常见。","appearance":"棕枕薮雀在外观上具有显著的特点，通常以成对或家庭小群的形式活动，偶尔也会加入混合物种的鸟群中。它们的头部呈灰褐色，枕部有一块明显的棕红色斑块，这是其得名的原因。身体其余部分多为橄榄褐色，腹部较淡，两翼和尾巴有深色条纹。成鸟和幼鸟在外形上有细微差别，但总体上保持一致的色彩模式。","call":"棕枕薮雀的鸣叫声清脆悦耳，但在文献中关于其具体叫声的描述较为有限，通常在群体中交流时发出。","habits":"这种鸟栖息于安第斯山脉的湿润山地森林中，偏好中高海拔的环境。它们的活动范围主要集中在森林的下层植被，以昆虫和其他小型无脊椎动物为主要食物来源。棕枕薮雀的飞行能力较强，能在树冠间灵活穿梭。","breeding":"有关棕枕薮雀的繁殖行为细节尚不完全清楚，但一般认为它们在春季开始繁殖季节，营巢于林下隐蔽处，由雌鸟负责孵卵，雄鸟则参与食物供应。","identification":"棕枕薮雀在其分布范围内较为独特，与北方的Black-faced Brushfinch和南方的黄头薮雀有明显的界限。与其他种类的薮雀相比，棕枕薮雀的枕部红棕色斑块是最显著的识别特征。","protection":"IUCN：LC（无危）","distribution":"棕枕薮雀主要分布于南美洲的玻利维亚，特别是在安第斯山脉的中高海拔湿润山地森林中。这一区域覆盖了玻利维亚的中部和北部。","other":"尽管与一些近缘种存在相似性，棕枕薮雀在形态和生态习性上有着独特的特征，使其成为研究玻利维亚山地生态系统的重要物种。"},{"name":"黄头薮雀","english_name":"Fulvous-headed Brushfinch","scientific_name":"Atlapetes fulviceps","overview":"黄头薮雀（英文名：Fulvous-headed Brushfinch，学名：Atlapetes fulviceps），是雀形目雀鹀科薮雀属的鸟类。眼先和颊带黄色形成鲜明对比，上体绿色，翼和尾石板灰色边缘略带绿，下体橄榄色胸带，两胁和肛周橄榄色，腹部黄色。分布于南美洲的玻利维亚和阿根廷西北部，栖息于安第斯山脉的湿润山地森林和开阔的湿润灌木丛。","appearance":"体长约17厘米，体重约28.2克。头部至脸颊、耳羽、颈侧和颈背为肉桂色，眼先和颊带黄色，与肉桂色形成鲜明对比。上体绿色，翼和尾石板灰色边缘略带绿色，翼覆羽呈绿色。下颏、喉部黄色，与肉桂色颊带形成对比。下体具橄榄色胸带，两胁和肛周橄榄色，腹部黄色。虹膜中棕色，喙黑色，腿棕色。性别相似。幼鸟未正式描述。","call":"鸣唱从低矮植被发出，相对均匀，短而爆炸性，先有一个引子音符，随后重复3-5次音符，如‘tii’Chew-Chew-Chew！’或更快的‘twi-tew’tew’tew’，有时延长至‘pit-twee pit’ Chew-Chew-Chew’。叫声为细薄的‘zit’；警报声为‘pi ziue’。","habits":"以昆虫、种子和果实为食。在距地面至3米高的灌木丛中觅食，偶尔沿厚苔藓覆盖的树枝搜索，会突然飞出捕捉昆虫。通常单独或成对活动。","identification":"与红黄灰背雀外观相似，但后者无黄色颊带和眼先，且黄头薮雀偏好较干燥和更开阔的生境。","protection":"IUCN：LC（无危）","distribution":"分布于安第斯山脉的玻利维亚（从拉巴斯向南至塔里哈）和相邻的阿根廷西北部（南至胡胡伊和萨尔塔）。"},{"name":"黄纹薮雀","english_name":"Yellow-striped Brushfinch","scientific_name":"Atlapetes citrinellus","overview":"黄纹薮雀（英文名：Yellow-striped Brushfinch，学名：Atlapetes citrinellus），是雀形目雀鹀科薮雀属的鸟类。栖息于亚热带或热带湿润的高山森林和高海拔灌木丛中。","appearance":"这种薮雀体型健壮，长约17厘米，体重可达28克。其最显著的特征是全身绿色，头部图案复杂，前额呈黑色渐变为暗橄榄褐色的冠羽和颈背，与黄色眉纹形成鲜明对比。眼圈下半部白色，与黑色的颊部和耳羽前方形成对比，耳羽下方有黄色斑点。下颌至喉部有亮黄色区域，被宽阔的黑色颊纹包围，胸部至腹部橄榄色，中央腹部和尾下覆羽黄色最明显，侧面带有绿意。虹膜深红色，喙黑色，腿灰黑色至淡粉色。雌雄相似，幼鸟描述尚未详尽。","call":"其鸣唱为简单而爆发性的‘chip-pip’ chew-chew-chew声，叫声为‘tsip’。","habits":"黄纹薮雀主要以昆虫为食，包括甲虫、蚂蚁、其他膜翅目昆虫和蜘蛛，同时也全年食用多种果实，至少30种不同的植物果实，尤其在尤恩加斯森林的南部区域，被认为在种子传播中扮演重要角色。它们通常成对或家庭小群活动，觅食主要在地面或近地面，当吃果实时则会进入树冠层。","identification":"与其它薮雀的区别在于其全身绿色，以及独特的头部颜色模式，尤其是明亮的黄色眉纹和喉部，以及黑色的颊纹。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲阿根廷西北部的安第斯山脉山脚地带。"},{"name":"黄踝饰雀","english_name":"Yellow-thighed Brushfinch","scientific_name":"Atlapetes tibialis","overview":"黄踝饰雀（英文名：Yellow-thighed Brushfinch，学名：Atlapetes tibialis），是雀形目雀鹀科薮雀属的独特鸟类。其最显著的特征是腿基部的黄色羽毛簇，整体呈灰黑色，头部和翅膀颜色更深。这种鸟体型较大，尾巴较长，喙呈圆锥形。常在地面附近活动，成对或小群体出现在热带湿润山林中，分布于哥斯达黎加和巴拿马的高海拔地区。","appearance":"成年黄踝饰雀背部和腹部呈烟灰色，头部、翅膀、长尾、喉部为深黑色。最引人注目的是其鲜亮的黄色大腿羽毛，与暗色的身体形成鲜明对比。雌雄外观相似，幼鸟缺乏黄色羽毛，整体色调较暗淡。","call":"鸣叫声为混杂的口哨声和嗡嗡声，快速重复，形成独特的歌曲。","habits":"栖息于海拔1200米以上的热带湿润山林，偏好森林边缘地带。以昆虫、蜘蛛、浆果和花蜜为食，活动范围广泛，包括森林下层、牧场、花园和森林边缘。","breeding":"繁殖期，雌鸟会建造隐蔽的巢，位于草地、竹丛或茂密树冠中，离地0.7至4.6米。每窝产2枚带有褐色斑点的白色或浅蓝色蛋，由雌鸟孵化约12至14天。","identification":"黄踝饰雀以其独特的黄色大腿羽毛易于识别。与同属的黄绿饰雀(Pezopetes luteoviridis)相比，后者分布区不重叠，且具有橄榄绿色的胸部、颈圈、下尾覆羽和腹部。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲的哥斯达黎加和巴拿马，主要栖息在1700米至林线之间的湿山林中，非繁殖季节可降至1200米。","other":"与大脚薮雀关系密切，同属Passerellidae科，而非真正的雀科鸟类。"},{"name":"绿踝饰雀","english_name":"Yellow-green Brushfinch","scientific_name":"Atlapetes luteoviridis","overview":"绿踝饰雀（英文名：Yellow-green Brushfinch，学名：Atlapetes luteoviridis），是雀形目雀鹀科薮雀属的鸟类。其橄榄绿色的身体与黑色头部形成鲜明对比，腿部基部的亮黄色羽毛使其独特。该物种仅分布在巴拿马西部高地，与近缘种黄腿雀无地理重叠。","appearance":"绿踝饰雀体型中等偏大，尾长，全身橄榄绿色，背部颜色较深，腹部略浅。头部黑色，翼弯处及腿部有鲜亮的黄色羽毛，翼羽及尾羽深橄榄色。雄雌外观相似，无显著性别差异。","habits":"绿踝饰雀偏好森林及边缘地带，通常在低矮灌木丛中成对或小群活动，有时也会到达中层树冠。它们主要在地面附近觅食，食物组成尚不清楚，但可能与近缘种黄腿雀类似。","identification":"绿踝饰雀与黄腿雀（Pselliophorus tibialis）在外形上有相似之处，但绿踝饰雀的橄榄绿体羽和黑色头部是明显区别点。两者地理分布上不重叠。","protection":"IUCN：VU（易危）","distribution":"绿踝饰雀主要分布在中美洲巴拿马西部的高海拔地区。"},{"name":"拟唐纳雀","english_name":"Tanager Finch","scientific_name":"Oreothraupis arremonops","overview":"拟唐纳雀（英文名：Tanager Finch，学名：Oreothraupis arremonops），是雀形目雀鹀科拟唐纳雀属的鸟类。体型略大且结实，分布于南美洲哥伦比亚西部和厄瓜多尔西北部的云雾森林中。其特征为栗褐色，头部黑色，脸部和头顶有银色条纹。","appearance":"拟唐纳雀体长约20至20.5厘米，结构圆胖，喙短且微弯，上颌有时覆盖下颌。头部黑色，有宽大的灰白色中冠条纹和眼上方至颈侧的明显灰白条纹；颈部和背部橄榄色泛棕，上翼和尾羽深黑色边缘棕色；喉咙黑，胸部和腹部明亮的tawny色，两胁橄榄色，腹部有明显的白色斑块，呈V形延伸至胸部下方；虹膜深栗色；喙黑；腿暗棕色。雌雄相似，幼鸟比成鸟更暗淡和棕色。","call":"鸣声高亢而刺耳，以3至5个鼻音开始，随后连续发出刺耳的颤音，如‘tzz tzz tzzz tz-zz-zz-tz tz tz tz tz tz’，声音在结尾处加强，有时会重复多次形成二重奏。叫声为尖锐的‘tseet’，还有一种类似蛙鸣的‘wert’。","habits":"常单独或成对出现在潮湿的灌木丛下，靠近地面，通常在湿润的植被下觅食，如落叶层中的苔藓森林，有时会翻找落叶。一般不在混种群中活动，常与家庭成员一起。以地面及其附近为觅食范围。","breeding":"关于饮食的信息不多。已知巢穴通常呈蛋形，由苔藓构成，离地约一米高，巢顶亦由苔藓组成，已知有一次发现含一枚白色卵的巢穴。","identification":"拟唐纳雀与其他种类的区别在于其独特的颜色模式，包括黑色头部与亮色腹部的对比，以及特定的叫声。","protection":"IUCN：LC（无危）。此前曾被认为是易危物种。在全球范围内不构成威胁，但在哥伦比亚和厄瓜多尔的局部地区，由于生境丧失，其数量正在减少。全球估计成熟个体数量在10,000到19,000之间，且被认为在下降。在哥伦比亚，Munchique国家公园的种群估计为1,000个成熟个体。在厄瓜多尔，现代记录来自Tandayapa地区和Cotacachi-Cayapas国家公园。生境的破坏主要源于人类活动，包括道路建设和伐木，导致栖息地损失。","distribution":"分布于哥伦比亚西部（安蒂奥基亚、里斯拉尔达、考卡谷、考卡和纳里尼奥）和厄瓜多尔西北部（因巴布拉和皮钦查）。","other":"该物种曾被错误分类为唐纳雀或雀科，后来被重新归类为新世界雀鹀科的一员。"},{"name":"丛唐纳雀","english_name":"Common Chlorospingus","scientific_name":"Chlorospingus flavopectus","overview":"丛唐纳雀（英文名：Common Chlorospingus，学名：Chlorospingus flavopectus），是雀形目雀鹀科灌丛唐纳雀属的鸟类。分布广泛，自墨西哥西南部至阿根廷西北部的中美洲和南美洲高山区可见其踪迹。具有橄榄色上体，灰白至褐色头部，鲜明的眼后白色斑块，喉部及下体呈淡黄色，腹部偏白。","appearance":"丛唐纳雀体型小巧，长约13.5厘米，平均重约20克。头部颜色多变，从灰色到褐色不等，眼周有显著的白色斑块，上体橄榄绿色，下体黄色逐渐变为白色腹部。幼鸟相比成鸟颜色更深，上体更棕色，下体更暗，眼后斑块较淡。不同亚种间存在显著差异，涉及头、喉及胸部的颜色、斑纹以及眼部标记。","call":"发出尖锐的‘tseeet’或‘chit’声，叫声多样，各地种群的歌曲差异显著。","habits":"栖息于海拔400至2300米的云雾森林，偏好茂密的下层植被和邻近的灌木空地。以小群体形式活动，加入混群觅食，主要食物为昆虫、蜘蛛、小果实和花蜜。通常在树冠层至地面活动，偶尔下地觅食。","breeding":"繁殖季节多在4月至6月，筑巢于树上或地面上，由苔藓、草、叶和细根构成，内部铺有细腻纤维。每窝产卵2枚，偶见3枚或仅1枚，卵壳呈淡白色，带有棕色、肉桂色和红色斑点。雌鸟孵卵，孵化期约为14天，双亲共同喂养雏鸟，雏鸟期大约13至14天。","identification":"与乌顶丛唐纳雀的区别在于后者头部更黑，有明显的白色眉纹而非眼后斑块。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲，从墨西哥西南部至阿根廷西北部，常见于哥伦比亚、委内瑞拉、厄瓜多尔和秘鲁的特定海拔范围内。","other":"丛唐纳雀在一些地区可能面临栖息地丧失的威胁，但由于其适应力强，即便在次生灌木林和狭窄的森林走廊中也能生存。"},{"name":"塔卡丛唐纳雀","english_name":"Tacarcuna Chlorospingus","scientific_name":"Chlorospingus tacarcunae","overview":"塔卡丛唐纳雀（英文名：Tacarcuna Chlorospingus，学名：Chlorospingus tacarcunae），是雀形目雀鹀科灌丛唐纳雀属的小鸟，体型较小，仅分布于巴拿马东部及邻近的哥伦比亚西北部。其自然栖息地位于海拔约800至1500米的湿润山地森林中。","appearance":"塔卡丛唐纳雀通体橄榄棕色，腹部更显黄赭色，腹部下方呈灰色，具有明显的虹膜颜色，通常为橙色或淡灰白色，眼睛周围有淡色眼圈。头部和上体包括翼羽覆盖着深橄榄色，翅膀弯曲处呈浅黄色，下体由喉咙到胸部为暗黄色，中间胸和腹部为黄白色。成年个体性状相似，幼鸟比成鸟稍暗淡，喉部为淡黄色。","call":"其叫声独特，与巴拿马丛唐纳雀和黄喉丛唐纳雀的叫声有明显区别，具体叫声特征尚需更多研究。","habits":"这种鸟类通常以小群体形式出现，常与多种物种混合群居，偏好湿润至潮湿的苔藓森林，偶尔也会出现在边缘地带、密集的次生林和靠近森林的零星树木附近。","identification":"与巴拿马丛唐纳雀相比，塔卡丛唐纳雀的腹部更为灰暗，面部与头部的暗色部分对比不那么鲜明，体型较小，平均长度约为13厘米。而与黄喉丛唐纳雀的区别在于后者拥有深褐色虹膜，喉咙鲜黄色与胸部淡黄色形成鲜明对比。","protection":"IUCN：LC（无危）","distribution":"塔卡丛唐纳雀主要分布于巴拿马东部和哥伦比亚西北部，特别是在塞罗·塔卡库纳山脉周边的云雾森林中，此地横跨两国边境。","other":"塔卡丛唐纳雀属于Chlorospingus属，该属的鸟类过去被归入裸鼻雀科，现认为更接近Passerellidae科的Arremonops。"},{"name":"巴拿马丛唐纳雀","english_name":"Pirre Chlorospingus","scientific_name":"Chlorospingus inornatus","overview":"巴拿马丛唐纳雀（英文名：Pirre Chlorospingus，学名：Chlorospingus inornatus），是雀形目雀鹀科灌丛唐纳雀属的鸟类。以橄榄棕色为主，腹部呈鲜艳的黄赭色，脸部深黑色，拥有一双引人注目的浅色眼睛。分布于巴拿马东部山麓地带，海拔约800至1200米。","appearance":"成年巴拿马丛唐纳雀体长约15厘米，体重介于20至36克之间。头部冠部至眼侧呈暗灰色，与橄榄绿色上体形成鲜明对比；翅膀基部边缘为暗绿色，内侧翼羽橄榄色更浓，尾羽中央为深色，外侧渐变为橄榄色；喉咙呈淡黄色，胸部逐渐变为橄榄黄色，腹部及臀部羽毛颜色更为鲜亮。虹膜白色至浅橙黄色，喙黑色，腿灰蓝至黑褐色。雌雄相似，幼鸟特征未详述。","call":"会发出三种不同类型的细薄、尖锐的高音，包括‘spéétza’、简单的‘tsip’和‘chuweet?’，这些叫声可单独发出，重复多达四次，或是以各种组合形式出现。","habits":"栖息于湿润森林的树冠层和边界，偏好藤蔓缠绕和竹林覆盖的矮木林。常见于海拔780至1700米之间，通常在3到6只的小群体中活动，有时混群或独立觅食。食物包括果实和小型节肢动物，觅食范围从树冠到低层植被。","identification":"在分布范围内具有独特性，与其他同类物种相比，其橄榄棕色的整体外观和亮黄赭色的腹部是明显的识别特征。","protection":"IUCN：LC（无危）","distribution":"分布于巴拿马极东地区，包括塞罗萨波、松加努鲁多山脉和皮雷山，直至哥伦比亚边境附近的尼奇高地。","other":"在达里恩国家公园中较为常见，尽管全球分布范围小，目前尚未受到森林砍伐的威胁。"},{"name":"暗腹丛唐纳雀","english_name":"Dusky Chlorospingus","scientific_name":"Chlorospingus semifuscus","overview":"暗腹丛唐纳雀（英文名：Dusky Chlorospingus，学名：Chlorospingus semifuscus），是雀形目雀鹀科灌丛唐纳雀属的鸟类。传统上归类于灌丛唐纳雀属，现认为与雀鹀科（Passerellidae）纹头雀属（Arremonops）更接近。常见于哥伦比亚西部和厄瓜多尔西部的云雾森林及其边缘地带，海拔约700至2200米。","appearance":"这种外表朴素、类似唐纳雀的雀科成员，雌雄相似，上部橄榄色，下部灰色，喙粗壮，眼睛呈红色或淡色。全身缺乏黄色，有助于与同属其它物种区分开来。","call":"发出尖锐的吱吱声和噼啪声，有时会加速成杂乱的叽叽喳喳声。","habits":"小群活动，通常在林下层和中间层穿梭，偶尔进入树冠层。常跟随混合物种群移动。","identification":"与同属其他物种相比，其全身缺乏黄色，易于辨认。","distribution":"南美洲的哥伦比亚西部和厄瓜多尔西部，主要栖息于亚热带或热带湿润的山地森林。"},{"name":"乌顶丛唐纳雀","english_name":"Sooty-capped Chlorospingus","scientific_name":"Chlorospingus pileatus","overview":"乌顶丛唐纳雀（英文名：Sooty-capped Chlorospingus，学名：Chlorospingus pileatus），是雀形目雀鹀科灌丛唐纳雀属的鸟类。小型的灌丛唐纳雀，以黑色头冠和明显的白色眉纹为显著特征，主要分布在中美洲的哥斯达黎加和巴拿马西部的高海拔地区。","appearance":"体长约14厘米，体重16至24.1克。头部呈烟灰色，有宽白侧冠纹，从眼睛前方延伸至颈部侧面，有时向眼睛方向有分支；上部橄榄色，飞羽暗淡，边缘橄榄黄，尾羽橄榄色。喉咙微白，带有几乎看不见的小黑点，与宽阔的橄榄黄色胸带形成鲜明对比，这种颜色延伸到两侧、胁腹和尾下覆羽；下胸部中心和腹部黄白色。成年鸟性别相似，幼鸟头部呈黄褐色，下方较暗淡，眉纹橄榄色较淡。","call":"鸣叫声包括尖细的‘tsit’音，有时连续不断或随后是‘t-z-z-z-z-zit, chat-t-t-t-, zwee-zwee-zwee...’等音调；还有一种高双音‘zit’或‘zeet’，以及各种尖锐的‘tsip’和‘tseep’声；短促的叽喳声和啾啾声。黎明时，雄鸟会发出刮擦而快速的‘see-chur see-chur see-chur see see see-chur’歌声，被描述为愉快、略带嘶嘶声的快速‘sit-sit swíee-d-d-d-d-d-d sit-a-wit’。","habits":"栖息于云雾湿润的山地森林、湿润的矮树丛和高大的次生林，偶尔出现在牧场中的小片林地，若靠近高大森林则更常见；海拔约1500至2850米，或接近树线；在哥斯达黎加，主要见于塔拉曼卡山脉上方2000米处和蒂拉兰山脉上方1600米处。以小群或松散的小群活动，由2至6个个体组成，其他时间与较大群体相关联，偶尔可达20至40只鸟；与多种其他物种混群，如黄䴕雀、新世界莺鸟（Parulidae）和其他小型鸟类。","breeding":"繁殖季节报告为哥斯达黎加的2月至7月。捍卫繁殖领地，可能是合作繁殖者，几个成鸟在同一巢穴中被观察到。巢穴为柔软、庞大的杯状结构，由苔藓、地衣和胡须苔（Usnea）制成，内衬精细的草或细黑根，位于裂缝、垂直河岸顶部或密集低矮灌木下的苔藓簇中，或在树枝上的寄生植物中，高达11米。每次产卵1至2枚，卵白色，有粉红棕色斑点，主要在大端；关于孵化期和雏鸟期的信息未知；三只或更多成鸟可能照顾雏鸟。","identification":"与普通丛唐纳雀相比，乌顶丛唐纳雀头部更黑，眉纹更为明显。在Irazu-Turrialba地区的某些个体更灰，缺乏下体的黄色。幼鸟头部呈褐色，下方较暗淡，眉纹橄榄色较淡。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲哥斯达黎加中部至巴拿马西部（Ngäbe-Buglé）的山区。"},{"name":"短嘴丛唐纳雀","english_name":"Yellow-whiskered Chlorospingus","scientific_name":"Chlorospingus parvirostris","overview":"短嘴丛唐纳雀（英文名：Yellow-whiskered Chlorospingus，学名：Chlorospingus parvirostris），是雀形目雀鹀科灌丛唐纳雀属的鸟类。传统上归类于雀鹀科灌丛唐纳雀属，现认为更接近雀鹀科纹头雀属（Arremonops）。该鸟种分布于南美地区的云雾森林，包括哥伦比亚、委内瑞拉、圭亚那、苏里南、厄瓜多尔、秘鲁、玻利维亚、巴拉圭、巴西、智利、阿根廷、乌拉圭以及马尔维纳斯群岛（福克兰群岛）。","appearance":"其外观呈现暗淡的橄榄绿色上部，灰色下部，拥有淡色的眼睛和黄色的喉部，后者环绕着颈部两侧。最显著的特征是其‘八字胡’形状的黄色喉部标记，以及更加白色的眼环。","habits":"通常成对或小群体出现在森林内部较低的位置，偏好阴暗的峡谷及靠近溪流的环境。","identification":"与黄喉丛唐纳雀极为相似，但可通过‘八字胡’形状的黄色喉部标记和更白的眼环进行区分。","distribution":"分布在南美洲的云雾森林地带，从哥伦比亚至玻利维亚，包括安第斯山脉东坡的地区。"},{"name":"黄喉丛唐纳雀","english_name":"Yellow-throated Chlorospingus","scientific_name":"Chlorospingus flavigularis","overview":"黄喉丛唐纳雀（英文名：Yellow-throated Chlorospingus，学名：Chlorospingus flavigularis），是雀形目雀鹀科灌丛唐纳雀属的小型鸟类。其特征为橄榄绿色的上体与灰白色的下体，最显著的是黄色的喉咙和腹侧羽。分布于中美洲巴拿马至南美洲秘鲁的安第斯山脉山麓和亚热带区域。","appearance":"黄喉丛唐纳雀的外观相对沉闷，类似唐纳雀，上体橄榄绿色，下体灰白色。其最为突出的特征是鲜亮的黄色喉咙和下尾羽覆羽。与Short-billed Chlorospingus相比，黄喉丛唐纳雀的黄色不仅限于胡须部分而是整个喉咙，眼周颜色为灰而非棕红色。成年个体通常在700至1800米的高度活动。","habits":"黄喉丛唐纳雀常见于小群体中，经常跟随混合物种的鸟群。它们栖息于海拔700至1800米的湿润山区森林，偏好亚热带或热带的潮湿环境。","breeding":"在哥伦比亚，二月发现巢穴，四月观察到喂养幼鸟，九月有筑巢行为。在东北厄瓜多尔，十二月发现正在建造的巢穴，八月观察到含有两个蛋的巢穴。巢穴结构为厚实的苔藓杯状，顶部覆盖自然生长的苔藓，置于距地面1至15米高的附生植物丛中，平均高度2.6米，内含两至三个蛋，平均尺寸为21.6mm x 16.1mm，新鲜重量约为3.2克。孵化期估计由雌鸟单独完成，大约16至18天，幼鸟孵化重量约2.6克，离巢时体重约21.6克。在秘鲁东南部，繁殖成功率在小型河流岛屿上较高，因较少受到潜在巢穴捕食者的侵扰。","protection":"IUCN：LC（无危）。在分布范围内，黄喉丛唐纳雀并非全球受威胁物种，常见于安第斯山脉的湿润山地斜坡，多个保护区覆盖了其狭长分布区，如哥伦比亚的法拉隆斯德卡利国家公园和库埃瓦德洛斯瓜查罗斯国家公园，厄瓜多尔的卡亚姆贝-科卡生态保护区和桑加伊国家公园，以及秘鲁的马努国家公园。然而，人类定居和森林砍伐对低海拔地区的压力最大，尽管短期内仍存在相当数量的完整栖息地。","distribution":"分布于中美洲巴拿马至南美洲秘鲁的安第斯山脉山麓和亚热带区域。"},{"name":"灰喉丛唐纳雀","english_name":"Ashy-throated Chlorospingus","scientific_name":"Chlorospingus canigularis","overview":"灰喉丛唐纳雀（英文名：Ashy-throated Chlorospingus，学名：Chlorospingus canigularis），是雀形目雀鹀科灌丛唐纳雀属的小型鸟类。分布于中美洲至南美洲，包括哥斯达黎加、巴拿马、哥伦比亚、厄瓜多尔、秘鲁和委内瑞拉。其栖息地主要为亚热带或热带的干燥森林、湿润低地森林以及湿润山地森林。","appearance":"灰喉丛唐纳雀体型小巧丰满，类似金翅雀的外观。背部呈暗淡的橄榄绿色，喉咙为淡灰色，腹部带有黄色调。喙部厚实。雄雌鸟外观相似。","habits":"生活在海拔较低的丘陵森林中，通常比丛唐纳雀所处的海拔要低，但仍存在重叠。常成对出现在混合物种的群落中，通常在树冠层觅食。","identification":"与丛唐纳雀相比，灰喉丛唐纳雀的分布区较低，喉咙颜色为灰色，有助于区分。","distribution":"分布于中美洲至南美洲，包括哥斯达黎加、巴拿马、哥伦比亚、厄瓜多尔、秘鲁和委内瑞拉。具体繁殖区域与非繁殖区域未明确区分。"},{"name":"西䳭唐纳雀","english_name":"Western Chat-Tanager","scientific_name":"Calyptophilus tertius","overview":"西䳭唐纳雀（英文名：Western Chat-Tanager，学名：Calyptophilus tertius），是雀形目拟䳭唐纳雀科拟䳭唐纳雀属的鸟类。分布在多米尼加共和国和海地的湿热带雨林中的羞涩地面觅食鸟类，常见于海拔700至2,000米地带，尤其靠近溪流处。其暗褐色的外表，搭配白色喉部逐渐过渡至灰棕色的胸腹，使它在森林中显得独特。","appearance":"该物种长约20至21厘米，重约40至55克，拥有长喙和长尾，外形与嘲鸫相似。成鸟头部呈深橄榄褐色，顶部近乎黑色，眼睛与喙之间有小块锈色斑点。上半身呈深红褐色，而喉咙和下体为白色，侧翼和下腹部则带有明显的灰色调。","call":"西䳭唐纳雀的完整歌曲是一系列响亮的口哨声，如“tsew, tsee-ew, tsee-ew, tsu, tsu, tsu”，尾音快速连续，常以片段形式演唱。鸣叫声为“chep”。","habits":"全年居住于其分布范围内，偏好密集的落叶林和灌木丛，特别是在山谷和水边。它主要在厚厚的落叶层中觅食，以昆虫和其他无脊椎动物为主，偶尔也会吃一些水果。","breeding":"繁殖季节估计在5月至7月，已知的巢穴构造复杂，由粗硬材料如木质茎、藤蔓、苔藓和地衣制成，内部铺有细腻的材料，通常离地面1至1.5米高。父母双方共同抚育雏鸟。","identification":"与东䳭唐纳雀相比，西䳭唐纳雀略大，且眼环为黄色。两者的鸣唱更为清晰，具有明显的口哨音。","protection":"IUCN：VU（易危）","distribution":"分布于多米尼加共和国的Sierra de Bahoruco山脉和海地的Massif de la Hotte及Chaîne de la Selle山区。","other":"曾被认为是东䳭唐纳雀的亚种，但基于线粒体DNA和内含子序列的高度差异，现被视为独立物种。"},{"name":"东䳭唐纳雀","english_name":"Eastern Chat-Tanager","scientific_name":"Calyptophilus frugivorus","overview":"东䳭唐纳雀（英文名：Eastern Chat-Tanager，学名：Calyptophilus frugivorus），是雀形目拟䳭唐纳雀科拟䳭唐纳雀属的鸟类。属于拟䳭唐纳雀科。仅分布于多米尼加共和国的海地岛，可能已在海地灭绝。本物种曾有三个亚种，其中两个被认为已灭绝。","appearance":"成年东䳭唐纳雀体长17至19厘米，体重约26至39克。其头部呈暗褐色，脸部主要为灰褐色，眼周有黄色线条和环。上身颜色为深橄榄褐色，喉咙和腹部白色，两侧和下腹带有灰褐色斑纹。亚种C. f. neibae体型较小，色泽较深，尾巴呈红色。","call":"鸣唱包括低沉滑音或哨声的“swerp, swerp, chip, chip, chip...”以及“weet-weet-werp chip-cheep-sweet...”。还发出尖锐的“chin chin chin”叫声。","habits":"东䳭唐纳雀全年居住在其分布范围内，偏好在地面或接近地面的地方觅食，主要以昆虫和其他无脊椎动物为食，辅以少量水果。","breeding":"繁殖季节估计在5月至7月之间，有关繁殖生态学的了解有限。已知的唯一一个巢穴位于黑莓丛旁的蕨类植物中，内有一枚卵。","identification":"与西䳭唐纳雀相比，东䳭唐纳雀略小，眼圈黄色，叫声和鸣唱有明显差异。","protection":"IUCN：NT（近危）","distribution":"东䳭唐纳雀分布于海地岛，包括多米尼加共和国的东北部海岸的萨马纳半岛（现已灭绝）和西部的内伊巴山脉，可能延伸至海地。Gonâve岛上的亚种C. f. abbotti自1980年代初期以来被认为已灭绝。","other":"面临的主要威胁是森林砍伐和农业用地扩张，导致栖息地丧失。"},{"name":"黑顶长尾唐纳雀","english_name":"Black-crowned Palm-tanager","scientific_name":"Phaenicophilus palmarum","overview":"黑顶长尾唐纳雀（英文名：Black-crowned Palm-tanager，学名：Phaenicophilus palmarum），是雀形目棕榈唐纳雀科棕榈唐纳雀属的鸟类。是海地和多米尼加共和国（包括萨奥纳岛）特有种，广泛分布于多种生境，包括城市和乡村地带。","appearance":"体长约17至18厘米，体重约24至32克。喙较长且尖锐，上颚黑色，下颚蓝灰色带黑色尖端。头部黑色，具白色眉纹和眼后斑，眼下方有一细白弧线；颈灰色，背部、翅膀和尾部橄榄黄绿色；喉部和胸部中央白色，胸侧、腹部及尾下覆羽灰色。幼鸟头部呈暗灰而非黑色，喉部有淡黄色调。","call":"鸣声变化多样，通常由杂乱的吱吱声组成，先渐强再减弱，最后以短促的“chit”音结尾。有时包含粗糙和嗡嗡声的乐句。叫声包括鼻音的“pe-u”和更高的“tseep”，以及低沉的“chep”。","habits":"栖息于各种环境，从干燥到湿润，从城市公园到乡村花园，甚至云雾林。常见于低海拔地区，少于2000米以上高度，最高可达约2500米。全年留居，主要以昆虫为食，辅以水果，偶尔摄取花蜜。活动范围广泛，常在家庭群中或混合种群中觅食。","breeding":"繁殖季节为4月至6月，筑深杯状巢于灌木或树上，高1至2米，有时更接近人类居住区。每窝产2至3枚蛋，孵化期约10天，雏鸟期同样约10天。","identification":"与灰顶长尾唐纳雀相似，但后者头顶和喉部中心灰色。鸣声和行为也有区别。","protection":"IUCN：LC（无危）","distribution":"分布于海地（东起Morne d’Enfer山，位于Selle山脉西缘）和多米尼加共和国（含Saona岛）。","other":"已成功适应人类改变的环境，常见于国家公园、自然保护区和生态走廊，以及受保护程度较低的农村和城市区域。"},{"name":"灰顶长尾唐纳雀","english_name":"Grey-crowned Palm-tanager","scientific_name":"Phaenicophilus poliocephalus","overview":"灰顶长尾唐纳雀（英文名：Grey-crowned Palm-tanager，学名：Phaenicophilus poliocephalus），是雀形目棕榈唐纳雀科棕榈唐纳雀属的鸟类。仅分布于Jacmel洼地以西，主要栖息在Tiburon半岛及周围地区，包括Massif de la Hotte山脉，这里是物种多样性和相对良好森林覆盖的庇护所。此鸟常见于森林，以探查枯叶中的节肢动物和软果为食，活动于多种生境，包括红树林、灌木丛、花园、城市公园、松林、半湿润森林和湿润森林。","appearance":"灰顶长尾唐纳雀全身下方为灰色，翅膀、背部和尾巴呈黄绿色，头部顶部、颈背和喉部为深灰色，与黑色面罩形成鲜明对比，而明亮的白色下巴更为突出。成鸟体长约18厘米，平均体重约27克，背部和翅膀颜色类似树叶的黄色绿色，腹部统一为灰色，冠部颜色与腹部相同为深灰色。","call":"其鸣唱和叫声特征尚不明确，但已知包括一个高音薄的‘tseeoo’声，比黑顶长尾唐纳雀的类似音调更短。","habits":"此鸟全年在栖息地居住，常在森林中层至树冠层觅食，偶尔加入混合物种觅食群。它主要以小型节肢动物为食，辅以水果。它通常通过从树叶上搜寻，无论是活的还是死的，来寻找节肢动物。","breeding":"繁殖季节为5月至7月，会用树枝搭建巢穴，高度可达9米，每窝产2至4枚蛋。幼鸟离巢后，家庭群体会继续在一起数月。","identification":"与黑顶长尾唐纳雀的区别在于，灰顶长尾唐纳雀的喉部区域为灰色，与明亮的白色下巴形成强烈对比，而黑顶长尾唐纳雀的喉部与脸部的黑色面具融为一体，没有明显的对比。","protection":"IUCN：NT（近危）","distribution":"灰顶长尾唐纳雀主要分布在海地西南部的Tiburon半岛和Grande Cayemite小岛，以及多米尼加共和国Sierra de Baoruco山脉的北坡和南坡，Loma de Toro南部和Hoyo de Pelempito，Île-à-Vache岛，Gonâve岛。海拔分布范围从海平面至2,400米。","other":"尽管在现存栖息地中常见，但由于海地和多米尼加共和国的严重森林砍伐，该物种的总数量可能在减少。"},{"name":"绿尾地唐纳雀","english_name":"Green-tailed Warbler","scientific_name":"Microligea palustris","overview":"绿尾地唐纳雀（英文名：Green-tailed Warbler，学名：Microligea palustris），是雀形目棕榈唐纳雀科绿尾地莺属的特有种，仅见于海地和多米尼加共和国共享的伊斯帕尼奥拉岛。该鸟具有独特的灰色头部和橄榄绿色背部，腹部灰白，红宝石般的眼睛十分醒目。","appearance":"体长12至14.5厘米，体重介于9.5至15.2克之间。头部呈灰色，眼周有白色弧线，虹膜红宝石色，上体橄榄绿，下体淡灰色，腹部更显洁白。两性相似。亚种M. p. vasta比指名亚种更淡，下体白色较多。","call":"发出一系列急促的‘tsip’音符，可能加速形成其歌声。叫声包括尖锐的吱吱声和嘶哑的斥责声。","habits":"栖息于海拔2925米以下的山地阔叶林和松树林，偏好密集未受干扰的下层植被。通常独居，偶尔加入混群觅食。以昆虫为主食，在密林和灌丛中觅食，也会在仙人掌上筑巢。","breeding":"繁殖季节主要在5月至6月，可能低地稍早。巢为杯状，由植物材料构成，置于1至10米高处。每窝产卵2至4枚，平均3.2枚。孵化率在低地和高地分别为30%和38%，失败多因天敌捕食。寿命至少七年。","identification":"与白翅地唐纳雀相比，绿尾地唐纳雀下体灰色而非白色，眼睛红色，尾部和翅膀无白色斑点。","protection":"IUCN：LC（无危）。在伊斯帕尼奥拉岛局部地区较常见，但其数量未知，据信正在下降。","distribution":"主要分布在中美洲的多米尼加和海地，特别是在伊斯帕尼奥拉岛的高海拔地区。","other":"绿尾地唐纳雀可能受到外来小印度獴（Herpestes auropunctatus）的巢穴捕食威胁，但目前尚未面临像白翅地唐纳雀那样的严重威胁。"},{"name":"白翅地唐纳雀","english_name":"White-winged Warbler","scientific_name":"Xenoligea montana","overview":"白翅地唐纳雀（英文名：White-winged Warbler，学名：Xenoligea montana），是雀形目棕榈唐纳雀科白翅地莺属的鸟类。为棕榈唐纳雀科白翅地莺属下的唯一物种，分布于多米尼加共和国和海地的希斯帕尼奥拉岛。其独特的橄榄色上部和白色翼斑使其在栖息地中易于识别。","appearance":"成年白翅地唐纳雀体长13至14厘米，体重约12到13克。头部和颈部为灰色，眼上方有一条从喙至眼的白色条纹，黑眼线之上有白色弧线环绕眼睛。背部和臀部呈橄榄绿色，尾羽深灰近黑，外侧尾羽尖端带有白色斑点。翅膀深灰，初级飞羽基部白色，形成明显的翼斑。下体为白色，胸腹部带有灰色调。雄雌相似，幼鸟整体呈棕色调，上体橄榄棕色，下体白色带有褐色污渍。","call":"发出一系列高音的吱吱声，结尾加速，还有低音的\"tseep\"和\"chir\"声的连续鸣叫。","habits":"白翅地唐纳雀全年居住在希斯帕尼奥拉岛的山地森林中，偏好有茂密灌木层的成熟湿润阔叶林、松阔叶混交林、松树林和石灰岩喀斯特森林。它们以昆虫和种子为食，常加入混合群落觅食。","breeding":"繁殖季节可能在5月至7月，已知巢穴为2004年发现的杯状结构，由苔藓、叶子、地衣和其他植物材料制成，内部铺有细纤维，位于距地面2.5米高的藤蔓丛中，含两枚卵。除此之外，繁殖生态细节尚不清楚。","identification":"与绿尾地唐纳雀相区别，后者具有红色虹膜，较暗的下体，且翼部无白色斑点。","protection":"IUCN：VU（易危）","distribution":"白翅地唐纳雀仅限于希斯帕尼奥拉岛的山地地区，具体包括多米尼加共和国的中央山脉、巴霍鲁科山脉和内伊巴山脉，以及海地西部蒂布隆半岛的Hotte山脉，可能还分布于靠近多米尼加边境的半岛其他部分。","other":"白翅地唐纳雀的寿命通常为三至六年，已知最长寿的个体被标记后存活了八年。"},{"name":"暗唐纳雀","english_name":"Puerto Rican Tanager","scientific_name":"Nesospingus speculiferus","overview":"暗唐纳雀（英文名：Puerto Rican Tanager，学名：Nesospingus speculiferus），是雀形目波多黎各唐纳雀科波多黎各唐纳雀属的鸟类。分布于波多黎各的山林中，拥有橄榄褐色的体羽和醒目的白色翼斑，是当地森林中喧闹的鸟类之一，常成为混种群的核心。","appearance":"成年暗唐纳雀主要呈现橄榄褐色的上体与白色的下体，胸部有淡褐色斑点，翼基部有独特的白色斑点，幼鸟缺乏这一特征，其下体呈棕色。成鸟头部灰橄榄色，背部橄榄色，翼羽边缘带灰橄榄色，翼基白色斑点由第四至第六初级飞羽外缘构成。下体白色，侧身及胁部转为浅灰橄榄色，胸羽带有橄榄灰斑点，尾下覆羽浅黄褐色，中央有灰橄榄色或棕色箭头状条纹。","call":"其鸣唱是一系列甜美两部分组成的乐句，如“chu-wit, see-you, chu-you”。常见叫声为高而细的‘tsit’或‘chit’，单独或连续发出。","habits":"暗唐纳雀栖息于中高海拔的森林中，常形成混种群，尤其偏好棕榈或竹丛作为共同栖息地。它们是群居性的鸟类，活动范围广泛，活跃于树冠层，以昆虫和其他小型无脊椎动物为食。","breeding":"。","identification":"与波多黎各鹀唐纳雀雌鸟在外观上有相似之处，但暗唐纳雀具有明显的翼基白色斑点，以及更丰富的下体斑纹。波多黎各鹀唐纳雀雌鸟的眉线较淡，髭纹明显，且下体斑纹更多。","protection":"IUCN：VU（易危）","distribution":"暗唐纳雀仅分布于北美波多黎各的山林中，具体在波多黎各岛的中高海拔森林。","other":"暗唐纳雀在当地被称为“llorosa”，意为‘哭泣者’，这可能源于其响亮的叫声让人联想到某种压力下的声音。"},{"name":"鹀唐纳雀","english_name":"Western Spindalis","scientific_name":"Spindalis zena","overview":"鹀唐纳雀（英文名：Western Spindalis，学名：Spindalis zena），是雀形目纹头唐纳雀科纹头唐纳雀属的鸟类。主要在结果实的树木和灌木丛中活动。雄鸟具有醒目的外观，黑色头部搭配白色条纹，橙色喉咙、胸部和颈背，以及鲜明的白色翼纹。雌鸟颜色较暗淡，灰橄榄色为主，翼上有小白斑，翼纹模糊。分布于北美巴哈马、古巴、开曼群岛和墨西哥科苏梅尔岛。","appearance":"雄鸟成鸟长15厘米，体重约21克，头部和喉侧黑色，有长白眉线，宽阔的白色髭纹，白色下巴，亮黄色中央喉咙，颈背和胸带栗色与金黄色相间，背部黑色，下背金黄色，臀部和短上尾羽深金色红褐色，长上尾羽黑色，尾巴黑色带宽白边，肩羽和上翼覆羽黑色，大覆羽外缘几乎全白，飞羽和三级飞羽黑色，小白色斑点位于外侧初级飞羽基部，下胸黄色，下体白色。雌鸟上身灰橄榄色，下体脏灰色至淡黄白色，喉部无斑纹。幼鸟似雌鸟但更暗淡，前胸图案极小。","call":"发出高音、细长、沙哑且略显多变的鸣唱，如‘see-tee’双音节混以高音‘seet’和芦苇般的‘deet’音，有时伴随颤音。飞行鸣唱为高音、沙哑的‘seeet sit-t-t-t-t’。还有一种轻柔的颤音歌。叫声包括高音薄‘seeip’和柔和的‘tsit-tsit-tsit’。","habits":"在低地至高地的相对干燥到湿润地区活动，包括巴哈马的本土松树和澳大利亚松树林，以及开曼群岛、古巴等地的开放林地、灌木丛、森林边缘、次生林和红树林，但在浓密高大森林内部不常见。成对活动或形成小型群体，主要以果实和浆果为食，偶尔食用嫩叶尖和其他植物部分。","breeding":"繁殖季节为4月至8月。雄鸟在飞行展示中，缓慢拍打翅膀飞升至树顶上方歌唱，随后俯冲至同一或另一栖枝，展翅展尾可能产生声响。巢由棕榈纤维构成，置于灌木或小至大树的低处或高处。一窝产2-3枚白色蛋，带有棕色斑点，平均尺寸22mm x 15mm（pretrei），23.5mm x 16.5mm（salvini）。","identification":"雄鸟与雌鸟的颜色差异明显，雄鸟鲜艳，雌鸟暗淡。与同属其他物种相比，西部的最小，喙短而圆锥形。不同亚种在背部颜色、颈背和胸部的色彩上有细微差别。","protection":"IUCN：LC（无危）","distribution":"繁殖区域：巴哈马、古巴、开曼群岛和墨西哥科苏梅尔岛。在非繁殖区域，偶尔会出现在美国佛罗里达州南部。","other":"利用多种次生林、受干扰和灌木丛生的栖息地，这有助于其抵御威胁。过去在古巴曾报告存在大型群体，但因捕捉活动，那里的种群数量可能已大幅减少。"},{"name":"海地鹀唐纳雀","english_name":"Hispaniolan Spindalis","scientific_name":"Spindalis dominicensis","overview":"海地鹀唐纳雀（英文名：Hispaniolan Spindalis，学名：Spindalis dominicensis），是雀形目纹头唐纳雀科纹头唐纳雀属的鸟类。特有于加勒比海岛国多米尼加共和国与海地共享的希斯帕尼奥拉岛。雄鸟头部黑白相间，具宽阔的白色眉纹和髭纹，明亮的黄色喉部中央有一块黑色三角形斑点，颈部黄而背部呈橄榄绿，尾羽黑色边缘白色，胸部深栗色，腹部至尾下覆羽白色。","appearance":"雄鸟全长约16-16.5厘米，重25-33.2克。头部黑色，宽大的白色眉纹和髭纹，下巴白色，喉部中央有明亮的黄色斑点，两侧黑色。颈部丰富黄色，背部橄榄绿色，肩部有小块锈红色斑点。翅膀和尾羽黑色，边缘白色。雌鸟灰橄榄色为主，头部更灰，上体黄橄榄色，翼暗褐色，边缘淡橄榄色，下体白色带淡褐色斑纹。幼鸟似雌鸟但更暗淡。","call":"黎明之歌为尖细高音的哨声，或延长的弱嘶声'tsee see see see'。常见叫声为高音'thseep'，也有更拖长的'seeee'。","habits":"栖息于各种潮湿森林环境，偏好有灌木丛和低矮植被的山地森林地带，也出现在果园和种植园。主要以果实、花蕾、种子和嫩叶为食，偶尔捕食昆虫。成对或小群活动，有时在果实丰富的树上聚集较多数量。","breeding":"繁殖季节通常为5月至6月，部分会养育第二窝。巢为小型杯状，由干草构成，置于树或灌木上1-4.5米高处。每窝产三枚蛋，蛋壳白色带棕色斑点，大小平均为22毫米×15毫米。","identification":"与相似物种牙买加鹀唐纳雀的区别在于体型较小，颈部黄色环带，肩部有小块锈红色斑点。","protection":"IUCN：LC（无危）","distribution":"分布于希斯帕尼奥拉岛（多米尼加共和国和海地）及戈纳夫岛。在多米尼加共和国的阿曼多·贝尔穆德兹国家公园、何塞·德尔卡门·拉米雷斯国家公园和其他多个保护区均有分布。","other":"广泛利用多种生境，包括次生林和灌木丛，这使得它能够抵御短期内的威胁，尽管其世界分布范围较小。"},{"name":"波多鹀唐纳雀","english_name":"Puerto Rican Spindalis","scientific_name":"Spindalis portoricensis","appearance":"雄性波多黎各鹀唐纳雀拥有鲜艳的羽毛，上身绿色，颈胸橙色，头部黑色并带有两条白色条纹，一条位于眼睛上方，另一条位于下方，尾羽和翅膀呈灰至黑色，尾端有细微的白色条纹。雌鸟羽毛较为暗淡，呈橄榄绿色，白色条纹较不明显。雄鸟体重平均30.8克，翼展平均85.2毫米，尾长平均63.3毫米；雌鸟体重略重，平均33.5克，翼展稍小，平均82.6毫米，尾长平均60.6毫米。","call":"波多黎各鹀唐纳雀的鸣叫声高亢尖锐，连续的高音调细哨声，节奏感强，还有快速的啾啾声和短暂的‘chi chi chi’声。","habits":"通常成对或小群活动，偏好果实丰富的环境，如马里奥卡森林、埃尔云克国家森林公园以及果园和花园。它们以Didymopanax morototoni等树种的果实为主食，同时也会食用昆虫和小型蜥蜴以补充能量。","breeding":"波多黎各鹀唐纳雀营巢于各种植物材料构成的杯状巢中，每次产卵2到4枚，卵呈浅蓝色，大端带有棕色斑点，平均尺寸为23.7 x 17.3毫米。","identification":"雄鸟与雌鸟的显著差异在于色彩和体型，雄鸟色彩鲜艳，雌鸟色彩暗淡。与同属其他物种相比，其独特的头部条纹和分布区域是主要的辨识特征。","protection":"IUCN：LC（无危）","distribution":"分布于整个波多黎各主岛，常见于海拔1000米以下的地区。","other":"曾经被认为是Stripe-headed Tanager的亚种，1997年基于形态、声音和分布的差异，被确认为独立种。"},{"name":"牙买加鹀唐纳雀","english_name":"Jamaican Spindalis","scientific_name":"Spindalis nigricephala","overview":"牙买加鹀唐纳雀（英文名：Jamaican Spindalis，学名：Spindalis nigricephala），是雀形目纹头唐纳雀科纹头唐纳雀属的鸟类。拥有独特的黑头白眉纹饰，雄鸟羽毛色彩鲜艳，雌鸟则色调较为暗淡。","appearance":"雄性牙买加鹀唐纳雀约18厘米长，体重介于38至64.8克之间，是最大的纹头唐纳雀。头部黑色，有宽大的白色眉纹延伸至颈侧，下巴和喉部白色，背部黄橄榄色，臀部及上尾覆羽棕黄色，翅膀和尾巴黑色，边缘白色，胸部橙黄色，腹部和尾下覆羽白色。雌鸟头部、喉咙和背部灰橄榄色，胸部淡橙黄色，腹部淡黄色，尾下覆羽接近白色。幼鸟似雌鸟，但颜色更暗淡。","call":"该鸟通常很安静，其叫声包括持续的低语歌，由大约4秒长的音节反复组成，如‘chu wheet, chee see whee see, chu wheet’。在群体觅食时会发出快速的‘chi-chi-chi-chi-chi’声。","habits":"生活在森林、林地和灌木丛中，偏好果树林和森林边缘地带，常见于低地和高地，尤其在山区更为密集。以各种水果、浆果为主食，包括非本地物种如橙子、香料树果实和皇家棕榈果实，偶尔吃树叶和花朵。成对或家庭群居，有时会形成8至10个个体的觅食群，互动频繁。","breeding":"繁殖季节为4月至7月。巢穴为松散的草杯状，通常放置在草和根须中，每窝产2至3枚绿色或浅灰色的蛋，蛋上带有棕色或灰色斑点，平均尺寸为24毫米×18毫米。","identification":"雄性牙买加鹀唐纳雀的黑头白眉纹饰极其独特，与牙买加其他鸟类明显不同。雌鸟和幼鸟虽颜色较为低调，但仍可通过其特定的体型和色彩模式辨认。","protection":"IUCN：LC（无危）","distribution":"仅分布于北美地区的牙买加，特别是在北岸和西南岸较局部，而在内陆山区更为常见。","other":"曾是条纹头唐纳雀的一个亚种，现已独立为一个物种。"},{"name":"冠鹩森莺","english_name":"Wrenthrush","scientific_name":"Zeledonia coronata","overview":"冠鹩森莺（英文名：Wrenthrush，学名：Zeledonia coronata），是雀形目冠鹩森莺科冠鹩森莺属的鸟类。独特的九主翼鸟，是哥斯达黎加和巴拿马特有种，拥有橙色的冠羽，主要栖息于高海拔森林中。","appearance":"体长约10至11.5厘米，体重约21克，短尾而丰满，喙短细似新世界林莺。成鸟具有橙黄色的头部斑块，边缘黑色，脸部及颈侧为铅灰色，上体、尾羽和侧腹为暗橄榄色，下体铅灰色带橄榄色尾下覆羽。幼鸟无橙色冠羽，上体颜色更偏褐色。","call":"鸣唱为一系列尖锐的哨音，如“ssee-del-deet”，强调结尾部分，可能连续歌唱数分钟。常见叫声为高亢、细长的‘pseee’。","habits":"栖息于高海拔常绿森林和高山矮林，偏好潮湿环境和竹林附近的密集植被。以昆虫和其他节肢动物为主食，尤其是蜘蛛和鳞翅目幼虫。活动范围低至地面，偶尔在藤蔓和附生植物中觅食。","breeding":"繁殖季节从三月至七月初，巢为苔藓、树枝和树叶制成的穹顶状结构，入口位于侧面，内部铺有干叶、草和苔藓。巢通常建于土壁洞穴中，被悬垂植物遮掩。每窝产卵3枚，孵化期未知，从孵化到离巢至少需18天，双亲共同喂养雏鸟。","identification":"外形独特，橙色冠羽和短尾是其显著特征。与其他相似物种相比，如蚁鵙（Grallaricula），冠鹩森莺更暗淡且体型较小。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲，北起哥斯达黎加的瓜纳卡斯特山脉，南至巴拿马西部的奇里基省和维拉瓜斯省。"},{"name":"黄头灰森莺","english_name":"Yellow-headed Warbler","scientific_name":"Teretistris fernandinae","overview":"黄头灰森莺（英文名：Yellow-headed Warbler，学名：Teretistris fernandinae），是雀形目灰森莺科灰森莺属的鸟类。特有种，仅见于古巴西部。其显著特征为鲜明的黄色头部，橄榄色的冠部和颈背，与灰色的身体形成鲜明对比。","appearance":"体长约13厘米，体重6至18.5克，全身覆盖着灰色的上体与灰白的下体，头部全黄，带有橄榄色调的冠部和颈背，眼环黄色，喙黑色，下颌基部灰色，腿脚蓝灰色。雌雄相似，幼鸟特征未详述。","call":"其歌喉由一系列刺耳的嘶哑音符组成，其间穿插着更甜美、音乐般的音符。常见叫声是一种快速、高音、断续的喋喋声，有时被描述为沙哑的颤音，通常重复多次，还有各种其他嘶哑和刺耳的音符。","habits":"常群居于密集的灌木丛和林地，不栖息于茂密森林或红树林。活跃于各种森林类型，偏好未受干扰的下层植被，同时出现在干旱地区的灌木丛中，从低地到高山均有分布。全年留居于其范围内，以昆虫和其他无脊椎动物为食，偶尔捕食小型蜥蜴，常在小群体中觅食。","breeding":"繁殖季节从三月持续至七月，筑巢期在四月至五月。巢由草、根须和其他植物纤维构成的杯状，通常位于灌木、藤蔓或幼树较低处。每次产卵2至3枚，孵化期和雏鸟离巢时间尚不明确。","identification":"与Prothonotary Warblers相比较，后者下方主要是黄色，背部呈绿色而非灰色。Pine Warblers具有绿色背部，白色翼条，下方黄色更为广泛。","protection":"IUCN：LC（无危）","distribution":"分布于古巴西部大陆，包括伊莎岛（Isle of Pines）和附近的Cayo Cantiles。","other":"黄头灰森莺是其家族中的单一物种，与灰森莺共享家族和属，最初归类于新世界森莺科（Parulidae），后因DNA研究被重新分类至独立的Cuban warbler family。"},{"name":"灰森莺","english_name":"Oriente Warbler","scientific_name":"Teretistris fornsi","overview":"灰森莺（英文名：Oriente Warbler，学名：Teretistris fornsi），是雀形目灰森莺科灰森莺属的鸟类。主要分布在古巴东部和中部地区，包括北部海岸附近的萨瓦纳-卡马圭群岛。以蓝灰色上体、黄色喉部至腹部以及灰色下腹的独特组合区别于其它物种。","appearance":"灰森莺长约13厘米，体重介于7.4至13克之间。头部、颈背及上体呈灰蓝色，脸部、喉部及大部分下体为黄色，腹部及尾下覆羽白色，两胁带有暗褐色斑点。眼睛周围有黄色眼圈，虹膜深色，喙灰黑色，腿脚蓝灰色。雌雄同形同色，幼鸟特征未详述。","call":"其鸣叫包括一系列相对高音且带嗡声的“zip”或“zhip”以及略显尖锐但带嗡声的“tip”。鸣唱为混杂了上述声音和其他类似音符的序列，与黄头灰森莺相似，但稍显单调。","habits":"灰森莺栖息于各种森林类型中，偏好未受干扰的林下层环境，同时也出现在半干旱地区的灌木丛中，从低地至高山均有分布。它们全年留居于其活动范围内，以昆虫和其他无脊椎动物为主食，偶尔也会捕食小型蜥蜴，可能还会食用小果实。觅食时，它们会从地面到中层林冠活动，主要通过啄食，有时也会悬停啄食或探查树皮缝隙和枯叶堆。非繁殖季节，常形成4至16只的小群体，成为混合物种觅食群的核心。","breeding":"繁殖季节为3月至7月，产卵期通常在3月至4月。巢由苔藓、草根、藤蔓和细草构成，放置于离地面约1米的水平枝条或树叉上，通常隐藏在苔藓丛中。每窝产2至3枚卵，孵化期为8至9天，雏鸟在巢中停留10至11天。","identification":"与黄头灰森莺相比，灰森莺的头顶和胸部不是黄色，而黄头灰森莺具有黄色的顶冠和灰色的胸部。此外，蓝翅黄森莺拥有绿色或黄色的顶冠和绿色的背部。","protection":"IUCN：LC（无危）","distribution":"主要分布于古巴东部和中部，包括北部海岸附近的萨瓦纳-卡马圭群岛及东南沿海的Sierra Maestra山脉。","other":"灰森莺有两个亚种：指名亚种为T. f. fornsi和T. f. turquinensis，后者在体型上略大，且头顶和上体颜色更接近烟灰色，两胁的斑点为灰色而非褐色。"},{"name":"黄胸大䳭莺","english_name":"Yellow-breasted Chat","scientific_name":"Icteria virens","overview":"黄胸大䳭莺（英文名：Yellow-breasted Chat，学名：Icteria virens），是雀形目黄胸大䳭莺科黄胸大䳭莺属的鸟类。属于独特的黄胸大䳭莺科（Icteriidae），此前曾归入北美林莺科（Parulidae）。该鸟体型较大，拥有鲜艳的柠檬黄色喉部和胸部，对比明显的白色眼圈和白须纹，以及暗橄榄绿色上体。分布于北美洲和中美洲，自加拿大南部至墨西哥中部，冬季南迁至哥斯达黎加。在东部北美洲，黄胸大䳭莺可能因森林砍伐和农田废弃而增加，但在某些地区正随成熟森林取代灌木生境而减少。","appearance":"体长约18厘米，体重约25克。显著特征包括亮黄色的喉部和胸部，橄榄绿至灰橄榄色的上体，以及对比鲜明的白色腹部和尾下覆羽。脸部灰色，黑色的眼先，白色的眼眉和下眼线形成眼镜状。雌雄相似，但在繁殖季节，雌鸟具有灰色眼先，灰色下颚，以及粉红色的口腔内壁，与雄鸟的黑色形成对比。季节变化不大，但在冬季，上体颜色更偏棕色，黄色部分略带橄榄色，侧翼更显淡褐色或棕色，喙部更呈棕色。","call":"鸣唱复杂多变，由缓慢的哨音、吼声和杂音组成，通常在繁殖季节的清晨或黄昏时最为活跃。","habits":"栖息于低矮、密集的植被中，偏好无封闭树冠的生境，包括沿溪流、沼泽和池塘边缘的灌木丛，森林边缘、再生的火烧林地和采伐区域，以及近期荒废农田的篱笆行和高地灌木丛。以昆虫为主食，冬季也会食用果实。","breeding":"在繁殖季节，雄鸟会在显眼的栖木上鸣唱，甚至进行飞行展示。巢穴建在浓密的灌木丛中，高度约2.5米，由草、叶、树皮条和杂草茎构成，内衬细草、植物茎、松针和有时会有根和毛发。每窝产3至5枚淡奶油色带有红棕色斑点或斑纹的蛋，由雌鸟孵化，孵化期约为11至12天。双亲共同抚养幼鸟，幼鸟约在8至11天后离巢。","identification":"黄胸大䳭莺的显著特征是其明亮的黄色喉部和胸部，以及独特的白色眼镜状标记，这使得它在野外容易识别。在西部的亚种，白须纹更长，上体略偏灰色，尾巴稍长。","protection":"IUCN：LC（无危）","distribution":"繁殖于加拿大南部至墨西哥中部，冬季迁徙至中美洲，包括巴拿马。在北美洲的分布广泛，但在东部北美洲因栖息地丧失和退化而数量下降。","other":"黄胸大䳭莺曾因分类地位争议而备受关注，2017年被升至独立家族Icteriidae。"},{"name":"黄头黑鹂","english_name":"Yellow-headed Blackbird","scientific_name":"Xanthocephalus xanthocephalus","overview":"黄头黑鹂（英文名：Yellow-headed Blackbird，学名：Xanthocephalus xanthocephalus），是雀形目拟鹂科黄头黑鹂属的大型黑鹂。以其独特的黄色头部和胸部以及黑色的其余部分著称。广泛分布于北美西部非森林区域的深水湿地中，从加拿大西南部和中南部到美国西南部，再到墨西哥西北部。繁殖季节，雄鸟的金黄色头部尤为醒目，雌鸟则呈现暗褐色，头部和胸部有较淡的黄色。在非繁殖季节，黄头黑鹂会形成大群，主要在墨西哥南部过冬。","appearance":"黄头黑鹂体型较大，雄鸟体重可达100克，体长265毫米，雌鸟体重不到60克，体长约比雄鸟短50毫米。雄鸟成鸟拥有醒目的金黄色头部、颈部和胸部，身体其余部分、眼纹和面颊呈黑色，翼上有明显的白色斑块。雌鸟和未成年雄鸟的羽毛色彩较为暗淡，以暗黑色和棕色为主，头部和胸部带有浅黄色，颈部和眉纹也有黄色，腹部呈棕色，与黄色胸部形成鲜明对比。两性脚和喙均为黑色，肛门周围有黄色羽毛。","call":"黄头黑鹂的叫声被形容为像生锈的农场大门开启的声音，是一种尖锐、机械的鸣唱。","habits":"黄头黑鹂栖息于北美的淡水湿地，尤其偏好有高大挺水植被如香蒲、莎草和芦苇的地方。它们在开阔地带觅食，如田野和裸露的泥土上。繁殖季节结束后，它们会组成大群，迁徙到美国南部和墨西哥南部过冬。在迁徙途中，它们通常与其他黑鹂混群。黄头黑鹂全年主要以种子为食，夏季则增加昆虫和水生无脊椎动物的比例。","breeding":"繁殖期，黄头黑鹂在湿地中营巢，雄鸟占据领地，吸引多个雌鸟。巢由雌鸟建造，位于水面之上，附着在挺水植物上。雄鸟通过展示和驱赶入侵者来维护领地。雌鸟负责孵卵和育雏，幼鸟主要以昆虫喂养。","identification":"与其他黑鹂相比，黄头黑鹂的黄色头部和胸部是最显著的区别。雌鸟和未成年个体可以通过其暗褐色的羽毛和黄色头部与胸部分辨出来。","protection":"IUCN：LC（无危）","distribution":"黄头黑鹂主要在北美西部繁殖，范围从加拿大西南部和中南部延伸至美国西南部和墨西哥西北部。冬季，它们迁徙至墨西哥南部。","other":"黄头黑鹂对巢穴的掠食风险敏感，例如面对长嘴沼泽鹪鹩的威胁，会调整其巢穴守护行为。"},{"name":"刺歌雀","english_name":"Bobolink","scientific_name":"Dolichonyx oryzivorus","overview":"刺歌雀（英文名：Bobolink，学名：Dolichonyx oryzivorus），是雀形目拟鹂科刺歌雀属的小型黑鹂。繁殖季节在北美，主要分布在美国北部和加拿大南部，冬季迁至南美洲南部，如阿根廷、玻利维亚和巴拉圭。其数量正在迅速下降，面临农业集约化和栖息地丧失等威胁。","appearance":"成年刺歌雀长约16至18厘米，体重约28克，具短而类似雀类的喙。雄鸟在繁殖季呈黑色，带有奶油色颈背和白色肩胛、下背及臀部。雌鸟及非繁殖期雄鸟呈淡褐色，背部和侧翼有黑色条纹，头部有深色条纹，翅膀和尾巴颜色较深。","call":"雄鸟在飞行时发出明亮、泡泡般的歌曲。","habits":"栖息于开阔的草地环境，尤其是干草田。进行长途迁徙，冬季前往南美洲。以种子和昆虫为主食，有时被视为农业害虫。","breeding":"雌鸟在杯状地面巢中产下5至6枚蛋，通常隐藏在密集植被中。双亲共同喂养幼鸟。雄鸟在优质栖息地中可能实行多配偶制。","identification":"与红翅黑鹂相比，体型较小，喙较短。雄鸟在繁殖季节的黑白对比鲜明，雌鸟及非繁殖期雄鸟外观与麻雀相似，但体型更大。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美，包括加拿大南部和美国北部。冬季迁至南美洲中部，如阿根廷、玻利维亚和巴拉圭。","other":"刺歌雀是唯一已知每年通过加拉帕戈斯群岛迁徙的陆鸟物种。"},{"name":"西草地鹨","english_name":"Western Meadowlark","scientific_name":"Sturnella neglecta","overview":"西草地鹨（英文名：Western Meadowlark，学名：Sturnella neglecta），是雀形目拟鹂科草地鹨属的鸟类。头顶条纹交错，上体呈复杂的棕褐色条纹。分布于加拿大西部至美国西部直至墨西哥中部，甚至被引入夏威夷。作为北美广泛分布的草甸鸟种之一，是六个州的州鸟：堪萨斯州、蒙大拿州、内布拉斯加州、北达科他州、俄勒冈州和怀俄明州。","appearance":"西草地鹨成鸟具有明亮的黄色腹部，胸部带有显著的黑色‘V’字形斑块，两翼和尾部边缘白色，上体为棕色和黑色条纹相间，头部条纹由深棕色和淡褐色组成。喙长而尖，体型健硕，尾巴较短。冬季时，其黄色部位变淡，胸部的‘V’字形斑纹变为灰色。雄雌外观相似，但雌鸟略小且标记稍淡。","call":"拥有似笛子般清澈的鸣唱，声音宛若流水，这与东方近亲——东草地鹨的简单哨音形成鲜明对比。","habits":"西草地鹨栖息于广阔的草原、牧场、废弃的田野，以及海拔高达10,000英尺的山地草甸。它们偏好低至中等高度的草地，而非高草丛生的区域。春季和夏季，雄鸟会在围栏、灌木丛、电线杆等高点上展示其美妙的歌声。","breeding":"繁殖季节，雌鸟会在隐蔽的地面位置筑巢，巢穴有时会覆盖草制的屋顶。一窝通常产下数枚蛋，孵化由雌鸟单独承担。雏鸟孵化后眼睛紧闭，全身几乎无毛，主要以昆虫为食。幼鸟约在10至12天后离巢，但在21天左右才能持续飞行，离巢后两周内仍受父母照料。一对西草地鹨可能尝试第二次繁殖。","identification":"与东草地鹨的区别在于下巴黄色面积更大，且西草地鹨在冬季显得更为苍白，头纹对比度较低，更倾向于群居，出现在较短草的区域。在交配季节，通过各自独特的鸣唱和叫声可以轻易区分两者。","protection":"IUCN：LC（无危）","distribution":"西草地鹨的繁殖区域涵盖加拿大西南部和中南部至美国西部，延伸至墨西哥中部。在繁殖区域之外，它们也会向南迁徙，北方的种群可能迁往南部地区，部分个体在美国南部向东迁移。在夏威夷的卡乌阿伊岛亦有其分布。","other":"西草地鹨是六个州的官方州鸟，显示出其在文化上的重要性。"},{"name":"东草地鹨","english_name":"Eastern Meadowlark","scientific_name":"Sturnella magna","overview":"东草地鹨（英文名：Eastern Meadowlark，学名：Sturnella magna），是雀形目拟鹂科草地鹨属的鸟类。以亮黄色胸部带有黑色新月标记，以及短翼和尖尾上的白色外羽为特征。在春季，其悠扬而略带忧伤的哨声成为乡间和开阔地带的标志性声音。分布广泛，从北美东部直至南美东北部，包括加拿大东部至巴西东北部。在繁殖季节活跃于田野和草地上，冬季则在密集的草丛中成小群活动。","appearance":"东草地鹨体型中等，长21-28厘米，翼展35-40厘米，体重76-150克。成年个体上身呈条纹状棕色，下身鲜黄，胸前有黑色“V”形标记，两侧和腹部下方有深色斑点。头部有明显的条纹，喙长且尖。雌雄相似，但雌鸟稍小。幼鸟喉咙呈淡黄色，有条纹胸，直到秋季换羽后才与成鸟相似。","call":"其鸣唱由纯净、略带哀愁的哨音组成，比西草地鹨的混杂笛音更为简单。鸣唱常用于辨别同属物种。","habits":"东草地鹨栖息于开阔的草地、牧场和草甸，偏好较为原始的草场环境。它们全年居住在其北美的大部分范围内，尽管最北部的种群会向南迁徙过冬。以昆虫为主食，也食用种子和浆果。","breeding":"繁殖期通常在夏季，雌鸟在地面筑巢，巢穴位于1-3英寸深的凹陷处，如牛蹄印中。巢由干草和植物茎构成，内衬草类、松针或马毛。每窝产卵数枚，孵化和育雏过程由雌鸟负责。","identification":"与西草地鹨相比，东草地鹨的喉部黄色较少延伸至面颊，头纹更加鲜明，侧翼条纹更重且更连贯。东草地鹨在尾羽外缘有更多的白色，尤其是西南部的Lilian's亚种。","protection":"IUCN：LC（无危）。虽然东草地鹨数量曾因森林清理而增加，但随着适宜栖息地的减少，其数量正在下降。在某些地区，如诺瓦斯科舍省，它们被列为濒危物种。","distribution":"分布于北美东部至南美东北部，包括加拿大东南部至巴西东北部。在北美东部为常见留鸟，而在更北部地区，部分种群迁往中美洲和南美洲北部过冬。","other":"东草地鹨与西草地鹨在形态学、生态学和行为学上存在显著差异，尤其是在交配季节，两物种表现出不同的领域行为。"},{"name":"奇瓦瓦草地鹨","english_name":"Chihuahuan Meadowlark","scientific_name":"Sturnella lilianae","overview":"奇瓦瓦草地鹨（英文名：Chihuahuan Meadowlark，学名：Sturnella lilianae），是雀形目拟鹂科草地鹨属的鸟类。属于拟鹂科，分布于美国西南部及墨西哥北部的沙漠草原地带。曾被认为是东草地鹨的一个亚种，但基于形态学、声学和基因组学证据，现已被确认为独立物种。","appearance":"这是一种中等体型的陆栖鸣禽，拥有长而细的喙，短尾，长腿和脚趾。头部顶部呈深棕色，具有一条淡色中线。眼上方的线条在靠近喙处变为深黄色。上体呈现复杂的掩护图案，包含浅黄褐色、棕色和深色条纹与斑点。下体颜色明亮，从亮黄色到藏红花色不等；侧面、侧腹和尾下覆羽为暗白色，带有淡淡的深棕色条纹和斑点。成年个体胸部有显著的黑色新月形标记。翅膀和尾巴羽毛带有深棕色、淡棕色，偶尔带有赤褐色条纹。外侧四根尾羽几乎全白，飞行时显眼，通常在地面时紧张地展露。","call":"其叫声比东草地鹨更嘶哑，音调更低沉，歌曲更为分离，常以短暂的‘chuck’音开头。","habits":"偏好高大的未受干扰的草地区域，通常散布着橡树。在地面觅食，通常保持隐蔽，有时会坐在暴露的栖木上，特别是在歌唱时。主要在春季至夏季期间活跃。","identification":"与东草地鹨相比，奇瓦瓦草地鹨的侧面颜色较淡，尾部白色更多，尤其是外侧四根尾羽几乎全白。与西草地鹨的鉴别主要依赖声音差异和头部、侧面及尾部的图案。","protection":"IUCN：LC（无危）","distribution":"分布于美国西南部（包括亚利桑那州东南部、新墨西哥州南部和德克萨斯州西部）以及墨西哥西北部至中部。在繁殖季节，可能在亚利桑那州和新墨西哥州的中央地区进行短距离迁徙。","other":"历史上，奇瓦瓦草地鹨的分布可能有所变化，尤其是在科罗拉多州有其繁殖记录，这可能是物种向北迁移的一部分，但需要更多的研究来证实这一现象。"},{"name":"彭巴草地鹨","english_name":"Red-breasted Meadowlark","scientific_name":"Leistes militaris","overview":"彭巴草地鹨（英文名：Red-breasted Meadowlark，学名：Leistes militaris），是雀形目拟鹂科Leistes的鸟类。以其鲜明的红胸和黑色身体著称，分布于中美洲东南部至南美洲玻利维亚西北部和巴西中北部，包括哥伦比亚、委内瑞拉、特立尼达和多巴哥等地。这开放地带的鸟类，常见于湿润的草地、牧场和耕作区。","appearance":"雄鸟平均长度19厘米，重约53克，头部和上身主要呈黑色，下巴、喉部和胸部鲜红色，翼覆羽边缘红色，腹部和臀部黑色；雌鸟平均18厘米，重约46.1克，头部和上身黑褐色条纹，下体淡黄褐色，胸部和两肋有暗褐色条纹，腹部带有粉色调。幼鸟类似雌鸟，但上体羽毛边缘苍白，下体更密集条纹，无红色羽毛。","call":"雄鸟的鸣唱由几个金属质感的短音节后跟刺耳的嗡鸣组成，通常以几个短音结尾。报警声为‘ee’或‘pist’。","habits":"栖息于开阔地带，包括湿润的草地、牧场和耕作区。主要以昆虫和其他节肢动物为食，偶尔吃种子（如稻谷），罕见地食用果实。社会性很强，常形成百只左右的大群。","breeding":"繁殖季节在不同地区有所不同，如哥斯达黎加为5月至8月，特立尼达为3月至12月。可能实行一雄多雌制。在密草丛、牧场或农田中松散地筑巢群。雄鸟在空中展示，边唱边降落。巢由雌鸟单独建造，位于地面，用草茎和其他植物材料构成，内部铺细草或植物绒毛。","identification":"雄鸟与白眉草地鹨的雄鸟容易区分，后者具有明亮的白色眉纹，而雌鸟几乎相同，但红胸草地鹨的喙较长，体型较小，翅膀较短，下体红色较多，条纹较少。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲东南部至南美洲玻利维亚西北部和巴西中北部，具体包括尼加拉瓜南部、哥伦比亚、委内瑞拉、特立尼达、圭亚那、亚马逊地区的巴西、厄瓜多尔、秘鲁东北部、玻利维亚东北部。","other":"红胸草地鹨与白眉草地鹨在分类上非常接近，曾被认为是其亚种。"},{"name":"白眉草地鹨","english_name":"White-browed Meadowlark","scientific_name":"Leistes superciliaris","overview":"白眉草地鹨（英文名：White-browed Meadowlark，学名：Leistes superciliaris），是雀形目拟鹂科Leistes的鸟类。其显著特征为白色的眉纹，分布于南美洲，包括玻利维亚北部、巴西西南部至阿根廷中部、乌拉圭以及巴西东部。该物种受益于森林清除和牧场活动创造的开放生境，正在扩大其分布范围。","appearance":"雄鸟平均体长17.8厘米，体重50.2克；雌鸟平均体长17厘米，体重40.9克。雄鸟具有黑色头部和背部，突出的白色眉纹位于眼后，鲜亮的红色喉咙、胸部和肩部，翅膀和下翼覆羽边缘红色，腹部和臀部黑色。雌鸟头部和背部条纹呈黑褐色和淡黄色，有淡黄色眉纹和头顶中线，下体淡黄色，喉部最浅，胸部、胁部和臀部有暗褐色条纹，腹部中央略带粉色。幼鸟似雌鸟，但下体条纹更密集，羽毛无红色。","call":"雄鸟的鸣唱从栖息处或飞行展示开始，先是一串鼻音的嗡嗡声，随后是较短的音符，如“tsi-tzíéé-teng chup chup...”，个体间存在差异。雌鸟可能发出干燥的咔哒声。接触叫声在阿根廷被描述为金属质感的“peng”声。","habits":"主要栖息于开阔地带，如湿润的草地、牧场和农田，通常靠近灌木或围栏。形成单物种群落，有时可达数百只，偶尔与其他黄鹂科鸟类混群。以昆虫和蜘蛛为主食，春季和夏季时占食物的75-85%，也吃草籽、莎草和菊科杂草种子。在潘塔纳尔湿地，食物中还包括小型淡水蟹。","breeding":"繁殖季节在阿根廷为10月至1月，部分雄鸟可能实行一雄多雌制。通常在松散的群体中繁殖，有时靠近其他鸟类的巢穴。巢为深杯状，由草和其他植物材料构成，置于地面浓密的植被中，常见于牧场或作物田。每窝产3-5枚蓝底红棕色斑点的蛋，平均尺寸为23×17.3毫米。孵化和育雏期未知。雏鸟主要由雌鸟喂养。受到紫辉牛鹂的寄生，曾有一例巢中发现19枚牛鹂蛋与一枚草地鹨蛋。","identification":"与红胸草地鹨彭巴草地鹨关系密切，但雄性白眉草地鹨的白色眉纹明显。雌鸟二者相似，但红胸草地鹨雌鸟喙较长，体型较小，翼较短，下体红色更多，条纹较少。","protection":"IUCN：LC（无危）","distribution":"繁殖于玻利维亚东北部（贝尼）、巴西中部和东部（从马托格罗索州南部至亚马逊州南部，托坎廷斯、马拉尼昂和塞阿拉），向南至巴拉圭、阿根廷（至门多萨、拉潘帕和里奥内格罗）和乌拉圭；迁徙到秘鲁东南部（马德雷德迪奥斯）。","other":"历史上曾被视为红胸草地鹨的亚种。"},{"name":"红胸草地鹨","english_name":"Peruvian Meadowlark","scientific_name":"Leistes bellicosus","overview":"红胸草地鹨（英文名：Peruvian Meadowlark，学名：Leistes bellicosus），是雀形目拟鹂科Leistes的鸟类。雄鸟特征鲜明，喉部至下体呈亮红色，分布于南美洲，自哥伦比亚远西南部至智利远西北部。雌鸟色彩较淡，体羽更显斑驳。","appearance":"雄鸟平均长度约20.5厘米，重约78.5克；雌鸟平均重61.4克。雄鸟上体灰褐，饰以黑纹，头部及颈侧呈黑色；眼上方有一长的超眉线，眼前红色，眼后白色，下颌至胸部鲜红，腹部黑色，两胁及臀下覆羽条纹状。雌鸟较雄鸟颜色暗淡，下体淡灰色，喉部近白，腹部中央微泛淡红色，胸部至腹侧具暗色斑纹。","call":"雄鸟飞行鸣唱复杂多变，结尾带嗡鸣声，持续约3秒；栖息时鸣唱较短，由3-4个下降音符接粗嘎嗡鸣组成，\"tee-tleptu-chzzz\"。叫声为嗡鸣音。","habits":"栖息于草地、牧场和农业地带，包括沿海沙漠中的绿洲或灌溉田地，有时见于盐沼。通常地面觅食，以节肢动物、小型脊椎动物、种子和部分果实为主食。飞行特征为上下波动，类似啄木鸟。","breeding":"繁殖季节在厄瓜多尔为3月至5月，智利为10月至11月。巢由干草和茎构成，无明显内衬，建于地面，常利用轻微凹陷处，置于小灌木或草丛下。每窝产卵4-5枚，卵色为淡黄色、粉色或乳白色，饰有红褐色斑点，平均尺寸25.4×18.5毫米，孵化期14天，雏鸟期约12天。受到紫辉牛鹂寄生。","identification":"雄性红胸草地鹨与其他Leistes属物种相比，体型较小，尾巴和喙较短。雌鸟及幼鸟缺乏红色调，下体斑纹更多。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲西部，自哥伦比亚西南部至智利西北部，海拔可达2500米。","other":"近年来，随着林地转化为牧场，其分布范围有所扩大。"},{"name":"长尾草地鹨","english_name":"Long-tailed Meadowlark","scientific_name":"Leistes loyca","overview":"长尾草地鹨（英文名：Long-tailed Meadowlark，学名：Leistes loyca），是雀形目拟鹂科Leistes的鸟类。因长而显著的尾巴和尖锐的喙而引人注目。这种鸟主要分布在智利南部、阿根廷南部及西部地区，以及福克兰群岛，其中福克兰群岛的亚种被称为军事星椋鸟。栖息于各种类型的草地、草原和农田，甚至城镇公园的草地上。","appearance":"雄鸟平均长度约26.9厘米，体重112.4克；雌鸟平均体重97.1克。雄鸟指名亚种为主要褐色，背部有黑色条纹，头部和颈部侧面呈黑色；眼前方有一条鲜红的眉纹，后方转为白色，白色颊线和下眼睑；翼羽边缘呈玫瑰红色；下巴至喉咙和下部羽毛呈玫瑰红色，周围环绕着黑色，腹部黑色，胸部侧边至两侧和尾下覆羽有斑驳的黄褐色和黑色条纹；翅膀下方覆羽淡灰色；虹膜深棕色；喙蓝色象牙色，嘴峰和尖端呈暗褐色；腿灰色。雌鸟比雄鸟更淡，喉部白色，眉纹无红色；下部羽毛条纹厚重，围绕着淡红色的下腹部。幼鸟类似雌鸟，但红色减少，有时仅为淡粉色斑块，喙色也较浅。","call":"雄鸟和雌鸟都会从栖息处（如灌木、岩石、围栏柱）发出歌声，歌声变化多样，可能包含口哨声或颤音后跟长鼻音嗡嗡声，也可能唱出长达8个音符的短语，通常混合一些刺耳的嗡嗡声。繁殖伴侣可能会合唱。叫声包括'peet'和'chuck'。","habits":"长尾草地鹨栖息于中湿到干燥的草地和灌木草原，偏好沿水道或靠近沼泽的相对湿润的草地。它们在阿根廷的科多巴和圣路易斯地区的高山岩石草地上也能找到，同时在树脂状的romerillo灌木草原上。沿着阿根廷大西洋海岸的布宜诺斯艾利斯，它们生活在沿海沙丘附近的湿润洼地的丛生草地中。在巴塔哥尼亚，它们生活在最中湿或湿润的灌木草原，接近南方山毛榉森林的边缘。在福克兰群岛，它们出现在白草田中，也靠近居住区。如今，它们也在农业领域（小麦）和种植的牧场中被观察到。","breeding":"繁殖季节在智利和阿根廷为9月至1月；在福克兰群岛有时8月底开始筑巢。可能是单配偶制。单独繁殖，成对筑巢；在圣路易斯山区（obscurus亚种）的配对较为分散和领地性。巢由雌鸟建造，主要由植物材料构成，尤其是草茎，有时有部分穹顶状屋顶，尺寸相当可变，内部直径8-11厘米，深度5.5-9厘米，建在地面凹陷处密集植被中，隐蔽性极好，难以发现，有时有穿过植被通往巢穴的通道；在福克兰群岛，巢可能位于高达1米的Poa flabellata草丛中。一窝产3-4枚蛋，颜色从淡黄色到灰色，密布着深色斑点、斑块和线条，平均尺寸28.6 x 20.6毫米（指名亚种片种），30.3 x 21.1毫米（falklandicus亚种），每天间隔产一枚；孵化由雌鸟负责，雄鸟可能守护巢穴，双方共同喂养雏鸟；关于孵化期和雏鸟期的持续时间未知；家庭群体可以持续数月。在阿根廷，巢穴可能受到紫辉牛鹂的寄生。","identification":"与相似的小红胸草地鹨相比，长尾草地鹨体型更大，尾巴和喙更长，翅膀下方覆羽颜色较浅。雌鸟比雄鸟更淡，喉部白色，无红色眉纹；下部羽毛条纹厚重，围绕着淡红色的下腹部。幼鸟类似雌鸟，但红色减少，有时仅为淡粉色斑块，喙色也较浅。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲南部，包括智利南部、阿根廷南部及西部地区，以及福克兰群岛。"},{"name":"小红胸草地鹨","english_name":"Pampas Meadowlark","scientific_name":"Leistes defilippii","overview":"小红胸草地鹨（英文名：Pampas Meadowlark，学名：Leistes defilippii），是雀形目拟鹂科Leistes的鸟类。体型中等，雄鸟头部和颈部侧面黑色，眼前方有一条红色的超眉线，下颊纹白色，上体呈暗褐色并有棕色条纹，下体红玫瑰色，侧胸、胁部和腹部黑色，翅膀下覆羽黑色带红边。雌鸟较雄鸟淡色且偏棕色，喉部白色，下体条纹包裹着浅粉色的下胸。主要分布在南美洲阿根廷中东部和乌拉圭部分地区。","appearance":"雄鸟平均体长21厘米，体重约73.6克；雌鸟略轻，平均67.5克。雄鸟头部和颈侧黑色，有明显的白眉线，前方转为红色，下颊纹和下眼睑白色，上体暗褐色，背部有棕色条纹，尾上覆羽具横斑，尾羽深色有橄榄色细斑，部分上翼覆羽玫瑰红色；下体自颏至腹部红玫瑰色，侧胸、胁部和腹下部黑色，翅膀下覆羽黑色，边缘红色；雌鸟颜色较淡，更偏向棕色，喉部白色，下体条纹中包含浅粉红色的下胸部分。幼鸟似雌鸟，但下体无红色，喙角质色。","call":"雄鸟的飞行鸣唱变化多样且较为悦耳，常结合上升和下降的哨音与响亮持续的音符，如“tse-tse-réé-tsew-tsee-tsew”，结尾音符较为柔和；停栖时的鸣唱（通常离地面较低，常在草丛上）包括最终的嗡嗡或沙哑音符，类似长尾草地鹨的鸣叫。叫声为‘peet’，同时伴有沙哑音。","habits":"栖息于原生草原和牧场，偶尔出现在农田。多数个体（占现存种群的82%）在自然草原筑巢，其余在农田中；在阿根廷，筑巢使用的草原包括Baccharis（菊科）和Stipa、Piptochaetium属的草类。乌拉圭种群在混合有carqueja（Baccharis trimera）的原生草原繁殖。弃耕五年以上的农业用地逐渐成为适宜筑巢的环境。能生活在无树区域，很少在灌木或围栏上栖息。海拔高度低至900米。","breeding":"繁殖季节为10月至11月在阿根廷。雄鸟保卫相对较小的领地，平均巢间距研究中为23厘米。飞行展示时，雄鸟飞升至约7米高，然后边鸣唱边下降。巢由植物材料制成的杯状结构，直径9.5厘米，置于地面凹陷处，靠近草丛，可能有长约8厘米的入口通道。一窝产卵3至5枚，平均3.14枚，卵色从浅黄到灰色，带有深色斑点、斑块和线条，平均尺寸25.8×18.3毫米；孵化期未知；雏鸟主要由雌鸟喂养，孵化期约10天；雄鸟可能参与喂养幼鸟。被寄生，但频率远低于长尾草地鹨；似乎这种寄生鸟的雌鸟发现本物种的巢穴较难定位。在一项研究中，29%的卵成功产生了雏鸟。","identification":"与更广泛分布且常见的长尾草地鹨非常相似，但在Pampas地区，雄鸟上体色彩对比不那么明显，呈棕色，两性均有深色翅膀下覆羽。与相似的长尾草地鹨相比，体型更健壮，尾巴更短，条纹较少，飞行时也通过黑色翅膀下覆羽加以区分。雌鸟比雄鸟更淡色，更偏向棕色，喉部白色，下体条纹中包含浅粉色的下胸部分。","protection":"IUCN：VU（易危）","distribution":"主要分布在阿根廷中东部（西南部布宜诺斯艾利斯、拉潘帕和里奥内格罗）和乌拉圭北部及中部（萨尔托和弗洛雷斯部门）。在巴西近期无记录。","other":"历史上曾广泛分布于阿根廷至少七个省份（南部科尔多瓦、圣路易斯、东部拉潘帕、科连特斯、圣塔菲、恩特雷里奥斯和布宜诺斯艾利斯）、乌拉圭更广泛的地区以及巴西最东南部（里奥格兰德州南部沿海）。自19世纪末以来，由于自然草原被作物和种植牧草取代，其数量和分布范围大幅减少。"},{"name":"黄嘴酋长鹂","english_name":"Yellow-billed Cacique","scientific_name":"Amblycercus holosericeus","overview":"黄嘴酋长鹂（英文名：Yellow-billed Cacique，学名：Amblycercus holosericeus），是雀形目拟鹂科黄嘴酋长鹂属的鸟类。包括墨西哥中部至委内瑞拉西部和玻利维亚北部。栖息于次生林、废弃农地和杂草丛生的田野，尤其偏好密集的竹林。","appearance":"雄性黄嘴酋长鹂全长约21.5厘米，重68.6克；雌鸟稍小，约20.5厘米，重53克。雄鸟全身黑色，无光泽，喙长而尖，象牙黄至黄色，鼻孔被特殊皮瓣覆盖；雌鸟相似，但体型较小，羽毛略显灰蓝，不如雄鸟纯黑。幼鸟颜色较暗，虹膜深色。亚种flavirostris体型更小，喙色更亮；australis体型最小，尾巴较长，喙细长，基部灰色。","call":"发出一连串响亮的哨声‘sh-wheu’，雌鸟有时会以干涩的‘chrrr’声回应，形成二重唱。也会从巢中发出声音，同时伴有鼻音叫声。","habits":"生活在密集灌木丛，包括竹林，常出现在溪流附近。活动范围从海平面至海拔1500米，但在巴拿马和哥斯达黎加可达3100米。主要以昆虫为食，如直翅目、半翅目、膜翅目和鞘翅目的昆虫，偶尔吃果实。在密集植被中觅食，利用‘张嘴探查’动作和敲击技巧从叶子和茎中取出猎物。通常成对或家庭群活动，有时跟随混合物种觅食群。","breeding":"繁殖季节在哥斯达黎加为4月至6月，在哥伦比亚为6月，在厄瓜多尔为12月。巢为坚固的杯状，由植物材料构成，如香蕉叶条、干藤蔓和草，直径12-15厘米，深度6-6.5厘米，置于离地面1-2.5米的浓密植被中。每窝产2枚蛋，淡蓝色，带有黑色斑点和线条，平均尺寸为26.9×18.3毫米（哥斯达黎加）和27.1×19.3毫米（厄瓜多尔）。寄生现象常见，至少在局部地区，如寄生其巢。","identification":"通过其淡黄色的喙和黄色的眼睛识别，即使在快速飞行中也很显眼。与同属物种相比，黄嘴酋长鹂的喙更为钝厚，且亚种之间在体型和喙色上有差异。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲，从墨西哥中东部至委内瑞拉西部和玻利维亚北部，包括巴拿马、哥斯达黎加、哥伦比亚、厄瓜多尔等地。","other":"耐受部分森林砍伐，能利用次生林进行筑巢。在许多保护区中都有其身影。"},{"name":"黄翅酋长鹂","english_name":"Mexican Cacique","scientific_name":"Cassiculus melanicterus","overview":"黄翅酋长鹂（英文名：Mexican Cacique，学名：Cassiculus melanicterus），是雀形目拟鹂科 Cassiculus 属的唯一物种，分布于墨西哥西部至危地马拉北部边缘的热带低地。这显著的黑黄相间色彩的鸟类。","appearance":"该鸟拥有醒目的黑色与黄色羽毛，头部具有独特的可竖立的冠羽，如同喷泉般向外散开，十分引人注目。通常成群活动，活跃于树冠层，也常在地面觅食。","habits":"黄翅酋长鹂偏好于落叶林、林缘、种植园和高树下的灌木丛，常见于城镇与村庄附近，尤其是靠近河流的地方。它们通常以群体形式移动，穿梭于开花和结果的树木间觅食，同时也会在地面取食，常与松鸦类鸟群相伴。","identification":"在分布范围内没有类似物种，其黑色与黄色鲜明对比的羽毛以及独特的冠羽是辨认的关键。","protection":"IUCN：LC（无危）","distribution":"分布于墨西哥西部，从索诺拉州沿太平洋斜坡南至恰帕斯州，向内陆延伸至墨西哥西南部的巴尔萨斯河流域；此外，还见于危地马拉南部和萨尔瓦多南部。"},{"name":"栗头拟椋鸟","english_name":"Chestnut-headed Oropendola","scientific_name":"Psarocolius wagleri","overview":"栗头拟椋鸟（英文名：Chestnut-headed Oropendola，学名：Psarocolius wagleri），是雀形目拟鹂科拟椋鸟属的鸟类。从墨西哥中东部到哥斯达黎加中部，再到巴拿马和哥伦比亚中东部及厄瓜多尔东北部。以大型垂挂的纤维巢而著称。","appearance":"雄鸟平均长度35厘米，体重214克；雌鸟平均长度28厘米，体重113克。头部呈暗紫栗色，体羽和翅膀黑色带蓝光泽，臀部和上尾覆羽深栗色，尾羽黄色，中央一对尾羽黑色，外侧尾羽具黑边。喙呈象牙色，有时略带绿色调，尖端和切割边缘淡蓝灰色。雌鸟较雄鸟小，色彩较暗淡。幼鸟比成鸟颜色更暗淡，眼睛棕色或蓝棕色，喙棕色，前额有黄色羽毛。","call":"歌曲短促但多变，由低沉的“pop”声后跟尖锐、嘈杂的声音组成，类似砍伐植被的砍刀声。常见叫声为液态低音的“waku-waku”。飞行时，雄鸟会产生可听见的翼鸣。","habits":"主要以小型脊椎动物（如蛙类和蜥蜴）、昆虫和其他节肢动物为食，也吃大型花朵的果实和花蜜。通常在树冠高处觅食，会探查并张口在附生植物中寻找食物。","breeding":"繁殖季节为1月至6月，实行一雄多雌制。群体繁殖，每群15至60个巢（偶尔130个），常位于孤立树木上。巢由雌鸟建造，长达60至120厘米的袋状巢，由多种植物纤维编织，如Tillandsia、藤蔓条、棕榈叶等，内衬干绿叶，悬挂于各种植物枝梢。雌鸟孵卵，孵化期17天；幼鸟由雌鸟喂养，巢期可达35天；雄鸟守护并防御巢区。巢可能被寄生。","identification":"与褐拟椋鸟相比，飞行速度更快，翼拍深且呈俯冲状，产生疾风声。雄鸟体型明显大于雌鸟。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲，从墨西哥中东部至哥斯达黎加中部，再到巴拿马，以及哥伦比亚中东部和厄瓜多尔东北部的低地森林。","other":"在特定时间和地点，可能在较高海拔（高达1,300米）更为常见，但其垂直迁移模式尚未充分了解。"},{"name":"褐背拟椋鸟","english_name":"Russet-backed Oropendola","scientific_name":"Psarocolius angustifrons","overview":"褐背拟椋鸟（英文名：Russet-backed Oropendola，学名：Psarocolius angustifrons），是雀形目拟鹂科拟椋鸟属的鸟类。广泛分布于南美洲的高海拔地区，包括北部和中部安第斯山脉、委内瑞拉沿海山脉以及亚马逊盆地的低地。该物种普遍常见，具有橄榄色和棕色的羽毛，雄鸟体型较雌鸟大，尾羽边缘呈黄色，雄鸟低地亚种喙部黑色，而高地亚种喙部颜色较浅。","appearance":"褐背拟椋鸟的雄鸟平均长度为46.5厘米，体重介于254至284.3克之间，而雌鸟平均长度为36.2厘米，体重在157至184克之间。成年鸟主要呈黄绿色，背部带有红褐色调，翅膀内侧可能呈现红褐色，次级飞羽和初级飞羽边缘为黄橄榄色，三级飞羽外半部分橄榄色，臀部和尾下覆羽红褐色，中央和最外侧尾羽橄榄色，其余尾羽大部分为黄色带橄榄色尖端。喙部绿色象牙色，通常基部略带灰色，但在野外观察时可能几乎全为灰色；虹膜为棕色。幼鸟与成鸟相似，但整个喙部黄色，前额黄色明显（持续至一岁左右）。","call":"雄鸟的鸣唱在展示时较短（0.7至1.7秒）且较为简单，但个体间和地域间存在差异。歌曲通常以低音开始，随后音调和音量逐渐升高至高潮。在厄瓜多尔东部、秘鲁和玻利维亚，该物种的当地俗名Cucupacho模仿了其歌曲的特点，雄鸟neglectus亚种的歌声为渐强的‘up-up-rup chéó’，而atrocastaneus亚种的歌声更独特且较长，含有喉音，并以响亮的颤音结束。报警声包括刺耳的‘chak’，以及柔和的‘whep’用于接触。","habits":"褐背拟椋鸟几乎为杂食性，食物包括野果，如亚马逊河谷中几种Cecropia树的果实和Coussapoa果实。在玻利维亚的Chapare地区，alfredi亚种会吃多种栽培水果，从橙子到木瓜，并从balsa花（Ochroma pyramidale）中吸食花蜜。它们常在附生植物如凤梨科植物或空中落叶中捕获猎物。这种鸟群居生活，有时与其他发冠拟椋鸟和一起觅食，高山亚种可能与松鸦科鸟类混群。","breeding":"繁殖季节在哥伦比亚低地（指名亚种）为9月至次年3月；在玻利维亚中部（alfredi亚种）筑巢始于6月至7月，8月至12月发现有蛋和雏鸟。所有亚种均为一雄多雌制。群体繁殖，通常每群2至20个巢，散布在3至5棵相邻的树上（不集群），每群有1至3只主导雄鸟；alfredi亚种形成小型群体，最多14个巢，1至4只雄鸟访问并在群体中展示；指名亚种在哥伦比亚形成较大群体（多达29个巢），通常在小岛上的孤立树木或牛轭湖中的树木上筑巢，alfredi亚种可能与形成混合群体，要么在同一棵树中，要么在附近一棵树中；在秘鲁东南部发现的32个活跃群体中，有17个与共享。巢由雌鸟建造，耗时3至5周，替换巢（较小和/或质量较差）可在12天内建成；袋状巢，长75至150厘米，顶部开口，由粗大的棕褐色植物纤维编织而成，主要来自单子叶植物如凤梨科、香蕉科、Cyclanthaceae和其他类似植物的叶片，内衬粗大的宽纤维，悬挂在树枝尖端或悬挂在附生天南星科植物上，通常离地面5至10米；利用多种中等大小的野生和栽培树种，包括Cecropia和结果树；alfredi亚种在各种中等大小的野生和栽培树种中筑巢，特别是在peach palms（Bactris gasipaes）中，常见于林中空地和种植园中的树木，甚至城镇中的树木。每次产卵1至2枚，卵为鲑鱼色，宽端有深色斑点和污迹（salmoni亚种），平均尺寸为36.5毫米×24.2毫米；孵卵由雌鸟完成，周期为19至20天；雏鸟由雌鸟喂养，巢穴期为30至32天；雄鸟的父爱仅限于守卫群体。alfredi亚种在低地和山脚下的某些巢可能被寄生。成功率不一；一些群体中每巢仅抚养一只雏鸟。","identification":"与同属其他物种相比，褐背拟椋鸟可通过其特有的红褐色背部和臀部、黄色尾羽外缘以及特定的鸣叫声来区分。不同亚种在体型、羽毛色彩、喙和眼睛的颜色上有细微差别，例如neglectus亚种颜色更深，额头黄色区域更为显著；atrocastaneus亚种整体红褐色，头部黄色区域更大，喙部橙黄色，虹膜可能全蓝或部分蓝色。","protection":"IUCN：LC（无危）","distribution":"褐背拟椋鸟主要分布在南美洲，包括委内瑞拉沿海山脉、北至中部安第斯山脉和亚马逊盆地的低地。在低地普遍常见，在安第斯山脉则较为罕见至局部常见。在厄瓜多尔西部，某些安第斯山脉亚种可能在其分布范围内有所下降；然而，指名亚种和alfredi亚种能够适应人类改变的环境，数量有所增加。最近在巴西朗多尼亚州被记录，其分布范围远东于亚马逊盆地已知的区域。"},{"name":"暗绿拟椋鸟","english_name":"Dusky-green Oropendola","scientific_name":"Psarocolius atrovirens","overview":"暗绿拟椋鸟（英文名：Dusky-green Oropendola，学名：Psarocolius atrovirens），是雀形目拟鹂科拟椋鸟属的鸟类。分布于南美的安第斯山脉东侧，从秘鲁中部至玻利维亚中部。体色均匀呈橄榄绿色，具有深色的眼睛和淡色的喙。在森林边缘和树冠上空常见，编织悬垂的巢穴形成小规模的群体。","appearance":"暗绿拟椋鸟体型中等，雄鸟长约42厘米，雌鸟约33厘米，两性形态相似。羽毛主要为深褐色或黑绿色，臀部和尾下覆羽为赤褐色，喙为黄绿色。头部可能带有黄色羽毛，虹膜颜色为棕色或蓝色，蓝色可能是年老个体的特征。与相似的褐背拟椋鸟相比，暗绿拟椋鸟体型较小，头部颜色更暗。","call":"其鸣唱是一系列变化丰富的清脆哨音和爆裂声，同时也能听到响亮的“chak”叫声。","habits":"栖息于亚热带或热带湿润的山地森林，以及严重退化的前森林地带。飞行活跃，偏好在森林边缘活动，常在树冠层上方飞翔。以昆虫、节肢动物、小型脊椎动物、花蜜和果实为食。","breeding":"繁殖季节通常在10月至12月之间，成群繁殖但群体规模较小。","identification":"与褐背拟椋鸟区分，后者上体更为赤褐色，额部黄色，头部橄榄绿色与背部和翅膀形成对比。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的秘鲁中部至玻利维亚中部，位于安第斯山脉的东侧，海拔介于800至2,600米之间。"},{"name":"发冠拟椋鸟","english_name":"Crested Oropendola","scientific_name":"Psarocolius decumanus","overview":"发冠拟椋鸟（英文名：Crested Oropendola，学名：Psarocolius decumanus），是雀形目拟鹂科拟椋鸟属的大型拟椋鸟。分布广泛，主要栖息于安第斯山脉以东的低地南美洲，北起巴拿马和哥伦比亚，南至阿根廷北部，同时出现在特立尼达和多巴哥群岛。雄鸟长约46厘米，重约300克，雌鸟略小，长度37厘米，重量约为180克。其羽毛散发出麝香味，源于其尾脂腺分泌的油质。","appearance":"成年雄性发冠拟椋鸟全身基本黑色，臀部转为栗色，尾巴除两根中央羽外皆呈亮黄色，头顶有一细长而常不易察觉的黑色冠羽。眼虹膜蓝色，长喙呈白色。雌鸟相似，但体型较小，色泽较暗淡，无明显冠羽。","call":"雄鸟的独特鸣声包括类似在钢琴上滑动手的下降音调，以及双方都具有的响亮咔嗒声。","habits":"发冠拟椋鸟栖息于森林边缘和开阔地带，通常在树冠层活动，主要食物为大昆虫、果实、种子和部分花蜜。在繁殖季节外，它们具有一定的流动性，会进行季节性迁移。","breeding":"发冠拟椋鸟群居繁殖，雌鸟会在高达125厘米的悬挂式编织巢中产下两枚蓝灰色带斑点的蛋，孵化期为15至19天，雏鸟约需24至36天离巢。每一群落通常由一只优势雄鸟主导，通过复杂的鞠躬展示与多数雌鸟交配。","identification":"发冠拟椋鸟与同类物种的区别在于其较大的体型、深色的羽毛和独特的黄色尾巴，以及蓝眼和白色长喙。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲的哥斯达黎加西南部至南美洲北部（除厄瓜多尔安第斯山脉西侧至智利），亚马逊地区至阿根廷西北部、东北部和巴拉圭东部；特立尼达和多巴哥群岛。","other":"发冠拟椋鸟是Acanthocephalan肠道寄生虫Apororhynchus aculeatus的宿主。"},{"name":"绿拟椋鸟","english_name":"Green Oropendola","scientific_name":"Psarocolius viridis","overview":"绿拟椋鸟（英文名：Green Oropendola，学名：Psarocolius viridis），是雀形目拟鹂科拟椋鸟属的大型鸟类。其绿色与栗色相间的羽毛在某些条件下和远观时可能显得近乎黑色。主要分布在南美洲的亚马逊雨林地带，包括委内瑞拉东部和南部、圭亚那、哥伦比亚东南部、厄瓜多尔东部、秘鲁东北部和中部、玻利维亚北部以及巴西大部分亚马逊流域。","appearance":"绿拟椋鸟体型庞大且健壮，雄鸟体长可达约43厘米，雌鸟约为37厘米。头部、胸部和背部呈淡橄榄绿色，翅膀为灰绿色，臀部和下体为栗色。尾羽中央为黑色，外侧为黄色。喙部颜色独特，尖端橙色，基部及周围皮肤为黄色。虹膜为淡蓝色，头部后方有不明显的冠羽。","call":"雄鸟的独特鸣唱能在很远处被听见，是其显著的声学特征。","habits":"绿拟椋鸟通常在森林树冠层活动，以混合物种群体的形式穿梭于森林中寻找果实和花朵。它们有时会在栖息地和觅食区之间成群结队地移动。在觅食时，它们会食用整个果实，因此在生态系统中扮演着种子传播者的角色。","breeding":"绿拟椋鸟是群居性和聚居性的鸟类，会建造长而袋状的巢，悬挂于树枝上。它们实行多配偶制，雌鸟负责筑巢和孵化。绿拟椋鸟的巢穴偶尔会被巨牛鹂寄生，后者在其巢中产卵。","identification":"绿拟椋鸟通过其较大的体型、黄色的尾羽和独特的浅绿色与红色的喙部与其它绿色羽毛的拟椋鸟区别开来。","protection":"IUCN：LC（无危）","distribution":"绿拟椋鸟广泛分布于南美洲的热带雨林中，包括委内瑞拉、圭亚那、苏里南、法属圭亚那、巴西、哥伦比亚、秘鲁、玻利维亚和厄瓜多尔。","other":"绿拟椋鸟是亚马逊雨林中常见的物种，以其独特的外观和生态角色受到关注。"},{"name":"亚马孙拟椋鸟","english_name":"Olive Oropendola","scientific_name":"Psarocolius bifasciatus","overview":"亚马孙拟椋鸟（英文名：Olive Oropendola，学名：Psarocolius bifasciatus），是雀形目拟鹂科拟椋鸟属的鸟类。南美洲亚马逊盆地的热带雨林为其主要栖息地，除了圭亚那高地的大部分区域。偶尔被分为两种，P. yuracares和亚马孙拟椋鸟，但P. y. neivae通常被视为杂交群体。","appearance":"雄鸟平均长度51厘米，体重449.6克；雌鸟平均长度42厘米，体重259.2克。雄鸟头部至肩部鲜亮的橄榄绿色或橄榄黄色，翼和体后部亮栗色，尾羽黄色，中央一对尾羽橄榄绿色；面部裸露皮肤粉红色；喙黑色，顶端橙色；腿黑褐色。雌鸟比雄鸟小，无顶冠。幼鸟颜色较暗淡，面部裸露部分颜色更暗淡。","call":"雄鸟的鸣唱常为细长下降的哨音，随后是复杂的咔嚓声带木质感，以响亮的颤音或持续音结束，伴有复杂的和音；叫声包括柔和的'yok'和响亮的'awk'。","habits":"主要栖息于亚马逊盆地的成熟低地森林，饮食上为杂食性，包括昆虫、软体动物和果实。在树冠层觅食，有时会与同类或黄腰酋长鹂组成混合物种觅食群。","breeding":"繁殖季节为1月至4月在委内瑞拉，8月至11月在玻利维亚。一夫多妻制。群居繁殖，每群通常少于五只鸟。巢由雌鸟建造，呈悬挂的袋子状，位于高树上。","identification":"与绿拟椋鸟相比，背部和翼覆羽为橄榄色，缺乏广泛的裸露面部皮肤，喙基部淡色，眼蓝色。","protection":"IUCN状态未知，具体保护等级需查证。","distribution":"南美亚马逊雨林，从哥伦比亚东部、厄瓜多尔东部和委内瑞拉南部至玻利维亚中部和巴西中南部。","other":"关于其繁殖习性的信息相对较少。"},{"name":"褐拟椋鸟","english_name":"Montezuma Oropendola","scientific_name":"Psarocolius montezuma","overview":"褐拟椋鸟（英文名：Montezuma Oropendola，学名：Psarocolius montezuma），是雀形目拟鹂科拟椋鸟属的鸟类。体型庞大，生活在墨西哥东南部至巴拿马的加勒比海岸低地。在尼加拉瓜和哥斯达黎加的太平洋斜坡以及洪都拉斯也有分布。雄鸟明显大于雌鸟，拥有独特的外观特征，包括黑头部和黄色尾侧，以及装饰性的脸部和喙纹。其令人难忘的鸣叫声如同从瓶中倾倒水的声音。","appearance":"雄性褐拟椋鸟主要呈锈褐色，头部和上胸部黑色，尾侧鲜明黄色，喙部有醒目的双色设计，基部黑色，尖端橙红色。面部两侧有大面积的裸露淡蓝色皮肤，下方有一小块粉红色区域。雌鸟与雄鸟羽毛相似，但体型明显较小。幼鸟颜色较为暗淡，黑色部分不具光泽，更接近煤黑色。","call":"雄性褐拟椋鸟发出的叫声独特，先是一段交谈般的咕噜声，随后是响亮的咕噜声，tic-tic-glik-glak-GLUUuuuuu。两性都会发出响亮的cack和crrrk叫声。","habits":"褐拟椋鸟栖息于热带低地森林边缘、开阔的林地、种植园和半开放区域的树木。它们在树冠层中以小群或大群的形式活动，寻找水果和大型昆虫，偶尔也会食用小型脊椎动物。迁徙模式不明，但在非繁殖季节，它们表现出一定的移动性。","breeding":"褐拟椋鸟在树上高达30米处，由雌鸟单独建造长达60-180厘米的悬挂式纤维和藤蔓巢。繁殖群通常由一只主导雄鸟领导，通过复杂的鞠躬展示与雌鸟交配。雌鸟每次产下两枚带有暗斑点的白色或淡黄色蛋，独自孵化约15天，幼鸟约30天后离巢。巢中喂养的食物主要是蜘蛛、其他节肢动物、青蛙、蜥蜴和水果。","identification":"与蒙特苏马拟椋鸟地理重叠的有栗头拟椋鸟，后者体型较小，颜色较浅的棕色，喙为淡黄绿色，与褐拟椋鸟的黑色和橙色喙形成鲜明对比。栗头拟椋鸟头部颜色较淡，上体黑色或暗色，面部皮肤无裸露的蓝粉区域。","protection":"IUCN：LC（无危）","distribution":"褐拟椋鸟在中美洲的分布从墨西哥南部延伸至巴拿马，主要栖息在加勒比海沿岸的低地森林中，同时也出现在尼加拉瓜、洪都拉斯和哥斯达黎加的太平洋斜坡。","other":"褐拟椋鸟在繁殖期间表现出高度的性二态性，雄鸟体型是雌鸟的两倍。雄鸟通过保卫性行为保护雌鸟，显示了一种雌鸟防卫的交配系统，类似于某些多配偶制哺乳动物而非鸟类。"},{"name":"黑拟椋鸟","english_name":"Black Oropendola","scientific_name":"Psarocolius guatimozinus","overview":"黑拟椋鸟（英文名：Black Oropendola，学名：Psarocolius guatimozinus），是雀形目拟鹂科拟椋鸟属的大型鸟类，主要分布在中美洲的巴拿马以及南美洲的哥伦比亚。其最显著的外部特征是全身黑色，背部和翅膀呈现深栗色，脸颊上有一块蓝色裸露皮肤，边缘带有粉色。分布于低地森林的冠层或亚冠层，最高可达海拔800米。","appearance":"雄性黑拟椋鸟长约47厘米，雌鸟约39厘米。整体黑色，背部、肩羽、上翼覆羽、下背部至尾上覆羽（除最末端部分）呈暗栗色。尾部黄色，中央一对尾羽黑色。头顶有细薄的黑色羽毛形成的短冠。虹膜棕色，喙基部有大片蓝色皮肤，喙尖橙色，喙部肿胀形成盔状结构，腿黑色。雌雄相似，但雌鸟体型较小，短冠亦较短。幼鸟描述未详。","call":"雄鸟在展示时发出响亮的歌曲，包含低沉的咕噜声和高音金属音符，与褐拟椋鸟类似，但有时缺乏渐强的音调。还有一种低沉的“cruk”叫声。","habits":"栖息于低地森林的较高层次，以昆虫和其他节肢动物、小型脊椎动物、果实及大型花朵的花蜜为食。常单独或小群体活动，偶尔在较大群体中出现。会在花朵中探查并用张开的喙在花内张口。","breeding":"可能为一雄多雌制，一个雄鸟与多个雌鸟交配。繁殖季节在巴拿马为2月，在哥伦比亚为4月至6月。群居筑巢，最多二十只鸟在同一棵树上建造巢穴。蛋壳淡粉色，少量红棕色斑点。","identification":"与褐拟椋鸟有明显的区别，但两者没有分布重叠。与罕见的博多拟椋鸟相比，后者面部有粉色而非蓝色斑块。","protection":"IUCN：LC（无危）","distribution":"分布于巴拿马（巴拿马省和达连）和哥伦比亚西北部（乔科、安蒂奥基亚和卡尔达斯）。在中美洲和南美洲的这一特定区域内，包括巴拿马东南部和哥伦比亚西北部，直至马格达莱纳河东岸。"},{"name":"栗背拟椋鸟","english_name":"Baudo Oropendola","scientific_name":"Psarocolius cassini","overview":"栗背拟椋鸟（英文名：Baudo Oropendola，学名：Psarocolius cassini），是雀形目拟鹂科拟椋鸟属的大型、色彩鲜艳的鸟类。仅分布于哥伦比亚西北部的低地和山麓雨林地带。其最显著的特征是鲑鱼色的脸颊斑块，以及栗色的背部和腹部，黄色的尾巴和橙色的喙尖，易于与黑拟椋鸟区分开来。雄鸟体型较雌鸟大。","appearance":"成年雄性栗背拟椋鸟体长约46厘米，雌鸟约39.5厘米。具有粉红色的裸露面部皮肤和脸颊肉垂，头部和下体大部分呈黑色，背部、臀部、翅膀、侧腹和肛周区域变为丰富的栗色。尾巴黄色，中央一对尾羽黑色。虹膜棕色，喙部膨胀成肿胀的盔状，黑色基部带有橙色尖端，腿黑色。雌雄相似，但雌鸟较小，颜色较暗淡。幼鸟特征未详述。","call":"鸣声特征了解不多，雄鸟的歌唱被报告为类似黑拟椋鸟和褐拟椋鸟。","habits":"通常在果树林的树冠层中发现，尤其是在空地和森林边缘。栖息地为哥伦比亚西北部沿海低地和山麓的雨林。","identification":"与黑拟椋鸟相比，主要通过粉色而非蓝色的裸露面部皮肤、栗色的翅膀以及缺乏顶冠来区分。","protection":"IUCN：VU（易危）","distribution":"分布局限于哥伦比亚西北部，包括Chocó、Antioquia西北部和Risaralda地区的沿海低地和山麓。","other":"栖息于Ensenada de Utría自然国家公园至少一处群落沿R Boroboro，也可能存在于Paramillo自然国家公园的较低海拔区域。"},{"name":"黑酋长鹂","english_name":"Solitary Cacique","scientific_name":"Cacicus solitarius","appearance":"雄鸟平均长度约27.5厘米，重90.1克；雌鸟平均长度约23.5厘米，重80克。全身羽毛纯黑，略带光泽，虹膜颜色从棕色到栗棕色，喙部象牙色，腿黑色。雄雌外观相似，幼鸟比成鸟颜色更暗淡。","call":"歌声多变，含有丰富的个人曲目。巢边的歌声通常以一系列低音符开始，可能包含管状空洞的声音、突然的高潮和奇特的谐音。在其他情境下的歌声可能较短且更简单。模仿其他鸟类的叫声。领土争端时，所有个体可能会连续发声30分钟以上。常见叫声为响亮的鼻音‘kwah-kwah’，也有猫叫般的叫声。","habits":"栖息于河流和渠道旁的洪水森林和河岸森林，延伸至主要河流（如亚马逊河、巴拉那河等）岛屿上的茂密河岸植被；也占据沼泽林地。在较为干燥的查科地区，出现在季节性落叶林中，常靠近季节性河流和沼泽，以及人工水库附近。活动范围从低地至海拔600米，偶尔可达1400米。主要以昆虫和其他节肢动物为食，也吃小型脊椎动物，尤其是树蛙，以及果实和花蜜。在植被较低层和灌木丛中觅食，偶尔在地上跳跃。通常成对或家庭群活动，很少加入混合物种觅食群。","breeding":"繁殖发生在10月至1月之间，具体时间取决于地理位置。在阿根廷，认为会养育两窝幼鸟。许多同属鸟类在群体中筑巢，但黑酋长鹂独居繁殖。","identification":"与厄瓜多尔酋长鹂相比，黑酋长鹂更大，喙部象牙色，虹膜颜色不同。","protection":"IUCN：LC（无危）","distribution":"主要分布于南美，包括委内瑞拉西南部、哥伦比亚东部、厄瓜多尔东部、秘鲁东部、巴西南部亚马逊雨林东至塞阿拉、伯南布哥和巴西亚西部、玻利维亚中部和东部、巴拉圭查科地区、阿根廷北部和东部、乌拉圭西部。","other":"在南美洲的部分范围内较为常见，能容忍适度的栖息地干扰，在阿根廷的布宜诺斯艾利斯城市沿海城区定期繁殖。在阿根廷的多个保护区中被发现，如Kaa-lya del Gran Chaco国家公园（玻利维亚）、Pantanal Mato-grossense国家公园（巴西）、San Rafael国家公园（巴拉圭）以及Río Pilcomayo、查科和Mburucuyá国家公园（阿根廷）。"},{"name":"金翅酋长鹂","english_name":"Golden-winged Cacique","scientific_name":"Cacicus chrysopterus","overview":"金翅酋长鹂（英文名：Golden-winged Cacique，学名：Cacicus chrysopterus），是雀形目拟鹂科酋长鹂属的鸟类。黑黄相间的鸟种。其最显著的特征是亮丽的黄色翅膀斑块和臀部，分布于南美洲的玻利维亚中部至阿根廷中北部，巴西南部，巴拉圭东部，阿根廷东北部和乌拉圭。","appearance":"雄鸟体长20.7厘米，体重34.6-47.2克；雌鸟稍小，体长19.3厘米，体重30.2-34克。整体黑色，具有醒目的黄色翅膀斑块和下臀部。眼睛颜色从珍珠白到黄色，喙呈淡蓝灰色，腿黑色。雌雄相似，但雌鸟体型略小。幼鸟比成鸟暗淡，眼睛深色。","call":"鸣唱多变而悦耳，通常以低音开始，随后突然升高，如'dreow-deo-deo-psikléé-o'。雄鸟唱歌时会鞠躬。配对的鸟可能通过低音的口哨声或带有奇特谐波的颤音交流。有时会模仿其他鸟类的声音。接触叫声为上升的、粗糙的鼻音'aa-ah'。","habits":"栖息于湿润森林、山地森林和次生林，常单独或成对活动，偶尔形成大群，尤其在非繁殖季节或高海拔移动期间。以昆虫和其他无脊椎动物、小型脊椎动物、果实和花蜜为食。常见于混种觅食群体，常与和其他拟鹂科鸟类一同活动。","breeding":"关于其繁殖行为的详细信息未提供。","identification":"通过其独特的黄色翅膀斑块和臀部以及黑色身体的对比来辨识。叫声和鸣唱特征也是辨识的重要依据。","protection":"IUCN状态未知，未提及在华盛顿公约(CITES)或中国国家重点保护野生动物名录中的情况。","distribution":"分布于南美洲，从玻利维亚东部（圣克鲁斯）和巴西南部（从马托格罗索州南部和里约热内卢）向南至阿根廷北部（图库曼、卡塔马卡、圣菲和恩特雷里奥斯）以及乌拉圭中部。","other":"在觅食时，会探查树皮、寄生植物，打开空心枝条和昆虫虫瘿，甚至倒挂觅食。"},{"name":"秘鲁酋长鹂","english_name":"Selva Cacique","scientific_name":"Cacicus koepckeae","overview":"秘鲁酋长鹂（英文名：Selva Cacique，学名：Cacicus koepckeae），是雀形目拟鹂科酋长鹂属的鸟类。罕见，主要分布于南美洲东南部秘鲁低地森林，以及巴西西南极地区域，尤其偏好森林边缘湖泊和河流附近的栖息地。其最显著的外部特征是黄色臀部和淡蓝色的眼睛。","appearance":"秘鲁酋长鹂全身大致呈黑色，除了醒目的黄色臀部和上尾覆羽。它是一种细长、尾长的鸟类，总身长约为23厘米。喙和虹膜呈现蓝白色，而腿脚为深色。","call":"它的鸣声多样，包括哨音、金属质感的尖叫声和各种嗡嗡声，还有其他类型的叫声。","habits":"秘鲁酋长鹂栖息于低地热带湿润森林，偏好靠近小河与溪流的浓密河边植被。它在低海拔地区和低丘陵地带活动，高度大约在300至575米之间。","breeding":"关于其繁殖行为的信息较为缺乏，但推测可能与近缘物种类似。","identification":"通过黄色限于臀部的特点，可将其与黄臀酋长鹂区分开来；同时，它与黑酋长鹂的区别在于后者没有黄色臀部。与厄瓜多尔酋长鹂不存在地理重叠，便于区分。","protection":"IUCN：NT（近危）","distribution":"秘鲁酋长鹂分布于秘鲁东部的乌卡亚利、库斯科和马德雷德迪奥斯地区，以及相邻巴西阿克雷州。已知的栖息地在秘鲁境内呈碎片化分布，推测也可能存在于巴西阿克雷州的部分地区。","other":"秘鲁酋长鹂的生存状况受到关注，其自然栖息地正遭受农业扩张带来的威胁，导致种群数量被认为正在快速下降。"},{"name":"厄瓜多尔酋长鹂","english_name":"Ecuadorian Cacique","scientific_name":"Cacicus sclateri","overview":"厄瓜多尔酋长鹂（英文名：Ecuadorian Cacique，学名：Cacicus sclateri），是雀形目拟鹂科酋长鹂属的鸟类。主要分布于南美洲安第斯山脉以东的雨林地带，尤其是森林边缘湖泊和河流附近。该鸟种以其独特的蓝色眼睛而易于识别。","appearance":"雄性厄瓜多尔酋长鹂体长约23厘米（9英寸），雌鸟略小。全身羽毛黑色，喙部呈白色，尖锐且长，成年个体的眼睛呈现淡蓝色，幼鸟的眼睛则是棕色。其外形特征与黑酋长鹂相似，但后者体型更大，眼睛颜色更深，更多时间在灌木丛和地面活动，较少出现在树上。红腰酋长鹂也有相似之处，但在飞行时会露出其鲜红色臀部，从而易于区分。","call":"该鸟种拥有丰富的叫声，包括类似警笛的哨声、金属质感的吱吱声以及类似猫叫的尖叫等。其中典型的叫声包括重复的'péach-yo'和'péach-yo-yo'，通常在尾羽竖起时发出，还有'k-cheeyow?'和'kweeyh-kweeyh-kweeyh-kweeyh-wonhh?'等多种叫声。","habits":"厄瓜多尔酋长鹂主要栖息于湿润的林地及河岸森林边缘，海拔高度可达400米（1300英尺）。它们通常是树栖鸟类，单独觅食，偶尔成对或小家庭群在树冠层中移动。该鸟常访问开花和结果的树木，有时可见其在Cecropia树的叶柄处探查。饮食以昆虫为主，如蚂蚁、甲虫和毛虫，同时也食用果实和可能的花蜜。","breeding":"关于厄瓜多尔酋长鹂的繁殖生态细节尚未详细记载。","identification":"与黑酋长鹂的区别在于后者体型更大，眼睛颜色更深，且更倾向于在低矮植被和地面活动；与红腰酋长鹂的区别在于飞行时后者会显露红色臀部。","protection":"IUCN：LC（物种关注程度最低）。尽管其栖息的热带森林正遭受破坏，导致适宜生存的环境面积减少，但由于该物种数量相对较多，且总体数量下降速度较慢，因此被 IUCN 评定为无危。","distribution":"该物种原生于南美洲南部哥伦比亚、东部厄瓜多尔和东北部秘鲁。在哥伦比亚的分布范围可追溯至Serranía de la Macarena，向南延伸至厄瓜多尔东部及秘鲁北部亚马逊地区的Amazonas和Loreto。"},{"name":"黄腰酋长鹂","english_name":"Yellow-rumped Cacique","scientific_name":"Cacicus cela","overview":"黄腰酋长鹂（英文名：Yellow-rumped Cacique，学名：Cacicus cela），是雀形目拟鹂科酋长鹂属的鸟类。最显著的外部特征是黑色羽衣搭配明亮的黄色腰部、翼斑和下腹部。分布于中美洲巴拿马中部至南美洲玻利维亚北部和巴西中南部。","appearance":"雄性黄腰酋长鹂平均长度约28厘米，重约104克，而雌鸟略小，长约23厘米，重约60克。该鸟体态修长，拥有长尾、蓝眼和浅黄色尖喙。其主要羽色为黑色，但黄色的臀部、尾基、下腹部和翼上的‘肩章’非常醒目。雌鸟的黑色不如雄鸟鲜明，幼鸟类似雌鸟，但具有暗色眼睛和棕色喙基。","call":"雄性黄腰酋长鹂的鸣唱是一系列笛音混合着咯咯声、喘息声，有时甚至模仿其他声音，种类繁多，使得活跃的鸟群在远处就能被听到。","habits":"黄腰酋长鹂栖息于开阔的林地或种植园中的大树上，以大型昆虫、蜘蛛、花蜜和果实为食。它们的社会性很强，通常集群活动。","breeding":"黄腰酋长鹂是群居繁殖者，每棵树上可能有高达100个袋状巢穴，通常这些树上还会有活跃的黄蜂巢，提供额外的保护。雌鸟负责筑巢、孵化和照顾幼鸟。巢穴长30-45厘米，底部宽大，悬挂在枝梢。雌鸟们会为了靠近黄蜂巢的优质筑巢位置而竞争。每次产卵两枚，带有深色斑点的淡蓝色或白色蛋。雌鸟在下完第二枚蛋后开始孵化，大约13到14天后幼鸟破壳而出。幼鸟在34到40天后离巢，通常每巢只有一只幼鸟存活。","identification":"黄腰酋长鹂与同属其他物种的区别在于其独特的黄色臀部和翼斑，以及体型和叫声的差异。例如，秘鲁酋长鹂体型较小，翅膀和腹部全黑，黄色臀部斑块较小。Band-tailed Oropendola（Ocyalus latirostris）体型更大，头部有小型盔状突起，缺乏黄色的翅膀、臀部和腹部标记。黄肩黑拟鹂体型较小，尾巴更长，全黑，喙也全黑，臀部黄色较少，腹部黑色。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲巴拿马中部至南美洲北部，包括玻利维亚北部和巴西中南部。","other":"黄腰酋长鹂受益于森林清理和牧场开发创造的更加开放的生境，因此其种群数量稳定。"},{"name":"橙腰酋长鹂","english_name":"Scarlet-rumped Cacique","scientific_name":"Cacicus microrhynchus","overview":"橙腰酋长鹂（英文名：Scarlet-rumped Cacique，学名：Cacicus microrhynchus），是雀形目拟鹂科酋长鹂属的鸟类。广泛分布于中美洲至南美洲的洪都拉斯东部至厄瓜多尔西南部。","appearance":"橙腰酋长鹂表现出明显的两性异形，雄鸟长度约23厘米，体重约为68克，而雌鸟略小，长约20厘米，重约53克。这是一种拥有细长翅膀和相对较短尾巴的苗条鸟类，其特征还包括蓝色的眼睛和浅黄色尖喙。其羽毛主要是黑色，但在下背部和上臀部有一块醒目的橙红色斑块。雌鸟相比雄鸟颜色较暗淡，幼鸟的羽毛带有棕色调，臀部为棕橙色。","call":"它们的叫声是一连串悦耳的‘whee-whee-whee-wheet’，但在太平洋亚种中，叫声会变成下降式的忧郁‘wheeo-wheeo-wheeo-wheeo’，而C. m. microrhynchus的叫声更粗糙，类似‘pleeo’，C. m. pacificus的叫声则更为甜美，像‘keeo’或‘shree’。","habits":"橙腰酋长鹂不像某些其他同类物种那样群居繁殖，它们的巢呈袋状，通常建在离地面3.5到30米高的树上，巢附近常常有活跃的黄蜂巢。巢长36至64厘米，底部加宽，悬挂在树枝末端。一次通常产下两个带有深色斑点的白色蛋。雄鸟会协助喂养幼鸟，但不会孵卵。","breeding":"繁殖期和求偶行为的信息较为有限，但已知雄鸟会在繁殖季节参与喂养幼鸟。巢由雌鸟建造，雄鸟可能提供辅助，巢的形状独特，有利于保护蛋和幼鸟。","identification":"与同属其他种类相比，橙腰酋长鹂最显著的辨识特征是其橙红色的臀部斑块，此外，它们的体型、叫声以及具体的栖息地选择也可以作为辨识依据。","protection":"IUCN状态未知，需进一步确认。","distribution":"橙腰酋长鹂的分布范围涵盖中美洲至南美洲，具体从洪都拉斯东部延伸至厄瓜多尔西南部，包括了中美洲和南美洲的多个国家和地区。","other":"现为亚热带酋长鹂亚种。"},{"name":"亚热带酋长鹂","english_name":"Subtropical Cacique","scientific_name":"Cacicus uropygialis","overview":"亚热带酋长鹂（英文名：Scarlet-rumped Cacique，学名：Cacicus uropygialis），是雀形目拟鹂科酋长鹂属的鸟类。中型林栖鸟，通体近黑，尾上覆羽鲜红，飞行时尤为醒目；喙长而尖，呈淡黄象牙色，虹膜淡蓝。分布于中美洲至南美西北部，自洪都拉斯东部经巴拿马至厄瓜多尔西南与秘鲁东南，海拔自海平面至2450米。部分高海拔族群体型更大，尾更长，或将被提升为独立种。","appearance":"体长20–30.5厘米，体重50–119克。雄鸟全身黑色带微亮光泽，尾上覆羽具鲜亮红色小斑，停栖时常被翼覆羽遮挡；雌鸟光泽较弱。幼鸟羽色暗淡，虹膜深褐。喙长而略下弯，象牙色，基部微黄，余部略带灰、蓝或绿色；眼周裸露皮肤黑色；脚黑色。三指名亚种体型差异显著：microrhynchus与pacificus相对较小，uropygialis明显更大，尾占比例更长而翼相对短。","call":"嘈杂而富有变化，雄雌皆可在巢边发出清晰口哨声，旋律先升后降，西厄瓜多尔族群常被形容为“whip, wheeo wheeo wheeo”的忧郁哨音。另有多种叫声：三段式颤音、尖锐“keap！”、流水般“wurt-wurt-wurt”、急促“chi-chi-zi-zi-jew”及似鸦的“greer”等。","habits":"栖息于湿润亚热带低地、丘陵及山地森林、林缘及次生灌丛，海拔0–2450米；安第斯山西坡一般低于1000米，东坡多高于1500米。通常4–10只成群在林冠层活动，常加入混合觅食群，与山酋长鹂、赤背拟鹂、蓝绿松鸦及安第斯动冠伞鸟等同游。倒挂枝叶间探查凤梨、枯叶及缝隙，以节肢动物、果实、小型脊椎动物、花蜜为食，亦掠食黄蜂幼虫。夜栖时可聚集数百只于浓荫中。","breeding":"繁殖期因地而异：microrhynchus于哥斯达黎加2–6月、巴拿马2–8月，可能一年两窝；pacificus在哥伦比亚1–5月及8月筑巢；uropygialis在哥伦比亚3–5月，秘鲁6月仍处繁殖状态。一夫一妻制，营小群落繁殖，microrhynchus多单独营巢，pacificus及uropygialis可多达12对共域。雌鸟独自以棕褐色植物纤维、根、花序等编成38–74厘米长的囊状巢，顶端开口，内衬种毛，悬挂于树枝或棕榈叶尖，常邻近胡蜂巢。每窝2枚白色卵，带少量棕黑斑；雌鸟孵卵，双亲及群内成鸟共同育雏。","identification":"与更大型的红腰酋长鹂相较，后者红色臀斑更宽，可延伸至背下部。高海拔族群因体型更大、尾更长而明显区别于低地族群。","protection":"IUCN: LC（无危）。分布广泛且数量局部丰盛，见于多国国家公园及保护区。","distribution":"繁殖与非繁殖区域重叠：中美洲自洪都拉斯极东部经尼加拉瓜、哥斯达黎加、巴拿马（除达连省外），南美沿太平洋低地由哥伦比亚至厄瓜多尔埃尔奥罗省；安第斯山区自哥伦比亚经厄瓜多尔、秘鲁东南至委内瑞拉西北部。玻利维亚记录已被否定。","other":"系统分类上，因pacificus形态介于microrhynchus与uropygialis之间，曾被视作单种内分化，但分子研究显示pacificus与uropygialis亲缘更近，未来或为两至三独立种。"},{"name":"北山酋长鹂","english_name":"Northern Mountain Cacique","scientific_name":"Cacicus leucoramphus","overview":"北山酋长鹂（英文名：Northern Mountain Cacique，学名：Cacicus leucoramphus），是雀形目拟鹂科酋长鹂属的鸟类。分布广泛，自委内瑞拉至秘鲁中部，以其全身黑色配以醒目的黄色腰部斑块和翅膀条纹而著称，虹膜呈现独特的蓝色。","appearance":"北山酋长鹂全身覆盖着深邃的黑色羽毛，最引人注目的是其黄色的腰部斑块，以及由黄色的中间和内部覆羽构成的鲜明翅膀条纹。虹膜呈现出不常见的蓝色，增添了其神秘感。","habits":"北山酋长鹂栖息于南美洲的亚热带或热带湿润山地森林中，具体分布于玻利维亚、哥伦比亚、厄瓜多尔、秘鲁和委内瑞拉。它们的生活习性包括迁徙模式、飞行特点、活动范围及觅食方式等细节尚需进一步研究。","identification":"与其他酋长鹂属鸟类相比，北山酋长鹂的独特之处在于其明显的黄色翅膀条纹和蓝色虹膜，这些特征有助于在野外进行识别。","protection":"IUCN：LC（无危）","distribution":"北山酋长鹂主要分布在南美大陆，包括玻利维亚、哥伦比亚、厄瓜多尔、秘鲁和委内瑞拉的亚热带或热带湿润山地森林中。"},{"name":"南山酋长鹂","english_name":"Mountain Cacique","scientific_name":"Cacicus chrysonotus","overview":"南山酋长鹂（英文名：Mountain Cacique，学名：Cacicus chrysonotus），是雀形目拟鹂科酋长鹂属的鸟类。引人注目的黑黄相间的鸟类。分布于南美洲安第斯山脉，从哥伦比亚和委内瑞拉西部至玻利维亚中部。南山酋长鹂曾与北山酋长鹂被视为同一物种，但南山酋长鹂的翅膀上缺乏黄色，虹膜颜色更接近淡蓝至白色。","appearance":"南山酋长鹂成年雄鸟长约28厘米，重约98克；雌鸟稍小，长25厘米，重约64.5克。雄鸟主要为光泽黑色，背部下方和臀部为鲜黄色，部分个体在上翼覆羽有黄色羽毛；雌鸟整体较暗淡。幼鸟眼睛呈深棕色，嘴部颜色比成鸟更深。","call":"发出重复响亮的叫声，类似北山酋长鹂，但节奏更慢、音调更高，还有一种由五个音符组成的复杂叫声，可能是其歌声，低沉的喉音与高低哨声交替。","habits":"生活在海拔1800至3600米的亚热带至温带湿润山林中，偏好有Weinmannia和Clusia等树种的森林。以昆虫和其他节肢动物为主食，也会食用花蜜和果实。常在树冠层或森林边缘觅食，会探入竹子、附生植物和树皮中寻找食物。通常以小群或混种觅食群出现，与Cyanolica jay或Buthraupis山鵙等物种一同觅食。","breeding":"在哥伦比亚，繁殖季节为2月至7月。在哥伦比亚的Cundinamarca，被报告为独居繁殖者，暗示可能有合作繁殖的行为；在厄瓜多尔的Baeza附近发现六个活跃的巢穴集群，但在Tungurahua火山三个较为靠近的巢穴中，只有一个正在使用。巢穴呈长袋状，约50厘米长，入口在顶部，由粗大的植物材料构成，悬挂在斜坡上方的树枝上。","identification":"南山酋长鹂与北山酋长鹂相比，主要区别在于缺乏隐藏的白色领环，通常翅膀覆羽没有黄色，且喙较长。雌鸟与雄鸟相似，但整体颜色较暗。","protection":"IUCN：LC（无危），在厄瓜多尔不常见至相当常见，在玻利维亚、委内瑞拉和哥伦比亚则较为稀少或局部分布。）","distribution":"南山酋长鹂分布在南美的安第斯山脉，从哥伦比亚和委内瑞拉西部至玻利维亚中部。在秘鲁南部至玻利维亚中部尤其可见。","other":"南山酋长鹂未被报道为巨牛鹂的宿主，可能是因为它栖息在较高的海拔。"},{"name":"斑尾拟椋鸟","english_name":"Band-tailed Cacique","scientific_name":"Cacicus latirostris","overview":"斑尾拟椋鸟（英文名：Band-tailed Cacique，学名：Cacicus latirostris），是雀形目拟鹂科酋长鹂属的大型鸟类。原称为斑尾拟鹂，在西部亚马逊地区的特有种，通常在低密度环境下生存，与水淹森林紧密相关。","appearance":"这种大型拟椋鸟外观更接近拟鹂而非同类其他物种。其显著特征包括大而尖锐的白色喙，棕色的上背和头冠，以及黄色的尾羽。其余羽毛一般呈光泽的黑色或灰色。体型较大，容易通过独特的颜色组合识别。","call":"尽管体型较大，但在亚马逊地区更常被听到而非看到，其鸣叫声具有独特性，是辨识该鸟的重要线索。","habits":"通常在混合群中与其他拟椋鸟或拟鹂共同出现，群体规模通常在3至5只之间。栖息于西部亚马逊的低地热带雨林，偏好水淹森林环境。","breeding":"关于其繁殖行为的具体信息有限，但预计与其他拟椋鸟相似，包括营巢、交配和育雏的常规模式。","identification":"与其他拟椋鸟相比，斑尾拟椋鸟的白色大喙、棕色上背、头冠和黄色尾羽是明显的辨识特征。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲西部亚马逊地区的低地，范围从哥伦比亚西南部到秘鲁东部，以及巴西西部。","other":"曾被归类为拟鹂，现已确认为酋长鹂属的一员。"},{"name":"盔拟椋鸟","english_name":"Casqued Cacique","scientific_name":"Cacicus oseryi","appearance":"成年雄鸟平均体长37厘米，体重约187.7克；雌鸟平均体长29厘米，体重约101.4克。羽毛大多为丰富的栗色，脸部颜色最深，喉部灰橄榄色，上胸和颈部侧面黄橄榄色；上翼为栗色，飞羽边缘黄色；尾部暗橄榄色，外侧羽毛鲜亮黄色；虹膜淡蓝色，偶尔呈淡黄灰色；喙的颜色多变，有时上喙暗灰色，下喙黄绿色带暗灰色尖端，头盔部分从暗黄灰色到橄榄灰色不等，有时象牙色，可能带有绿色调并向尖端逐渐变暗，有时全为暗灰色；腿黑色。两性相似，但雌鸟体型小，头盔亦较小。幼鸟虹膜颜色较深。","call":"鸣唱多变，其中一种类型为‘klow klow shrr-weo’，音质类似；繁殖季节的巢穴群极为嘈杂。","habits":"生活在亚马逊西部的低地雨林，偏好湿润地带。以昆虫、小型脊椎动物和花蜜为主食，曾观察到食用未知红色浆果，以及Coussapoa属（桑科）和Cecropia果实。与群居，夜晚与其他悬垂鸟和拟椋鸟共同栖息。","breeding":"繁殖季在秘鲁为9月至11月。一夫多妻制，但缺乏详细的繁殖研究。巢群由14至25个巢组成，位于小河流沿岸；筑巢活动高度同步，如19个巢穴在一个星期内全部建成；有时与共巢。巢由雌鸟建造，呈开口顶部的袋子形状，由多种棕色植物纤维编织而成，类似于群居拟椋鸟的巢。已知的所有秘鲁和巴西的巢群都位于孤立的Cecropia树上。孵化由雌鸟承担，雄鸟主要负责巢穴守卫和防御猴子、巨嘴鸟科和其他捕食者的侵袭。","identification":"与大多数拟椋鸟相比，更似悬垂鸟；识别特征包括其独特的喙形和淡蓝色眼睛。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲西部亚马逊流域，自哥伦比亚西南远至巴西西部和玻利维亚北部。"},{"name":"红腰酋长鹂","english_name":"Red-rumped Cacique","scientific_name":"Cacicus haemorrhous","overview":"红腰酋长鹂（英文名：Red-rumped Cacique，学名：Cacicus haemorrhous），是雀形目拟鹂科酋长鹂属的鸟类。南美洲特有的大型拟鹂。以亚马逊盆地和圭亚那高地为主要栖息地，分布于巴西东部沿海、巴拉圭以及阿根廷东北部等地。此外，该物种还可见于玻利维亚、哥伦比亚、厄瓜多尔、法属圭亚那、圭亚那、秘鲁、苏里南和委内瑞拉。","appearance":"红腰酋长鹂拥有长长的、细瘦的象牙色喙，全身羽毛呈现深邃的黑色，仅腰部显现出醒目的红色，这一特征在静止时可能不易察觉。眼睛呈蓝色，增添了其独特的外观。","call":"其鸣唱多变，包括响亮的哨音和尖锐的‘kak-kak-kak’警报声。","habits":"红腰酋长鹂栖息于湿润森林的树冠层，它们可能会随着雨季的迁移而移动。它们在热带低地森林、沼泽地带以及重度退化的前森林环境中生存。","breeding":"这种鸟倾向于群居，会在群体中建造大型的垂挂巢穴，用于繁殖。","identification":"与其他拟鹂科鸟类相比，红腰酋长鹂的红色腰部和蓝色眼睛是显著的辨识特征。","protection":"IUCN：LC（无危）","distribution":"红腰酋长鹂的分布范围包括南美洲的亚马逊盆地，从哥伦比亚东部延伸至玻利维亚北部，覆盖巴西东部、巴拉圭东部以及阿根廷东北部，同时也出现在圭亚那高地。"},{"name":"斯氏拟鹂","english_name":"Scott's Oriole","scientific_name":"Icterus parisorum","overview":"斯氏拟鹂（英文名：Scott's Oriole，学名：Icterus parisorum），是雀形目拟鹂科拟鹂属的鸟类。主要分布在北美的西南部，南至下加利福尼亚和墨西哥中部。其显著特征为成年雄鸟的柠檬黄色身体与黑色头部、胸部和背部形成鲜明对比，雌鸟则呈现较为暗淡的橄榄绿色，带有少量黑色斑纹。此鸟以热衷于干燥环境而著称，尤其偏爱有丝兰树丛生的山地斜坡。","appearance":"成年雄性斯氏拟鹂具有醒目的黑色头部、胸部和背部，与明亮的柠檬黄色身体形成强烈反差；翅膀黑色，带有白色翼带和黄色肩部。雌鸟个体上部灰橄榄色，略显暗淡，头部、背部和喉部有不同程度的黑色斑点，翼部棕色，有两道白色的翼带，尾巴一般为橄榄色。幼鸟色泽较淡，背部有模糊的条纹。","call":"斯氏拟鹂的鸣唱是一系列快速而清晰的哨音。","habits":"栖息于相对较高的干燥环境，如山地斜坡和半干旱平原，偏好与沙漠相邻的地带。它适应炎热干燥的环境，常在沙漠特有树种如丝兰、沙漠棕榈、杜松和皮诺松中筑巢。以昆虫、花蜜和果实为食，展现出迁徙习性，美国繁殖群体冬季会向南迁移至墨西哥。","breeding":"季节性一夫一妻制，每年3月底开始返回美国繁殖地，通常停留至7月或8月，多数配对能成功育成两窝，部分尝试第三窝。巢建得较低，呈杯状，不同于橙腹拟鹂和布氏拟鹂的难以触及的袋状巢。主要在较远的地方觅食，以捕食节肢动物为主。","identification":"与黑臀拟鹂相比，斯氏拟鹂缺少尾羽和翼带上的黄色，体型更大，尤其是尾部更长。成年雄性斯氏拟鹂的黄色尾基和尾羽尖端的黄色也是区别于其他拟鹂的重要特征。","protection":"IUCN：LC（无危）","distribution":"繁殖区位于美国西南部和墨西哥，非繁殖期主要分布于墨西哥，包括下加利福尼亚和墨西哥中部。","other":"此物种曾有提议更名为丝兰拟鹂，以反映其栖息地选择和解决现名与历史上负面事件的关联问题。"},{"name":"黄背拟鹂","english_name":"Yellow-backed Oriole","scientific_name":"Icterus chrysater","overview":"黄背拟鹂（英文名：Yellow-backed Oriole，学名：Icterus chrysater），是雀形目拟鹂科拟鹂属的鸟类。主要分布在中美洲高海拔的松栎森林和墨西哥尤卡坦半岛的热带湿润低地。该鸟以鲜明的黄色头身和黑色面罩、喉部斑块以及黑色翅膀和尾巴为显著特征。","appearance":"成年黄背拟鹂长约21.5厘米，雄鸟平均体重51.8克，雌鸟平均48.7克。雄鸟具金色黄色体羽，头部至胸部有明显的黑色区域，翼和尾部全黑；雌鸟相似但略显暗淡，冠部和背部带有橄榄色晕染。幼鸟缺乏头部和胸部的黑色，整体羽毛比成鸟更暗淡。不同亚种间存在细微差异，如mayensis亚种体型较小。","call":"黄背拟鹂发出丰富而略带停顿的哨音，歌声悠扬，长度变化，通常由4至10个升、降音调组成，声音质量因地域而异，有时嘹亮、丰富且悦耳，有时则显得单调或重复。","habits":"栖息于多种环境，包括墨西哥、伯利兹和尼加拉瓜的松木林，墨西哥、危地马拉和萨尔瓦多的山地栎树林，以及尤卡坦北部的干燥灌木丛。在巴拿马，常见于原始和次生林边缘，在哥伦比亚圣玛尔塔山区则多见于咖啡种植园、空旷地带和带森林斑块的耕地上。主要以昆虫和其他节肢动物、果实和花蜜为食，常在家族群或小群中觅食。","breeding":"繁殖季在巴拿马为2月至5月，哥伦比亚也有1月产卵记录。可能是单配偶制。巢呈篮状，用干草编织，直径约11厘米，深度9至13厘米，悬挂于树叉7米高处。每窝产2至3枚蛋，白色底有紫色斑点和少数深色划痕，平均尺寸为25.1×17.2毫米。已知是紫辉牛鹂的寄主。","identification":"与南美黄拟鹂类似，但可通过颜色模式和分布区加以区分。黄背拟鹂的黄色部分更为鲜亮，黑色部分界限分明。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲和北南美洲，包括墨西哥南部至委内瑞拉和厄瓜多尔。在圣玛尔塔地区的哥伦比亚北部，随着咖啡栽培的建立而入侵。在多个保护区中发现，如墨西哥的Sian Ka'an生物圈保护区和巴拿马的Barro Colorado自然纪念碑。","other":"能够适应各种被改造的生境，甚至在某些地方繁荣生长。"},{"name":"黑头拟鹂","english_name":"Audubon's Oriole","scientific_name":"Icterus graduacauda","overview":"黑头拟鹂（英文名：Audubon's Oriole，学名：Icterus graduacauda），是雀形目拟鹂科拟鹂属的鸟类。其特征在于拥有完全黑色的头部和黄色的身体，仅在墨西哥和美国德克萨斯州东南部的森林和灌木丛中可见。该物种由四个亚种组成，分为两个不连续的繁殖区：西部范围从纳亚里特延伸至奥阿哈卡南部，东部范围覆盖了下格兰德河谷至科雷塔罗北部。并非迁徙鸟类，且性别间差异不大。DNA分析显示，与黄背拟鹂关系最为密切。","appearance":"雄性黑头拟鹂具有黑色的头部、喙、喉咙和尾巴，翅膀黑色，边缘带白色，形成明显的翼斑。背部和腹侧为橄榄黄色，腹部几乎通体黄色。雌鸟比雄鸟略显橄榄色，尤其在颈背处，但整体相似。幼鸟的翅膀和尾巴呈暗褐色而非黑色，全身羽毛较淡，缺乏黑色部分，上体橄榄色，下体黄色，翼羽边缘黄色，覆羽灰而带有橄榄边，尾部橄榄色，中央尾羽较深。成年鸟的翅膀和尾部在换羽后会变得更黑。","call":"黑头拟鹂的歌声是一系列缓慢、柔和、类似人类口哨的声音，由几乎纯音调组成，比巴尔的摩拟鹂的歌声更长但复杂度较低，频率调节较少，覆盖频率范围窄。鸣唱还包括鼻音的“ike, ike, ike”和吹口哨般的“peu”。","habits":"黑头拟鹂栖息于密集的常绿森林和灌木丛，偏好河流边的环境。它们通常在浓密的植被中觅食，靠近林地空地。在飞行时，它们会加入混合种类的鸟群，包括其他拟鹂、松鸦、唐纳雀等。食物主要包括昆虫、蜘蛛、果实，也会在喂鸟器中寻找向日葵种子。","breeding":"黑头拟鹂的巢类似于兜帽拟鹂和果园拟鹂的巢，直径约三英寸，深度相似，外观像悬挂的袋子或篮子，不如其他种类深。巢由长草茎编织而成，内部铺以细草。一对黑头拟鹂每年通常孵化两窝，每窝含有三到五枚蛋，但晚出生的小鸟往往无法度过冬季。","identification":"黑头拟鹂最显著的区别在于其独特的黑色头部和黄色身体。与斯氏拟鹂相比，它的背部不是黑色而是橄榄绿色，且分布范围不重叠。与黑顶拟鹂和大安的列斯拟鹂的区别在于后者有明亮的黄色臀部和尾羽上覆羽，且体型更为纤细。","protection":"IUCN：LC（无危）","distribution":"繁殖于美国德克萨斯州南部和墨西哥，非繁殖期可能在更广泛的墨西哥地区。","other":"黑头拟鹂的巢常被棕头牛鹂寄生，这对种群数量有一定影响。"},{"name":"牙买加拟鹂","english_name":"Jamaican Oriole","scientific_name":"Icterus leucopteryx","overview":"牙买加拟鹂（英文名：Jamaican Oriole，学名：Icterus leucopteryx），是雀形目拟鹂科拟鹂属的鸟类。主要栖息于牙买加和哥伦比亚的圣安德烈斯岛。其独特的黑色面具和喉咙，以及腹部鲜艳的黄色，使其在热带森林中十分显眼。该物种曾存在于开曼群岛的大开曼岛，但现已在当地灭绝。","appearance":"成年牙买加拟鹂体长约21厘米，体重约34至42克。雄鸟头部至胸部呈黑色，其余部分为橄榄黄色，腹部颜色更为鲜亮。翅膀上的显著白色斑块覆盖了大半的黑色翅膀，形成鲜明对比。尾巴黑色，眼睛深棕色，喙部蓝灰色，嘴峰黑色，腿脚暗灰色。雌鸟与雄鸟相似，但色彩可能略显暗淡。幼鸟为橄榄绿色，头部黑色区域减少，翅膀和尾巴带有更多黑色，尾部呈灰绿色。","call":"牙买加拟鹂的鸣唱由两到三个音节组成，旋律悠扬，调子多变，例如“tie-tiewu”、“tie-tiewu-tiewu”等，常被转写为“Auntie Katie”。叫声包括单音或双音的哨声，以及短促的叽喳声。","habits":"牙买加拟鹂栖息于低地和山地的湿润森林，也适应于严重退化的前森林环境。它们以昆虫、其他节肢动物、小型脊椎动物、花蜜和水果为食，偏好本地植物的果实，如Trophis、Guapira、Clusia、Pithecellobium、Miconia、Bursera和Trichilia属植物，也会食用栽培的番木瓜、橙子、香蕉和Annona属的水果。此外，它们会从引进的Erythrina植物中吸取花蜜，偶尔访问蜂鸟喂食器。独特的觅食方式包括用喙剥离树皮以暴露隐藏的食物，这是拟鹂科中罕见的行为。","breeding":"关于牙买加拟鹂的繁殖行为，现有资料较为有限，但已知它们会在繁殖季节中建立家庭群，进行繁殖活动。","identification":"与圃拟鹂相比，牙买加拟鹂体型较大，拥有明显的白色翼斑。幼鸟与成鸟的区别在于头部黑色区域较小，翅膀和尾巴具有更多黑色，尾部呈灰绿色。","protection":"IUCN：LC（无危）","distribution":"牙买加拟鹂主要分布在牙买加和哥伦比亚的圣安德烈斯岛，曾在开曼群岛的大开曼岛上存在，但现在该物种在开曼群岛已灭绝。","other":"牙买加拟鹂与北美大陆的拟鹂关系更近，如橙腹拟鹂和墨西哥橙拟鹂，而非与其他加勒比海地区的同属成员。"},{"name":"墨西哥橙拟鹂","english_name":"Orange Oriole","scientific_name":"Icterus auratus","overview":"墨西哥橙拟鹂（英文名：Orange Oriole，学名：Icterus auratus），是雀形目拟鹂科拟鹂属的鸟类。色彩鲜明的小型鸟类，以橙色羽毛著称。主要分布于墨西哥东南部的尤卡坦半岛，包括穆赫雷斯岛和科苏梅尔岛，以及伯利兹东北极端地区。","appearance":"成年雄性橙拟鹂具有黑色眼纹和黑色中喉条纹延伸至上胸，头部和身体呈现鲜艳的橙色，背部和腹部橙黄色，肩羽黑色，边缘橙色；翅膀黑色，次级飞羽和三级飞羽边缘白色形成小白色斑块；尾巴黑色，端部模糊灰色；虹膜深棕色；喙笔直，黑色，下颚基部蓝灰色；腿蓝灰色。雌鸟较雄鸟颜色暗淡，橙黄色带有橄榄色，有时背部有条纹。幼鸟似雌鸟，但橄榄色更浓，尾巴橄榄色而非黑色。","call":"鸣声为缓慢交替的上升和下降哨音序列，也发出快速的“chuchuchuchu”。常见叫声为鼻音的“nyeek”。","habits":"栖息于森林、灌木林地、森林边缘和半开放地带，常见于本土树木Talisia olivaeformis的果实上觅食，偶尔也在药用树Metopium brownie的果实上觅食。觅食时会单独或成对活动，常与其他拟鹂共同觅食。","breeding":"繁殖季节为7月，它们在20至35个巢组成的群体中繁殖，每棵树可能有高达5个巢。巢由黑黄纤维构成，直径7.5厘米，深12.5厘米，位于树上或靠近自然水坑。","identification":"雄性橙拟鹂与本地的兜帽拟鹂相比，背部为橙色，两性都有笔直的喙（而非稍向下弯曲），并且面部和喉咙的黑色面罩比兜帽拟鹂少。雌鸟和幼鸟颜色较暗淡。","protection":"IUCN：LC（无危）","distribution":"分布于墨西哥东南部（尤卡坦半岛南至卡门南部），以及伯利兹东北极端地区；同时出现在穆赫雷斯岛和科苏梅尔岛。","other":"根据鸟类世界数据库，由于该物种仅在墨西哥东南部发现，建议其名为“尤卡坦拟鹂”。"},{"name":"橙拟鹂","english_name":"Altamira Oriole","scientific_name":"Icterus gularis","overview":"橙拟鹂（英文名：Altamira Oriole，学名：Icterus gularis），是雀形目拟鹂科拟鹂属的鸟类。以橙色头部和腹部、黑色背部和眼罩为特征。广泛分布于墨西哥湾沿岸的亚热带低地、北中美洲太平洋海岸及内陆，自1939年起在美国南部德克萨斯州也有记录。该鸟种为永久居民，两性外观相似。","appearance":"橙拟鹂体型大，总长21-25厘米，体重约56克，是最庞大的Icterus属拟鹂。其特征鲜明，拥有厚实的黑色喙，仅基部呈蓝灰色。成年个体除黑色的眼罩、喉部、上背部和肩胛骨外，全身鲜亮的橙色。尾羽黑色，翼部主要为黑色，带有橙色小覆羽，宽大的白色翼斑位于大覆羽上，外侧主羽基部白色。幼鸟色泽较淡，背部、翅膀和尾巴橄榄棕色，头部和下体黄色，眼罩暗色，初级飞羽基部可见白色，缺乏黑色领巾状斑纹。与巾冠拟鹂相比，橙拟鹂更大更壮，肩部橙色斑块明显，喙更厚。","call":"鸣唱是一系列清晰、缓慢的音乐性哨音，与其他许多拟鹂相似，但节奏更慢，模式更为从容、均匀。此外，还发出尖锐的哨音、嘶哑的叽喳声和鼻音的\"ike\"声。","habits":"生活在半干旱地带，散落树木之间，开放的河岸林木环境。独居筑巢，巢间距平均约为250米。它们的巢呈细长编织袋状，悬挂于水平树枝末端，有时甚至悬挂在电话线上。觅食于树冠层，偶尔降至灌木层甚至地面。食物主要包括昆虫和浆果。","breeding":"繁殖季节在德克萨斯州从4月末持续到7月末。巢穴类似小型口袋，由苔藓、草、棕榈纤维、杂草、树皮条编织而成，内部铺垫羽毛，可能由雌鸟单独构建。每窝产卵4-6枚，雏鸟由双亲共同喂养和照顾。","identification":"与巾冠拟鹂和条背拟鹂相比，橙拟鹂体型更大，色彩更偏向红橙色，翼部白色更多，背部橙色带暗纹。幼鸟通过体型较大和喙部厚实来与其他德州地区的年轻拟鹂相区分。","protection":"IUCN：LC（无危）","distribution":"分布于北美和中美洲，从美国南部德克萨斯州至洪都拉斯，主要繁殖区域在墨西哥湾沿岸亚热带低地、北中美洲太平洋海岸及内陆。","other":"已确认存在六个亚种，但只有tamaulipensis亚种出现在美国境内。亚种间差异微小，主要体现在体型、翼部白色程度和橙色鲜艳度上。"},{"name":"黄拟鹂","english_name":"Yellow Oriole","scientific_name":"Icterus nigrogularis","overview":"黄拟鹂（英文名：Yellow Oriole，学名：Icterus nigrogularis），是雀形目拟鹂科拟鹂属的鸟类。在委内瑞拉被称为gonzalito，生活在南美洲北部低地。主要栖息于开阔的林地、灌木丛和花园中，广泛分布于哥伦比亚、委内瑞拉、特立尼达、圭亚那和巴西的部分地区。","appearance":"黄拟鹂体长20-21厘米，体重约38克，全身以黄色为主，如其名所示。成年雄鸟具有黑色的眼罩、细黑喉线、黑色尾羽和翅膀，翼上有一条白色翼带，部分飞羽边缘呈白色。雌鸟外观相似，但色彩略显暗淡，而幼鸟背部泛橄榄绿黄，面部缺乏黑色标记。","call":"黄拟鹂的鸣唱悦耳动听，旋律悠扬，伴有轻微的嗡嗡声。其叫声包括类似猫的呜咽声和叽叽喳喳的噪音。","habits":"黄拟鹂偏好开放的林地环境，如次生林、灌木丛和花园。它们主要以大型昆虫为食，但也吃花蜜和水果，如浆果、樱桃、芒果和香蕉。","breeding":"繁殖期间，黄拟鹂会建造长达40厘米的悬挂式篮状巢，悬挂在树枝末端。一般每窝产3枚淡绿色或灰色的蛋。","identification":"黄拟鹂与其它或iole物种的区别在于其黄色背部和有限的黑色眼罩及喉部。雄鸟拥有明显的黑色标记，而雌鸟和幼鸟的色彩较淡。","protection":"IUCN：LC（无危）","distribution":"黄拟鹂繁殖于南美洲北部，包括哥伦比亚、委内瑞拉、特立尼达岛、圭亚那以及巴西的罗赖马州北部和阿马帕州东部。","other":"四个亚种中，三个亚种仅限于岛屿，与大陆种群在体型、喙大小和羽毛细节上有所不同。"},{"name":"布氏拟鹂","english_name":"Bullock's Oriole","scientific_name":"Icterus bullockii","overview":"布氏拟鹂（英文名：Bullock's Oriole，学名：Icterus bullockii），是雀形目拟鹂科拟鹂属的鸟类。属于新世界黑鸟科，广泛分布于北美西部的鸟类，冬季迁徙至墨西哥全境。成年雄鸟拥有鲜明的橙黄色头部与黑色眼线，雌鸟整体较灰暗，腹部偏灰，头部、胸部和尾部呈黄色或淡绿色。该物种曾与橙腹拟鹂被视作北方拟鹂的同一物种，但基于繁殖习性、换羽周期和遗传差异，现已确认为独立物种。","appearance":"布氏拟鹂的雄鸟个体体长约17.2至19.3厘米，体重29至43克，雌鸟稍小。雄鸟具有对比强烈的橙色与黑色羽毛，头部、胸腹及脸部橙黄，背部、翅膀和尾部黑色，翼上有白色斑块，尾端外侧三至四枚尾羽尖端橙色。雌鸟上体灰褐色，下体淡黄色至灰绿色，喉部可能带有黑色斑点。幼鸟类似雌鸟，但颜色更鲜艳，喉部通常无黑色羽毛。","call":"布氏拟鹂的鸣声与橙腹拟鹂相似，但音调更快且略显粗糙。","habits":"栖息于开阔林地，尤其是沿河棉木、梧桐和柳树林，冬季适应各种林地环境。夏季以节肢动物为主食，辅以成熟水果。雌鸟会访问含花蜜和水果的喂食器。","breeding":"季节性一夫一妻制，繁殖期从五月持续到七月。巢由植物纤维编织而成，呈深垂篮状，雌鸟承担主要筑巢工作。每巢产卵三至六枚。双亲共同育雏并保护巢穴。","identification":"与橙腹拟鹂相比，布氏拟鹂脸部色彩更为鲜艳，而非胸部。雌鸟与橙腹拟鹂雌鸟区分困难，但布氏拟鹂翼上的白色覆羽边缘更加锯齿状，且下体色彩更淡。","protection":"IUCN：LC（无危）","distribution":"繁殖于加拿大西南部至美国西部直至墨西哥北部，冬季迁徙至墨西哥至尼加拉瓜。","other":"与橙腹拟鹂在大平原地区频繁杂交，曾一度被视为单一物种。"},{"name":"红头拟鹂","english_name":"Streak-backed Oriole","scientific_name":"Icterus pustulatus","overview":"红头拟鹂（英文名：Streak-backed Oriole，学名：Icterus pustulatus），是雀形目拟鹂科拟鹂属的鸟类。在中美洲热带低地和沿海山丘最为常见，沿墨西哥太平洋海岸和中美洲分布，偶尔出现在美国西南部。红头拟鹂以橙黑相间的羽毛著称，雄鸟头部和胸部深橙色，与黑色面部和上胸形成鲜明对比。雌鸟颜色稍淡，两性均具有黑色喉部斑块。","appearance":"雄鸟平均重43.1克，雌鸟平均重34.6克，长度19-21厘米。雄鸟头部和胸部橙色至深橙色，上体橙色带黑色条纹，尾羽黑色，翼上有白色边缘，下体橙色到橙黄色。雌鸟相似但色彩较淡。幼鸟颜色暗淡，背部条纹模糊，下体脏黄色。","call":"鸣唱主要是一系列旋律性的口哨声，有时包含不和谐的“churr”音符。常见叫声包括叽叽喳喳和尖锐的“chit”。","habits":"栖息于林冠边缘、落叶林、沼泽、灌木丛和村庄。海拔高度从低地到约500米，某些亚种可达2000米。以昆虫、节肢动物、花蜜和果实为食。通常成对或家庭群活动。","breeding":"繁殖季节为5月至7月，筑悬吊袋状巢，长25-50厘米，由植物纤维和真菌根丝构成，通常位于树高处。每窝产卵3-4枚，孵化期12-14天，雏鸟期约14天。巢常被寄生。","identification":"与巾冠拟鹂相比，红头拟鹂体型更壮，尾部更短，喙更直，翼羽白边更多，背部条纹变化大。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲，包括哥斯达黎加、尼加拉瓜、洪都拉斯、萨尔瓦多、危地马拉、墨西哥，偶尔访问美国西南部。","other":"红头拟鹂的某些亚种因其独特的颜色和地理隔离而值得注意。"},{"name":"黑背拟鹂","english_name":"Black-backed Oriole","scientific_name":"Icterus abeillei","overview":"黑背拟鹂（英文名：Black-backed Oriole，学名：Icterus abeillei），是雀形目拟鹂科拟鹂属的独特鸟类，为墨西哥中部特有种。以橙黑色的羽毛著称，其雄鸟的黄色和橙色羽毛鲜明，与其它拟鹂形成鲜明对比。雌鸟与布氏拟鹂雌鸟相似，但头部图案隐约可见雄鸟的痕迹。","appearance":"雄性黑背拟鹂拥有醒目的黄橙色与黑色相间的羽毛，独特的白色翼斑、黑色颈背和脸颊，以及黑色的侧腹。雌鸟与雄鸟相似，但色彩较为柔和，头部图案隐约可见雄鸟的痕迹，与布氏拟鹂雌鸟相比，展现出雄鸟头部图案的幽影。","habits":"黑背拟鹂偏爱开放的树林、种植园、高树的树篱和城镇环境，迁徙季节也会出现在山区的松栎林中。它们在树木和灌木丛的各个层次上觅食，与其他拟鹂混群活动。","identification":"雄性黑背拟鹂通过其独特的橙黑色羽毛、白色翼斑、黑色颈背和脸颊，以及黑色的侧腹与其它拟鹂区分开来。雌鸟与布氏拟鹂雌鸟相似，但头部图案的幽影是辨识的关键。","protection":"IUCN：LC（无危）","distribution":"黑背拟鹂分布在墨西哥中南部，从杜兰戈和新莱昂州向南至米却肯州和韦拉克鲁斯州西部；冬季主要沿墨西哥的横火山带南至瓦哈卡州。","other":"它是少数能食用帝王蝶的物种之一，因为它们进化出了对该蝴蝶天然毒素的耐受能力。"},{"name":"橙腹拟鹂","english_name":"Baltimore Oriole","scientific_name":"Icterus galbula","overview":"橙腹拟鹂（英文名：Baltimore Oriole，学名：Icterus galbula），是雀形目拟鹂科拟鹂属的鸟类。中等体型的拟鹂。体长17-19厘米，翼展23-30厘米。雄鸟拥有醒目的黑头黑翅黑尾，搭配鲜明的鲜橙色胸肩腹，翅膀上有一道白色横纹。雌鸟则呈现橄榄棕色的背部，头部颜色较深，下体为暗黄橙色。广泛分布于北美，从加拿大中部和东南部至美国中部和东南部，冬季迁徙至哥伦比亚和委内瑞拉等地。","appearance":"雄鸟体长可达18.8厘米，雌鸟约17厘米，体重约30-40克。雄鸟的头部、上背、翅膀和尾巴为黑色，其余部分、肩膀和尾羽外端为鲜艳的橙色，翅膀上具有一条白色横纹。雌鸟的颜色较为柔和，背部为橄榄棕色，头部颜色稍深，下体为淡橙黄色，两性均具有白色的翼斑。","call":"鸣唱为一系列甜美而清脆的哨音，通常包含上升和下降的音调，有时伴有颤音。叫声包括尖锐的‘veeer’声，低沉的叽叽喳喳声，以及高音的‘tyew-li’和‘kleek’声。","habits":"栖息于落叶林、混交林、河岸林地、果园和公园。以昆虫为主要食物，也食用浆果。在树冠层中捕食，有时会飞到空中捕捉昆虫。春季，雄鸟通过鸣唱和展示行为吸引雌鸟。","breeding":"繁殖期一般在夏季。雄鸟建立领地后，通过鸣唱和展示行为吸引雌鸟。雌鸟负责筑巢，巢呈吊篮状，位于树枝末端，由细小的植物纤维构成。每窝产卵3-7枚，平均4枚，孵化期为12-14天。双亲共同喂养幼鸟，幼鸟约两周后开始离巢。","identification":"与布氏拟鹂区别明显，后者脸部橙色更重，翅膀上有白色斑点而非单一的翼斑。雌鸟与布氏拟鹂雌鸟相似，但布氏拟鹂雌鸟腹部更灰白，耳羽更浅，与头部形成对比。","protection":"IUCN：LC（无危）","distribution":"繁殖于加拿大中部和东南部，美国中部和东南部。冬季迁徙至中美洲和南美洲北部，包括哥伦比亚和委内瑞拉。","other":"历史上，橙腹拟鹂适应了城市公园和郊区环境，成为北美最熟悉的鸣禽之一。"},{"name":"黄尾拟鹂","english_name":"Yellow-tailed Oriole","scientific_name":"Icterus mesomelas","overview":"黄尾拟鹂（英文名：Yellow-tailed Oriole，学名：Icterus mesomelas），是雀形目拟鹂科拟鹂属的色彩鲜艳的鸟类，分布于中美洲和南美洲，自墨西哥中东部至秘鲁西北部，栖息于热带湿润低地的河流沿岸和水域附近的灌丛与密林。","appearance":"成年黄尾拟鹂长约22-23厘米，体重约70克。主要呈现黄色，背部、下脸和上胸部分为黑色。翅膀黑色，带有醒目的黄色肩斑。尾巴上部黑色，两侧黄色，在飞行中尤为显眼；从下方看，几乎全为黄色。雄雌相似，幼鸟背部和尾巴上的黑色被橄榄绿色替代，颜色较为暗淡。","call":"鸣唱丰富而富有节奏感，常以旋律性的连续哨声呈现，有时以二重唱形式，雌鸟回应或与雄鸟的较长乐句重叠。","habits":"偏好栖息于沼泽低地的茂密灌木丛中，常与藤蔓、Heliconias等密集植被相伴。通常成对或小群体活动，主要食物为昆虫，也会摄取花蜜和特定果实，如gumbo-limbo（Bursera simaruba）。","breeding":"筑造深而薄的杯状巢，位于溪流旁的荆棘灌木中，高度约2米。每窝产3枚白色带暗斑的蛋，孵化期约为13天，雏鸟再过14天左右离巢。","identification":"黄尾拟鹂最显著的识别特征在于其尾部的黄色，这是该物种独有的标志。","protection":"IUCN：LC（无危）；在某些范围内数量减少，因笼鸟贸易的迫害。","distribution":"分布于中美洲至南美洲，自墨西哥中东部至秘鲁西北部，亦见于秘鲁的河谷走廊。"},{"name":"斑胸拟鹂","english_name":"Spot-breasted Oriole","scientific_name":"Icterus pectoralis","overview":"斑胸拟鹂（英文名：Spot-breasted Oriole，学名：Icterus pectoralis），是雀形目拟鹂科拟鹂属的鸟类。中等体型的鸣禽，以橙黑相间的鲜艳色彩著称。分布于中美洲太平洋沿岸低地，亦见于北部中美洲内陆及加勒比海沿岸低地的局部区域。偏好热带林地、边缘地带和半开阔地带，常栖息于有树篱和零散高树的环境。","appearance":"成年斑胸拟鹂全身呈现亮丽的橙色，具有黑色的胸前斑纹和侧胸上的黑色斑点。翅膀大部分为黑色，带有白色楔形标记于三级飞羽上。嘴部略显厚重且微向下弯曲。雌雄外观相似，但雌鸟和幼鸟背部呈橄榄绿色，翅膀较暗，面部、喉咙及胸部的黑色较少或几乎无黑色。成鸟体长约21至24厘米，雄鸟平均体重约50克，雌鸟约45克。","habits":"斑胸拟鹂常见于热带森林、湿润低地森林和重度退化前森林区域。它们在中美洲的太平洋一侧广泛分布，且在南佛罗里达州的亚特兰大海岸有引入繁殖的种群。","identification":"与其它拟鹂种类相比，斑胸拟鹂可通过其橙色主体、黑色胸前斑纹和侧胸的黑色斑点来识别。","protection":"IUCN：LC（无危）","distribution":"在中美洲，包括哥斯达黎加、萨尔瓦多、危地马拉、洪都拉斯、墨西哥和尼加拉瓜广泛分布。在南佛罗里达州亚特兰大海岸也有引入繁殖的稳定种群。"},{"name":"白翅斑拟鹂","english_name":"White-edged Oriole","scientific_name":"Icterus graceannae","overview":"白翅斑拟鹂（英文名：White-edged Oriole，学名：Icterus graceannae），是雀形目拟鹂科拟鹂属的鸟类。分布于南美的厄瓜多尔西南部和秘鲁西北部，主要栖息于亚热带或热带的干燥森林及湿润低地森林中。","appearance":"白翅斑拟鹂拥有鲜艳的橙黑相间的羽毛，其独特之处在于尾巴下方缺乏黄色，翅膀上有着更为显著的白色斑纹，通常呈现出更深的橙色。幼鸟的色彩较为暗淡，橙色不如成鸟鲜明。","habits":"白翅斑拟鹂常在树冠层活跃，甚至在某些区域会访问人类设置的喂食器。它们的栖息地多样，包括亚热带或热带的干燥和湿润森林。","identification":"在白翅斑拟鹂的分布范围内，另一种相似的鸟种是黄尾拟鹂，但白翅斑拟鹂的尾巴下方没有黄色，翅膀上的白色更多，颜色通常更深的橙色。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的太平洋沿岸，包括厄瓜多尔南部（自马纳维省以南）和秘鲁西北部（南至拉利伯塔德）。"},{"name":"草原拟鹂","english_name":"Campo Troupial","scientific_name":"Icterus jamacaii","overview":"草原拟鹂（英文名：Campo Troupial，学名：Icterus jamacaii），是雀形目拟鹂科拟鹂属的鸟类。以黑色为主调，橙色为辅，拥有醒目的橙色领环、腹部和臀部。分布于南美巴西东北部，常见于干林边缘、花园及城市公园。","appearance":"草原拟鹂是一种大型、吸引人的黑色鸟类，身长约23厘米，尾长而尖锐，喙部锋利。全身主要为黑色，但拥有鲜明的橙色领环、腹部和臀部。翼上的橙色肩斑和白色翼斑在其黑色翅膀上尤为突出。具有刺眼的黄色眼睛。","call":"其鸣唱为一系列悦耳的哨音，叫声包含粗糙的音符。","habits":"栖息于干林边缘，偏好干燥的灌木丛和落叶林，海拔可达700米以上。饮食以昆虫和其他小型无脊椎动物、果实和花蜜为主。","breeding":"繁殖期在雨季，通常在12月至3月之间。","identification":"与普通拟鹂相似，但委内瑞拉拟鹂翼上有更大的白色斑点，眼周有蓝皮肤，而草原拟鹂仅有小片白色翼斑，肩部有橙色护肩。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲巴西东北部，自马兰昂和托坎廷斯东至里奥格兰德杜诺尔特和帕拉伊巴，南至米纳斯吉拉斯，并逐渐扩散至埃斯皮里图桑托和里约热内卢。","other":"曾被认为与普通拟鹂和橙背拟鹂同种，现已被确认为独立物种。"},{"name":"普通拟鹂","english_name":"Venezuelan Troupial","scientific_name":"Icterus icterus","overview":"普通拟鹂（英文名：Venezuelan Troupial，学名：Icterus icterus），是雀形目拟鹂科拟鹂属的鸟类。委内瑞拉的国鸟，分布于哥伦比亚、委内瑞拉及加勒比海诸岛，如阿鲁巴、库拉索、博内尔、特立尼达和波多黎各。曾与橙背拟鹂和草原拟鹂共同归为Troupial这一超物种，后被区分为独立物种。","appearance":"体长23-27厘米，体重因性别和地区差异，介于58.5至88克之间。头部至颈上部及上胸黑色，颈部后方至背部、臀部和下体橙黄鲜艳，肩部黑色。翼部黑色，具白色条纹，闭合时形成明显的白色斑块，眼周有醒目的黄色虹膜和亮蓝色裸皮。喙黑，下颌基部灰，腿蓝灰色。雌雄相似，幼鸟较暗淡，具较小的灰色眼周裸皮。","call":"鸣声为响亮而悦耳的旋律，通常由2-4个元素组成，如\"troo-pear-pééá\"，元素常为颤音或调制的哨音。叫声包括鼻音和愉快的哨声。飞行时产生可听的翼音。","habits":"栖息于干燥地带，如灌木林、画廊森林、干燥灌丛、平原和开阔草原。以仙人掌果为主食，季节性食用芒果、番石榴、山榄果等水果，也会捕食小型脊椎动物和昆虫。成对或家族群觅食，有时与其他拟鹂混群。","breeding":"繁殖期从3月至12月，可能全年在阿鲁巴和库拉索繁殖。每次尝试繁殖2-3窝。单配偶制，强烈守卫领地。利用其他鸟种的旧巢或攻击巢穴驱赶原住鸟，有时会吃掉巢中的蛋和幼鸟。孵化由雌鸟承担，孵化期未知，雏鸟期21-23天，双亲共同喂养。","identification":"与巴尔的摩拟鹂的区别在于体型更大、更粗壮，胸前黑色面积更大。亚种ridgwayi体型更大，腿更强壮；metae亚种背部分隔线为黑色，翼上的白色斑块被一黑色线条分割。","protection":"IUCN：LC（无危）","distribution":"南美洲的哥伦比亚和委内瑞拉，以及加勒比海岛屿如阿鲁巴、库拉索、博内尔、特立尼达和波多黎各。","other":"在委内瑞拉，普通拟鹂被视为国家象征，出现在货币上。"},{"name":"橙背拟鹂","english_name":"Orange-backed Troupial","scientific_name":"Icterus croconotus","overview":"橙背拟鹂（英文名：Orange-backed Troupial，学名：Icterus croconotus），是雀形目拟鹂科拟鹂属的大型橙黑相间鸣禽。拥有亮丽的橙色背部，黑色面部、喉咙和上胸部，以及白色翼斑。在亚马逊盆地内，是唯一具有鲜明橙黑对比色的大体型或莺。广泛分布于南美洲东部，包括巴西、玻利维亚、秘鲁、圭亚那、巴拉圭及厄瓜多尔东部地区。","appearance":"橙背拟鹂体长约23厘米，雄鸟平均重量48克，雌鸟平均41克。头部、喉咙和上胸部黑色，冠部至颈背、颈侧、背部、腹部均为鲜艳的橙黄色，肩羽黑色；翅膀黑色，小翼羽和中翼覆羽橙黄色，内侧次级飞羽和部分三级飞羽具宽阔的白色外缘；尾巴全黑；眼睛黄色，眼周有一小圈蓝灰色裸露皮肤；喙黑色，下颚基部灰色；腿脚暗蓝灰色。幼鸟图案类似成鸟，但颜色较暗淡，缺乏橙色肩饰。严格额纹亚种比指名亚种额头黑色较少，翼部白色较多。","call":"鸣唱由两性共同发出，重复吹哨般的旋律，如“chee-chew-hwe-chew”。音节序列和音节间的停顿变化多端。伴侣间常合唱。叫声记录不多，但在秘鲁，有一种接触叫声是响亮而短暂的调制哨声，带有强烈的金属共鸣。","habits":"栖息于次生林、森林边缘、郊区，经常靠近水源。以花蜜、果实、昆虫和其他节肢动物以及小型脊椎动物为食。在查科地区，可能通过撕裂管状花朵或碾压整个花朵来掠夺Tabebuia、Cercidium和Capparis的花蜜。善于树栖，觅食时常倒挂；在查科地区，观察到它在附生凤梨科植物（Tillandsia duratii）丛中搜寻。通常成对或家庭群体觅食。","breeding":"繁殖期在哥伦比亚为7月至8月，而在玻利维亚和巴拉圭则在11月至次年3月之间。倾向于不自行筑巢，而是占用黄腰酋长鹂的巢穴。","identification":"与普通拟鹂相比，橙背拟鹂的围嘴下缘整洁，围嘴底端呈整齐而非蓬松，翼部白纹较小。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的亚马孙雨林北部、西部和西南部至阿根廷北部。具体而言，其范围涵盖从圭亚那南部、哥伦比亚南部、厄瓜多尔东部和秘鲁东部，贯穿巴西东部和中部，到达玻利维亚和巴拉圭北部。","other":"与普通拟鹂和草原拟鹂关系密切，曾一度被认为属于同一物种。"},{"name":"斑翅拟鹂","english_name":"Bar-winged Oriole","scientific_name":"Icterus maculialatus","appearance":"雄性斑翅拟鹂呈现明显的黄黑对比色，翼上有独特的白色条纹。雌鸟和幼鸟外观相似，羽色灰暗，翼部带有狭窄的白色条纹，与黑色翼部形成鲜明对比，但不如黑顶拟鹂那样对比强烈。","habits":"斑翅拟鹂偏好栖息在半落叶的橡木林和灌木丛生的环境中，常见于海拔较高的山地森林。它们会在开花和果实成熟的树木周围活动，通常与其他拟鹂一起出现，但更倾向于在遮蔽处活动。","identification":"雄性斑翅拟鹂通过其独特的黄色、黑色搭配和白色翼纹与同类区分开来。雌鸟和幼鸟则通过翼部的灰色调和窄白色条纹与黑顶拟鹂相区别，黑顶拟鹂的翼部黑色更加鲜明。","protection":"IUCN：LC（无危）","distribution":"斑翅拟鹂的分布范围涵盖墨西哥南部（东奥阿哈卡和恰帕斯州）至萨尔瓦多北部，同时也出现在洪都拉斯西南部，但其在当地的确切状态尚不明朗。"},{"name":"黑臀拟鹂","english_name":"Black-vented Oriole","scientific_name":"Icterus wagleri","overview":"黑臀拟鹂（英文名：Black-vented Oriole，学名：Icterus wagleri），是雀形目拟鹂科拟鹂属的鸟类。吸引人的或莺，分布于中美洲的墨西哥至尼加拉瓜，其自然栖息地包括亚热带或热带的干燥森林、湿润低地森林以及湿润山地森林。","appearance":"黑臀拟鹂通常成对出现，雌雄外观相似，黄色胸部带有独特的磨光橙色调。上体在翼覆住臀部时呈现全黑色，成年个体的黑色臀部是显著特征。幼鸟的外观可变，缺乏翼纹，羽毛呈橙黄调，且拥有较长而直的喙。","habits":"偏好灌木丛生的林地和半开放地带，尤其是高大的开花树木形成的树篱；太平洋沿岸可见于开花的椰子种植园。它们可能单独活动，也可能与其他或莺混群。生活于中美洲的内陆和高地，部分个体冬季会迁徙至太平洋沿岸的低地。","identification":"成年黑臀拟鹂的黑色臀部是与其他或莺区分的重要特征。幼鸟与成鸟相比，缺乏翼纹，羽毛颜色更偏向橙黄，喙型较直且长。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲，包括墨西哥至尼加拉瓜的繁殖区域。在美国的分布情况未提及。"},{"name":"巾冠拟鹂","english_name":"Hooded Oriole","scientific_name":"Icterus cucullatus","overview":"巾冠拟鹂（英文名：Hooded Oriole，学名：Icterus cucullatus），是雀形目拟鹂科拟鹂属的鸟类。以橙色头部、黑色面罩和喉咙为显著特征，分布于美国西南部、墨西哥和伯利兹的开放林地和灌木丛中。成年雄鸟橙色鲜艳，雌鸟橄榄绿和黄色相间。","appearance":"巾冠拟鹂体长约18至20厘米，体重约24克。雄鸟头部、颈背、臀部和下体橙色至橙黄色，具黑色面罩和喉咙；雌鸟头、臀和下体橄榄黄色，上体灰橄榄色，两翼具两道白色翼斑。雌雄差异显著，幼鸟似雌鸟，但雄鸟幼鸟喉部黑色。","call":"鸣声为短促尖锐的哨音和‘wheet’声，歌声混杂，包含急促的音符，有时带鼻音和哀怨的音质。","habits":"栖息于开放的树林和灌木丛，偏好棕榈树。春季迁徙至北美南部繁殖，冬季南迁至墨西哥西南部海岸，部分在巴哈加州南部和墨西哥东海岸以及伯利兹为留鸟。以昆虫、花蜜和水果为主食，常访问花蜜喂食器。","breeding":"繁殖季节为春季至夏季，雄鸟先到达繁殖地建立领地。巢为编织结构，深篮状，通常挂在树下或叶底，由雌鸟建造，使用草、棕榈或丝兰纤维。每窝产卵3至5枚，孵化期12至14天，雏鸟约14天离巢。","identification":"与圃拟鹂相似，但可通过更长、更弯曲的喙以及较明亮的橙色和白色翼斑来区分。雄鸟幼鸟和雌鸟外观近似，但雄鸟幼鸟具有黑色喉部。","protection":"IUCN：LC（无危）","distribution":"繁殖于美国西南部，包括得克萨斯州至加利福尼亚州，以及墨西哥北部。非繁殖季节迁徙至墨西哥西南部海岸，巴哈加州南部，墨西哥东海岸，以及伯利兹。","other":"适应了人类居住区，常见于公园和居民区的棕榈树中。"},{"name":"黑顶拟鹂","english_name":"Black-cowled Oriole","scientific_name":"Icterus prosthemelas","overview":"黑顶拟鹂（英文名：Black-cowled Oriole，学名：Icterus prosthemelas），是雀形目拟鹂科拟鹂属的鸟类。中等体型的鸟类，广泛分布于中美洲的热带低地和丘陵地带，自墨西哥南部延伸至巴拿马西部。以其鲜明的黑黄两色羽毛著称，雄鸟具有黑色头部和背部，腹部黄色，而雌鸟的颜色则随地理位置变化。","appearance":"黑顶拟鹂体长18.5至21厘米，雄鸟重约32.5克，雌鸟稍轻，平均27.5克。雄鸟拥有黑色的头部、背部以及亮黄色的肩部、臀部和翼下覆羽。腹部、大腿和臀部全为黄色，胸腹部有一条狭窄的栗色带。雌鸟面部、喉咙和上胸部黑色，头顶和上体橄榄黄色。幼鸟呈淡黄橄榄色，背部羽毛基部黑色，脸部、额头和喉部呈哑光黑色。","call":"其鸣声为一系列复杂而柔和的哨音和较刺耳的叽喳声，包括刮擦的上升音、鼻音、深沉的鼻音、安静的呼噜声和尖锐的啼叫。","habits":"黑顶拟鹂栖息于湿润或半湿润森林，偏好沿水道的开放林地和种植园，尤其是香蕉种植园，常与棕榈树相伴。它们通常成对或小群体活动，偶尔混群于多种鸟类群中，以昆虫、果实和花蜜为食。","breeding":"繁殖季节在哥斯达黎加为3月至7月，可能实行一夫一妻制。巢呈浅篮状，由暗色和浅色纤维制成，悬挂在大叶植物的叶片下，或利用房屋檐下固定。每窝产卵3枚，白色底带褐色斑点，父母共同筑巢、孵卵和喂养幼鸟。","identification":"与黄尾拟鹂和幼年圃拟鹂相似，但可通过全黑尾巴和无翼杠区别开来。与黑臀拟鹂的区别在于后者体型更大，尾更长，且生活在干燥高地。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲东部，从墨西哥南部到巴拿马西部，主要在海拔500米以下的热带低地和丘陵，偶尔扩展至哥斯达黎加的太平洋斜坡。","other":"21世纪初，黑顶拟鹂的分布范围扩展到了哥斯达黎加的太平洋斜坡，有时在中央和南部低地也有零星报道。"},{"name":"圃拟鹂","english_name":"Orchard Oriole","scientific_name":"Icterus spurius","overview":"圃拟鹂（英文名：Orchard Oriole，学名：Icterus spurius），是雀形目拟鹂科拟鹂属的鸟类。北美最小的拟鹂科鸟类，体长约15厘米。分布广泛，自加拿大东南部至墨西哥中部和东部，其墨西哥加勒比海岸的fuertesi亚种现被视为独立物种，称为赭拟鹂。","appearance":"成年雄鸟呈独特的深栗色胸腹部，头和上背部黑色，翼下覆羽有栗色斑块。雌鸟和幼鸟上体橄榄绿色，下体黄绿色，具两道白色翼纹，无头部黑色。一岁雄鸟类似雌鸟，但喉部黑色。","habits":"栖息于半开放地带的落叶树林，偏好湖泊和河流附近的树荫环境。繁殖季节在春季，夜间迁徙，饮食随季节变化，以昆虫、蜘蛛为主，冬季加入果实、花蜜和种子。","breeding":"繁殖期夏季，筑巢于水平树枝上的紧密编织袋状巢，巢间距离较近。通常在春季抵达繁殖地，夏季结束前离开。","identification":"雄鸟与雌鸟色彩差异显著，与同属其他种类如斯氏拟鹂和巾冠拟鹂在色彩和体型上有明显区别。","protection":"IUCN：LC（无危）","distribution":"繁殖区域包括北美东部至墨西哥中部和东部。冬季迁徙至墨西哥沿海低地至北哥伦比亚和西北委内瑞拉。"},{"name":"赭拟鹂","english_name":"Ochre Oriole","scientific_name":"Icterus fuertesi","overview":"赭拟鹂（英文名：Ochre Oriole，学名：Icterus fuertesi），是雀形目拟鹂科拟鹂属的鸟类。原作为圃拟鹂的一个亚种，现已提升为独立物种。分布于墨西哥的加勒比海岸，以其独特的赭色羽毛和较小体型著称。","appearance":"赭拟鹂是一种小型鸟类，长度约5.9至7.1英寸，重量介于0.6至1.0盎司之间，翼展可达9.8英寸。成年雄鸟的下体、肩部和臀部呈栗色或赭色，其余羽毛为黑色。成年雌鸟和幼鸟上体为橄榄绿色，胸部和腹部呈淡黄色。所有成年个体都有尖锐的喙和白色翼带。","habits":"它们栖息在北美东部、塔毛利帕斯南部和韦拉克鲁斯的半开放地带，偏好有落叶树的环境。冬季，它们的分布范围从锡那罗亚中部和韦拉克鲁斯南部延伸到哥伦比亚北部和委内瑞拉西北部。这些鸟类是夜间迁徙者，以昆虫、蜘蛛、果实、花蜜和种子为食，食谱随季节变化。","breeding":"繁殖期，赭拟鹂在公园湖泊和溪流旁的遮荫树上筑巢，巢为紧密编织的袋状结构，挂在水平树枝的分叉处。通常，它们在3月和4月离开冬栖地，于4月底至5月底抵达繁殖地。7月底至8月初离开繁殖领地，8月中旬到达冬栖地。","identification":"赭拟鹂与圃拟鹂的区别在于其赭色的下体，而圃拟鹂的雄鸟下体为栗色。此外，赭拟鹂的分布区域主要限于墨西哥的加勒比海岸。","protection":"IUCN：LC（无危）","distribution":"繁殖区域主要集中在墨西哥的加勒比海岸，包括塔毛利帕斯南部和韦拉克鲁斯。冬季分布于锡那罗亚中部、韦拉克鲁斯南部至哥伦比亚北部和委内瑞拉西北部。"},{"name":"古巴拟鹂","english_name":"Cuban Oriole","scientific_name":"Icterus melanopsis","overview":"古巴拟鹂（英文名：Cuban Oriole，学名：Icterus melanopsis），是雀形目拟鹂科拟鹂属的鸟类。主要分布于古巴主岛、青年岛及周边一些小岛。其显著特征为黑色体羽搭配黄色臀部和肩部，成鸟和幼鸟在颜色上有明显差异。","appearance":"成年古巴拟鹂全身主要为黑色，黄色仅出现在臀部、肩部以及翼下覆羽。雄鸟和雌鸟外观相似。幼鸟呈橄榄绿色，喉部和脸部为黑色，腹部和肛周区域更偏黄绿色。喙部上颌黑色，下颌蓝灰色。","call":"叫声包括吹哨般的‘tsee-tsoo’和‘pit-see-ee-oo’，以及响亮的吱吱声‘spwit’。完整的鸣唱是由一系列上扬和下滑的哨音组成。","habits":"古巴拟鹂栖息于森林、农田带树的环境和公园，偏好有棕榈树的区域。它们会到花园和公园中寻找花朵和果实。以昆虫、软果和花蜜为食，偶尔会从花底取食而不参与授粉。","breeding":"繁殖期从2月持续至7月，古巴拟鹂会建造类似篮子的悬挂巢，通常由棕榈和香蕉树叶材料构成。每窝产三枚绿色带有灰或橄榄色斑点的蛋。成鸟可能终生产一夫一妻制。","identification":"成年古巴拟鹂的黑色体羽和黄色臀部使其容易识别，幼鸟的橄榄绿色和黑色面部特征有助于与成鸟区分开。与其他大安的列斯群岛的拟鹂相比，古巴拟鹂的下体黑色更多，黄色仅限于腿部羽毛、翼下覆羽和臀部。","protection":"IUCN：LC（无危）","distribution":"古巴拟鹂广泛分布于古巴主岛、青年岛及周边的一些小岛。","other":"直到最近，古巴拟鹂还被归类为大安的列斯群岛拟鹂的亚种之一，现在则被视为独立物种。"},{"name":"巴哈马拟鹂","english_name":"Bahama Oriole","scientific_name":"Icterus northropi","overview":"巴哈马拟鹂（英文名：Bahama Oriole，学名：Icterus northropi），是雀形目拟鹂科拟鹂属的鸟类。热带拟鹂，原生于巴哈马群岛的安德罗斯岛和阿巴科岛。四大安的列斯群岛拟鹂之一，也是其中最为稀少的物种。据 IUCN 已被列为“极危”物种。","appearance":"巴哈马拟鹂外观优雅，主要栖息于树木繁茂地带，偶尔会出现在花园和公园中寻找花蜜和果实，偏好有棕榈树的环境。成鸟特征鲜明，背部、头部和胸部为深黑色，与明亮的黄色至橙黄色腹部、臀部和肩部形成强烈对比。幼鸟呈现黄绿色至橙黄色，有时带有凌乱的黑色胡须状羽毛，但其亮黄色的肩部是一大特征。雌鸟和幼年果园拟鹂相似，体型较小，缺乏鲜艳的肩部色彩。","call":"其鸣唱由起伏的哨音组成，声音悠扬，上下起伏。叫声包括清脆的‘suh-wee-eee’、快速的‘pwi’或‘pwit-pwit’，以及沙哑的‘weet’。","habits":"巴哈马拟鹂历史上仅分布于巴哈马群岛中的安德罗斯岛和阿巴科岛，但在1990年代已从阿巴科岛消失。目前仅在安德罗斯岛上的三个主要岛屿北安德罗斯、红树林岛和南安德罗斯被发现。它们的栖息地包括人类居住区，尤其是在靠近海岸的开发地区，经常利用引进的椰子树作为筑巢场所。此外，它们也会在松林和阔叶林中活动，利用灌木层的棕榈树作为筑巢点。","breeding":"关于巴哈马拟鹂的繁殖信息有限，但已知它们在开发地区筑巢，使用引入的椰子树。最近的研究发现它们也在松树林中筑巢，选择白皮棕榈Leucothrinax morrisii和本地加勒比松作为巢址。此外，它们还被观察到在其他本土棕榈树、香蕉树等树种中筑巢。","identification":"巴哈马拟鹂与古巴拟鹂、波多黎各拟鹂和海地拟鹂类似，但可以通过其更广泛的黄色下体来区分，黑色部分仅延伸至胸部。","protection":"IUCN：EN（濒危）","distribution":"巴哈马拟鹂目前仅分布于安德罗斯岛的北安德罗斯、红树林岛和南安德罗斯。在阿巴科岛已灭绝。","other":"巴哈马拟鹂的非繁殖季节栖息地未知，确切数量估计模糊。"},{"name":"马提拟鹂","english_name":"Martinique Oriole","scientific_name":"Icterus bonana","overview":"马提拟鹂（英文名：Martinique Oriole，学名：Icterus bonana），是雀形目拟鹂科拟鹂属的鸟类。独特而鲜艳的鸟类，以其黑色背部、棕色头罩和橙红色腹部著称。主要栖息于从海岸到山区的森林树冠层，也可见于种植园和花园中，以昆虫、果实和花朵为食。","appearance":"马提拟鹂拥有显著的黑褐色背部和翅膀，头部呈棕色，下体和肩部呈现烧橙色，成年鸟体长约18至21厘米。雄鸟的颜色比雌鸟更为鲜艳。幼鸟的羽毛颜色可能较为柔和，随成长逐渐变得鲜明。","call":"其叫声包括清晰的哨音和尖锐的叫声。","habits":"栖息于多种生境，包括亚热带或热带干燥森林、湿润低地森林、红树林和种植园。偏好与高度城市化社区保持距离，通常单独或成对觅食，有时也会与家庭成员群居。食物来源广泛，包括树冠中的果实、浆果和各种昆虫。","breeding":"繁殖季节一般在2月至7月之间，但在特定条件下，如适宜的环境，也可能在12月进行繁殖。它们会将巢筑在宽叶植物如香蕉树、棕榈或Heliconia的叶片下方，每次产卵两枚，偶尔三枚。","identification":"在分布范围内无类似物种，独特的羽毛色彩组合使其易于识别。","protection":"IUCN：VU（易危）","distribution":"仅限于北美地区的马提尼克岛（法属西印度群岛的一部分）。","other":"近年来，由于森林砍伐导致了紫辉牛鹂的入侵，这种寄生鸟每年寄生75%的马提拟鹂巢穴，对种群造成了威胁。然而，近期闪亮牛鸟数量的减少使马提拟鹂得以轻微恢复。"},{"name":"波多黎各拟鹂","english_name":"Puerto Rican Oriole","scientific_name":"Icterus portoricensis","overview":"波多黎各拟鹂（英文名：Puerto Rican Oriole，学名：Icterus portoricensis），是雀形目拟鹂科拟鹂属的鸟类。是北美特有种，常见于波多黎各的森林边缘、多种类型的林地、棕榈林、公园及花园。成鸟以独特的全黑羽色为特征，仅腹部、臀部及肩部呈黄色，无相似物种与其共存于同一区域。","appearance":"波多黎各拟鹂长约22厘米，雄鸟体重介于37.2至44.9克，雌鸟体重34至38.9克。其羽毛大部分为黑色，具有黄色的下背、臀部、较小和中等的上翼覆羽（形成肩章）、下腹和大腿；上尾覆羽和后下尾覆羽黑色，带黄色尖端；虹膜深棕色；喙黑色；腿灰色。两性相似，幼鸟上体橄榄绿，头部略带红色调，下体主要为暗淡的黄色，胸膛带有锈色痕迹。","call":"其歌声持续约2秒，是一系列高音的上升和下降的哨声，混杂着嗡嗡声和颤音。常见的叫声是刺耳的‘chk’。","habits":"波多黎各拟鹂居住在多种类型的森林边缘和林地中，也见于棕榈林、公园和花园。它们主要以昆虫和其他节肢动物、小型脊椎动物、果实和花蜜为食。通常成对或家庭群出现，觅食时主要在树上，从树叶和附生植物中捕获食物。","breeding":"繁殖季节为3月至6月，可能实行一夫一妻制。巢由雌鸟单独建造，大小和复杂程度不一，通常固定在棕榈叶下或Heliconia或香蕉叶中。巢中有2至3枚蛋，颜色从白色到浅蓝白色，带有稀疏的灰色和棕色斑点，平均尺寸为24.1×17.5毫米；孵化仅由雌鸟承担，但缺乏关于孵化期的信息；双亲共同喂养雏鸟，雏鸟期约为14天；雄鸟守卫并保护巢穴。巢穴常被紫辉牛鹂寄生，研究显示几乎所有的沿海巢穴受到寄生，而内陆地区的28个巢穴中，11个（39%）未受寄生影响。","identification":"波多黎各拟鹂的辨识特征在于其独特的全黑羽色，仅腹部、臀部及肩部呈现黄色，幼鸟的橄榄绿色上体和暗淡的黄色下体。无相似物种在其分布范围内。","protection":"IUCN：LC（无危）","distribution":"波多黎各拟鹂仅分布于波多黎各，包括其森林边缘、林地、棕榈林、公园和花园。","other":"波多黎各拟鹂即使在受人类影响的环境中也能保持常见至较常见的状态。"},{"name":"蒙岛拟鹂","english_name":"Montserrat Oriole","scientific_name":"Icterus oberi","overview":"蒙岛拟鹂（英文名：Montserrat Oriole，学名：Icterus oberi），是雀形目拟鹂科拟鹂属的鸟类。中等体型的黑黄相间的新世界拟鹂科鸟类，仅存于加勒比海小安的列斯群岛中的蒙特塞拉特岛，这里是它的唯一家园。作为英国海外领土的国鸟，面临着栖息地丧失的威胁，曾被列为极度濒危物种。其数量估计在200至800只之间，受自然灾害如飓风和火山活动影响严重。","appearance":"雄鸟拥有黑色的头部、胸部和背部，与黄色的腹部和臀部形成鲜明对比；雌鸟则是上体暗绿带黄，下体淡黄色。两性均具有细长的身体和中等大小、三角形的喙。幼鸟外观与雌鸟相似，但整体色彩较暗淡。雄鸟的过渡期可见眼周和面部明显的黑色羽毛。","call":"鸣唱由一系列响亮、间隔开的哨声组成，而接触和警报叫声则是刺耳的‘chuck’音。","habits":"蒙岛拟鹂栖息于中湿到湿润的热带森林，主要以昆虫和果实为食，活动范围受限于岛上的两个区域：Centre Hills和South Soufriere Hills。它们在林冠层活动，利用长而尖锐的喙捕食昆虫。","breeding":"繁殖期不详，但一般认为在一年龄时开始繁殖。巢呈浅篮状，悬挂在森林中的Heliconia叶子下。每窝通常产两枚带有斑点的蛋。","identification":"在蒙特塞拉特岛上没有类似的物种。与偶尔出现的圃拟鹂和橙腹拟鹂的区别在于后者具有浅色的翼条。","protection":"IUCN：VU（易危）","distribution":"北美：蒙特塞拉特，具体在Centre Hills（1110公顷）和South Soufriere Hills（250公顷）。","other":"蒙岛拟鹂是加勒比海Icterus属中唯一显示显著性别羽色差异的物种。"},{"name":"圣卢拟鹂","english_name":"St. Lucia Oriole","scientific_name":"Icterus laudabilis","overview":"圣卢拟鹂（英文名：St. Lucia Oriole，学名：Icterus laudabilis），是雀形目拟鹂科拟鹂属的鸟类。生活在木林地带，尤其是带有棕榈树区域的优雅鸟种。雄鸟个体以黑色为主，腹部、肩部和臀部呈现橙色，而雌鸟色彩较暗淡，幼鸟整体呈黄绿色。其全球范围内无相似物种。该鸟种在全球分布极为有限，数量估计在1000至2500只成熟个体之间，实际数量可能更接近下限。","appearance":"雄性圣卢拟鹂身披黑色羽毛，腹部、肩部及臀部呈现鲜明的橙色。雌鸟色彩相对暗淡，而幼鸟整体颜色为黄绿色，整体外观较为朴素。","call":"鸣唱为快速的哨音和尖叫声交织，叫声则为粗糙的‘zzzhe’声。","habits":"偏好居住在带有棕榈树的木林地带，具体生活习性不详。","breeding":"繁殖习性未详述，但面临生境丧失、杀虫剂喷洒和寄生现象的挑战，后者有时高达75%的巢穴被寄生，然而这种现象对当前种群的影响未知。","identification":"在它的分布范围内，没有其他类似物种存在，辨识相对容易。","protection":"IUCN：EN（濒危）","distribution":"仅分布于北美地区的圣卢西亚岛，是该岛特有的鸟种。","other":"自1930年代以来，数量有所减少且分布更加局部化，可能与生境丧失、农药使用和寄生现象有关。"},{"name":"海地拟鹂","english_name":"Hispaniolan Oriole","scientific_name":"Icterus dominicensis","overview":"海地拟鹂（英文名：Hispaniolan Oriole，学名：Icterus dominicensis），是雀形目拟鹂科拟鹂属的鸟类。主要栖息在海地和多米尼加共和国的希斯帕尼奥拉岛上。这种鸟以黑色为主，肩部、臀部和下腹部点缀着黄色斑块，成鸟的这一特征尤为明显，使其在同类中独树一帜。偏好森林地带，尤其是有棕榈树的环境。","appearance":"海地拟鹂体长约20至22厘米，雄鸟体重35至38克，雌鸟略重，约33至40克。雄鸟头部至背部、腹部及上侧腹为黑色，臀部和上覆羽呈黄色；翅膀和尾巴黑色，小翼羽和中翼羽处有黄色斑点（类似肩章），翼弯处也有黄色斑块；下腹部、大腿及后侧腹黄色；虹膜棕色；喙黑色；腿深蓝灰色。雌鸟外观与雄鸟相似，但色彩较暗淡。幼鸟上半身橄榄绿色，头部至胸部和背部带栗色，翅膀黑色，多数羽毛边缘橄榄绿，中翼羽宽端黄色，下半身自胸以下绿色泛黄。","call":"鸣唱为一系列高音口哨声，常见叫声包括尖锐的‘kt’和刺耳的‘chrr’。","habits":"海地拟鹂常在热带和亚热带森林、林缘、灌木丛及花园中活动，偏好有棕榈树的区域。它们全年留居在希斯帕尼奥拉岛上，饮食以节肢动物、花蜜和水果为主，偶尔会在密集植被中觅食，有时会倒挂取食。","breeding":"繁殖季节为3月至6月，筑巢于棕榈叶或香蕉叶下侧，巢由植物纤维编织而成，内部铺有棉絮状材料，通常产卵3至4枚，白色或浅蓝白色，带有红褐色斑点，雏鸟主要喂食昆虫和蜘蛛，辅以果肉。","identification":"与巴哈马拟鹂相比，海地拟鹂显示更多的黄色。幼鸟与成鸟颜色差异明显，与成年鸟相比，幼鸟上半身主要为橄榄色，下身淡黄色。成鸟与幼鸟在颜色上有显著区别。","protection":"IUCN：LC（无危）","distribution":"海地拟鹂主要分布在希斯帕尼奥拉岛（包括海地和多米尼加共和国）以及附近的托图加、戈纳夫、Î-à-Vache和萨奥纳等岛屿。","other":"海地拟鹂曾被视为独立物种，但在1936年被归入更大的分类中。"},{"name":"橙冠拟鹂","english_name":"Orange-crowned Oriole","scientific_name":"Icterus auricapillus","overview":"橙冠拟鹂（英文名：Orange-crowned Oriole，学名：Icterus auricapillus），是雀形目拟鹂科拟鹂属的美丽鸟类。其特征为黑橙相间的羽色，分布于巴拿马东部至哥伦比亚北部和委内瑞拉北部的地区。","appearance":"成年橙冠拟鹂长约18厘米，雄鸟平均重33.1克，雌鸟平均重32克。前额、眼周、面颊、喉部及胸部黑色，头顶、颈侧及头部侧面橙红色；背部上半部黑色，下半部及臀部黄色，最末端尾上覆羽黑色，边缘带窄黄边，尾羽全黑；上翅黑色，小覆羽和中覆羽黄色；下体自胸以下黄色；虹膜棕色；喙黑色；腿灰色。两性相似。幼鸟比成鸟颜色更淡，面部橙黄色，头顶及背部橄榄色，臀部泛黄，翅膀及尾部灰褐色，大覆羽尖端黄绿色，喉部及下体浅黄色，胸部略带绿意；亚成鸟似成鸟，但色泽较暗淡。","call":"其歌声为吹哨式的四音符短语，常重复播放。常见叫声为尖锐的‘cheet’声。可能模仿其他鸟类的叫声。","habits":"以昆虫和其他节肢动物为主食，也会食用果实和花蜜。常光顾Erythrina poepiggiana等开花树木，也会访问Bauhinia等花卉。在树冠层觅食。通常成对或小家庭群活动；在哥伦比亚，会与其他拟鹂如橙腹拟鹂混群。","identification":"橙冠拟鹂以其独特的黑橙配色及头部的橙红冠区别于其他拟鹂。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲的巴拿马东部，南美洲的哥伦比亚北部至委内瑞拉北部，具体包括巴拿马省和达连省向东，哥伦比亚南部至Huila和Meta北部，委内瑞拉东部至Sucre和Monagas，南部至Bolívar北部。"},{"name":"杂色黑拟鹂","english_name":"Variable Oriole","scientific_name":"Icterus pyrrhopterus","overview":"杂色黑拟鹂（英文名：Variable Oriole，学名：Icterus pyrrhopterus），是雀形目拟鹂科拟鹂属的鸟类。具有显著变异性的小型黑鹂。其最明显的特征在于肩部颜色的变化，可为栗色或黄色，以及大腿部可能的黄黑变换。广泛分布于南美洲中南部，包括阿根廷、玻利维亚、巴西、巴拉圭和乌拉圭等地的湿润森林边缘、树木繁茂的草原及城市公园。","appearance":"杂色黑拟鹂体型纤细，约20厘米长，尾巴较长，喙直而细。成鸟除肩部和大腿部的变色区域外，全身大致呈黑色。肩部颜色随亚种不同，可为暗栗色或黄色，大腿部则可能是黄色或黑色。眼睛虹膜为红棕色至深红褐色，喙黑色，腿灰色至黑色。两性相似，幼鸟的黑色部分更显暗淡，肩部色彩略浅。","call":"鸣声快速多变，悦耳但不够旋律。常见叫声为尖锐的“keet”。它会模仿多种鸟类的声音，包括平原霸鹟、阔嘴鵟、滑嘴犀鹃等非雀形目鸟类的警报叫声，以及大食蝇霸鹟、棕灶鸟等雀形目的叫声。在圈养条件下，它还能模仿附近鹦鹉和金丝雀的叫声。","habits":"栖息于湿润森林边缘、树丛草原和城市绿化区。以昆虫、节肢动物、花蜜和果实为食。会撕开或刺穿管状花（如Tabebuia）以获取花蜜，同时也是某些植物的潜在传粉者。几乎完全树栖，常倒挂着进食。在非繁殖季节，常加入混合物种觅食群，与多种雀形目鸟类共同活动。","breeding":"繁殖期在阿根廷为10月至1月，可能为一夫一妻制。单独繁殖，筑造浅篮状巢，由细植物纤维编织而成，常附着于棕榈叶下，或利用废弃的红腰酋长鹂巢。每窝产3-4枚蛋，白色至淡蓝灰色，有棕色、黑色和灰色斑点，平均尺寸26×16.3毫米。孵化期14天，双亲共同喂养雏鸟，雏鸟期14-15天。巢穴常被紫辉牛鹂寄生。","identification":"与同属的其他黑鹂相比，杂色黑拟鹂的肩部和大腿部颜色变化为其主要识别特征。亚种间存在颜色差异，需仔细辨别。","protection":"IUCN：LC（无危）","distribution":"主要分布在南美洲中南部，包括阿根廷、玻利维亚、巴西、巴拉圭和乌拉圭的湿润森林边缘、树丛草原和城市绿化区。","other":"在非繁殖季节，杂色黑拟鹂常加入混合物种的觅食群，显示了一定的社会性。"},{"name":"黄肩黑拟鹂","english_name":"Epaulet Oriole","scientific_name":"Icterus cayanensis","overview":"黄肩黑拟鹂（英文名：Epaulet Oriole，学名：Icterus cayanensis），是雀形目拟鹂科拟鹂属的鸟类。但现在已被明确区分为独立物种。","appearance":"黄肩黑拟鹂体长约22厘米，雄鸟平均重量43.5克，雌鸟平均42.1克。通体黑色，翼弯处有明显的金黄色斑块（俗称肩章），部分个体大腿处亦有黄色。成鸟眼睛深红棕色，喙黑色，腿呈铅灰色至黑色。雌雄外观相似。幼鸟外观类似成鸟，但羽毛略带褐色，黄色部位较暗淡，上翼覆羽尖端微黄，形成不明显翼条。","call":"其歌声不甚悦耳，由一系列升调和降调音符组成，混杂着咔哒声和嗡嗡声，主频率范围在1.5至7.5千赫兹。常见叫声为短促的鼻音。","habits":"主要栖息于低地雨林，偏好开阔地带，常在水源附近，如河流边的茂密植被、森林边缘和新生森林空地。以昆虫、蜘蛛、果实和花蜜为食，尤其喜欢访问开花的红木树以获取花蜜。通常单独或成对活动，有时加入混合物种觅食群。","breeding":"繁殖季节在法属圭亚那为8月至10月。一夫一妻制。筑巢行为由双方共同承担，巢穴形似吊床，长约40厘米，形状大致呈椭圆形，两端开口，由坚韧的黑色真菌根状物制成，内部空间长达20至25厘米，固定于离地面约6米高的香蕉叶下或椰子树叶片下。巢的结构类似于最精致的波多黎各拟鹂所建之巢。每窝可能产2至3枚卵，已观察到一个巢中有三只长有羽毛的雏鸟，双亲共同喂养雏鸟并共同守护巢穴。","identification":"与莫里奇拟鹂的区别在于后者头部和臀部亦有金色，而黄肩黑拟鹂仅翼弯处有金黄色斑块。与其他同属物种的辨识要点在于其特有的黑色底色与金黄色肩章的组合。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的圭亚那高地和亚马逊地区，包括苏里南、法属圭亚那、委内瑞拉南部、特立尼达岛、圭亚那、哥伦比亚东部、厄瓜多尔东部、秘鲁北部、玻利维亚的拉巴斯和贝尼地区，以及巴西的罗赖马州、亚马逊州东部至帕拉州北部。","other":"曾被认为与莫里奇拟鹂和变色拟鹂同种，现已明确区分。"},{"name":"牙买加黑鹂","english_name":"Jamaican Blackbird","scientific_name":"Nesopsar nigerrimus","overview":"牙买加黑鹂（英文名：Jamaican Blackbird，学名：Nesopsar nigerrimus），是雀形目拟鹂科牙买加黑鹂属的鸟类。中型黑鹂，全身羽毛呈黑色，拥有短尾巴和中等长度的细长喙。在牙买加的高海拔森林中活动，主要见于Cockpit Country、中部地区以及Blue和John Crow山脉。","appearance":"牙买加黑鹂体型较小，全身羽毛漆黑，尾部较短且常展开。喙部适中，细长而结实，适应于其独特的生态位。雌雄鸟羽色相似，幼鸟信息未详。","call":"其鸣唱为喘息式的‘whee-whee-oooo’及其变奏，常见叫声为尖锐的‘wheet’。","habits":"牙买加黑鹂严格栖息于树上，偏好湿润的高山森林，包括精灵森林和雾林，这些森林有丰富的附生植物和苔藓覆盖的树木。它们的活动范围通常在海拔575米以上，很少在低地出现。以树干和内部枝条上的昆虫为主要食物来源，利用其特化的腿部和爪子攀爬树干，适应于树干探查这一生态位。","breeding":"关于牙买加黑鹂的繁殖信息未提供。","identification":"与之相似的紫辉牛鹂具有更短、更粗的喙和更长的尾巴。黑拟八哥体型更大，尾巴更长，眼睛颜色浅而非深色。","protection":"IUCN：EN（濒危）","distribution":"牙买加黑鹂仅分布于牙买加岛，主要集中在Cockpit Country、中部山区以及Blue和John Crow山脉。","other":"牙买加黑鹂面临着栖息地丧失的严重威胁，包括铝土矿开采、林业、农业和开发。尽管在Blue和John Crow Mountains国家公园得到保护，但由于监管不力，长期安全无法保证。"},{"name":"黄肩黑鹂","english_name":"Yellow-shouldered Blackbird","scientific_name":"Agelaius xanthomus","overview":"黄肩黑鹂（英文名：Yellow-shouldered Blackbird，学名：Agelaius xanthomus），是雀形目拟鹂科黑鹂属的鸟类。独特的黑鹂属鸟类，仅见于波多黎各。其最显著特征为肩部的鲜明黄色斑块，全身其余部位呈黑色。分布于波多黎各的沿海红树林和灌木丛地带，数量曾因生境破坏和寄生威胁而大幅下降。","appearance":"黄肩黑鹂成年个体羽毛呈黑色，肩部有明显的黄色斑块，边缘常有白色镶边。雄鸟比雌鸟大，平均体重分别为41克和35克，翼展上也有差异，雄鸟的平均翼长约为102毫米，雌鸟为93毫米。幼鸟颜色较暗淡，腹部呈棕色。","call":"黄肩黑鹂的叫声包括粗糙的‘chet’声或‘chulp’声，以及类似‘naaaaaaaah’的嘶鸣声。","habits":"黄肩黑鹂是常驻居民，但部分个体在非繁殖季节会从沿海向内陆迁移以觅食。它们栖息于红树林、灌木丛、郊区、城镇、沿海灌木和大草原。食物多样，包括昆虫、花蜜、果实、种子，以及人类食物。","breeding":"繁殖季通常从四月持续至八月，有时会延至十一月。黄肩黑鹂被认为是单配偶制，每年尝试一次筑巢，通常在松散的群体中繁殖。巢由雌鸟单独建造，雄鸟则保卫巢周围的领土。每巢产卵一到四枚，平均三枚，卵为蓝绿色带褐色斑点，孵化期为13天。","identification":"黄肩黑鹂与紫辉牛鹂和黑拟八哥在大小和外观上有相似之处，但后者两者均无黄色肩部斑块。闪亮牛鹂体型较小，喙更短更粗，而大安的列斯灰头翁体型更大，尾部更长。","protection":"IUCN：EN（濒危）黄肩黑鹂于1976年被列为濒危物种。由于生境管理和寄生控制措施的实施，种群数量有所恢复。","distribution":"黄肩黑鹂分布于波多黎各，包括主岛西南部的红树林区域，以及莫纳岛上的干燥灌木丛。部分种群零星分布在波多黎各其他地区。","other":"黄肩黑鹂是寄生虫闪亮牛鹂的主要宿主，自1955年起，寄生现象导致其繁殖成功率显著下降。"},{"name":"黄褐肩黑鹂","english_name":"Tawny-shouldered Blackbird","scientific_name":"Agelaius humeralis","overview":"黄褐肩黑鹂（英文名：Tawny-shouldered Blackbird，学名：Agelaius humeralis），是雀形目拟鹂科黑鹂属的鸟类。高度群居的鸟类，们广泛分布于多种生境，主要栖息于古巴和海地（位于多米尼加共和国和海地之间）。偶尔在美国佛罗里达群岛作为迷鸟出现。其显著特征是全身黑色，肩部有一片独特的黄橙色斑块。","appearance":"黄褐肩黑鹂体长约20厘米，通体呈黑色，最引人注目的是肩部的黄橙色斑块，当翅膀收拢时可能不明显，但在飞翔时尤为显眼。雌雄成鸟的这一特征相似，而幼鸟的细节变化则不详。","call":"其鸣叫包括粗糙的“chet”声，尖锐悦耳的“chee”声，以及金属质感的上扬“willeee”声，这些声音有助于识别它们。","habits":"黄褐肩黑鹂栖息于亚热带或热带的干燥灌木丛、牧场和严重退化的前森林地带。它们的食谱广泛，包括昆虫、种子、花蜜、果实和小型蜥蜴。","breeding":"繁殖季节从4月持续至8月，它们会在树上的杯状巢中产下3至4枚绿白色带褐色斑点的蛋，巢内铺垫柔软材料。","identification":"与红翅黑鹂极为相似，区别在于后者肩部颜色更偏红色。雌性红肩黑鹂肩部无色彩，仅在肩部斑块隐藏时与黄褐肩黑鹂难以区分，此时需通过飞行姿态辨别。而铜色牛鹂没有肩部斑块，光泽感更强，喙部比黄褐肩黑鹂更短更粗。","protection":"IUCN：LC（无危）","distribution":"主要分布在古巴和海地（位于多米尼加共和国和海地），偶尔出现在美国佛罗里达群岛。"},{"name":"三色黑鹂","english_name":"Tricolored Blackbird","scientific_name":"Agelaius tricolor","overview":"三色黑鹂（英文名：Tricolored Blackbird，学名：Agelaius tricolor），是雀形目拟鹂科黑鹂属的鸟类。主要分布在加利福尼亚州，其99%以上的全球种群都集中在此。这种鸟在加利福尼亚的中央谷地、周边山麓、南部和中部沿海地区，以及零星的东北部地区、俄勒冈、华盛顿中部、内华达西部和下加利福尼亚西北部可见。三色黑鹂雌雄异型性物种，雄鸟比雌鸟大，拥有引人注目的红、白、黑色羽毛，而雌鸟暗褐色，具有条纹，比任何麻雀都要大和暗。雄鸟具有光泽的黑色羽衣，肩部有红色斑块，边缘为白色；雌鸟呈暗棕色，腹部条纹明显。","appearance":"三色黑鹂体型中等，总长度在18至24厘米之间，体重38至77克，依性别和季节而异。雄鸟全身黑色，带蓝色光泽，肩部有醒目的红色斑块，翼部中覆羽纯白。雌鸟背部暗褐色，下巴和喉咙相对白色，腹部条纹密集，形成几乎均匀的深棕色腹部。雄鸟的初级飞羽最外侧比第六根更长，而雌鸟类似雄鸟，但翅膀缺乏红色斑块。","call":"三色黑鹂的叫声鼻音重，音调低沉，不如红翅黑鹂的鸣唱复杂或悦耳。","habits":"三色黑鹂栖息于沼泽和相邻的田野，以集群方式繁殖。它们对栖息地的丧失极为敏感，导致种群数量显著下降。它们的栖息地包括半自然草地、农业耕地、碱蓬灌丛和淡水水源。冬季可能形成单一物种或单性别的群体，但通常与其它黑鹂种类一起觅食和栖息。","breeding":"三色黑鹂形成北美陆地上最大的繁殖群体，历史上曾吸引数十万甚至上百万的鸟儿。它们在适宜的筑巢基质周围寻找觅食栖息地，可能包括半自然草地、农业耕地或碱蓬灌丛，以及附近的淡水水源。它们在不同的地点繁殖，可能是一种适应利用短暂栖息地或丰富昆虫资源的方式。","identification":"与红翅黑鹂相比，三色黑鹂可通过喙形、尾形和翼式来区分。雄性三色黑鹂的翼部中覆羽更白，而雌鸟的羽毛颜色更深。雌性三色黑鹂的腹部条纹汇合成更加均匀的深棕色腹部，而红翅黑鹂雌鸟的腹部条纹持续存在。","protection":"IUCN：EN（濒危）","distribution":"三色黑鹂主要分布在美国加利福尼亚州，偶尔在俄勒冈州出现，繁殖区域扩展到下加利福尼亚北部。在加利福尼亚的中央谷地、周边山麓、南部和中部沿海地区，以及零星的东北部地区、俄勒冈、华盛顿中部、内华达西部和下加利福尼亚西北部可见。","other":"三色黑鹂是加州特有的鸟类，超过99%的全球种群都在加州。它们对栖息地的丧失极为敏感，导致种群数量显著下降。"},{"name":"红翅黑鹂","english_name":"Red-winged Blackbird","scientific_name":"Agelaius phoeniceus","overview":"红翅黑鹂（英文名：Red-winged Blackbird，学名：Agelaius phoeniceus），是雀形目拟鹂科黑鹂属的鸟类。别名: 红肩黑鸟、红翅黑鸟或美洲红翼鸫，是北美洲最为广泛研究的鸟类之一，分布自阿拉斯加至中美洲，是雀形目拟鹂科中数量极为庞大的物种。雄鸟拥有醒目的红肩带与黄色边缘，而雌鸟则呈深褐色，具有明显的条纹。红翅黑鹂主要栖息于湿地和开阔地带，以种子和昆虫为食。","appearance":"雄性红翅黑鹂通体黑色，肩部有鲜艳的红色斑块，边缘有时会呈现黄色，冬季时的羽毛边缘可能略显锈色。雌鸟整体呈条纹状的棕色，胸部颜色较浅，具有醒目的淡色眉纹。雄鸟比雌鸟重约50%，平均体重在45-75克之间，而雌鸟平均体重在30-50克左右。雄鸟在成年基本羽毛阶段，肩部的红色斑块尤为明显，边缘由黄色的次级飞羽构成。雌鸟在成年基本羽毛阶段，喉部颜色可变，从粉色到淡黄色，肩部斑块颜色从暗橙色到鲜亮的红橙色。","call":"雄鸟的鸣叫声为响亮的“konk-la-ree!”，同时会展开翅膀展示其肩部的红色斑块。此外，雄鸟和雌鸟还会发出尖锐的“check”声和高音的口哨声。","habits":"红翅黑鹂栖息于开放的湿地和上地环境，如淡水和咸水沼泽，以及草地、牧场、旧田地和城市公园。它们在春季迁徙到北方繁殖，夏季则返回南方过冬。红翅黑鹂是群居鸟类，冬季会形成大型混合群落，有时会与其他黑鸟物种一起。","breeding":"红翅黑鹂在春季开始繁殖，雄鸟建立领地并吸引雌鸟。它们通常在芦苇丛中筑巢，巢由草、苔藓和泥土构成。每窝产卵3-5枚，由雌鸟单独孵化，孵化期约为11-12天。雏鸟在孵化后11-14天离巢。","identification":"雄性红翅黑鹂的独特红色肩部斑块使其易于识别。雌鸟与某些黑鹂相似，但可通过其更长、更尖的喙和较为粗壮的体型来区分。与三色黑鹂在外观上有相似之处，尤其是雄鸟，但后者肩部的红色斑块边缘为白色而非黄色。","protection":"IUCN：LC（无危）","distribution":"红翅黑鹂分布广泛，从阿拉斯加和加拿大南部到中美洲的哥斯达黎加、佛罗里达群岛和巴哈马。在北美的北部地区，红翅黑鹂是迁徙性鸟类，而在美国西部和墨西哥湾沿岸的部分地区，以及中美洲和巴哈马群岛，红翅黑鹂则是全年居民。","other":"红翅黑鹂在农业上有时被视为害鸟，因为它们会损害玉米、向日葵和水稻等作物。然而，它们在控制害虫方面也有积极作用，通过捕食田间的昆虫和杂草种子。"},{"name":"红肩黑鹂","english_name":"Red-shouldered Blackbird","scientific_name":"Agelaius assimilis","overview":"红肩黑鹂（英文名：Red-shouldered Blackbird，学名：Agelaius assimilis），是雀形目拟鹂科黑鹂属的鸟类。古巴特有种。与红翅黑鹂极为相似，但通过近期研究已被确认为独立物种。红肩黑鹂主要栖息在古巴的湿地环境中。","appearance":"雄性红肩黑鹂长约22厘米，重约46至54克，雌鸟略小，长约20厘米，重36至43克。雄鸟全身黑色，带有轻微的蓝绿色光泽，翅膀上有醒目的橙红色小翼羽和淡黄色边缘。雌鸟全身黑色，不如雄鸟有光泽，且缺乏红色和黄色的翼羽装饰。幼鸟的翼羽较小且颜色较浅，雌鸟幼鸟则更显棕色。","call":"其叫声为‘chut’或连续的‘chut-chut’，鸣唱声尖锐，类似‘Shuh-reee-eee’。","habits":"红肩黑鹂全年栖息在古巴西部的湿地中，它们不会像北美的其他拟鹂科鸟类那样离开栖息地到远处觅食。它们主要以昆虫、种子和果实为食。","breeding":"繁殖季节从4月至8月，红肩黑鹂在此期间会进行配对，形成稳定的配偶关系。它们的筑巢、交配、产卵和育雏等繁殖行为发生在湿地环境中。","identification":"与红翅黑鹂相比，红肩黑鹂体型较小，腿较长，雌雄差异不明显，且鸣叫声有所不同。红肩黑鹂的雄鸟肩部有橙红色斑块，而红翅黑鹂的肩部斑块更大且颜色更鲜艳。","protection":"IUCN：LC（无危）","distribution":"红肩黑鹂仅分布在古巴西部的湿地和青少年岛（Island of Youth）。","other":"尽管分布范围有限，但红肩黑鹂的数量被认为稳定，没有显著威胁或数量下降的迹象。"},{"name":"啸声牛鹂","english_name":"Screaming Cowbird","scientific_name":"Molothrus rufoaxillaris","overview":"啸声牛鹂（英文名：Screaming Cowbird，学名：Molothrus rufoaxillaris），是雀形目拟鹂科牛鹂属的鸟类。亦被称为短喙牛鹂。专门的寄生鸟，几乎只寄生于栗翅牛鹂的巢中。分布于南美，从玻利维亚南部和巴西南部至阿根廷中东部。","appearance":"啸声牛鹂体型中等，全身黑色，略带蓝绿色光泽，雌雄相似但雄鸟较大。翼下覆羽呈栗色，但在野外观察时通常难以察觉。虹膜棕色到灰褐色，喙和腿均为黑色。成年鸟全长18-21厘米，雄鸟平均体重约58克，雌鸟约48克。","call":"啸声牛鹂的叫声被描述为刺耳、爆炸性和穿透力强，带有类似锉刀般的鸣叫，有助于野外识别。","habits":"啸声牛鹂主要栖息于牧场和草地边缘，常伴随放牧的牛群活动。它们在地面觅食，以被牛群惊扰的昆虫为食。近年来，由于森林砍伐导致的栖息地改变，其分布范围显著扩大。","breeding":"啸声牛鹂是专门的寄生鸟，主要寄生于湾翼牛鹂的巢中。它们不筑巢，而是将蛋寄生在宿主的巢里。寄生率在湾翼牛鹂的巢中高达74%-100%。啸声牛鹂的蛋上有斑点，类似于宿主的蛋，但形状、底色和标记可能有所不同。","identification":"啸声牛鹂与紫辉牛鹂相似，但啸声牛鹂的喙更厚实，光泽较弱。与主要宿主湾翼牛鹂相比，啸声牛鹂在孵化前的阶段非常相似，但皮肤和喙的颜色在最初几天略有差异。","protection":"IUCN：LC（无危）","distribution":"啸声牛鹂分布在南美洲，具体包括北东及中阿根廷、东南玻利维亚、中巴西、全帕拉圭和乌拉圭。"},{"name":"巨牛鹂","english_name":"Giant Cowbird","scientific_name":"Molothrus oryzivorus","appearance":"雄性巨牛鹂体长约34厘米，体重介于174至242克之间，全身覆盖着带有光泽的黑色羽毛，尤其是背部呈青铜色，腹部羽毛边缘形成鲜明的终端带，使基部黑色部分格外显眼。其翅膀长而尖锐，尾巴圆润且长度约为翅膀的四分之三。头部较小，颈部周围有显著的羽毛围领，雌鸟相对较小，平均体长29厘米，体重约144至167克，缺乏雄鸟的光泽，颈部围领也不明显。幼鸟类似成年雄鸟，但颜色较暗淡，嘴喙为浅色而非黑色。","call":"巨牛鹂较为安静，尤其是对于拟鹂科而言。雄鸟会发出刺耳的口哨声，叫声为“shweeaa-tpic-tpic”，另有尖锐的“chek-chik”声。它们也是出色的模仿者。","habits":"巨牛鹂偏好开阔的林地和有大树的耕作区，但也是唯一能在深林中发现的牛鹂。它们群居，主要以昆虫为食，也会吃一些种子，包括稻谷。它们在地面和树上觅食，沿湖泊和河流寻找水果、花蜜和节肢动物，在香蕉种植园和玉米地中觅食。尽管不像某些近亲那样常栖息在牛背上，但在巴西，巨牛鹂会搭乘水豚以去除蜱虫和马蝇。","breeding":"巨牛鹂是寄生繁殖者，将卵产在黄鹂科的Oropendola和Cacique的巢中。卵有两种类型：白色无斑点或淡蓝色或绿色带暗斑和斑点。不会破坏宿主的卵和雏鸟。由于宿主的巢穴常常密集，且宿主会积极保卫巢穴，因此巨牛鹂需在较大范围内寻找足够的产卵机会。有时，一个宿主巢穴中可能有多枚巨牛鹂的卵。","identification":"雄性巨牛鹂在远处可能与大尾拟八哥混淆，两者体型相近，但巨牛鹂体态更壮实，颈部厚实，头部较小，颈部周围有羽毛围领。其喙较短且粗，尾巴比Grackle短，缺少Grackle特有的‘船首’形状。雌性巨牛鹂比大尾拟八哥小，但比其他相似的黑鸟如紫辉牛鹂和艳拟鹂大。","protection":"IUCN：LC（无危）","distribution":"巨牛鹂分布于中美洲和南美洲，从墨西哥东部至南美北部，包括特立尼达和多巴哥岛。在安第斯山脉的分布可能因森林砍伐而向更高海拔扩展，但在一些地区，随着宿主物种消失，巨牛鹂也可能已经消失。","other":"巨牛鹂在成长过程中的换羽时间及程度未知，幼鸟完全依赖宿主抚养，出生时近乎裸体无助，仅在特定部位有少量灰色绒毛。"},{"name":"紫辉牛鹂","english_name":"Shiny Cowbird","scientific_name":"Molothrus bonariensis","overview":"紫辉牛鹂（英文名：Shiny Cowbird，学名：Molothrus bonariensis），是雀形目拟鹂科牛鹂属的鸟类，原生于南美洲，广泛分布于加勒比和南美地区。雄鸟光泽蓝黑，雌鸟灰褐，体型小，具巢寄生习性。自1985年起，通过安的列斯群岛自然扩展，已到达北美的佛罗里达州，成为当地永久居民。","appearance":"雄性紫辉牛鹂全身光泽蓝黑，翅膀和尾巴带绿蓝色光泽；雌鸟上身灰褐色，下身较淡，部分亚种下身暗棕。喙黑色，中等长度，锥形。体长范围18-22厘米，体重31-65克。幼鸟上身深色，下身灰褐色，有暗色条纹。","call":"歌喉含混颤音，随后是一系列上升的短高音。","habits":"偏好半开放和开阔草地环境，常与家畜相伴。主要在地上觅食，但也栖息于灌木和树上。以昆虫、其他节肢动物和种子为食，曾在牛槽中寻找谷物。","breeding":"实行强制巢寄生，将卵产在约250种其他鸟类的巢中，依赖宿主养育后代。雌鸟不筑巢，偏好选择封闭型巢穴，如树洞巢。宿主对寄生卵的反应各异，从接受到排斥。","identification":"与雌性褐头牛鹂的区别在于较长、较细的喙和扁平的头部。与啸声牛鹂相比，喙更长，羽色更光泽，虹膜颜色更深。","protection":"IUCN：LC（无危）","distribution":"分布于南美大部分地区，最近扩展至加勒比海岛屿和美国东南部（佛罗里达州，罕见）。在哥斯达黎加至智利中部和阿根廷中南部也有记录。","other":"紫辉牛鹂的扩散可能威胁到加勒比海和美国本土的某些濒危鸟类物种。"},{"name":"铜色牛鹂","english_name":"Bronzed Cowbird","scientific_name":"Molothrus aeneus","overview":"铜色牛鹂（英文名：Bronzed Cowbird，学名：Molothrus aeneus），是雀形目拟鹂科牛鹂属的小型鸟类。分布广泛，自美国西南部加州、亚利桑那、新墨西哥、得克萨斯和路易斯安那州南部，经中美洲至巴拿马。主要栖息于农田、灌木丛和牧场，非繁殖季节则偏好开阔地带，夜晚则栖息于密林。","appearance":"雄性铜色牛鹂约20厘米长，体重68克，拥有绿铜色光泽的黑色羽毛。繁殖季节眼睛呈现红色，其余时间呈棕色。雌鸟略小，长约18.5厘米，重56克，体羽较暗淡，腹部呈棕色，眼睛为棕色。幼鸟外观与雌鸟相似，但边缘羽毛呈灰色。","habits":"栖息于开放的农业区，常在牧场附近活动，以种子、昆虫为主食，繁殖季节会食用蜗牛以补充钙质。冬季栖息于非常开阔的环境，夜宿于茂密树林。","breeding":"作为强制性巢寄生鸟，雌鸟会在其他鸟种的巢中产卵，由寄主鸟代为喂养其幼鸟，牺牲寄主的亲生幼鸟。寄主包括Prevost's ground-sparrows和white-naped brush finches，幼鸟生长迅速，约10-12天即可离巢。","identification":"与同属其他物种相比，铜色牛鹂的显著特征在于其金属光泽的绿铜色羽毛和特定的地理分布。","protection":"IUCN：LC（无危）","distribution":"繁殖区域包括美国西南部至巴拿马，非繁殖季节分布于更开阔的地带。"},{"name":"铜褐牛鹂","english_name":"Bronze-brown Cowbird","scientific_name":"Molothrus armenti","overview":"铜褐牛鹂（英文名：Bronze-brown Cowbird，学名：Molothrus armenti），是雀形目拟鹂科牛鹂属的鸟类。曾被认为是孤立的铜色牛鹂种群，实为牛鹂属的独特物种。分布仅限于南美洲哥伦比亚西北部狭窄的沿海地带。","appearance":"具体描述铜褐牛鹂的外观特征，包括羽毛颜色、体型大小等，此处由于原始资料缺乏具体细节，无法提供详尽描述。","habits":"铜褐牛鹂的生活习性、栖息地和活动范围尚未详细记录，但作为牛鹂属的一员，可能偏好开阔地带或农田边缘。","identification":"与其他牛鹂种类的区别辨识特征尚未明确记录，但一般可通过羽毛颜色和分布区域进行初步区分。","protection":"IUCN：NT（近危）","distribution":"铜褐牛鹂的分布局限于南美洲哥伦比亚的西北部沿海地带。"},{"name":"褐头牛鹂","english_name":"Brown-headed Cowbird","scientific_name":"Molothrus ater","overview":"褐头牛鹂（英文名：Brown-headed Cowbird，学名：Molothrus ater），是雀形目拟鹂科牛鹂属的鸟类。北美洲温带和亚热带地区的特有种。原本栖息于短草平原，跟随北美野牛群，后随欧洲殖民扩张至今日的农业和郊区景观。南方种群全年留居，而北方种群则迁徙至美国南部和墨西哥越冬，翌年春返回北方繁殖。","appearance":"成年雄性褐头牛鹂具光泽的黑色体羽，头颈部呈独特的巧克力棕色，雌鸟体型略小，羽毛颜色较为朴素，整体呈灰褐色，喉部稍浅，下体有细密条纹，幼鸟则全身斑驳。体长16至22厘米，翼展约36厘米，雌鸟平均重38.8克，雄鸟平均49克。","call":"鸣叫声多样，包括尖锐的高音和流水般的咕噜声，具体描述未详。","habits":"褐头牛鹂偏好开阔或半开阔地带，如田野、牧场、草地边缘和草坪。它们结群活动，地面觅食，随牲畜移动捕食被惊起的昆虫，也吃种子和偶尔的浆果。在冬季，它们可能聚集在郊区的鸟食器附近。","breeding":"褐头牛鹂是典型的巢寄生鸟类，将卵产在其他220多种小型雀形目鸟类的巢中，由宿主代为孵化和喂养。雌鸟一季可产卵多达40个。它们会定期检查寄生的巢，若发现卵被抛弃，会采取报复行动，如破坏巢穴。","identification":"与相似物种区分，如铜色牛鹂和紫辉牛鹂，主要通过体型、色彩和嘴型差异。雌雄成鸟间差异明显，雄鸟具独特棕色头颈，雌鸟则全身灰褐色。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美，从加拿大南部至墨西哥南部，非繁殖季节广泛分布于美国南部和墨西哥。","other":"由于其巢寄生行为，对某些宿主物种产生负面影响，导致人们实施控制计划。然而，控制过度可能导致意外增加牛鹂的繁殖成功率。"},{"name":"丛拟鹂","english_name":"Scrub Blackbird","scientific_name":"Dives warczewiczi","overview":"丛拟鹂（英文名：Scrub Blackbird，学名：Dives warczewiczi），是雀形目拟鹂科艳拟鹂属的鸟类。全黑的羽毛在光线照射下可能显现出轻微的蓝绿色光泽，分布于西哥伦比亚、厄瓜多尔西部和秘鲁沿海地区。","appearance":"丛拟鹂是一种中等体型的黑色鸟类，身长约为21.5厘米，雄鸟平均重量85.5克至110克（kalinowskii亚种），雌鸟平均84克。全身黑色，带有蓝色到绿色的金属光泽，眼睛深棕色，喙和腿均为黑色。雄雌相似，幼鸟较暗淡，羽毛呈黑褐色，头部、背部和胸部有轻微的金属光泽。","call":"其鸣唱为一系列响亮的哨音，通常在显眼的栖木上发出，同时可能垂直头部并上下摆动。飞行中的尖锐‘teeeew’叫声。","habits":"栖息于低地和山麓的干旱开阔林地和灌木丛，包括农业区、果园、公园、花园和城市住宅区。在秘鲁几乎无雨的海岸，主要分布在绿洲、河岸地带或灌溉农田附近。海拔高度可达3000米（kalinowskii亚种）。以昆虫和其他节肢动物、小型脊椎动物、果实和种子为食，常在地上觅食，多成对出现。","breeding":"繁殖季节为2月至5月，可能为一夫一妻制。巢为浅杯状，由树枝、杂草、草和香蕉叶碎片构成，内部直径9.3厘米，深度5.1厘米，位于树上5至6米高处，如Prosopis juliflora、Cordia lutea或柠檬树。每窝产2至3枚蛋，平均尺寸27.5×19.2毫米，淡蓝色带棕色至黑色点斑，孵化期未知，雏鸟期12天。巢穴被寄生。","identification":"与雄性紫辉牛鹂极为相似，但体型更大，喙更长，羽毛光泽较少。kalinowskii亚种比指名亚种大，有紫色光泽。","protection":"IUCN：LC（无危）。常见且数量众多，能适应栖息地改变，似乎正在秘鲁和厄瓜多尔扩大其分布范围。","distribution":"分布于远西南部哥伦比亚、厄瓜多尔西部和秘鲁沿海至库斯科西部，包括低地和山麓地带。"},{"name":"艳拟鹂","english_name":"Melodious Blackbird","scientific_name":"Dives dives","overview":"艳拟鹂（英文名：Melodious Blackbird，学名：Dives dives），是雀形目拟鹂科艳拟鹂属的鸟类。中等体型的黑色热带鸟类。常见于中美洲的热带低地半开放生境，通常成对或小群体出现。其全身羽毛全黑，带有蓝绿色光泽，尾巴圆润，喙尖锐，眼睛深邃。分布区域从墨西哥至尼加拉瓜。","appearance":"成年艳拟鹂体长在23至25.5厘米之间，体重约95至108克，雌雄体型相似。羽毛通体漆黑，带有一层微妙的丝绒光泽。喙、腿和脚均为黑色，眼睛呈棕色。年轻个体羽毛呈褐色，缺乏成鸟的金属光泽。无亚种分化。","call":"鸣声独特，为一对伴侣间的二重奏，先发出see音，随后是whit音，最后是类似北方红雀的哨声。叫声则是一种金属质感的puitt声。","habits":"适应人类居住环境，常出现在花园和草坪上。以昆虫为主食，也会摄取花蜜、成熟的玉米和各种果实，如gumbo-limbo树（Bursera simaruba）和Trophis racemosa的果实。非繁殖季节形成小型群落。","breeding":"繁殖期间高度领地性，成鸟会驱赶入侵的捕食者，如棕雅雀。筑巢由两性共同参与，巢为杯状，位于灌木或树木3至7米高处，内部铺垫泥和粪便。雌鸟产下3至4枚带有棕色斑点的蓝色蛋，独自孵化，雄鸟协助喂养雏鸟。","identification":"全黑的羽毛和尖锐的喙是其显著特征，容易与同属的其他物种区分开来。鸣叫声也是辨识的重要依据。","protection":"IUCN：LC（无危）","distribution":"繁殖区域从墨西哥东部和东南部沿海地带至尼加拉瓜。随着森林砍伐，其分布范围迅速扩张，已成功在萨尔瓦多（1950年代）和危地马拉东部（1960年代）定居，现在至少南至哥斯达黎加首都圣何塞附近都能见到其身影。","other":"得益于森林砍伐导致的适宜栖息地增加，该物种得以快速扩展其分布范围。"},{"name":"古巴黑鹂","english_name":"Cuban Blackbird","scientific_name":"Ptiloxena atroviolacea","overview":"古巴黑鹂（英文名：Cuban Blackbird，学名：Ptiloxena atroviolacea），是雀形目拟鹂科Ptiloxena的鸟类。上体带微紫光泽，仅眼部为棕色。常见于古巴的低地湿润森林和重度退化的前森林地带。","appearance":"古巴黑鹂长约27厘米（约11英寸），通体黑色，上体具轻微的紫色光泽。唯一非黑色的部分是其棕色的眼睛。雄鸟与雌鸟在颜色上相似，但雌鸟体型可能略小。","call":"其鸣叫包括金属质感的“schee-o”声和响亮的“chuck”声，两者均可单独或连续发出。另一种常见的叫声为“chok, chok, chok, lee, lee, lee”。","habits":"古巴黑鹂是一种群居的鸟类，广泛出现在多种生境中，但避开密林，常靠近人类居住区。它活跃于低地湿润森林和重度退化的前森林地带。","breeding":"关于古巴黑鹂的繁殖信息尚未详细记录。","identification":"与古巴黑鹂相似的物种包括闪亮牛鹂、红肩黑鹂和大安的列斯鹊鸲。闪亮牛鹂体型较小，喙较短，羽毛光泽更强。大安的列斯鹊鸲具有淡色而非深色的眼睛，喙较窄，尾巴较长。红肩黑鹂雌鸟的体型稍小，喙较窄，光泽较弱。","protection":"IUCN状态未知。在古巴广泛分布且数量较多。","distribution":"古巴黑鹂仅分布于古巴，于该岛广泛而常见，但在Isla de la Juventud和部分离岸小岛则未发现其踪迹。"},{"name":"锈色黑鹂","english_name":"Rusty Blackbird","scientific_name":"Euphagus carolinus","overview":"锈色黑鹂（英文名：Rusty Blackbird，学名：Euphagus carolinus），是雀形目拟鹂科锈色黑鹂属的鸟类。与Grackle关系密切，过去被称为'锈色Grackle'。这种鸟偏好湿润森林环境，繁殖于北美的针叶林和沼泽地带，如加拿大北部、美国东北部部分地区以及阿拉斯加，冬季迁徙至美国东南部。锈色黑鹂曾广泛分布，但近年来数量急剧下降，原因尚不明晰。","appearance":"成年锈色黑鹂具有尖锐的喙和淡黄色的眼睛，雄鸟在繁殖季节全身黑色，带有微弱的绿紫色光泽，雌鸟呈灰褐色。冬季，其上体羽毛边缘呈现锈色，头部、颈背及背部可见锈棕色，眼上有一条较浅的棕色至米色羽毛。雌雄幼鸟与成鸟相似，但锈色和浅棕色边缘更宽，整体外观更偏棕色。所有锈色黑鹂的喙都比头短，翼长而窄，尾长近似于翼，略呈圆形。","call":"鸣唱由两到三个音符组成，随后是一个高升的音符，类似生锈铰链的吱嘎声。","habits":"繁殖于湿温带针叶林和沼泽，巢通常位于水边的树木或茂密灌木中，夏季以龙虱及其幼虫为主要食物。迁徙至美国东南部和谷物带，偶尔进入墨西哥，也有记录在格陵兰岛和俄罗斯西伯利亚出现。以小群形式活动，偏好湿润环境，如洪水泛滥的树林、沼泽、湿地和池塘边缘。它们在地面觅食，主要吃昆虫、小鱼和种子，会翻动叶子和撕扯水生植物。","breeding":"繁殖期相对较早，通常在北方林区停留以完成换羽。秋季迁徙缓慢，春季迁徙迅速。最大越冬集中地在美国下密西西比河谷，较小规模的群体出现在皮埃蒙特和南大西洋沿海平原。","identification":"与蓝头黑鹂相比，锈色黑鹂的雄鸟头部光泽为绿色而非紫色，喙基部较细。雌性锈色黑鹂为灰色（非灰褐色），且眼睛颜色深。锈色黑鹂的形状和色泽让人联想到短尾Grackle。","protection":"IUCN：VU（易危）","distribution":"繁殖区主要在北美北部，包括加拿大、新英格兰、密歇根州上半岛、纽约州阿迪朗达克山脉和阿拉斯加。非繁殖区主要在美国东南部。","other":"自1970年至2010年间，锈色黑鹂的数量减少了85%-95%，可能与栖息地丧失、汞污染、以及针对其他黑鹂种类的毒杀有关。"},{"name":"蓝头黑鹂","english_name":"Brewer's Blackbird","scientific_name":"Euphagus cyanocephalus","overview":"蓝头黑鹂（英文名：Brewer's Blackbird，学名：Euphagus cyanocephalus），是雀形目拟鹂科锈色黑鹂属的鸟类。因托马斯·梅奥·布鲁尔而得名。雄鸟拥有闪亮的黑色羽毛，头部和颈部呈紫色光泽，身体其余部分有蓝绿色的光泽。雌鸟呈暗褐色，带有轻微的金属光泽。该物种在北美中部和西部的开阔和半开阔地带繁殖，其分布范围已扩展至大湖地区东部。","appearance":"雄性蓝头黑鹂体长约21-25厘米，雌鸟约20-22厘米，平均体重分别为67克和58克。雄鸟羽毛光亮，头部和颈部在强光下呈现紫色光泽，身体其他部位显示蓝绿色光泽。雌鸟颜色较淡，头部和颈部有浅紫色光泽，身体其余部位略带金属绿色光泽。两性皆具直而尖的喙，脚和腿为黑色。","call":"叫声为尖锐的'check'声，有助于区分。","habits":"栖息于开阔地带，包括近水区域、停车场、学校周边等，能适应人类环境。在较低海拔（低至海平面以下）至海拔8,000英尺的高度生存。冬季，它们会迁徙至美国东南部和墨西哥。它们能够生活在多种环境中，包括湿地和森林。","breeding":"蓝头黑鹂在春季繁殖，形成由多达30对组成的繁殖群落。雌鸟主要负责筑巢，巢通常位于树顶20-40英尺高处，有时在水边的芦苇和其他水生植物中。每窝产卵3-7枚，蛋壳为浅棕色带深色斑点，由雌鸟孵育12-14天。雏鸟出生两周后即可离巢。","identification":"与锈色黑鹂相比，蓝头黑鹂雄鸟的头部更显紫色光泽，且体型较小。与拟八哥相比，蓝头黑鹂尾部较短。","protection":"IUCN：LC（无危）","distribution":"繁殖区域覆盖加拿大西南部和中南部至美国西部。非繁殖季节，它们向南迁徙至墨西哥南部。","other":"蓝头黑鹂的分布范围在20世纪显著向东扩张，尤其是在大湖地区。"},{"name":"拟八哥","english_name":"Common Grackle","scientific_name":"Quiscalus quiscula","overview":"拟八哥（英文名：Common Grackle，学名：Quiscalus quiscula），是雀形目拟鹂科拟八哥属的鸟类。大型的黑鸟，属于拟鹂科，以其长腿、长尾和长而厚重的喙著称。眼珠淡黄，头部羽毛具蓝紫色光泽，身体羽毛呈暗铜色。广泛分布于北美东部地区，偏好开阔地带与零星树木环境。这种鸟种在春季早期开始繁殖，通常在三月底或四月初。杂食性，食物包括昆虫、小鱼、蛙类、鸟蛋、浆果、种子、谷类。","appearance":"成年拟八哥体长介于28至34厘米，翼展可达36至46厘米，体重在74至142克之间。雄鸟平均重122克，比雌鸟的平均94克大。头部和颈部呈蓝紫或蓝绿色金属光泽，背部呈青铜色光泽。雌鸟体型较小，光泽较弱，尾巴较短，无金属光泽。幼鸟呈深褐色，虹膜颜色较深。","call":"拟八哥的叫声独特，包括粗哑的嘎吱声和高音清脆的哨声，持续时间不到一秒，常被形容为类似生锈的门轴声。鸣唱时，雄鸟会膨胀身体羽毛，展开尾巴。","habits":"栖息于开放和半开放区域，偏好松树林或灌木丛，靠近水源。它们以地面、浅水区或灌木丛为觅食场所，有时会从其他鸟类那里偷取食物。杂食性，饮食包括昆虫、小型鱼类、青蛙、鸟蛋、浆果、种子、谷物等。","breeding":"繁殖季节，雄鸟会展示头部后仰和羽毛蓬松的行为，以此吓退其他雄鸟。巢穴通常建在密集的树木或灌木丛中，有时也会选择树洞或人造结构。每次产卵数量为4到7枚。","identification":"与红翅黑鹂相比，拟八哥的尾巴更长，翅膀更短，眼睛更大。雄鸟比雌鸟光泽更强，尾巴更长，呈船形。幼鸟呈棕色，眼睛较暗。","protection":"IUCN：NT（近危）","distribution":"繁殖区域主要位于北美的中部和东部，非繁殖季节则迁移到美国东南部。随着森林的清理，其分布范围向西扩展。","other":"拟八哥的种群数量自历史高峰下降了61%，目前约有7300万只，而历史最高点曾超过1.9亿只。"},{"name":"尼加拉瓜拟八哥","english_name":"Nicaraguan Grackle","scientific_name":"Quiscalus nicaraguensis","overview":"尼加拉瓜拟八哥（英文名：Nicaraguan Grackle，学名：Quiscalus nicaraguensis），是雀形目拟鹂科拟八哥属的鸟类。中等体型，仅在尼加拉瓜和其北邻哥斯达黎加的极北端可见。","appearance":"尼加拉瓜拟八哥具有显著的长尾，且腿和喙都相对较长。成年雄鸟全身乌黑，带有一定的金属光泽，通常呈绿色调；雌鸟上部呈褐色，下部颜色较浅，具有一条淡色的眼纹，使暗色的头部和耳羽更为突出。雄鸟长约31厘米，而雌鸟稍短，约25厘米。","call":"这种鸟拥有多种叫声，包括常见的鼻音，不同的哨音，以及尖锐上升的哀鸣。其鸣唱由一系列哨声组成，速度和频率逐渐增加。","habits":"尼加拉瓜拟八哥居住在开阔的草地和湿地中，常以小群的形式活动。它们在地面觅食，寻找种子和昆虫，有时会翻动石头或杂物来寻找藏于其下的食物，常常在牛群附近觅食。","breeding":"它们在灌木丛、树木或沼泽植被中建立小型群落进行筑巢，巢穴杯状，由草、芦苇叶和根制成，隐蔽于其中。每巢产2至3枚蛋，蛋壳呈蓝色，大端有深色斑点。仅雌鸟孵卵，但双亲共同喂养雏鸟。","identification":"与之相似的大尾拟八哥在其分布范围内有重叠，但体型更大，尾更长，喙更大。雄性大尾拟八哥的光泽不如尼加拉瓜拟八哥绿，雌鸟的下部颜色更深，眼纹不明显。","protection":"IUCN：LC（无危）","distribution":"尼加拉瓜拟八哥主要分布在尼加拉瓜西部，包括尼加拉瓜湖和马那瓜湖周边，以及哥斯达黎加北部的Caño Negro区域沿Río Frio河一带。"},{"name":"辉拟八哥","english_name":"Carib Grackle","scientific_name":"Quiscalus lugubris","overview":"辉拟八哥（英文名：Carib Grackle，学名：Quiscalus lugubris），是雀形目拟鹂科拟八哥属的鸟类。分布于特立尼达岛和南美大陆，1905年被引入多巴哥岛，现今在当地非常常见。","appearance":"雄性辉拟八哥平均长度为26厘米，体重约66至80克，全身黑色带有紫蓝色光泽，尾部楔形且较长，但不及其他种类的拟八哥长，眼睛黄色，喙部和腿部呈黑色。雌鸟平均长度为21.7厘米，体重49至58克，上体呈暗灰褐色，下体略淡，同样具有黄色的眼睛。幼鸟雄鸟的尾部较短，部分羽色仍为棕色；幼鸟雌鸟与成年雌鸟相似，但色泽更暖。不同亚种在羽色深浅、体型大小和光泽表现上存在差异。","call":"鸣声多样，包含尖锐与较为悦耳的金属音调，如‘tickita-tickita-tickita-ting’和快速的‘chi-chi-chi-chi’。鸣叫时通常会蓬松羽毛，叫声在不同岛屿间存在方言差异。","habits":"栖息于开阔地带，包括农田和人类居住区，常在城市中大量出现，尤其沿海岸线。它们以群居方式生活，主要在地面寻找昆虫、小型无脊椎动物、小鱼、蛙类、蜥蜴或人类丢弃的食物残渣。面对潜在威胁如狗、獴或人类时，会集体攻击。夜间则群居休息。","breeding":"繁殖季节几乎全年，主要集中在5月至9月（特立尼达岛）或6月至7月（委内瑞拉大草原）。筑巢于树、棕榈或灌木中，巢由草和其他植物材料混泥制成，深度可达10厘米，直径17厘米，离地高度最高可达15米。每巢产卵2至4枚，绿色带蓝底，有黑色和灰色斑点，平均尺寸为27.3×19.8毫米。孵卵期12天，由雌鸟负责，孵化后双亲共同喂养，幼鸟留巢期为14天。部分巢穴可能受到紫辉牛鹂的寄生，但辉拟八哥能够成功排除寄生蛋。","identification":"雄性辉拟八哥与同属的其他种类相比，尾部相对短些，雌鸟羽色较暗，与近似种的区别在于羽色光泽、体型和叫声。不同亚种间的辨识依据羽色深浅、体型大小和光泽的不同。","protection":"IUCN：LC（无危）","distribution":"分布于小安的列斯群岛和南美洲北部，包括哥伦比亚东部、委内瑞拉、巴西东北部等地。在多巴哥、巴布达、安提瓜、圣基茨、安圭拉等北小安的列斯群岛扩散。在哥伦比亚的扩张与人类活动导致的栖息地改变有关。","other":"历史上，指名亚种被引入多巴哥，而fortirostris亚种在20世纪初期成功引入北小安的列斯群岛。"},{"name":"黑拟八哥","english_name":"Greater Antillean Grackle","scientific_name":"Quiscalus niger","overview":"黑拟八哥（英文名：Greater Antillean Grackle，学名：Quiscalus niger），是雀形目拟鹂科拟八哥属的鸟类。广泛分布于大安的列斯群岛及其附近小岛，常见于人口密集区。以‘kling-kling’之名闻名于牙买加，‘chinchilín’于多米尼加共和国，‘ching ching’于开曼群岛，及‘chango’于波多黎各。","appearance":"成年黑拟八哥体长约27厘米（雄鸟）至24厘米（雌鸟），全身覆盖着光泽的黑色羽毛，拥有大而类似舵的尾巴，雄鸟的尾羽尤为显著。雌鸟体型略小，尾部较短，色泽不如雄鸟鲜艳。其黄色的眼睛是全身唯一非黑色的部分，与光滑的黑色羽毛形成鲜明对比。","call":"鸣叫声多样，大多带有‘生锈铰链吱嘎’的特质，同时也发出尖锐的‘chack’声。","habits":"黑拟八哥群居，喧闹，除密林外，适应多种栖息环境，尤其偏爱人类居住区。它们是杂食性鸟类，食物来源广泛，包括水果、面包、植物物质，以及小型脊椎和无脊椎动物。","identification":"与滑嘴犀鹃相似，但在喙的厚重程度上明显不同。古巴黑鹂与其颜色和大小相近，但后者尾巴较短，无舵状特征，且眼睛颜色较深。","distribution":"分布于北美大安的列斯群岛，包括但不限于波多黎各、牙买加、多米尼加共和国及开曼群岛。"},{"name":"宽尾拟八哥","english_name":"Boat-tailed Grackle","scientific_name":"Quiscalus major","overview":"宽尾拟八哥（英文名：Boat-tailed Grackle，学名：Quiscalus major），是雀形目拟鹂科拟八哥属的大型鸟类。常见于北美东部及东南部沿海地区。雄鸟体型硕大，羽毛呈现光泽的蓝黑色，尾羽异常延长，近似其体长，常呈V形展开，犹如船尾。雌鸟较小，羽毛呈棕色，面部有细微的花纹。眼色随地理位置变化，从西部海湾沿岸的棕色至大西洋沿岸的黄色。","appearance":"雄性宽尾拟八哥拥有长达15-17英寸的整体长度，体重介于5.8至8.8盎司之间，全身覆盖着带有金属光泽的黑色羽毛，尾部形成独特的船尾状。雌鸟个体显著较小，约10-13英寸长，重3.2-4.1盎司，羽毛为淡褐色，翼和尾较暗。幼年雄鸟黑色但缺乏成鸟的金属光泽，而幼年雌鸟则是成年雌鸟的暗淡版本，胸有斑点。眼色依地域而异，内陆与海湾沿岸的鸟儿有深色眼睛，而大西洋沿岸的鸟儿则有浅色的眼睛。","call":"其鸣唱为尖锐的'jeeb'声，伴随着一系列典型的拟八哥类鸟的叽叽喳喳和吱吱声。","habits":"这种鸟栖息于沿海盐沼，尤其是在佛罗里达州，它们也会出现在内陆水域附近。城市环境中，宽尾拟八哥会出没于垃圾箱、垃圾堆和停车场寻找食物。它们是杂食性动物，食谱广泛，包括昆虫、小鱼、蛙类、鸟蛋、浆果、种子、谷物甚至小型鸟类。","breeding":"繁殖期，宽尾拟八哥会在靠近水源的树或灌木丛中建造隐蔽的巢穴，平均产卵数略高于三枚。","identification":"与同类物种相比，宽尾拟八哥的雄鸟具有更长的尾羽和圆顶状头部。与大尾拟八哥的区别在于体型稍小，尾羽更长，缺乏本种特有的圆顶头型。与普通拟八哥的差异在于体型更大，尾羽更长，且头部形状不同。","protection":"IUCN：LC（无危）","distribution":"繁殖区域主要集中在北美东部和东南部，包括美国的东海岸和墨西哥湾沿岸。在佛罗里达半岛上，它们的分布更为广泛，不仅限于沿海地带。"},{"name":"大尾拟八哥","english_name":"Great-tailed Grackle","scientific_name":"Quiscalus mexicanus","overview":"大尾拟八哥（英文名：Great-tailed Grackle，学名：Quiscalus mexicanus），是雀形目拟鹂科拟八哥属的中型鸟类。广泛分布于北美洲至南美洲。雄鸟呈现闪亮的黑色，具紫色光泽，拥有超长的V形尾巴，而雌鸟则是较暗的棕色。这种鸟在二十世纪经历了显著的地理扩张，其分布范围覆盖了美国至少14个州，最北可达加拿大。在沿海德克萨斯州，与宽尾拟八哥在栖息地选择上有所差异。","appearance":"雄性大尾拟八哥体型较大，约38-46厘米长，体重介于203-265克之间，头部、背部及腹部的羽毛呈现紫蓝色光泽，尾羽长且呈梯形。雌鸟体型较小，约重115-142克，全身棕色，翅膀和尾部颜色更深，黄色眼睛比雄鸟的更淡，喉部和眼上方有浅色条纹，下体颜色从肉桂色到灰棕色不等。幼鸟与雌鸟相似，但光泽度较低，腹部有斑纹，虹膜为深色。","call":"未提供详细描述。","habits":"大尾拟八哥适应性强，常见于城市草坪、树丛和垃圾箱附近。它们的食物多样，包括昆虫、小型脊椎动物、植物物质和人类垃圾。在繁殖季节，雄鸟会保卫一片由一棵或多棵树组成的领地，吸引雌鸟在此筑巢。它们在开放的草地、牧场和城市环境中觅食。","breeding":"大尾拟八哥的繁殖期通常始于四月初，巢穴建于大树顶部，由雌鸟用草、枝条等材料编织，有时也会掺入人造物品。每次产卵4-7枚，孵化期约为13-14天，幼鸟在12-17天后离巢，但父母仍会继续喂养数周直至其成熟。","identification":"与宽尾拟八哥相比，大尾拟八哥体型略大，雄鸟尾羽更长，雌鸟体型更大，色彩更暗。雄性大尾拟八哥背部和胸部的光泽更偏向紫色，而宽尾拟八哥则更偏蓝绿色。雌性大尾拟八哥的冠部为黑色或灰棕色，而宽尾拟八哥的冠部为肉桂色。","protection":"IUCN：LC（无危）","distribution":"大尾拟八哥的分布范围从南美西部、北部，延伸至美国南部，最北可达加拿大。具体包括西北委内瑞拉、哥伦比亚西部、厄瓜多尔西部至美国的明尼苏达州、俄勒冈州、爱达荷州、加利福尼亚州以及佛罗里达州，偶见于加拿大南部。","other":"大尾拟八哥在二十世纪经历了快速的地理范围扩展，尤其在1960年后，与人类活动如灌溉和城市化密切相关。"},{"name":"墨西哥拟八哥","english_name":"Slender-billed Grackle","scientific_name":"Quiscalus palustris","overview":"墨西哥拟八哥（英文名：Slender-billed Grackle，学名：Quiscalus palustris），是雀形目拟鹂科拟八哥属的已灭绝鸟类。原生于墨西哥中部，特别是在墨西哥谷和托卢卡谷，曾被发现于农业区和城镇。其近亲为大尾拟八哥西部种群，两者大约在120万年前分化。","appearance":"墨西哥拟八哥的体重介于2.5至5盎司之间，具有细长的喙，这是其显著的外部特征之一。雄鸟通过喧闹的行为宣告其繁殖领地，而雌鸟与幼鸟的详细羽毛描述未提供。","habits":"墨西哥拟八哥栖息于墨西哥谷和托卢卡谷的湿地与沼泽地带，适应性强，亦能在城镇和农田中生存。它们以动物、植物和果实为食，主要食物包括蠕虫、苍蝇和玉米。这种鸟倾向于群居，形成群体。","breeding":"墨西哥拟八哥通常在沼泽和水生植被中筑巢，选择芦苇作为孵卵地点。然而，随着墨西哥人口的增长，该物种适应环境变化，开始在城镇和农田中筑巢。","identification":"墨西哥拟八哥以其细长的喙和特定的栖息地偏好与其它拟八哥种类相区分。关于其亚种间的辨识要点信息缺失。","protection":"IUCN：EX（已灭绝）","distribution":"墨西哥中部，特别是在墨西哥谷和托卢卡谷的湿地。最后一次记录是在1910年。","other":"在欧洲移民初期，阿兹特克人将墨西哥拟八哥视为害鸟，可能因其破坏作物，也可能因其羽毛用于仪式装饰。它们的黑色尾羽被优先选用，原因不明。"},{"name":"红腹拟鹩哥","english_name":"Red-bellied Grackle","scientific_name":"Hypopyrrhus pyrohypogaster","overview":"红腹拟鹩哥（英文名：Red-bellied Grackle，学名：Hypopyrrhus pyrohypogaster），是雀形目拟鹂科红腹拟鹩哥属的鸟类。尾部修长，全身呈深黑色，腹部拥有鲜艳的红色，眼睛为刺眼的黄色。通常以小群体出现在海拔1000至2400米的云雾森林树冠层，偶尔与松鸦或织雀混群。","appearance":"雄鸟平均体长31.5厘米，体重约101克；雌鸟平均体长27厘米。外观独特，体羽光泽黑亮，腹部和臀部鲜红，头部和喉部的羽毛尖端呈闪亮的黑色，形成条纹状外观。虹膜淡黄色，喙和腿黑色。两性相似，雌鸟较雄鸟小。幼鸟与成鸟的区别在于黑色部位呈暗褐色，红色部位更偏橙色，大腿和后侧翼棕色，红色羽毛尖端明显；幼鸟类似成鸟，但保留的幼鸟飞羽对比鲜明地呈棕色。","call":"发出响亮的尖叫和咕噜声，叫声音乐感强，包括'peero-peero'的叫声，还有颤音和波动音。鸣唱被描述为'glok-glok-schle-o'，但存在显著的地域差异。联系叫声为尖锐的音符；尖细的'peep'声。","habits":"可能为杂食性，以Cupania果实、Miconia和无花果的浆果为主食，偶尔食用Chusquea竹子的种子。捕食的节肢动物包括蜘蛛、直翅目昆虫和毛虫。雏鸟饮食主要为昆虫。通常在树冠层以不超过30个个体的小群体觅食；有时会与其它山地黄鹂科混合物种觅食群一起，如亚热带酋长鹂、红领果伞鸟和绿蓝鸦。","breeding":"繁殖季节在中部安第斯山脉为1月至5月，其他地方为3月至8月，但也有报道在8月至12月繁殖。单独筑巢，合作繁殖，群体由3至6个个体组成，包括两性的成鸟和幼鸟；报道过群体成员间相互喂食。雌鸟筑巢，巢为大而开放的杯状，由树枝和大型干叶制成，外部直径可达17.3厘米，深度15厘米，置于本土树种（如Cupania、Tibouchina、Miconia）或外来树种（如柏树）的树上或灌木丛中。一巢位于牧场孤立树木的9米高处。每窝产卵2至4枚，蛋壳绿色带灰，有深棕色和紫罗兰色斑点；孵化由雌鸟承担，周期为13至15天；雏鸟由多个群体成员喂养，包括年幼的个体，孵化期为14至18天；离巢雏鸟在巢附近停留约5天。","identification":"红腹拟鹩哥与其他同类物种的区别在于其独特的红腹和明亮的黄色眼睛，以及其叫声的特性。在幼鸟阶段，可以通过暗褐色的黑色部位和更橙色的红色部位来识别。","protection":"IUCN：VU（易危）","distribution":"在哥伦比亚的西北部、中部安第斯山脉和上马格达莱纳河谷间断分布。在哥伦比亚的西部安第斯山脉从塔塔马山脊（Valle del Cauca）向北延伸至安蒂奥基亚省，在中部安第斯山脉从安蒂奥基亚省（历史记录较多，现代记录较少）局部向南至普图马约省，在东部安第斯山脉在南部胡伊拉省和卡奎塔省西部有记录。","other":"主要威胁来自农业、畜牧业、木材和采矿导致的森林砍伐。尽管在1980年代后在当地零星发现，总数量仍然较小且分散，目前估计成熟个体少于1万只。已失去64%的原始栖息地，在2000年至2010年间减少了7.8%。能够适应林缘和旧次生林生存，显示出对森林清理和干扰有一定的容忍度。有时被视为作物害鸟而遭受迫害；有时被捕获用于笼鸟贸易。已知分布范围内至少有七个国家公园，如Cueva de los Guácharos国家公园（胡利亚省）、Las Orquídeas国家公园（安蒂奥基亚省）、Cordillera de los Pichados国家公园（卡奎塔省）和Tatamá国家公园（里斯阿拉尔达省-乔科省-巴勒省）。"},{"name":"绒额拟鹩哥","english_name":"Velvet-fronted Grackle","scientific_name":"Lampropsar tanagrinus","overview":"绒额拟鹩哥（英文名：Velvet-fronted Grackle，学名：Lampropsar tanagrinus），是雀形目拟鹂科绒额拟鹩哥属的鸟类。中等体型的黑色鸟类，是绒额拟鹩哥属的唯一物种。全身羽毛呈黑色，具有金属光泽，额头有一片密集而柔软的羽毛，形成独特的绒面外观。常见于南美洲的湿地环境，如圭亚那高地、亚马逊西部和南部的森林湿地。","appearance":"雄鸟平均长度约为20.3厘米，重约59.4克；雌鸟略小，平均19厘米，重约55.2克。全身羽毛黑亮，带有蓝紫色金属光泽，头部前额的羽毛短而密集，质地类似天鹅绒。喙短而锥形，尾巴长且呈扇形。雌雄羽毛颜色相似，但雌鸟光泽较弱。幼鸟与成鸟相似。","call":"鸣叫声包括刺耳的‘chack’声和尖锐的‘cheziit’哨音，其歌声有时在黄昏时分自枝头发出，是一种快速而略带旋律的咕噜声。","habits":"常栖息于水边，如河流、沼泽、河岸森林和阴凉的种植园，也见于委内瑞拉和圭亚那的红树林。成群活动，通常由3至10只组成，有时可达30只甚至更多。在植被较低和中层觅食，也会在浮水植物上跳跃寻找食物，主要以甲虫和飞蚁为食。","breeding":"繁殖季节在圭亚那为3月，在厄瓜多尔为9月，在玻利维亚为10月和2月。可能为合作繁殖模式。巢由根须构建，放置于树上或灌木丛中，距地面2米左右。每次产卵3枚，蛋壳淡蓝色，带有棕色和黑色斑点，孵化和育雏期未知。","identification":"与其他拟鹂科鸟类相比，本种的暗色眼睛、较短的喙和尾巴形状是识别要点。与紫辉牛鹂的区别在于叫声和栖息习性的差异。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的圭亚那高地、亚马逊西部和南部的森林湿地，包括委内瑞拉、圭亚那、巴西、哥伦比亚、厄瓜多尔、秘鲁和玻利维亚。","other":"能适应适度的栖息地改变，局部地区较为常见。"},{"name":"黄头拟鹂","english_name":"Oriole Blackbird","scientific_name":"Gymnomystax mexicanus","overview":"黄头拟鹂（英文名：Oriole Blackbird，学名：Gymnomystax mexicanus），是雀形目拟鹂科黄头拟鹂属的鸟类。以金黄色头部和黑色背部为主要特征。分布于南美洲北部，包括巴西、哥伦比亚、厄瓜多尔等地的低地森林、湿地及周边环境。","appearance":"成鸟长约30厘米，雄雌外观相似，头部、颈部、肩部和下体呈明亮的黄色，背部、翅膀、臀部和尾巴为黑色，翼下覆羽边缘有一条黄色条纹。眼周环绕着黑色眼环，喙大而尖，脚爪颜色深黑。","call":"发出响亮且粗糙的叫声，如锈链般的嘶哑声，通常在高处或飞行时鸣叫。","habits":"栖息于开阔地带，如草地、沼泽和靠近水源的开放林地，常结成小群。活动范围广泛，以地面觅食为主，偏好湿润地带。食物包括昆虫、两栖类、果实及玉米种子。","breeding":"繁殖季节为5月至6月，筑杯状巢于树上，由干草和杂草茎编织而成，内衬根须。蛋色浅蓝，带有黑色、棕色和淡紫色斑点。孵化期约18天，仅由雌鸟承担。双亲共同喂养雏鸟，提供整只的小型昆虫和青蛙。","identification":"比多数拟鹂体型更大，独特的金黄色与黑色组合，尤其是黑色眼罩和髭纹使其易于识别。","protection":"IUCN：LC（无危）","distribution":"主要分布在奥里诺科盆地和亚马逊北部的森林湿地，遍及委内瑞拉、哥伦比亚、圭亚那、巴西等地。","other":"其种群趋势稳定，由于广泛分布和常见性，未被列入濒危物种名单。"},{"name":"山拟鹩哥","english_name":"Colombian Mountain Grackle","scientific_name":"Macroagelaius subalaris","overview":"山拟鹩哥（英文名：Colombian Mountain Grackle，学名：Macroagelaius subalaris），是雀形目拟鹂科山鹩哥属的鸟类。主要分布在哥伦比亚东部安第斯山脉北部的高海拔地区。其几乎全身黑色，带有蓝色光泽，翼下有一片红褐色斑块，通常隐藏在视线之外。在森林树冠层活动，有时会聚集形成大群。","appearance":"雄鸟体长29-30厘米，雌鸟略小，约27-28厘米。身形纤细，尾巴较长，羽毛近乎全黑，带蓝绿色金属光泽。翼下的腋羽和大部分覆羽呈深红褐色，但野外几乎不可见。虹膜深棕色，喙和腿均为黑色。与相似物种金簇山拟鹩哥的区别在于具有红褐色的翼斑，无黄色胸毛，喙稍厚，体型更瘦长。雌雄外观相似。幼鸟光泽较弱，颜色更暗淡，尤其在飞羽部分，翼下红褐色斑块不明显。","call":"鸣唱变化多样，有时以低沉的咔嗒声和嗡嗡音开始，随后是一系列不同的颤音或哨音主题，每个主题通常重复2-4次。重复的模式使歌声与模仿鸟（Mimus）的歌声有些相似。叫声包括尖锐的“check”和“chuip”音，用于联系。","habits":"生活在富含附生植物的湿润高山森林中，尤其在橡树林（Quercus humboldtii）中，海拔高度在1900至3100米之间。主要以昆虫和其他节肢动物为食，如象鼻虫、直翅目昆虫、半翅目昆虫、膜翅目昆虫和蜘蛛。也吃Oreopanax floribundum和Hedyosmum bonplandianum的浆果。觅食高度通常在15至30米之间，常在叶间、花序和附生植物中寻找食物。成群活动，最多可达40只，有时与其他物种混合觅食。","breeding":"繁殖季节为5月至9月。独巢繁殖，由4-5只个体组成的群体照料巢穴或幼鸟。巢由群组中的多个成员共同建造，开放式的杯子形状，主要材料为干树叶、竹子枝条、草茎和Miconia的干枝，外壁可能包含苔藓，内部衬垫包括蕨类植物茎和棕榈或凤梨纤维。巢通常位于橡树上，有时在Escallonia paniculata或Clethra上，高度5-10米，通常在难以接近的外部树枝或陡峭斜坡上方。关于卵数、孵化期和雏鸟期的信息未知。","identification":"与金簇山拟鹩哥相比，山拟鹩哥的翼下有红褐色斑点，没有黄色胸毛，喙略厚，身体更修长。雌雄相似，幼鸟颜色较暗淡。","protection":"IUCN：EN（濒危）","distribution":"分布于哥伦比亚东部安第斯山脉北部，从Norte de Santander和Santander省（包括Serranía de los Yariguíes山脉）向南到Boyacá省。","other":"由于栖息地丧失，数量急剧减少。在20世纪被从许多地区清除，现在分布零散。栖息地破坏是主要威胁，至少80%的高山橡树林已被砍伐或转变为牧场。"},{"name":"金簇山拟鹩哥","english_name":"Golden-tufted Mountain Grackle","scientific_name":"Macroagelaius imthurni","overview":"金簇山拟鹩哥（英文名：Golden-tufted Mountain Grackle，学名：Macroagelaius imthurni），是雀形目拟鹂科山鹩哥属的鸟类。主要分布于南美洲的特普伊山脉区域，包括委内瑞拉、圭亚那和巴西。其显著特征是全身黑色，翼弯处有黄色羽簇，成年个体较为明亮，而幼鸟则呈暗黑灰色，缺乏黄色羽簇。","appearance":"金簇山拟鹩哥体型中等，雄鸟平均长度28厘米，体重87.3克；雌鸟平均长度25厘米，体重71.7克。羽毛几乎全黑，带蓝绿色光泽，腹部、臀部和飞羽内侧较暗淡。翅膀下覆羽黑色，腋下羽毛颜色从黄色到淡黄色不等，形成胸部羽簇。虹膜颜色从榛色至深棕色。喙和腿均为黑色。幼鸟光泽较弱，尤其是飞行羽部分，颜色更接近灰褐色。","call":"发出多种吱吱声和咯咯声，许多带有强烈的金属质感，不同于特普伊高原上的任何其他鸟类。叫声复杂多变，混合尖锐和沙哑的颤音与悦耳的金属音符，常在飞行中歌唱。常见重复的‘chak’叫声可能作为警报。","habits":"栖息于高海拔的热带湿润森林，偏好生长有丰富常绿树木的环境，如Eschweilera odorata、Guarea silvatica和Euterpe棕榈树等，覆盖着大量凤梨科植物和其他附生植物。在海拔1200米以上，出现在贫瘠砂土上矮化森林中，由Miconia等Melastomataceae科树木主导，附生和陆生凤梨科植物丰富。主要以昆虫、小型脊椎动物和果实为食。通常形成10-30只的单一物种群体。","breeding":"在委内瑞拉，3月开始繁殖。合作繁殖模式。已知巢穴为大型杯状，直径约30厘米，松散构建，位于树冠中，高度约12米。巢中观察到成年鸟喂养雏鸟。","identification":"与相似的山拟鹩哥相比，金簇山拟鹩哥具有黄色胸部羽簇，翅膀中几乎没有栗色，喙较细，体型略粗壮。","protection":"IUCN：LC（无危）","distribution":"分布于委内瑞拉西部和中部亚马逊地区、东南部玻利瓦尔州、巴西最北端的罗赖马州和圭亚那西部。在特普伊山脉的多个国家公园内都有发现，如委内瑞拉的卡奈玛和杜伊达-马哈乌阿卡国家公园、巴西的蒙特罗赖马国家公园和圭亚那的凯特尔国家公园。","other":"金簇山拟鹩哥在当地适宜的环境中数量较为丰富。"},{"name":"南美黑鹂","english_name":"Austral Blackbird","scientific_name":"Curaeus curaeus","overview":"南美黑鹂（英文名：Austral Blackbird，学名：Curaeus curaeus），是雀形目拟鹂科南美黑鹂属的鸟类。分布于南美洲的阿根廷和智利，偏好温带森林、高海拔的亚热带灌木丛和重度退化的旧森林地带。","appearance":"全身呈现出光泽的黑色，拥有较长且尖锐的喙，这一特征在各种开放生境中显得尤为突出，包括城镇公园、带有树篱和灌木的农田、马托拉尔灌木丛和开阔的森林。","habits":"常在地面、花间和树上觅食水果，通常以小群体的形式活动。其鸣声变化多样，有时响亮，容易吸引注意。","identification":"与牛鹂相比，南美黑鹂体型较大，喙部更长。在中央智利较为常见，向南和阿根廷方向数量减少。","distribution":"主要分布在南美洲的南锥体区域，包括阿根廷和智利的大部分地区。"},{"name":"红头黑鹂","english_name":"Scarlet-headed Blackbird","scientific_name":"Amblyramphus holosericeus","overview":"红头黑鹂（英文名：Scarlet-headed Blackbird，学名：Amblyramphus holosericeus），是雀形目拟鹂科红头黑鹂属的鸟类。分布于玻利维亚中部至巴西南部，乌拉圭和阿根廷东部。","appearance":"红头黑鹂体长约24厘米，拥有独特的长而尖锐、略显上翘的喙。成年鸟的头部、胸部和大腿呈鲜艳的橙红色，身体其余部分为深黑色。幼鸟全身黑色，橙红色羽毛首先出现在胸部和喉部，随后逐渐扩展到颈部、头部和大腿。","call":"红头黑鹂的叫声为响亮的下降式哨音，通常由暴露在外的栖木发出，声音清晰而旋律优美。","habits":"红头黑鹂偏好栖息于高大茂密的湿地植被中，如大型芦苇丛。它们以果实为主食，辅以种子和昆虫等无脊椎动物。它们利用喙像锤子一样敲击食物以助进食。","breeding":"红头黑鹂是单配偶制，它们在繁殖季节会聚集领土。巢是一个开放的杯状结构，放置在灌木的分叉处或编织在植被中，每次产卵两枚。","identification":"红头黑鹂最显著的识别特征是其头部、胸部和大腿的鲜艳橙红色与黑色身体的强烈对比，以及其独特的长而尖锐的喙。","protection":"IUCN：LC（无危）","distribution":"红头黑鹂分布于南美，具体包括玻利维亚中部至巴西南部，乌拉圭和阿根廷东部。"},{"name":"福氏黑鹂","english_name":"Forbes's Blackbird","scientific_name":"Anumara forbesi","overview":"福氏黑鹂（英文名：Forbes's Blackbird，学名：Anumara forbesi），是雀形目拟鹂科Anumara的中型黑鹂。其羽毛均匀呈哑光黑色，拥有细长的直喙，分布于南美巴西东部的特定地区。","appearance":"福氏黑鹂是一种中等体型、修长的黑鹂，体长约为21至24厘米。全身羽毛呈均匀的暗黑色，背部和腹部略带褐色或灰暗色调，头部和有时喉部的羽毛具有光泽感。喙尖锐而笔直，上喙无弯曲，虹膜黑色，喙和腿均为黑色。与相似的巴西拟鹂相比，福氏黑鹂体型较小，喙更纤细，上喙笔直且下颌无沟槽。两性外观相似，幼鸟特征尚未详述。","call":"其鸣唱声音较为粗糙，是一种双音鼻音嗡嗡声，基本频率约1.7千赫兹。飞行叫声似‘perelet’，警戒叫声则为咔哒声。","habits":"福氏黑鹂偏好栖息在森林边缘，靠近沼泽地带，甚至出现在甘蔗种植园。在巴西东北部，它们常在芒果树丛中觅食，而在米纳斯吉拉斯州北部，则栖息于湿润的亚热带森林或石灰岩地区的落叶林中。它们也被发现在甘蔗田中活动，最高海拔可达890米。","breeding":"繁殖季节通常在3月至8月，每季可育两窝。营巢行为呈现合作模式，其中一只鸟负责整理巢材，由其他2到3只鸟提供材料。巢呈厚杯状，主要由植物茎构成，有时混合泥土和粪便，直径17厘米，高12厘米，内部直径8厘米，深6厘米，置于离地面3至12米高的树上，尤其偏爱芒果树。产卵数通常为3枚，孵化期12至14天，雏鸟由多个成鸟喂养，寄生现象常见，尤其是被紫辉牛鹂寄生，导致巢穴废弃。","identification":"与巴西拟鹂相比，福氏黑鹂体型更小，羽毛无光泽，喙更细长且直，下颌无沟槽。两者之间可通过上述特征进行区分。","protection":"IUCN：VU（易危）","distribution":"福氏黑鹂分布于巴西东北部的非常局部区域，包括伯南布哥州和阿拉戈斯州，以及米纳斯吉拉斯州北部。在米纳斯吉拉斯州，已知的五个分布点包括杜塞河沿岸和佩尔瓦苏洞穴国家公园边缘。","other":"福氏黑鹂曾因与更常见的巴西拟鹂混淆而被忽视，直到上世纪80年代才被重新发现。目前全球数量估计在1000至2499只之间，且数量可能正在减少。"},{"name":"巴西拟鹂","english_name":"Chopi Blackbird","scientific_name":"Gnorimopsar chopi","overview":"巴西拟鹂（英文名：Chopi Blackbird，学名：Gnorimopsar chopi），是雀形目拟鹂科巴西拟鹂属的鸟类。分布于南美洲东部、东南部及中南部。体长约25厘米，全身羽毛呈均匀的黑色，无光泽，喙部稍弯，具有一条沿下颚的沟槽。叫声丰富，包括模仿多种声音，最常见的是柔和悦耳的‘cho-pee’哨声。","appearance":"巴西拟鹂体型较大，全身羽毛颜色统一为黑色，无金属光泽，喙部略微弯曲，下颚有一条明显的沟槽。与福布斯黑鹂相似，但可通过其独特的喙部形状加以区分。雄鸟、雌鸟及幼鸟羽毛颜色基本一致，体长约25厘米（9.8英寸）。","call":"其鸣叫特征多样，拥有多变的音调，包括大量模仿其他鸟类的声音。最典型的叫声是一种柔和而悦耳的哨声，发音类似其名字‘cho-pee’。","habits":"栖息于森林边缘、林地、草原、农业地带，通常以小群体在地面觅食。食性包括昆虫、果实，甚至有记录显示它们会捕食蛙类和其他小型鸟类。","identification":"与福布斯黑鹂相比，巴西拟鹂的喙部具有轻微的弯曲和下颚沟槽，这是辨识两者的关键特征。","protection":"IUCN：LC（无危）","distribution":"主要分布在南美洲的东部、东南部和中南部，具体包括阿根廷、玻利维亚、巴西、巴拉圭、秘鲁和乌拉圭。"},{"name":"玻利维亚拟鹂","english_name":"Bolivian Blackbird","scientific_name":"Oreopsar bolivianus","overview":"玻利维亚拟鹂（英文名：Bolivian Blackbird，学名：Oreopsar bolivianus），是雀形目拟鹂科Oreopsar的鸟类。体型中等，全身几乎黑色，仅翼羽呈赤褐色，分布于玻利维亚中部和北部的高安第斯山脉干燥山谷。","appearance":"成年玻利维亚拟鹂长约23厘米，雄鸟平均体重73.5克，雌鸟略轻，约66.2克。全身羽毛接近纯黑，仅有轻微光泽，翅膀飞羽呈赤褐色，十分醒目。喙部弯曲，腿脚灰暗色，两性相似，幼鸟上覆羽和下体略带褐色调。","call":"其鸣唱为简单的短‘chip’音符序列，穿插着‘chip-it’音符，比巴西拟鹂的鸣唱更简单、不那么和谐且音调更高。叫声包括联系声‘chu-pee’和飞行叫声‘pee’，类似于栗翅牛鹂和巴西拟鹂。","habits":"偏好植被稀疏的环境，如Polylepis林地、农业区、城镇、仙人掌森林和灌木丛。通常单独或小群体觅食，常在开阔地带的显眼位置歌唱。","breeding":"具体繁殖细节尚待研究，但已知会在悬崖附近筑巢。","identification":"与紫辉牛鹂相比，体型更大，无明显金属光泽；与巴西拟鹂的区别在于翼羽的褐色。叫声和鸣唱与栗翅牛鹂和巴西拟鹂相似。","protection":"IUCN状态未知，需进一步关注。","distribution":"主要分布于玻利维亚，尤其在科恰班巴、波托西省和丘基萨卡省，可能也出现在拉巴斯和奥鲁罗附近的区域，位于1400至3500米的海拔高度。","other":"在灌溉和耕作的土地上常见，甚至出现在农村建筑周边。"},{"name":"栗翅牛鹂","english_name":"Greyish Baywing","scientific_name":"Agelaioides badius","overview":"栗翅牛鹂（英文名：Greyish Baywing，学名：Agelaioides badius），是雀形目拟鹂科栗翅牛鹂属的鸟类。传统上被视为原始的非寄生型牛鹂，曾被归类于Molothrus属。分布于南美洲的中南部地区，包括阿根廷北部、玻利维亚、乌拉圭、巴拉圭及巴西南部和中部。在东北巴西的隔离种群现被认为是独立物种，即纯色栗翅牛鹂。该物种偶尔会流浪至智利。","appearance":"成鸟体长约18厘米，整体呈现灰褐色，具有鲜明的黑色眼纹和红棕色翅膀。面部有更多黑色，整体更为红棕色（而非灰褐色）的是fringillarius亚种。雌雄相似，体重在40到50克之间，嘴短，翼展适中。","call":"鸣唱包含旋律性的哨音，间杂短暂的嗡鸣声，个体间歌声有所差异。","habits":"常栖息于开阔林地、草原和灌木丛地带，亦可见于农田、种植园和城市公园，通常以小群体活动。在大西洋森林地区较为罕见。适应多种半开放环境，如灌木丛和轻度林区。","breeding":"不同于真正的Molothrus属牛鹂，栗翅牛鹂不实行巢寄生，而是自己孵化和抚育后代，有时会有帮手协助。它们还经常照料啸声牛鹂的幼鸟，后者是一种几乎专一寄生于栗翅牛鹂的巢寄生鸟。","identification":"唯一拥有红棕色翅膀的物种，与啸声牛鹂幼鸟在外观上有高度相似性，但啸声牛鹂幼鸟腋下和翼内侧较暗，且翅膀更长。","protection":"IUCN：LC（无危）","distribution":"主要分布在南美洲的中南部，包括阿根廷北部、玻利维亚、乌拉圭、巴拉圭及巴西南部和中部。东北巴西的种群现被视为独立物种。偶尔出现在智利。","other":"与啸声牛鹂有着紧密的繁殖生态关系，后者几乎专一寄生于栗翅牛鹂。"},{"name":"纯色栗翅牛鹂","english_name":"Pale Baywing","scientific_name":"Agelaioides fringillarius","overview":"纯色栗翅牛鹂（英文名：Pale Baywing，学名：Agelaioides fringillarius），是雀形目拟鹂科栗翅牛鹂属的鸟类。中等体型的黑鹂，通身淡褐色并具显著黑色面罩，翼羽呈肉桂色，曾被视为栗翅牛鹂的亚种。分布于巴西东北内陆干旱灌丛与次生林，适应放牧地与农田等人为环境，具合作繁殖习性。","appearance":"体长约17.5厘米，体重约40克。成鸟通体淡沙褐色，臀部更淡；眼周具黑色眼罩，耳羽灰褐；飞羽黑褐但各羽外缘为浓厚肉桂色，使翼面显肉桂色；尾羽暗褐；虹膜深褐；喙与腿黑色。两性同色。幼鸟似成鸟，但羽色偏淡，翼下覆羽色更浅。与模仿栗翅牛鹂幼鸟的啸声牛鹂幼鸟相比，体型较小，翼较短，嘴略小，翼下覆羽色更淡。","call":"鸣唱为缓慢、犹豫的下降哨音与叫声交织，较栗翅牛鹂柔和、哀怨且变化少；群体可合唱。常见粗糙或带摩擦感的“kwoink”等联络叫声，有人形容其叫声类似家麻雀。","habits":"栖息于巴西东北内陆海拔800米以下的干旱灌丛（卡廷加林地）边缘、次生林、牧场及农田，亦见于乡村庄园甚至小镇。留鸟，不迁徙。多在地面觅食，常行走于畜栏、场院与猪圈；食物以种子（玉米、高粱等栽培作物）与节肢动物为主，偶见尝试捕食小蜥蜴。通常成对或组成约20只的小群活动；夜栖时常与栗顶黑鹂、紫辉牛鹂及家麻雀混群。","breeding":"繁殖期北部为1–4月，南部为11–1月，具合作繁殖习性，每巢可多达6只助手。巢为植物纤维、毛发及羽毛构成的杯状巢，通常置于其他鸟类的封闭巢内，尤其是棕额棘雀的巢，偶用棕巨灶鸫或霍托针尾雀的巢，亦见于树洞或棕榈叶基部的缝隙。巢常被紫辉牛鹂寄生。助手负责护巢、驱赶捕食者并运送食物，与草原拟鹂（巢位竞争者及潜在捕食者）的冲突可涉及整群。","identification":"与栗翅牛鹂相比，纯色栗翅牛鹂羽色更淡、面罩更明显，鸣唱亦不同；地理分布亦互不重叠。幼鸟与啸声牛鹂幼鸟区别在于体型更小、翼更短、喙较小且翼下覆羽色更淡。","protection":"IUCN: LC（无危）。","distribution":"繁殖区与非繁殖区均限于巴西东北内陆，自皮奥伊州、塞阿拉州、北里奥格兰德州向南至米纳斯吉拉斯州北部。","other":"分类历史上曾被归入栗翅牛鹂；单型种，无亚种分化。随着啸声牛鹂在巴西北部扩张，未来可能成为其潜在寄主。"},{"name":"黄翅黑鹂","english_name":"Yellow-winged Blackbird","scientific_name":"Agelasticus thilius","overview":"黄翅黑鹂（英文名：Yellow-winged Blackbird，学名：Agelasticus thilius），是雀形目拟鹂科白眼黑鹂属的鸟类。南美洲特有鸟类。主要分布在南美的西南部和中南部，包括阿根廷、玻利维亚、巴西、智利、巴拉圭、秘鲁和乌拉圭等地。黄翅黑鹂最显著的特征是雄鸟的黄色肩羽，这在飞行时尤为明显。","appearance":"雄性黄翅黑鹂平均长度约17.9厘米，体重约33.5克；雌鸟稍轻，平均约28.8克。雄鸟呈暗黑色，具独特的黄色翼缘和较小的上翼覆羽（肩羽），雌鸟则有明显的淡色眉纹，头部和背部棕色带深色条纹，翅膀和尾部黑色，下体淡色带深色条纹。幼鸟外观似雌鸟，但整体更偏棕黄色。","call":"雄性黄翅黑鹂的歌声变化多端，包括3至7个音符的颤音，类似纯蓝黑鹂的叫声，也有类似‘tréé-o-lay’或‘séé-you-there’的哨音，以及以强烈鼻音或嗡嗡声结束的类似颤音。雌雄双方都会发出尖锐的‘chep’叫声。","habits":"黄翅黑鹂主要栖息于沼泽和湿地中的水生植物群落，如香蒲、藨草和芦苇，偶尔出现在稍咸的沼泽。它们在附近的草地和农田中也很常见。这种鸟在浅滩或靠近干燥陆地的水域边缘觅食，主要以昆虫和种子为食。","breeding":"繁殖季节在智利和阿根廷通常为10月至12月。黄翅黑鹂似乎是单配偶制，群居繁殖，巢由雌鸟建造，通常由湿草、香蒲或其他沼泽植物构成。巢高不超过1米，多位于藨草床中，每窝产2至4枚蛋，孵化期约为12至13天，幼鸟由双亲喂养，巢期大约10至12天。","identification":"黄翅黑鹂的雄鸟黄色肩羽是其最显著的识别特征，尤其是在飞行时更为明显。雌鸟与雄鸟的差异在于颜色和条纹的细节。","protection":"IUCN：LC（无危）","distribution":"黄翅黑鹂在南美洲的西南部和中南部广泛分布，包括阿根廷、玻利维亚、巴西、智利、巴拉圭、秘鲁和乌拉圭。在阿根廷，其繁殖范围至少延伸到圣胡安德尔埃斯特罗、圣塔菲和可能的科连特斯南部。在巴拉圭，它是非繁殖季的稀有访客。","other":"黄翅黑鹂的巢常被寄生，尤其是的雏鸟，黄翅黑鹂能成功抚养这些寄生雏鸟。"},{"name":"白眼黑鹂","english_name":"Pale-eyed Blackbird","scientific_name":"Agelasticus xanthophthalmus","overview":"白眼黑鹂（英文名：Pale-eyed Blackbird，学名：Agelasticus xanthophthalmus），是雀形目拟鹂科白眼黑鹂属的鸟类。具有独特的白色或淡黄色眼睛，黑色光泽的羽毛，以及尖锐的黑色喙。分布于亚马逊地区的厄瓜多尔和秘鲁低地，常见于湿地和牛轭湖边缘的草丛中。","appearance":"成年白眼黑鹂全身呈黑色，无论雌雄。其最显著的特征是拥有白色或浅黄色的眼虹膜，这与周围暗色的眼睛形成鲜明对比，使它容易与其他黑鸟区分开来，如绒额拟鹩哥和闪亮牛鹂。幼鸟和未成熟的个体则呈现褐色黑色，腹部带有黄色或淡色条纹。","call":"白眼黑鹂的叫声响亮且具金属质感，通常被描述为一系列的“tew-tew-tew-tew”声，与黑顶鹪莺的叫声类似。这种叫声常从灌木顶端发出。","habits":"白眼黑鹂偏好湿地环境，如湖泊周边和牛轭湖边缘的草丛地带。它们一般单独、成对或小群体活动，白天大部分时间在茂密的低矮植被中度过。清晨时，它们会出现在较开阔的区域觅食，此时也是听到其歌唱的最佳时机。","identification":"白眼黑鹂通过其独特的浅色眼睛、较长且更尖锐的喙以及相对较短的尾巴，与绒额拟鹩哥和其他类似黑鸟种类相区别。","protection":"IUCN：LC（无危）","distribution":"白眼黑鹂分布于亚马逊盆地的东部厄瓜多尔和秘鲁，特别是在该地区的湿地和牛轭湖附近。自1969年首次发现以来，它在厄瓜多尔纳波河附近的利蒙科查国家生物保护区和秘鲁马德雷德迪奥斯河附近的坦博帕塔国家保护区被频繁观察到。"},{"name":"纯蓝黑鹂","english_name":"Unicolored Blackbird","scientific_name":"Agelasticus cyanopus","overview":"纯蓝黑鹂（英文名：Unicolored Blackbird，学名：Agelasticus cyanopus），是雀形目拟鹂科白眼黑鹂属的鸟类。广泛分布在南美洲的巴西中南部、东部，以及阿根廷、玻利维亚和巴拉圭的部分地区。以沼泽和邻近的草地为其自然栖息地。","appearance":"雄性纯蓝黑鹂全身羽毛呈现光泽的黑色，深邃的眼睛与其漆黑的外表相呼应。而雌鸟则展现性二型性，羽毛呈条纹状的棕色与黑色交织，腹部点缀着黄色条纹。雌鸟的面部有深色面罩，翅膀为红褐色边缘带黑色。来自亚马逊下游地区和巴西东南部的雌鸟，颜色相对暗淡，翅膀的红褐色和腹部的黄色较浅。其腿、眼睛虹膜皆为黑色，喙长而尖锐。雄鸟可能与绒额拟鹩哥或巴西拟鹂混淆。","call":"纯蓝黑鹂的叫声为响亮的‘tchew-tchew-tchew’声，通常从高处发出，此外还会发出一系列音调和音高各异的颤音和噼啪声。","habits":"纯蓝黑鹂常以成对形式出现，相较于栗顶黑鹂，它在沼泽环境中显得不那么群居。它们在浮水植被上活动，穿梭于芦苇丛中觅食，始终不会远离水源。其栖息范围从南美的北部玻利维亚和巴西南部延伸至阿根廷北部，包括亚马逊河下游的广大区域，海拔高度可达约600米（2,000英尺）。在巴西潘塔纳尔湿地，尤其常见。","identification":"雄性纯蓝黑鹂与绒额拟鹩哥或巴西拟鹂在外形上有相似之处，需仔细辨别。","protection":"IUCN：LC（无危）","distribution":"纯蓝黑鹂的分布集中在南美洲，具体而言，其栖息于巴西中南部、东部，以及阿根廷、玻利维亚和巴拉圭的特定区域，主要在亚马逊河下游地带活动。"},{"name":"栗顶黑鹂","english_name":"Chestnut-capped Blackbird","scientific_name":"Chrysomus ruficapillus","overview":"栗顶黑鹂（英文名：Chestnut-capped Blackbird，学名：Chrysomus ruficapillus），是雀形目拟鹂科栗顶黑鹂属的中等体型的鸟类。分布于南美洲东北部和中南部，常见于沼泽、稻田和湿润草地。雄鸟头部和喉部呈深栗色，其余部位黑色略带蓝光泽；雌鸟上部暗橄榄棕色，下部淡橄榄棕色，喉部至胸淡黄褐色。群体生活，可达千余只。","appearance":"雄鸟平均体长18.5厘米，体重41.3克；雌鸟平均体长17.1厘米，体重32.2克。雄鸟指名亚种头部、喉部及上胸深暗栗色（光线不佳或距离远时看似黑色），其余羽毛黑色，微泛蓝光泽。雌鸟上部暗橄榄棕色，具模糊的黑褐色条纹；喉部至胸淡黄褐色至淡红褐色，下体暗橄榄黄褐色，具淡暗条纹。幼鸟似雌鸟，但更淡，更偏棕黄色，上翼覆羽边缘更暖棕色，下体条纹更重。","call":"雄鸟有两种歌曲类型，有时交替演唱：一种以咔哒声、颤音或哨声开始，以降调鼻音嗡嗡结束；另一种音乐性较强，或一系列响亮、短促、颤音围绕固定音高，或类似竖笛的音符上升。北部亚种frontalis的歌曲与指名亚种相似，但音质更粗糙。群唱普遍。","habits":"栖息于沼泽、稻田、湿草地和农业用地；会侵入新淹没的地区。在开放林地附近出现，有时在树上筑巢和栖息。移动模式与旱季和洪水有关，特别是在范围南缘。食物包括种子、昆虫和蜘蛛。群体觅食，数量可达数千。","breeding":"繁殖季节为11月至3月在巴西中部和东南部（两亚种）和4月至5月在东北部（frontalis亚种）。雄鸟筑杯状巢，由湿植物材料制成，外部直径9-12.5厘米，深度8-10厘米，位于水生植物中，如巨藨草、香蒲、杜鹃果等。每窝产3-4枚蛋，淡蓝色带少许黑色斑点，平均尺寸23.4 x 17毫米。雌鸟孵卵，孵化期13天；雏鸟主要由雌鸟喂养，留巢期13天。","identification":"雄鸟头部和喉部的栗色是辨识关键。与同属其他物种相比，背部条纹较不明显。北部亚种frontalis头部和喉咙颜色更浅，喙基部有窄黑带。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲东北部和中南部，包括阿根廷、玻利维亚、巴西、法属圭亚那、巴拉圭和乌拉圭。在巴西中部和东北部、阿根廷东北部、乌拉圭和巴拉圭广泛分布。","other":"在稻田被视为农业害鸟，但控制措施未见成效。在自然保护区常见，如Amboró国家公园（玻利维亚）、Pantanal Mato-grossense国家公园（巴西）等。"},{"name":"黄巾黑鹂","english_name":"Yellow-hooded Blackbird","scientific_name":"Chrysomus icterocephalus","overview":"黄巾黑鹂（英文名：Yellow-hooded Blackbird，学名：Chrysomus icterocephalus），是雀形目拟鹂科栗顶黑鹂属的鸟类。雄鸟在分布区内特征明显，通体几乎全黑，头部鲜黄；雌鸟暗橄榄色，上胸最亮黄色。喙粗尖，典型黑鹂特征。分布于南美洲北部和中部，偏好湿润栖息地，尤其在湖泊或河流边较为常见，通常数量不多，成对或小群出现。","appearance":"雄性黄巾黑鹂身长约17至19厘米，平均重35.9克，头至喉部及上胸亮黄色，眼纹黑色，余下羽毛光泽黑色，眼虹膜深棕色，喙与腿黑色。雌鸟上眉线至喉部及上胸黄色，脸与冠金黄色，上体灰橄榄色带暗色条纹，翼与尾较深，呈棕橄榄色；下体橄榄色，腹部更偏褐色，隐约可见橄榄色条纹，喙黑色，下颚基部常较浅。幼鸟似雌鸟，但色泽更暗淡，头部黄色较少，上体颜色较浅，腹部模糊条纹；亚成年雄鸟似雌鸟，但喉咙黄色更鲜艳，范围更广，可能在体下部和上部显示黑色羽毛。bogotensis亚种体型大于指名亚种，雌鸟颜色更深，头部黄色减少，眼纹至耳羽处黑色面具强烈对比，长长的黄色眉线环绕耳羽，与黄色围兜相接。","call":"雄鸟有两种歌曲类型，一种由短音符或哨声后跟刺耳的嗡嗡声组成，另一种是更变化多端且悦耳的颤音或哨声序列；两种类型可能交替出现；歌声结构类似于栗顶黑鹂雄鸟，但音调更为刺耳，音乐感较差。群体歌唱频繁。叫声“chek”，另有一下降的哨声。","habits":"黄巾黑鹂栖息于靠近水源的草地和灌木区，主要在草丛和植被中觅食，偶尔在地面。在非繁殖季节，它们往往以较大的群体出现，有时可达数百只。雌鸟在繁殖季节通常在雄鸟领地之外寻找食物，而bogotensis亚种的雌鸟则在领地内获取食物。","breeding":"饮食主要包括种子和昆虫，其中栽培稻米很重要；也会食用野生稻(Oryza perennis)。昆虫食物包括毛虫(Lepidoptera)和象鼻虫(Curculionidae)。雏鸟的食物主要是昆虫，尤其是螽斯(Tettigoniidae)和其他直翅目昆虫。","identification":"黄巾黑鹂雄鸟在分布区内独特，雌鸟暗橄榄色，头部黄色较浅，与同类物种区分明显。与北美的黄头黑鹂相似，但后者翼上有白色标记。","protection":"IUCN：LC（无危）","distribution":"主要分布在南美洲北部和中部，包括Darien Lowlands等地。","other":"2007年，一例罕见迷鸟出现在巴拿马的Darien Lowlands，很可能来自哥伦比亚。"},{"name":"橙头黑鹂","english_name":"Saffron-cowled Blackbird","scientific_name":"Xanthopsar flavus","overview":"橙头黑鹂（英文名：Saffron-cowled Blackbird，学名：Xanthopsar flavus），是雀形目拟鹂科橙头黑鹂属的唯一物种。拥有鲜艳的黄色下体和黑色或深褐色上体，分布于南美洲的东部巴拉圭、南部巴西、东北部阿根廷及乌拉圭，特别是在Quebrada de los Cuervos地区。其自然栖息地为亚热带或热带低地干旱草原、季节性湿润或洪水泛滥的低地草原及牧场，正面临因栖息地丧失带来的威胁。","appearance":"雄性橙头黑鹂的后颈至背部呈光泽的黑色；面部、腹部及臀部为黄色，前额和胸部带有橙色色调；具有醒目的黄色肩斑，由较小和边缘的上翼覆羽形成，下翼也有相似的图案；臀部黄色；大腿黑色，最末端的下尾羽覆盖物黑色，尖端黄色；虹膜橙棕色至深红棕色；喙和腿黑色。雌鸟的黑色部分被褐色取代。幼鸟类似雌鸟，臀部柠檬黄色；一年生雄鸟可能保留头部和上体混有黑色和黄色的棕褐色羽毛。","call":"两性皆会发出短暂而单调的歌声，开始时为短促的哨声或颤音，以粗糙的‘kluijjjjjj’结尾。最常见的叫声为‘chep’；在繁殖期间，会发出报警哨声。","habits":"常与水相伴，出没于沼泽和自然草地，通常群居于地面觅食。在阿根廷潘帕斯的无树区域，但在其他地方能容忍一些树木植被的存在。在巴拉圭东南部，生活于开阔草地（campos）与大西洋森林内部的突然交界处，栖息在广阔的自然草地和沼泽中，周围被密集的亚热带森林或竹子Bambusa angustifolia林立。也在稻田中出现，甚至在繁殖季节。在乌拉圭的Entre Ríos，占据起伏的乡村地带，土壤肥沃，大部分被农田和牛牧场覆盖。在巴西的Rio Grande do Sul高地，发现于靠近Araucaria森林的草地。海拔高度可达1000米。","breeding":"繁殖季节为10月至12月，繁殖活动通常同步发生；似乎单窝繁殖。单独筑巢或在小型群体中繁殖，每群约有30-40个巢，位于浅沼泽或废弃的稻田，有时在干燥的土地上（如阿根廷的大部分Entre Ríos）。存在可能的合作繁殖现象，雄鸟在巢边提供帮助。巢由雌鸟建造，是一个开放的杯状结构，主要由植物材料构成，如草茎和叶片，内部衬有植物纤维，直径12-15厘米，深度7-8厘米，置于距地面高达1米的沼泽植物如Ludwigia、水生草、莎草Rhynchospora corymbosa或草本植物中，包括刺蓟Cirsium vulgare和野蓟Dipsacus fullonum，或低矮灌木如Baccharis中。少数巢建在地上。每次产卵3-5枚，通常为4枚，颜色淡，布满砖红色斑点；仅雌鸟孵化，有时由雄鸟喂食，孵化期12-13天；双亲共同防御巢穴并喂养雏鸟，育雏期通常为12天。巢被寄生；在乌拉圭的Entre Ríos，寄主雏鸟数量在繁殖后群体中超过寄生雏鸟。","identification":"雄性橙头黑鹂的黑色后颈和上背，黄色带橙色调的面部、腹部及臀部，以及独特的黄色肩斑是其显著特征。雌鸟和幼鸟的黑色部分被褐色取代，臀部柠檬黄色。与同属物种区别明显，可通过上述特征识别。","protection":"IUCN：EN（濒危）","distribution":"分布于南美洲东部巴拉圭、南部巴西（从圣卡塔琳娜州）、东北部阿根廷（科连特斯和Entre Ríos）和乌拉圭；曾经广泛分布。","other":"由于非法捕捉笼鸟贸易、大规模自然草地替换为松树Pinus和桉树Eucalyptus种植园导致的栖息地破坏、湿地排水、季节性火灾影响以及寄生等问题，橙头黑鹂的数量正在迅速下降。"},{"name":"褐黄沼泽雀","english_name":"Brown-and-yellow Marshbird","scientific_name":"Pseudoleistes virescens","overview":"褐黄沼泽雀（英文名：Brown-and-yellow Marshbird，学名：Pseudoleistes virescens），是雀形目拟鹂科沼泽雀属的大型鸟类。其显著特征是深棕色的身体与鲜明的黄色腹部形成对比，常见于南美洲阿根廷东北部、巴西南部及乌拉圭的湿地、湿草地及偶尔出现在农田中。","appearance":"褐黄沼泽雀体长约24厘米，雄鸟平均体重79.6克，雌鸟平均体重72.9克。头部至胸上部、背部及大部分翅膀呈深棕至橄榄棕色，小翼羽和翼弯处为鲜艳的黄色，形成微小的肩饰，在飞行中可见。尾巴深棕至橄榄棕色，下胸至腹部为鲜艳的黄色，两胁、大腿及尾下覆羽为橄榄棕色。虹膜为棕色，喙和腿为黑灰色。雌雄外观相似。幼鸟类似成鸟，但喉部略带黄色，胸部有淡黄色和棕色条纹，下颌黄色，这种羽毛仅持续很短时间。","call":"褐黄沼泽雀叫声嘈杂，歌曲由呼叫音符混合而成，一系列尖锐的叽叽喳喳音符与上升或罕见下降的哨声混杂。常见的叫声是由两性发出的响亮重复的‘chrrr-wéé’，通常在群体出发前合唱；通常的警报叫声是一种响亮的木制咔哒声。群体间频繁的叫声，即使在飞行中也是如此。","habits":"褐黄沼泽雀栖息于地面，以昆虫和其他节肢动物为主食，偶尔食用小型脊椎动物和种子。它会探查土壤或低矮植被中的猎物，甚至翻转物体（如牛粪）寻找隐藏的食物。非繁殖季节时，群体可达40-50只，通常会留下一些个体担任哨兵。它们与其它地栖的拟鹂科鸟类，如牛鸟和，以及同属物种黄腰沼泽雀一同觅食。","breeding":"繁殖季节在阿根廷为8月至12月，比同域的拟鹂科鸟类早开始筑巢，最早的小鸟在9月底就能离巢。它们是合作繁殖者，最多可有六个帮手。通常以小群体或群落形式繁殖，巢间距变化大，有时仅相隔4米。巢大多由雌鸟建造，用植物材料和泥土混合制成，内衬根须和细草，位于低矮的草本植物中，如潘帕斯草、引进的蓟类（Cynara和Carduus）、香蒲（Typha）或类似的植物，或低矮灌木或小树（Sambucus australis，Celtis spinosa）中。每窝产3-6枚白色带有红棕色斑点的蛋，孵化期14天，主要由雌鸟负责，常由配偶喂食。幼鸟由双亲及助手喂养，离巢期11-12天。离巢后，大多数幼鸟和家庭成员会加入繁殖后的群体。巢穴可能被和寄生，帮助养育这些寄生鸟的幼鸟。","identification":"与黄腰沼泽雀相比，褐黄沼泽雀外观更偏棕色，色彩较少，且臀部为棕色。可以通过颜色差异和叫声进行区分。","protection":"IUCN：LC（无危）","distribution":"主要分布在南美洲的阿根廷东北部、巴西南部和乌拉圭，繁殖区域与非繁殖区域一致。"},{"name":"黄腰沼泽雀","english_name":"Yellow-rumped Marshbird","scientific_name":"Pseudoleistes guirahuro","overview":"黄腰沼泽雀（英文名：Yellow-rumped Marshbird，学名：Pseudoleistes guirahuro），是雀形目拟鹂科沼泽雀属的鸟类。中等体型的拟鹂科鸟类，分布于南美的阿根廷、巴西、巴拉圭和乌拉圭。其最显著的外部特征是黄色的腹部、腰部、臀部和肩部，头部至胸部呈黑褐色，背部为棕色，性成熟个体间差异不大，而幼鸟则整体更显棕色。","appearance":"雄鸟平均体长25.5厘米，体重91.2克；雌鸟平均体重81.9克。头部至胸上部颜色为黑褐色，其余背部为棕色，突出的是鲜艳的黄色臀部；翅膀和尾巴大部分为棕色，较小和中等的上翼覆羽为鲜黄色，下体自胸下至腹下部为鲜黄色，尾下覆羽棕色，边缘略带黄色；虹膜为棕色，喙和腿为黑色。与相似物种相比，主要区别在于黄色臀部、黄色侧腹，整体颜色更深的棕色和更为鲜明的对比度。雌雄相似，幼鸟与成鸟类似，但上体较暗淡且更棕色，有些羽毛边缘较浅，喉部黄色（有时耳羽也有黄色），下方黄色较浅，胸部有宽的棕色条纹。","call":"鸣唱包含口哨声、颤音、滑音和鼻音嗡嗡声，通常比的鸣唱节奏更慢，声音更柔和悦耳。群聚时常见鸣叫。常见的叫声有'kwet-kwetéé'和'koink'。飞行中常鸣叫和歌唱。","habits":"栖息于干燥草原、沼泽和牧场地带，以昆虫和其他节肢动物、小型脊椎动物及部分种子为食。曾在巴拉圭发现其胃内容物包含蝽（半翅目）和甲虫（鞘翅目）。有时会进食收割机遗撒的稻米。在地面和低矮植被中觅食。具有发达的哨兵行为。非繁殖季节时，可见50只左右的大群体；有时与其他黑鸟科鸟类，尤其是一起活动。","breeding":"黄腰沼泽雀是群居鸟类，全年形成10-20只的群落。从9月到11月，可观察到单个配对的沼泽雀，标志着繁殖周期的开始。一只鸟负责收集筑巢材料，检查巢址，筑巢，另一只则发出短暂的歌声。产卵后，可见3-4只成年沼泽雀守护巢穴，为雏鸟带来食物，表明黄腰沼泽雀是典型的合作繁殖者。","identification":"与褐黄沼泽雀的主要区别在于黄色臀部、黄色侧腹，整体颜色更深的棕色和更为鲜明的对比度。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的东部巴拉圭、南部巴西、东北部阿根廷和乌拉圭。"},{"name":"橙顶灶莺","english_name":"Ovenbird","scientific_name":"Seiurus aurocapilla","overview":"橙顶灶莺（英文名：Ovenbird，学名：Seiurus aurocapilla），是雀形目森莺科灶莺属的鸟类。北美森林中常见的鸣禽，以其响亮而熟悉的“教师…教师…”歌声著称，雄鸟在繁殖季节频繁鸣唱。体羽橄榄棕色，头顶橙色条纹，胸部斑点，与林下层环境融为一体，更常闻其声而少见其影。以地面落叶中的节肢动物为食，巢穴隐蔽于地面，由叶子搭建，形似穹顶状的炉灶，因而得名。","appearance":"体长约15厘米，体重约21克，大型新世界鸣禽。上体橄榄灰绿色，下体白色，胸部和两侧有明显的黑色条纹。腿呈粉红色，两性相似。头顶有一线橙色羽毛，边缘橄榄绿，两侧以黑色条纹为界。幼鸟的冠羽尖端橄榄绿更宽，有时几乎或完全遮盖橙色条纹。秋季幼鸟色彩较淡，次级飞羽边缘浅黄色至暗褐色。","call":"主歌是一系列响亮、低沉的双音节动机，连续重复约八次，音量逐渐增大。黄昏时，雄鸟会发出甜美的叽叽喳喳的空中歌曲，融入部分主歌旋律。","habits":"栖息于成熟阔叶林和混交林，偏好少灌木丛生的地区。在冬季，主要生活在中美洲、西印度群岛、北委内瑞拉等地的低地，但也可上升至海拔1500米。全年领域性，单个或成对出现，迁徙期间形成较大群体。以地面的节肢动物和蜗牛为主食，冬季也会吃水果。","breeding":"巢为地面的穹顶结构，侧边有入口，通常由雌鸟筑造。产卵数4-5枚，斑点为棕或灰色，仅雌鸟孵卵，孵化期11-14天。雏鸟晚熟，双亲共同喂养，首次离巢时间为8-11天。","identification":"与水莺（Parkesia属）较为相似，但可以通过白色眼环、橙色头冠两侧的黑色条纹、缺乏淡色眉纹、圆润体型和橄榄绿色背部加以区分。","protection":"IUCN：LC（无危）","distribution":"繁殖于加拿大北部、中部和美国东部；非繁殖期分布于中美洲、西印度群岛、墨西哥至北南美洲北部，包括佛罗里达。","other":"曾有少量记录显示，橙顶灶莺可能有能力跨越大西洋，出现在挪威、爱尔兰和英国。"},{"name":"食虫森莺","english_name":"Worm-eating Warbler","scientific_name":"Helmitheros vermivorum","overview":"食虫森莺（英文名：Worm-eating Warbler，学名：Helmitheros vermivorum），是雀形目森莺科食虫莺属的唯一物种，以橄榄色、棕色和淡褐色为主色调，头部具有黑色和浅棕色条纹，长喙锐利，腿呈粉色。分布于北美东部，在成熟落叶林和混合林中筑巢，尤其偏好陡峭干燥的山坡地带。冬季迁徙至中美洲和加勒比海地区。与黑白森莺、橙顶灶莺、黄眉灶莺、白眉灶莺和黄腹地莺等同为地面筑巢的森林鸣禽。","appearance":"体长约13厘米，重11.8至17.4克，上身橄榄棕色，下身颜色较淡，头部有黑色和浅棕色条纹。喙尖而细长，腿粉色。幼鸟头纹呈棕色。雄鸟和雌鸟外观相似，仅在繁殖季节通过雌鸟的孵卵斑和雄鸟的泄殖腔突起来区分性别。","call":"雄鸟的鸣唱为高音的颤音，类似于松莺，但音质更尖锐。叫声为短促的‘chip’或‘tseet’声。","habits":"栖息于茂密的落叶林，偏爱斜坡地形。繁殖期间在地面筑巢，隐藏于枯叶之中。饮食以昆虫为主，尤其是鳞翅目幼虫。冬季迁徙至中美洲和加勒比海地区的灌木丛和湿润森林。","breeding":"巢为开放式的杯状结构，通常置于地面。每窝产卵4至5枚。双亲共同育雏，通过假装受伤吸引远离巢穴附近的捕食者。可能受到褐头牛鹂寄生的影响。","identification":"与斯温森森莺相比，可通过头部条纹（斯温森森莺冠部红褐色，食虫森莺头部条纹）和栖息习惯（斯温森森莺常在地面，食虫森莺在低矮的灌木层）区分。","protection":"IUCN：LC（无危）","distribution":"繁殖区位于北美东部，非繁殖期则迁徙至中美洲和西印度群岛，包括加勒比海沿岸的湿润森林和灌木丛。","other":"适应力较强，能利用多种森林类型，如沿海松树林。其栖息地选择与灌木结构紧密相关，而非林龄或规模。"},{"name":"白眉灶莺","english_name":"Louisiana Waterthrush","scientific_name":"Parkesia motacilla","overview":"白眉灶莺（英文名：Louisiana Waterthrush，学名：Parkesia motacilla），是雀形目森莺科眉纹灶莺属的鸟类。以其响亮而回荡的歌声闻名。这种鸟主要栖息于溪流边，偏好快速流动的溪水环境，其歌声能够穿越持续的流水声。繁殖季节主要在美国东部和加拿大南部，冬季则迁徙至中美洲和西印度群岛。","appearance":"体型较大的新世界森莺，平均重量约20克，背部呈橄榄棕色，腹部白色，带有黑色条纹，侧面和下尾覆羽呈淡黄色。拥有显著的白色眉纹，腿脚粉红色，雌雄羽色相似，幼鸟下部羽毛偏黄。比黄眉灶莺略大，具有更宽的白色眉纹和更亮的腿脚颜色。","call":"鸣唱由一系列清晰的哨音开始，随后是一段复杂且抑扬顿挫的音符串，叫声为响亮的金属质感的“chink”。","habits":"栖息于森林中的急流溪边，偏好岩石密布的溪流环境。在迁徙和冬季，它们可能会远离林地湿地，在洪水淹没的道路、公园、草坪和花园等地觅食。它们在行走时会不断摆动尾巴。","breeding":"繁殖期为5月至6月，巢建在岩石缝隙、泥岸或树根之间，每次产卵4至6枚。双亲共同筑巢，雌鸟负责孵卵，孵化期约为12至13天，雏鸟出壳后9至10天离巢，之后双亲继续喂养4周。","identification":"与黄眉灶莺的区别在于更宽阔的白色眉纹，更明亮的腿脚颜色，以及更白的下部羽毛，喉部通常无斑点。鸣唱起始音调下降，而黄眉灶莺的鸣唱音调变化不大。","protection":"IUCN：LC（无危）","distribution":"繁殖于美国东部，冬季迁徙至中美洲和西印度群岛，偶尔作为稀有迷鸟出现在美国西部。","other":"早期迁徙者，春季返回繁殖地的时间比大多数其他森莺早约两个月，秋季离开繁殖地的时间也较早，部分个体最早可在7月离开。"},{"name":"黄眉灶莺","english_name":"Northern Waterthrush","scientific_name":"Parkesia noveboracensis","overview":"黄眉灶莺（英文名：Northern Waterthrush，学名：Parkesia noveboracensis），是雀形目森莺科眉纹灶莺属的鸟类。以地面觅食为主。主要分布在北美的加拿大、美国北部和阿拉斯加，冬季则迁往中美洲、西印度群岛、佛罗里达，以及南美洲的委内瑞拉、哥伦比亚和厄瓜多尔。其近亲为白眉灶莺。这种鸟在头部有明显的白色眉纹，背部呈均匀的棕色，腹部有深色条纹，喉咙部分有较轻的条纹。两性在外形上相似，但幼鸟的下体颜色更偏向于淡黄色。","appearance":"黄眉灶莺体长12至15厘米，翼展21至24厘米，体重介于13至25克之间。头部的冠羽呈棕色，有一条显著的白色眉纹。喙尖且暗色，喉部有轻微的褐色至黑色条纹，胸部和侧翼上的条纹更为明显。背部颜色均匀，呈棕色。雌雄鸟在外形上难以区分。幼鸟的下体颜色较成鸟更偏黄色。","call":"其鸣唱为响亮、强调且清晰的唧唧声，通常音调下降并加速，可以是成对或三重音节，变化不大。叫声为响亮而坚硬的‘spwik’，带有强烈的K音。飞行叫声为高音且略微上升的‘zzip’。","habits":"黄眉灶莺偏好湿地环境，包括沼泽、池塘、溪流附近的树林。它们在冬季会飞往热带地区的红树林中过冬。它们的觅食方式独特，通过地面行走而非跳跃，移动时会摇晃臀部。在繁殖季节，它们倾向于在浓密的灌木丛、密集的泥炭沼泽或水流缓慢水域周围的桤木洼地活动。","breeding":"黄眉灶莺的繁殖地通常位于靠近水源的湿林地带。它们会在树桩或树根间筑巢，巢由树叶、树皮碎片和细根构成，内部铺垫柔软材料。每窝产3至6枚蛋，蛋壳呈奶油色或浅黄色，带有棕色和灰色斑点。","identification":"与白眉灶莺相比，黄眉灶莺的体型稍大，嘴较小，眼线较窄且颜色更深，下体颜色更黄。此外，黄眉灶莺的腿色较为暗淡，不像白眉灶莺那样粉红。叫声和习性也是区分两者的线索。","protection":"IUCN：LC（无危）","distribution":"繁殖区域覆盖了北美的加拿大、美国西北部和东北部，包括阿拉斯加。非繁殖区域包括中美洲、西印度群岛、南美的北部地区，具体到委内瑞拉、哥伦比亚和厄瓜多尔。","other":"黄眉灶莺曾被记录在欧洲的罕见迷鸟，首次记录是在1955年的法国乌桑特岛，而在英国的首次记录则是在1958年圣阿格尼斯岛。"},{"name":"黑胸虫森莺","english_name":"Bachman's Warbler","scientific_name":"Vermivora bachmanii","overview":"黑胸虫森莺（英文名：Bachman's Warbler，学名：Vermivora bachmanii），是雀形目森莺科虫森莺属的鸟类。又名: 黑眼纹虫森莺，亦称黑眼纹虫森莺，是北美特有的一种森莺，这种鸟类栖息于美国南部的沼泽和低地森林，为候鸟，冬季迁徙至古巴。其显著特征包括黄色额头、黑色冠顶和喉部，以及独特的灰绿色背部。尽管自19世纪以来受到持续关注，但关于它的硬数据稀少，使其成为神秘而引人入胜的研究对象。","appearance":"成年雄性黑胸虫森莺具有鲜明的外观特征：黄色额头、黑色冠顶、灰色颈背、黄色眼圈，以及黑色喉部斑块。雌鸟的颜色较为柔和，通常缺乏深色喉部斑块，拥有淡色眼圈、亮黄色或淡黄褐色额头，以及灰色冠顶上无黑色。两性皆有细长且略弯曲的喙，这一特征在该属中独一无二。幼鸟的羽毛较为暗淡，可能与其它相似的林莺混淆。","call":"已记录到的鸣唱由一系列快速的六至二十五个嗡鸣音组成，有时以尖锐、滑音的吱声结尾。","habits":"黑胸虫森莺偏好栖息于带有静水池塘的底部森林沼泽地带，主要由落叶树种构成，如柏木、甜胶树、山茱萸、红橡、山核桃、黑胶树和紫油木。它们在春季倾向于高处歌唱，而觅食时则在低至地面3至10英尺的高度范围内。主要食物包括毛虫、蜘蛛和其他节肢动物。在迁徙期间，它们也会在树顶觅食。","breeding":"黑胸虫森莺可能集体繁殖，巢穴深而大，由死叶、苔藓、草和杂草茎组成，内部以Ramalina地衣和西班牙苔藓的细纤维衬垫。巢筑于黑莓灌丛、竹子和棕榈树丛中，离地面或静水池塘约1至4英尺高。卵为纯白色，偶尔顶部有细微标记。","identification":"黑胸虫森莺的识别主要依赖于其独特的头部图案，包括黄色额头、黑色冠顶和喉部斑块。雌鸟和幼鸟的颜色较浅，可能与其它林莺种类混淆。成年雌雄之间主要通过颜色差异辨识。","protection":"IUCN：CR (PE)（极危（可能已灭绝））","distribution":"繁殖区域主要位于美国东南部，包括南卡罗来纳州近查尔斯顿地区。非繁殖季节则迁移至古巴，以及巴哈马的个别记录。最后一次确认的目击是在1988年的路易斯安那州。","other":"尽管曾有零星的目击报告直至20世纪80年代，但黑胸虫森莺的最后确凿记录发生在1960年代。"},{"name":"金翅虫森莺","english_name":"Golden-winged Warbler","scientific_name":"Vermivora chrysoptera","overview":"金翅虫森莺（英文名：Golden-winged Warbler，学名：Vermivora chrysoptera），是雀形目森莺科虫森莺属的鸟类。分布于北美东部的珍稀新世界森莺。其繁殖范围主要在加拿大东南部和美国中北部及东北部，特别是在阿巴拉契亚山脉和中北美的部分区域。全球约70%的种群在威斯康星州、明尼苏达州和曼尼托巴省繁殖。金翅虫森莺的种群正逐渐向北扩展，但总体上呈现下降趋势，可能与栖息地丧失和与近缘物种蓝翅虫森莺的竞争及杂交有关。目前，种群分布限于大湖地区和阿巴拉契亚山脉，其中阿巴拉契亚山脉的种群自1960年代以来已减少98%，面临严重威胁。","appearance":"金翅虫森莺体长约11.6厘米，体重8-10克，翼展可达20厘米。雄鸟拥有黑色喉部、黑色耳斑边缘白色，黄色的头顶和显著的翼斑；雌鸟类似，但喉部和耳斑呈淡灰色。两性皆有明显的白色尾羽下部。下体为灰白色，喙细长。幼鸟可以通过喉咙斑的颜色进行性别鉴定。","call":"鸣声多变，通常被描述为一连串的颤音，开始为长而嗡嗡的音符，随后是3至6个较短的低音节。","habits":"金翅虫森莺是迁徙性鸟类，夏季在北美东部繁殖，冬季迁往中美南部和邻近的南美部分地区。偏好开放的灌木丛生地、湿地和成熟森林边缘。以昆虫、蜘蛛和毛虫为主食，具有强大的喙肌，能揭开隐藏的毛虫。","breeding":"在开放的灌木丛和再生林中筑巢，每次产卵3-6枚（常为5枚），巢建于地面或低矮的灌木丛中。雄鸟通过展示其鲜艳的头部标记和白色的尾羽斑点来显示领地质量。","identification":"与蓝翅虫森莺形成两种明显杂交种：布鲁斯特氏虫森莺（灰色上体，下体白色或黄色）和劳伦斯氏虫森莺（绿色和黄色上体，黄色下体）。杂交个体的外观和鸣声可变异，但喉部颜色可靠地指示了杂交类型。","protection":"IUCN：NT（近危）","distribution":"繁殖区主要在美国中北部和东北部，以及加拿大东南部。非繁殖区分布于危地马拉至南美北部。","other":"2014年，五只在田纳西州的金翅虫森莺在暴风雨来临前数百英里迁徙，可能感知到风暴的低频声波。"},{"name":"蓝翅虫森莺","english_name":"Blue-winged Warbler","scientific_name":"Vermivora cyanoptera","overview":"蓝翅虫森莺（英文名：Blue-winged Warbler，学名：Vermivora cyanoptera），是雀形目森莺科虫森莺属的鸟类。体型较小的森莺科鸟类，以亮黄色的外观和独特的蓝灰色翅膀著称。活跃于北美的东部地区，包括美国的中部和东北部，以及加拿大的南部地带。这种鸟因其适应力强而常见于过熟的老草地和灌木沼泽环境中。","appearance":"蓝翅虫森莺的体长约为11.4至12.7厘米，翼展可达17至19.5厘米。成年雄鸟拥有明亮的黄色头部、胸部和下体，背部呈绿黄色，双翼为蓝灰色，带有两个白色的翼斑。雌鸟的色彩较为暗淡，冠部黄色减少，眼线不如雄鸟明显。幼鸟羽色橄榄绿，翼部特征与成鸟相似。","call":"蓝翅虫森莺的鸣声为一系列嗡嗡音组成的歌曲，叫声则为尖锐的‘chip’声。","habits":"这种鸟栖息于开阔的灌木丛生地带，如废弃的田野边缘，周围有高大的落叶树。它们主要以昆虫和蜘蛛为食，偶尔会倒挂在树枝上觅食昆虫。在繁殖季节，雄鸟会占据领地并发出特有的鸣叫声。","breeding":"蓝翅虫森莺在地面或低矮的灌木丛中筑巢，每次产卵4至7枚，由雌鸟孵卵，孵化期大约为10至11天。雏鸟属于晚成鸟，约在8至10天后离巢。","identification":"蓝翅虫森莺与近缘的金翅虫森莺有明显的区别，前者具有黑色的眼线和两个白色翼斑，后者则没有如此鲜明的特征。在两者交配区，会产生两种杂交类型：布鲁斯特氏（Brewster's）和劳伦斯氏（Lawrence's）杂交种。","protection":"IUCN：LC（无危）","distribution":"繁殖区位于北美，包括美国的中部和东北部，加拿大南部。非繁殖期则迁移至中美洲。","other":"蓝翅虫森莺的分布范围正在向北扩展，可能正在取代其近缘物种金翅虫森莺的部分栖息地。"},{"name":"黑白森莺","english_name":"Black-and-white Warbler","scientific_name":"Mniotilta varia","overview":"黑白森莺（英文名：Black-and-white Warbler，学名：Mniotilta varia），是雀形目森莺科黑白森莺属的鸟类。以其独特的黑白色条纹著称，广泛分布于北美，从加拿大中部至东南部到美国东北部，冬季则迁徙至墨西哥至秘鲁，以及西印度群岛。成年雄鸟拥有黑色喉咙和脸颊，而雌鸟和幼鸟的喉咙为白色，脸颊颜色较淡。在成熟落叶林或混交林中繁殖，冬季则出现在多种林地生境。","appearance":"黑白森莺身长11-13厘米，体重8-15克，翼展约18-22厘米。其特征为全身覆盖着鲜明的黑白色条纹，头部有黑白相间的冠羽，两眼上方有一条白色眉纹。翅膀为黑色，有两条白色翼斑，尾巴黑色，背部有黑白条纹，腹部有黑色条纹。雌雄差异明显，雄鸟喉部和脸颊黑色，雌鸟喉部白色，脸颊灰白，幼鸟则更显斑驳，带有更多斑点。","call":"其鸣唱为高音的重复‘wee-see’声，至少连续六次，还有‘chip’和‘seet-seet’的叫声。","habits":"栖息于落叶林或混交林，偏好湿润环境。迁徙期间，偏好森林而非其他土地类型，常出现在河流附近。冬季分布于从墨西哥到秘鲁，西印度群岛等地，适应多种生境，从红树林到各种森林类型。以昆虫和蜘蛛为主食，采用类似坚果啄木鸟的觅食方式，沿树干和树枝上下移动寻找食物。","breeding":"春季最早返回繁殖地，繁殖期在最南端的栖息地可始于四月中旬。雄鸟占据并保卫领地，通过鸣唱和驱逐竞争者。雌鸟负责筑巢，巢杯状，位于地面或树根间，由草、树皮和干叶构成，内衬柔软物质如苔藓和毛发。每窝产卵4-5枚，由雌鸟单独孵化，孵化期10-12天。幼鸟在8-12天后离巢，期间父母共同照顾。","identification":"与白颊林莺相似，但后者有实心的黑色帽顶。与松莺和黄喉林莺行为上相似，但后两者无黑白色条纹。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美，包括加拿大中部至东南部和美国东北部。非繁殖期分布于墨西哥至秘鲁，西印度群岛，以及北美洲部分地区。","other":"已知与蓝林莺和橙胸林莺杂交。"},{"name":"蓝翅黄森莺","english_name":"Prothonotary Warbler","scientific_name":"Protonotaria citrea","overview":"蓝翅黄森莺（英文名：Prothonotary Warbler，学名：Protonotaria citrea），是雀形目森莺科蓝翅黄森莺属的鸟类。北美特有种，别名金色沼泽莺，以其艳丽的金黄色羽毛著称，得名自罗马天主教会中身着金黄色法衣的教廷书记官。分布于美国东南部湿地森林，繁殖季节主要见于底土硬木林及近水森林地带。","appearance":"体长约13厘米，重约12.5克。雄鸟头部、胸部及腹部鲜亮橙黄色，背部橄榄绿色，翅膀和尾羽蓝灰色，下腹及尾下覆羽白色，尾羽基部有白色斑点，尾端黑色。雌鸟及幼鸟颜色略淡，头部黄绿色调更明显。喙长且尖，腿黑色。","call":"鸣唱为连续响亮的‘啾啾啾啾’声，音调清脆甜美。","habits":"栖息于湿润森林，偏好硬木沼泽地带，繁殖季在树洞中筑巢，常利用啄木鸟留下的空洞。以昆虫和蜗牛为主食，冬季迁徙至中美洲、加勒比海岛屿及南美北部的红树林。","breeding":"繁殖期在春季，雄鸟会建立多个未完成的巢穴，而真正的巢由雌鸟筑造，产卵数为3-7枚，雌鸟负责孵化。","identification":"独特的金黄色羽毛和橄榄绿背，尾部白色与黑色相间，易于识别。在冬季迁徙地可能与黄色林莺混淆，但通过其特有的鸣唱和行为可区分。","protection":"IUCN：LC（无危）。但在加拿大列为濒危物种，受栖息地丧失影响，数量呈下降趋势。","distribution":"繁殖于北美的美国东南部，非繁殖期分布于中美洲、西印度群岛及南美北部。","other":"历史上，蓝翅黄森莺曾成为证明Alger Hiss间谍案中关键证据之一，间接促成Richard Nixon的政治生涯。"},{"name":"斯氏森莺","english_name":"Swainson's Warbler","scientific_name":"Limnothlypis swainsonii","overview":"斯氏森莺（英文名：Swainson's Warbler，学名：Limnothlypis swainsonii），是雀形目森莺科白眉食虫莺属的鸟类。北美特有森莺，依赖于森林中茂密的下层植被，以翻找落叶层中的节肢动物为食。分布于美国东南部，冬季则迁移至加勒比海地区、尤卡坦半岛和墨西哥东部过冬。其独特而响亮的歌声是鸟友们识别它的关键。","appearance":"斯氏森莺是一种中等体型的鸟类，全长约130-140毫米，体重约15克。上体呈橄榄褐色，头部顶部为红褐色，下体颜色从淡黄白色到纯白色，无斑纹。最显著的特征是白色的眉纹和尖锐的粉红色喙。两性相似，无明显的季节性换羽差异。幼鸟背部为棕色，腹部污白色，缺乏眉纹，腿粉色，口角奶油色。","call":"斯氏森莺的歌声前半部分由响亮、清澈、下降的音符组成，类似于白眉灶莺的开始音符，后半部分则类似黑枕威森莺的结尾。其叫声为尖锐的'tchick'声，与白眼莺雀的首尾音符极为相似。","habits":"斯氏森莺偏好生活在有密集下层植被的落叶林或靠近水源的林地，常在林地地面搜寻食物。其分布范围较为局限，主要在美国东南部的密西西比冲积平原和沿海平原地区，以及南部阿巴拉契亚山脉的混合中生林中。迁徙期间，它们会前往加勒比海地区和尤卡坦半岛过冬。","breeding":"繁殖季节通常始于5月，成对建立领地。雌鸟会在林下层建造一个大型、厚实的巢，外观类似一簇悬挂的枯叶。每窝产3-5枚白色或偶尔带褐色斑点的蛋，仅由雌鸟孵化，孵化期大约14天。幼鸟在约12天后离巢。","identification":"斯氏森莺与食虫森莺、黄眉灶莺、白眉灶莺和白眼莺雀在外观上有明显区别，尤其是其独特的翻叶觅食行为和大型、尖锐的喙。叫声和歌声也是区分于其他鸟类的重要特征。","protection":"IUCN：LC（无危）","distribution":"繁殖于美国东南部，包括密西西比冲积平原、沿海平原和南部阿巴拉契亚山脉。冬季迁徙至中美洲的尤卡坦半岛和加勒比海地区，如牙买加的蓝山。","other":"尽管在历史上分布广泛，但由于适宜栖息地的丧失和改变，如底土硬木森林的减少和洪水影响，斯氏森莺的数量和分布范围已经显著下降。"},{"name":"月胸森莺","english_name":"Crescent-chested Warbler","scientific_name":"Oreothlypis superciliosa","overview":"月胸森莺（英文名：Crescent-chested Warbler，学名：Oreothlypis superciliosa），是雀形目森莺科奥利奥森莺属的鸟类。以亮黄色的腹部、灰色头部和绿色背部为显著特征，胸前有一独特的栗色月牙图案。常见于中美洲山区的橡树和松橡混交林中，从墨西哥北部延伸至尼加拉瓜北部，偶尔漂泊至美国得克萨斯州。","appearance":"月胸森莺拥有细长的体型和尖锐的喙，成年雄鸟的上身大部分呈深蓝灰色，背部橄榄绿，有明显的白色眉纹。喉咙、胸部和上腹部黄色，胸部上方有窄小的栗色月牙形斑块，下腹和尾下覆羽白色。雌鸟相似但色彩较暗淡，胸斑更小或缺失。幼鸟外观相似，但更暗淡，翅膀上有两个浅肉桂色条纹，喉部和下体呈脏黄白色，腹部逐渐变白。","call":"其鸣唱类似蝉鸣，发出连续的嗡嗡声。","habits":"月胸森莺偏好在中高海拔的森林中活动，尤其喜欢橡树林，冬季时会降至较低海拔。常与其他种类的森莺、旋木雀、山雀和莺等形成混合物种觅食群，主要以昆虫为食，偶尔也吃果实和浆果。","breeding":"它们通常一年筑巢1-2次，巢建在草丛或地面附近的斜坡旁，由雌鸟独自建造，使用苔藓、草、松针等材料。每次产卵约三枚纯白色卵，孵化期大约12-14天，雏鸟由雌鸟照料，双亲共同喂养，幼鸟约在8-10天后离巢。","identification":"与北森莺和绿背森莺相似，但后两者具有白色翼条，尾巴较短，且缺乏月胸森莺特有的白色眉纹。棕顶王森莺有宽大的白色眉纹，但上体主要是橄榄色，头顶和耳羽为锈色。","protection":"IUCN：LC（无危）","distribution":"月胸森莺分布于中美洲的山脉地带，从墨西哥南部至尼加拉瓜北部，主要栖息在中高海拔的橡树和松橡混交林中。"},{"name":"火喉森莺","english_name":"Flame-throated Warbler","scientific_name":"Oreothlypis gutturalis","overview":"火喉森莺（英文名：Flame-throated Warbler，学名：Oreothlypis gutturalis），是雀形目森莺科奥利奥森莺属的小鸟。以鲜艳的橙色喉咙而著称，上体呈蓝灰色，背部中央黑色，下体白色，喉咙至胸部为明亮的红橙色，喙细长尖锐。分布于中美洲的哥斯达黎加和巴拿马的高海拔地区。","appearance":"成年火喉森莺长约12厘米，重约10克。上体蓝灰色，背部中央、眼窝周围及头部两侧黑色，拥有醒目的红色至橙色喉咙和胸部，腹部白色。雄鸟的黑色面罩比雌鸟更宽泛，幼鸟上体橄榄灰色，下体较暗淡，具黄色至橙色的喉部，逐渐过渡到腹部的淡色。","call":"鸣叫声为尖锐的'chit'声，歌唱时发出嗡嗡的'pi pipipipi shwaaaa'声。","habits":"栖息于塔拉曼卡山脉森林的树冠层，活跃于林缘和开阔地带，海拔高度从2100米至林木线，雨季时可低至1400米。以捕食毛虫、昆虫和蜘蛛为主，使用其锋利的喙从树叶上捕捉猎物。","breeding":"繁殖季节为3月至5月，会在树上或低矮的土堤上建造深杯状的巢，通常被苔藓或寄生植物遮蔽，每次产两枚白色蛋。","identification":"与热带蓝喉莺（Parula pitiayumi）相似，但后者喉部颜色偏黄而非橙色，背部中心绿色而非黑色，且至少有一条白色翼纹。","protection":"IUCN：LC（无危）","distribution":"火喉森莺分布于中美洲的哥斯达黎加和巴拿马的塔拉曼卡山脉森林。"},{"name":"灰冠虫森莺","english_name":"Tennessee Warbler","scientific_name":"Leiothlypis peregrina","overview":"灰冠虫森莺（英文名：Tennessee Warbler，学名：Leiothlypis peregrina），是雀形目森莺科雷奥虫森莺属的鸟类。小型新世界林莺，英文名源自1811年在田纳西州采集到的标本，但实际上繁殖范围主要集中在加拿大北部的针叶林地带，包括阿留申群岛东部和美国极北地区。这种鸟以响亮的断奏式鸣唱而闻名，是春季迁徙期间北美东部常见的鸣鸟。","appearance":"灰冠虫森莺体长约10-13厘米，翼展约19.69厘米，体重约10克。繁殖期雄鸟背部、肩部、臀部呈橄榄绿色，翅膀呈棕黑色，头部、颈项和眼线为石板灰色，下体为灰白色。雌鸟颜色较暗淡，带黄橄榄色，尤其在下体更为明显。幼鸟与雌鸟相似。冬季和秋季，成年雄鸟下体泛黄，头颈转为橄榄绿，脸上的黄色眉纹突出，两性全年都有白色尾下覆羽。","call":"拥有响亮的鸣唱，通常由加速的三部分颤音组成，对于如此小的鸟来说声音异常响亮。","habits":"栖息于针叶林或针阔混交林，偏好在树冠高处的细枝上觅食昆虫，尤其是松毛虫。在迁徙期间，它们可在多种森林和灌木环境中被发现。冬季栖息于中美洲南部、加勒比海地区和南美洲北部的次生热带森林。","breeding":"在繁殖季节，灰冠虫森莺偏好在加拿大北部的针叶林中筑巢，巢呈杯状，由干草和苔藓制成，内衬更细腻的草茎、纤维和毛发，由雌鸟建造。巢位可能位于地面或沼泽上方的苔藓或灌木基部，每窝产4-7枚带有褐色斑点的白色蛋。","identification":"与橙冠虫森莺相似，但可通过白色而非黄色的尾下覆羽、缺乏模糊的胸侧条纹、背部更鲜艳的绿色以及较短的尾巴和较长的眉纹来区分。与红眼莺雀相比，体型更小，动作更敏捷，鸣唱频率较低。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美，包括阿拉斯加州东南部和加拿大西北部至加拿大东南部和美国东北部；非繁殖期分布于墨西哥至南美北部。","other":"数量随松毛虫数量波动，与松毛虫爆发周期紧密相关。"},{"name":"橙冠虫森莺","english_name":"Orange-crowned Warbler","scientific_name":"Leiothlypis celata","overview":"橙冠虫森莺（英文名：Orange-crowned Warbler，学名：Leiothlypis celata），是雀形目森莺科雷奥虫森莺属的鸟类。一种新世界森莺家族的小型鸣禽，广泛繁殖于北美西部和北部，以及加拿大东部。四亚种各有其独特的羽色、换羽模式、繁殖分布和迁徙路线。偏好灌木丛和低矮植被环境，常在橡树或白杨林边缘、河岸地带或灌木丛中筑巢。冬季会食用浆果和花蜜，吸引于脂肪块。","appearance":"中等体型（11-14厘米），橄榄绿的上体，臀部和上尾覆羽明亮黄绿色，头冠灰，隐秘的橙色斑块通常不明显。眼周有部分白色或黄色眼环，被暗色眼线分割。下体黄绿色至淡黄色，依亚种而异。最亮的黄色出现在下尾覆羽。喙小尖锐，腿和喙呈暗色。雌雄相似，但雌鸟可能更暗淡，橙色头冠不明显或缺失。","call":"歌声为下降音调和音量的颤音，叫声为高音的chip声。","habits":"栖息于开放的灌木丛区域，活跃于低矮的灌木丛中，飞行时从一枝跳到另一枝，有时悬停。主要以昆虫为食，也会食用浆果和花蜜。迁徙性强，部分加州沿岸亚种仅作短途迁徙。","breeding":"巢为小型隐蔽的地面杯状巢，位于植被下或灌木丛低处。雌鸟筑巢，每窝产4-6枚卵，由双亲共同喂养幼鸟。","identification":"与其他新世界森莺区别在于无翼纹、下体条纹不明显、面部标记强烈或色彩鲜艳。西方亚种较明亮黄绿色，东方亚种较暗淡。与秋季的灰冠虫森莺和黑喉蓝森莺相区别。","protection":"IUCN：LC（无危）","distribution":"繁殖于加拿大、阿拉斯加和美国西部；非繁殖季节分布于中美洲南部至美国南部。","other":"已有多项关于其换羽、羽序学和外寄生虫的研究。"},{"name":"黄腰虫森莺","english_name":"Colima Warbler","scientific_name":"Leiothlypis crissalis","overview":"黄腰虫森莺（英文名：Colima Warbler，学名：Leiothlypis crissalis），是雀形目森莺科雷奥虫森莺属的鸟类。北美洲特有的新世界森莺。主要栖息于墨西哥中西部的Sierra Madre Occidental和Oriental山脉，其分布边缘仅触及美国德克萨斯州西南部的Big Bend国家公园内的Chisos山脉。此鸟种以其独特的黄色臀部和尾羽下方羽毛而著称，雄鸟头顶有一橙色斑点。","appearance":"黄腰虫森莺长约11至13厘米，外观呈暗灰褐色，下腹部颜色较淡。其最显著的特征是黄色的臀部和尾羽下方的羽毛，以及围绕眼周的白色环纹。雄鸟头部顶部有一橙色斑点，雌鸟和幼鸟的色彩可能更为柔和，但差异不大，不易在野外区分。整个年份中，其羽毛颜色变化不大。","call":"黄腰虫森莺的鸣叫声为尖锐的金属声'bink'或'pink'，类似于Nashville、Virginia's和Lucy's Warblers的叫声。其歌曲由颤音后跟下降的滑音组成，更接近橙冠虫森莺而非其近亲的曲调。","habits":"此鸟偏好栖息于山地松栎林中的灌木丛和矮树上，冬季则移居至花丛密集的地带。它在地面筑巢，以昆虫幼虫为主食，同时也会从空中捕食昆虫，甚至从地面抓取毛虫。在繁殖季节之外，关于其迁徙和非繁殖季节的行为和生态知之甚少。","breeding":"黄腰虫森莺在地面隐蔽处筑巢，通常使用草、树叶和苔藓搭建一个松散的杯状巢。每次繁殖会产下四枚蛋，蛋壳颜色为白色至奶油色，表面带有棕色斑点。","identification":"与黄胸虫森莺相比，黄腰虫森莺体型更大、体格更健壮且喙部更粗重。黄胸虫森莺胸部的黄色或淡色比黄腰虫森莺更明显，后者胸部颜色更偏向灰色。黄腰虫森莺尾部上方和下方的黄色更偏橙黄色，而黄胸虫森莺的黄色更偏绿黄色。","protection":"IUCN：LC（无危）","distribution":"繁殖区域位于美国德克萨斯州西南部至墨西哥中部，非繁殖区域主要集中在墨西哥。","other":"黄腰虫森莺的命名来源于墨西哥的Colima地区，该地区虽非其主要越冬地，但却是最早收集到标本的地方。"},{"name":"赤腰虫森莺","english_name":"Lucy's Warbler","scientific_name":"Leiothlypis luciae","overview":"赤腰虫森莺（英文名：Lucy's Warbler，学名：Leiothlypis luciae），是雀形目森莺科雷奥虫森莺属的鸟类。是北美洲特有的小型新世界森莺，以在干燥的灌木丛和河岸林中筑巢而著称。不仅是最小的森莺之一，也是唯一在洞穴中筑巢的两种森莺之一。其名字纪念了鸟类学家Spencer Fullerton Baird的女儿Lucy Hunter Baird。","appearance":"体长9至12厘米，体重介于5.1至7.9克之间，是新世界最小的森莺种类。头部和上体呈现淡灰色，腹部白色。具有白色的眼圈和细尖的喙。成年雄鸟的头顶有一小块锈色斑点，雌鸟和雄鸟在外观上相似，但雌鸟头顶的锈色可能更淡或不明显。幼鸟颜色更浅，具有浅棕色的臀部和淡黄色的翼带。","call":"发出甜美类似黄喉森莺的歌声，但通常在结尾处带有更尖锐的音符。","habits":"栖息于西南美国和西北墨西哥的河岸林和灌木丛地带，偏好最干燥的植被区域。夏季早些时候离开繁殖地，迁徙到墨西哥太平洋沿岸过冬，偶尔远至瓦哈卡州。主要以昆虫为食，如毛虫、甲虫和叶蝉，捕食时会剧烈摇晃毛虫去除背上的刺毛。","breeding":"在自然洞穴、仙人掌或树木中的空洞，或是前一年由啄木鸟或黄头金雀挖掘的孔洞中筑巢。有时也会使用人造巢箱。巢穴密集，每公顷可达12对。冬季迁徙至墨西哥西部。","identification":"与黄胸虫森莺相似，但赤腰虫森莺完全缺乏黄色。与黄腰虫森莺和黄喉虫森莺有亲缘关系，但地理上和海拔上在繁殖季节分离。迁徙期间可通过完全缺乏黄色和具有锈色臀部来区分。","protection":"IUCN：LC（无危）","distribution":"繁殖于美国西南部和墨西哥西北部，冬季迁徙至墨西哥西部。","other":"栖息地丧失是其主要威胁，尤其是繁殖地的河岸环境被大量开发。褐头牛鹂的寄生现象也在一定程度上威胁着这一物种。"},{"name":"黄喉虫森莺","english_name":"Nashville Warbler","scientific_name":"Leiothlypis ruficapilla","overview":"黄喉虫森莺（英文名：Nashville Warbler，学名：Leiothlypis ruficapilla），是雀形目森莺科雷奥虫森莺属的鸟类。是北美洲小型鸣禽之一，特征为头部灰暗，背部橄榄绿，下体黄色带白色腹部，最明显的特征是完整的白眼环。分布于北美北部与西部，冬季迁徙至墨西哥与中美洲北部。","appearance":"体长约12厘米，体重平均10克，喙细而尖锐。成年雄鸟具灰色头，橄榄绿色背部，亮黄色下体，雌鸟颜色稍淡，幼鸟更暗淡。两地理分离群体，东部个体较暗，西部个体色彩更鲜明，具较长尾，且下腹白色更明显。","call":"鸣唱快速连贯，由急速的音节组成，叫声为高音的'heet'声。西部种群声音略低沉，更为丰富。","habits":"栖息于混交林、次生林和沼泽边缘，冬季偏好灌木丛生地带。以昆虫为主食，冬季补充浆果和花蜜。迁徙时会形成松散群落，有时加入混合种群觅食。","breeding":"筑巢于地面，隐藏于灌木下，巢由树皮、叶子和苔藓构成，内部铺有细软材料。每窝产卵4-5枚，孵化期11-12天，仅雌鸟孵卵，雄鸟提供食物。雏鸟孵化后11天离巢。","identification":"与黄胸虫森莺、赤腰虫森莺和黄腰虫森莺关系密切，区别在于黄喉虫森莺的绿色翅膀边沿，以及相对较小、尾部较短和喙更尖的特点。","protection":"IUCN：LC（无危）","distribution":"繁殖于加拿大东北部和美国北部，另一区域在美国西部。冬季迁徙至墨西哥中部、南部加州、得克萨斯州南部及中美洲北部的危地马拉和萨尔瓦多。","other":"历史上曾被归类于Vermivora属，现分类于Leiothlypis属。有两个地理上分离的种群，东部和西部种群在外观上有细微差异。"},{"name":"黄胸虫森莺","english_name":"Virginia's Warbler","scientific_name":"Leiothlypis virginiae","overview":"黄胸虫森莺（英文名：Virginia's Warbler，学名：Leiothlypis virginiae），是雀形目森莺科雷奥虫森莺属的鸟类。尽管其名可能让人联想到美国弗吉尼亚州，但实际上它的分布并未东至该州。这种鸟主要分布在美国西南部的中央山脉，如科罗拉多、怀俄明和新墨西哥。以发现者Dr. W. W. Anderson的妻子Virginia Anderson命名，由Spencer F. Baird于1860年首次科学描述。","appearance":"黄胸虫森莺体型小，长度约100至110毫米，主要呈灰色，腹部颜色较浅，具有白色眼环。最显著的特征是黄色的臀部和尾下覆羽，以及胸部的黄色斑块。头部有一片暗红色的冠羽，但通常被灰色羽毛遮掩。雌鸟比雄鸟颜色稍淡，胸部黄色较少。","call":"鸣唱甜美，由两到三部分组成。","habits":"栖息于海拔6,000至9,000英尺的浓密橡树和松木林地，夏季在美国西南部繁殖，冬季南迁至墨西哥西部，偏好密集灌丛和刷状生境。","breeding":"在地面筑巢，隐藏于枯叶和草丛中，靠近灌木或幼树基部。巢杯形，由苔藓、草、树皮条和根构成。雌鸟产3至5枚带有细小棕色斑点的白色蛋。幼鸟由双亲共同照顾，但具体的孵化期和其他繁殖细节尚不清楚。","identification":"与黄腰虫森莺相似，但体型较小，臀部更黄，分布更广泛。黄腰虫森莺缺乏黄色胸部斑块。","protection":"IUCN：LC（无危）","distribution":"繁殖区域主要位于美国西南部，包括科罗拉多、怀俄明和新墨西哥的中央山脉。非繁殖季节迁徙至墨西哥西部。","other":"历史上曾被归入多个不同的属，包括Helminthophilia、Oreothlypis和Vermivora。"},{"name":"淡脚森莺","english_name":"Semper's Warbler","scientific_name":"Leucopeza semperi","overview":"淡脚森莺（英文名：Semper's Warbler，学名：Leucopeza semperi），是雀形目森莺科淡脚森莺属的鸟类。长约14.5厘米，上身呈深灰色，下身灰白色，腿色偏淡黄。其名字是为了纪念居住在圣卢西亚的业余鸟类学家John E. Semper神父。仅见于圣卢西亚，属于极度濒危或可能已灭绝的物种。","appearance":"淡脚森莺体长约14.5厘米，头部及背部呈暗灰色，下部灰白，侧胸和胁腹带有灰色调。成年鸟的虹膜颜色深邃，喙部上部暗灰角质色，下部大部分为暗粉色，腿脚呈暗粉色。雌雄外观相似，雏鸟特征尚未详细描述，但第一年的个体上部颜色更偏向褐色，下部被淡黄褐色覆盖。","call":"其鸣叫声由一系列‘tuck-tick-tick-tuck’构成。","habits":"淡脚森莺栖息于圣卢西亚岛未受干扰的低山雨林下层植被和高山森林地带。它可能是一种地面筑巢的鸟，但具体生态习性尚不明确。","breeding":"关于淡脚森莺的繁殖行为知之甚少，据推测可能在地面筑巢。","identification":"淡脚森莺的独特之处在于其灰白的下部羽毛和暗灰色的上身，以及长而略尖的喙。在同属物种中，这一特征组合使其容易辨认。","protection":"IUCN：CR（极危）","distribution":"淡脚森莺的分布局限于圣卢西亚岛，属于北美区域，位于小安的列斯群岛。","other":"自1961年后，尽管进行了广泛搜寻，淡脚森莺再无确切记录，可能的目击报告虽未得到证实，但暗示着该物种可能仍存于岛上未被触及的高海拔或精灵森林中。"},{"name":"灰喉地莺","english_name":"Connecticut Warbler","scientific_name":"Oporornis agilis","overview":"灰喉地莺（英文名：Connecticut Warbler，学名：Oporornis agilis），是雀形目森莺科灰喉地莺属的鸟类。此鸟体型较大却十分隐秘，主要在北美中部的加拿大和美国大湖沿岸州的云杉、落叶松沼泽森林繁殖。在春季迁徙较晚，秋季则会飞往南美洲过冬，确切的越冬范围尚未完全了解。灰喉地莺下身柠檬黄色，上身橄榄褐色，具有独特的灰色头罩和完整的白色眼环。","appearance":"灰喉地莺体长约13-15厘米，体重约15克，拥有橄榄色背部，黄色腹部，灰色头罩，以及显著的白色眼环。雌鸟颜色较雄鸟暗淡，幼鸟头部呈褐色而非灰色，下半身颜色较暗。此鸟拥有长尾下覆羽，腿粉色，喙黑色基部带粉。","call":"灰喉地莺的鸣唱为重复的响亮'cheepa-cheepa'声，叫声类似沙哑的'witch'声，与黄腹地莺和灶鸟的音调相似。","habits":"灰喉地莺偏好在地面或低枝上觅食，主要以昆虫和其他小型无脊椎动物为食，偶尔也会食用种子和浆果。它们倾向于在密集植被中活动，使其难以观察。迁徙时，它们选择有茂密地面覆盖的林地。","breeding":"灰喉地莺在抵达繁殖地后开始求偶，雄鸟通过歌唱吸引雌鸟。它们一季仅繁殖一次，筑巢于浓密的林下层，巢由干草、杂草茎和马毛构成。雌鸟负责孵卵，孵化后，双亲共同喂养雏鸟，食物包括毛虫、幼虫、蛾子和浆果。","identification":"灰喉地莺与黑胸地莺和黄喉地莺亚成鸟的区别在于其完整的白色眼环、较大的体型、长的尾下覆羽，以及行走而非跳跃的习性。雌鸟和幼鸟较雄鸟更暗淡，头部棕色，喉咙部分较黄。","protection":"IUCN：LC（无危）","distribution":"繁殖区主要位于北美中部，包括加拿大中南部和美国中北部。非繁殖期分布于南美中部。","other":"灰喉地莺在春季迁徙路线与秋季不同，春季多数通过美国中西部，而秋季则更多见于东海岸。"},{"name":"灰冠黄喉地莺","english_name":"Grey-crowned Yellowthroat","scientific_name":"Geothlypis poliocephala","overview":"灰冠黄喉地莺（英文名：Grey-crowned Yellowthroat，学名：Geothlypis poliocephala），是雀形目森莺科黄喉地莺属的鸟类。分布于中美洲地区，包括墨西哥、中美诸国及美国南部部分地区。其最显著的外部特征是灰色的冠羽和黑色眼罩，黄色的喉部和胸部，以及橄榄绿色的背部。栖息于湿润的草地、灌木丛和半干旱的草原。","appearance":"成年灰冠黄喉地莺体长约14厘米，体重13.2至16.4克。雄鸟具有灰色的冠羽，黑色的眼罩和眼周区域，白色的眼眉纹，头部其余部分橄榄灰色。上体呈灰橄榄棕色，下体黄色，腹部淡黄色，两胁带有淡褐色。雌鸟与雄鸟相似，但颜色较为暗淡。幼鸟头部和上体橄榄褐色，翅膀上有柠檬橄榄色的翼斑，下体由浅黄色逐渐变为更淡的黄白色。","call":"其歌声为一系列丰富而杂乱的音乐性短语，类似Passerina雀的歌声，与其它黄喉地莺种类的歌声截然不同。在哥斯达黎加至少有两种歌曲，一种是快速连续的清晰哨音，逐渐加速至下降颤音；另一种在墨西哥被描述为一系列富有起伏的哨音，类似于墨西哥鹪鹩的叫声。常见叫声为高音、刺耳的'cheed-l-eet'，末音略高于起始音。","habits":"栖息于湿润草地、灌木篱笆、半干旱灌木丛和草原，包括甘蔗田等开阔的草本生境。主要在低地活动，局部可达约2000米。以昆虫和其他无脊椎动物为食，通过在灌木和草地低处啄食和地面觅食为主，偶尔也会捕捉飞虫。","breeding":"繁殖期在4月至7月。巢为深杯状，由草类构成，内部衬以细草和毛发，放置于浓密植被中较低的位置。每窝产卵2至4枚，通常在南部地区为2枚。无更多繁殖信息。","identification":"与其他黄喉地莺种类的区别在于其粗壮的喙、明显弯曲的喙尖、较长且呈渐尖的尾巴以及独特的头部图案。雌鸟和雄鸟的外观相似，但雌鸟头部颜色较暗淡。","protection":"IUCN：LC（无危）。在整个分布范围内普遍较为常见。由于森林砍伐提供了适宜的早期演替生境，在某些地区数量有所增加。然而，ralphi亚种曾在美国极南端（德克萨斯东南部）繁殖，但由于过度放牧和农业实践的变化导致栖息地退化，现已消失。","distribution":"分布于中美洲，包括墨西哥、中美诸国及美国南部部分地区。在中美洲广泛分布。"},{"name":"黑颊黄喉地莺","english_name":"Masked Yellowthroat","scientific_name":"Geothlypis aequinoctialis","overview":"黑颊黄喉地莺（英文名：Masked Yellowthroat，学名：Geothlypis aequinoctialis），是雀形目森莺科黄喉地莺属的鸟类。特征为雄鸟拥有显著的黑色面罩，雌鸟则较为朴素，缺乏黑色面罩，但腹部黄色更为鲜明。广泛分布于南美洲北部，从委内瑞拉、哥伦比亚至巴西亚马逊雨林北部，以及特立尼达岛。","appearance":"黑颊黄喉地莺体长约13.2厘米，体重约13克。上体呈黄绿色，下体鲜亮黄色，喙主要是黑色。雄鸟具有独特的黑色面罩，边缘上方有一灰色带状标记。雌鸟与雄鸟相似，但缺少黑色面罩，头部颜色变化不定，常几乎无灰色，眼周有黄色环，从喙到眼有一黄色条纹。不同亚种间雄鸟的羽毛存在明显差异。","call":"发出一系列变化多端的甜美哨声作为鸣唱，亦会发出快速下降的叽叽声。","habits":"偏好藏匿于茂密植被中，常见于沼泽和其他湿生环境中的密集低矮植被。也会在其他密集灌木丛中出现，但在较干燥的环境中较为罕见。通常成对出现，较少与其他物种混群。","breeding":"每窝产两枚白色带有红褐色斑点的蛋，巢筑于低处的草丛或茂密植被中，为杯状巢。","identification":"与冬季迁徙的黄喉地莺区别在于其下体颜色一致为黄色，而北美黄喉地莺下腹为白色。雌鸟与雌鸟黄喉莺类似，但嘴部更厚实，背部颜色更深。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲北部，包括委内瑞拉、哥伦比亚至巴西亚马逊雨林北部，以及特立尼达岛。","other":"过去，黑洛雷黄喉地莺和南部黄喉地莺被认为是其亚种。"},{"name":"巴拿马黄喉地莺","english_name":"Chiriqui Yellowthroat","scientific_name":"Geothlypis chiriquensis","overview":"巴拿马黄喉地莺（英文名：Chiriqui Yellowthroat，学名：Geothlypis chiriquensis），是雀形目森莺科黄喉地莺属的鸟类。是新大陆的一种森莺，分布于中美洲，从哥斯达黎加西南部至巴拿马。曾被视为面具黄喉地莺的一个亚种。","appearance":"巴拿马黄喉地莺具有独特的外观，但具体细节需参考更详细的资料以获取其羽毛颜色、大小和性别差异等信息。","call":"它的叫声是一种快速的叽喳声，与其它黄喉地莺种类的叫声截然不同，同时也会发出更为典型的尖锐的吱吱声。","habits":"巴拿马黄喉地莺通常成对出现，很少与其他物种混群。它们偏好藏匿于浓密的低矮植被中，偶尔会突然出现，尤其是在鸣唱时。它们的食物主要包括昆虫，如毛虫、蜻蜓、豆娘、蚱蜢和甲虫，以及蜘蛛，这些食物通常在密集的植被中捕获。","breeding":"关于巴拿马黄喉地莺的繁殖习性的详细信息，包括繁殖期、求偶行为、筑巢和育雏过程，需要查阅更详尽的研究资料。","identification":"与面具黄喉地莺相比，巴拿马黄喉地莺的叫声和行为模式有所不同，是区分两者的显著特征。","protection":"IUCN：LC（无危）","distribution":"巴拿马黄喉地莺的分布范围限于中美洲，主要在哥斯达黎加的西南部和巴拿马境内。","other":"现为绿冠黄喉地莺亚种。"},{"name":"黑眼先黄喉地莺","english_name":"Black-lored Yellowthroat","scientific_name":"Geothlypis auricularis","overview":"黑眼先黄喉地莺（英文名：Black-lored Yellowthroat，学名：Geothlypis auricularis），是雀形目森莺科黄喉地莺属的鸟类。新世界林莺。拥有多个独立的居民繁殖群体，分布在南美洲西部厄瓜多尔到秘鲁西部一带。过去曾被视为掩面黄喉地莺的一个亚种。","appearance":"雄鸟显著特征是黄色体羽搭配显眼的黑色面罩，而雌鸟外观普通，不起眼。雄鸟与绿冠黄喉地莺相似，但具有灰色顶冠和更细的面罩，雌鸟上体通常颜色更深，且喙部较厚，背部颜色更深，与雌性黄喉地莺相像。","call":"西安第斯山脉以西的典型歌声是一系列旋律优美的音符，接近结尾时加速。在马兰翁谷地，其歌声更为复杂，音调起伏。此外，还发出柔和的叽叽喳喳声和嗡嗡叫声。","habits":"栖息于沼泽和其他植被茂密的湿地环境，常成对出现，不与其他物种混群。通常隐匿，但有时会突然现身，尤其是为了歌唱。主要食物为昆虫，包括毛虫、蜻蜓、豆娘、蚱蜢和甲虫，以及蜘蛛，通常在密集植被中捕获。","identification":"雄鸟与绿冠黄喉地莺区别在于后者具有灰色顶冠和更细的面罩，雌鸟与雌性黄喉地莺的区别在于喙部较厚和背部颜色更深。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲西部，包括厄瓜多尔西部和秘鲁西部，有零星记录来自哥伦比亚西南极端地区。"},{"name":"南黄喉地莺","english_name":"Southern Yellowthroat","scientific_name":"Geothlypis velata","overview":"南黄喉地莺（英文名：Southern Yellowthroat，学名：Geothlypis velata），是雀形目森莺科黄喉地莺属的鸟类。新世界地莺。在南美洲拥有多个独立的居民繁殖群体，分布范围从秘鲁东南部、玻利维亚东部和巴西亚马孙雨林南部延伸至阿根廷和乌拉圭。过去曾被视为黑颊黄喉地莺的一个亚种。","appearance":"雄性南黄喉地莺具有独特的黑色面罩和灰色冠羽，而雌鸟则以黄色的喉部在橄榄色的上体和侧翼中脱颖而出。两性通常体型相似，约12厘米长，羽毛颜色在繁殖季节可能会有细微变化。","call":"其鸣唱为一系列丰富起伏的哨音，叫声则包括下降的连续细碎声和短促的摩擦声。这种鸣叫与其它黄喉地莺种类明显不同。","habits":"南黄喉地莺常栖息于湿地环境，如沼泽和其他带有浓密低矮植被的潮湿草地。它们一般成对出现，极少与其他物种混群。这种鸟善于隐蔽，但雄鸟偶尔会在显眼的枝头唱歌。它们以昆虫为食，包括毛虫、蜻蜓、豆娘、蚱蜢和甲虫，以及蜘蛛，这些食物通常在茂密的植被中捕获。","breeding":"南黄喉地莺在南美洲的湿地和密集植被中筑巢繁殖。繁殖期随地理位置而异，但在其分布区的南部，仅在南半球夏季繁殖，随后在冬季向北迁移。在某些地区，全年都可见到它们的身影。","identification":"雄性南黄喉地莺的黑色面罩和灰色冠羽使其容易识别，而雌鸟的黄色喉部在橄榄色的背景中尤为突出。与其他黄喉地莺相比，它们的鸣叫声更为独特。","protection":"IUCN：LC（无危）","distribution":"南黄喉地莺的繁殖区域主要集中在南美洲，具体包括秘鲁东南部、玻利维亚北部和巴西亚马孙雨林南部，一直延伸至阿根廷和乌拉圭。","other":"曾被认为是黑颊黄喉地莺的亚种，但现在被认定为独立物种。"},{"name":"灰头地莺","english_name":"MacGillivray's Warbler","scientific_name":"Geothlypis tolmiei","overview":"灰头地莺（英文名：MacGillivray's Warbler，学名：Geothlypis tolmiei），是雀形目森莺科黄喉地莺属的鸟类。体型较为健硕、善于隐蔽生活的莺鸟。其显著特征为头部蓝灰色，胸部和腹部黄色，背部橄榄色，拥有独特的白色眼弓。繁殖季节主要分布于北美西部山区，冬季迁徙至墨西哥至哥斯达黎加一带。","appearance":"成年灰头地莺体长10-15厘米，雄鸟头部颜色较深，呈暗灰色，眼周黑色，形成独特的白眼弓；雌鸟和幼鸟头部色泽较浅，喉部白色或淡灰色，体羽橄榄绿至黄绿色。下体黄色，上体橄榄色，具明显的白色眼弓。","call":"灰头地莺的鸣叫声未详述。","habits":"偏好生活在密集灌木丛、砍伐后的林地、混合森林开阔地带及河岸地带。它们在春季会以跳跃式迁徙模式返回繁殖地，从南到北，越冬地的南部种群会越过中间种群到达最北端的繁殖区域。","breeding":"繁殖期主要在山地地区，营巢于低矮植被中，筑巢材料多样，包括草、叶和根须等。具体繁殖细节未详述。","identification":"与黑胸地莺相比，灰头地莺具有更长的尾巴和白色的上下眼弓。成年黑胸地莺通常缺少眼弓，雄性黑胸地莺胸部和喉部的黑色羽毛分布更为集中。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美西部山脉，包括加拿大西北地区和美国阿拉斯加州东南部至墨西哥东北部。非繁殖季节分布于中美洲，从墨西哥南部至巴拿马北部。","other":"灰头地莺在繁殖地和迁徙途中依赖河流生态系统，是研究西部美国这一生态系统保护的重要物种。"},{"name":"黑胸地莺","english_name":"Mourning Warbler","scientific_name":"Geothlypis philadelphia","overview":"黑胸地莺（英文名：Mourning Warbler，学名：Geothlypis philadelphia），是雀形目森莺科黄喉地莺属的鸟类。体型中等的New World Warbler家族成员，主要分布在北美东部和中部，以及部分中美洲国家。属于Wood-warblers类别，这类色彩斑斓的鸣禽既有树栖也有陆栖。其外观与灰头地莺相似，尤其是雌鸟和幼鸟，但繁殖范围并不重叠到西部。雄鸟头部灰色，似披丧服，故名黑胸地莺。","appearance":"黑胸地莺身长10-15厘米，拥有橄榄绿的上部羽毛和黄色的腹部，喙尖而细，腿呈粉色。雄鸟具有灰色的头罩、黑色的颊部和胸部斑块；雌鸟和幼鸟头部灰棕色，眼环不完整，喉部淡黄色，胸部带有褐色或橄榄色调。成鸟体重约11-13克，翼展可达18厘米。","call":"这种鸟的鸣唱为明亮重复的颤音，由滚动的短语组成，音量通常在结尾处降低，听起来像“chirry, chirry, chirry, chorry, chorry”。叫声为尖锐的chip声。","habits":"黑胸地莺栖息于密集的次生林地带，偏好受干扰的森林环境，有茂密的灌木层和覆盖良好的树冠。它们以昆虫为主食，偶尔也吃植物材料，如冬季的Cecropia树果实。迁徙期间，它们会在低矮植被中觅食，有时也会在空中捕食昆虫。","breeding":"繁殖期在加拿大南部，巢穴通常建在地面，隐藏于浓密的灌木或其他植被下。巢由草、叶和树皮构成，内衬细根或其他柔软物质。每次产卵2-5枚，孵化期约为12天。成年雄鸟和雌鸟都会采用装死的策略来分散捕食者的注意力，以保护巢穴。","identification":"黑胸地莺与灰头地莺相似，但前者在繁殖期不会与后者重叠。雌鸟和幼鸟可能与灰喉地莺混淆，但后者有完整的眼环。黄喉虫森莺也容易混淆，但它们有黄色的喉部，背部灰色，体型更小且不如黑胸地莺活跃。","protection":"IUCN：LC（无危）","distribution":"繁殖区域集中在加拿大中部至东南部和美国东北部。非繁殖季节分布于尼加拉瓜至南美北部。","other":"黑胸地莺在人类干扰的森林景观中受益，是少数适应早期次生森林的近北极-新热带迁徙鸟类之一。"},{"name":"黄腹地莺","english_name":"Kentucky Warbler","scientific_name":"Geothlypis formosa","overview":"黄腹地莺（英文名：Kentucky Warbler，学名：Geothlypis formosa），是雀形目森莺科黄喉地莺属的鸟类。体型较小的新世界莺。其特征为橄榄绿背部和颈部，腹部呈亮丽的黄色，头部有黑色侧颊和冠羽，脸部有独特的黄色眼带，如同佩戴着一副眼镜。广泛分布于北美中部、东部及东南部，在湿润的落叶林中较为常见。","appearance":"成年黄腹地莺的背部和颈后橄榄绿色，腹部至喉部鲜亮黄色。雄鸟具有明显的黑色侧颊和冠羽，以及环绕眼睛的黄色眼带，形成独特的“眼镜”外观。雌鸟的黑色侧颊较淡，冠羽可能更小且带有灰橄榄色。幼鸟的黑色部分可能不明显。体长约13厘米，体重约13-14克，腿色浅粉红色，喙初期黄色后转为暗褐色。","call":"鸣唱为一系列快速、响亮、富有韵律的4-8个音符“preet, preet, preet, preet”，歌声清澈，通常在歌唱时会高飞。叫声为尖锐、略带金属质感的‘chip’声。","habits":"栖息于湿润的落叶林中，尤其偏好有茂密下层植被的环境，如沼泽地带或溪流附近。迁徙期间，它们会跨越墨西哥湾，到达尤卡坦半岛和加勒比海岛屿过冬。黄腹地莺善于地面活动，但在歌唱时会飞到较高位置。","breeding":"筑巢于地面，隐藏于灌木基部或杂草丛中。繁殖季节一般为春季，雌鸟单独孵化3-6枚白色或奶油色带有棕色斑点的卵，孵化期大约12天。幼鸟在孵化后约10天离巢。","identification":"与黄喉地莺属其他物种相比，黄腹地莺最显著的区别在于其独特的黄色眼带和黑色侧颊，以及橄榄绿上体和鲜亮的黄色下体。雄鸟和雌鸟在外表上有细微差异，而幼鸟的黑色标记较为模糊。","protection":"IUCN：LC（无危）","distribution":"繁殖区域主要位于北美的中部、东部和东南部美国。非繁殖季节，它们迁徙至墨西哥至南美北部地区。","other":"黄腹地莺的数量似乎正在减少，尤其是在某些地区更为明显。热带森林砍伐可能是影响这一物种的一个因素。"},{"name":"绿冠黄喉地莺","english_name":"Olive-crowned Yellowthroat","scientific_name":"Geothlypis semiflava","overview":"绿冠黄喉地莺（英文名：Olive-crowned Yellowthroat，学名：Geothlypis semiflava），是雀形目森莺科黄喉地莺属的鸟类。分布于中美洲东部洪都拉斯至巴拿马西部，以及与该北部种群不连续的哥伦比亚和厄瓜多尔西部太平洋坡地。本种包含三个亚种，有学者建议将其拆分为独立物种。外观近似黄喉地莺，但雄鸟面罩无上缘灰色，雌雄均具更鲜亮的绿色上体和纯黄色下体。","appearance":"体长11.1–13.5厘米，体重15.5–17.5克。雄鸟具宽阔黑色面罩，自额前延伸至颈侧；头顶及上体橄榄绿，喉及下体亮黄，两胁带橄榄色。雌鸟头顶及耳覆羽橄榄绿，具淡黄色眉纹，无黑色头纹，下体一致黄色。幼鸟似雌鸟，头及上体灰橄榄褐，喉胸具较浓橄榄色浸染。喙大部黑色，具淡色嘴缘；虹膜深褐；跗跖及趾淡粉角质或暗橙色。","call":"鸣唱为悠长而富于变化的啭鸣，常以双音节短句开始，逐渐转为杂乱的啁啾，音似“sew-sew-swe’swe’sweseewuu-seewuu…”。亚种bairdi的雄鸟鸣唱为长达数秒的加速重复双或三音短语，末端带卷舌音；亚种chiriquensis的鸣唱约5秒，短语重复并逐渐加快、变弱、升高，以明显尾音结束。叫声包括粗哑“chuck”、鼻音“chee-uw”、尖“chip”及短促下降的干涩颤音。","habits":"留鸟。栖息于潮湿的草地、香蒲沼泽、竹林灌丛及林缘灌草地，通常在低地至海拔1200 米，偶尔可达2300 米。多单只或成对在密丛中低处觅食，主要以昆虫、蜘蛛等无脊椎动物为食。","breeding":"繁殖期4–6月（bairdi），5月末有产卵记录（chiriquensis）。巢筑于草丛中，距地25–76厘米，为开放的草杯，内衬细草及植物纤维或毛发。卵1–2枚，白色具稀疏黑褐色斑点，斑点集中于大端；卵径约19.5 × 14.1 毫米。孵化期15天。","identification":"与同域其他黄喉地莺相比，本种头顶黑色范围更大；与黑颊黄喉地莺及黑眼先黄喉地莺区别在于头部无灰色调；与黄喉地莺区别在于下体一致黄色且上体更亮绿。亚种间差异：bairdi上体较暗，带褐，嘴略长；chiriquensis雄鸟头顶具灰色，上体黄绿色更亮；指名亚种semiflava上体最鲜亮。","protection":"IUCN: LC（无危）。","distribution":"繁殖区：中美洲东部洪都拉斯至巴拿马西部（加勒比坡为主），哥伦比亚西部（乔科至纳里尼奥及考卡谷地）及厄瓜多尔西部太平洋坡地至埃尔奥罗省；非繁殖区无迁徙，全年留居。","other":"亚种系统分类存在争议，chiriquensis曾被归入黑颊黄喉地莺，部分文献亦将bairdi提升为独立种（贝尔德黄喉地莺）。"},{"name":"黑顶黄喉地莺","english_name":"Black-polled Yellowthroat","scientific_name":"Geothlypis speciosa","overview":"黑顶黄喉地莺（英文名：Black-polled Yellowthroat，学名：Geothlypis speciosa），是雀形目森莺科黄喉地莺属的鸟类。仅分布于墨西哥中部的四个特定区域，包括Guanajuato、Michoacán和México州。这种鸟因其狭窄的分布范围和疑似种群数量的显著下降，被列为全球濒危物种。其生境主要局限于广阔的沼泽地带，无法在退化的环境中生存。","appearance":"雄性黑顶黄喉地莺具有褐色橄榄色的上部，黑色面罩延伸至暗绿色的背部，缺乏明亮的边界，黄色下体带有橙色胸部和赭色两翼。雌鸟无面罩，但有淡色眼环和浅色眉纹，整体较暗，上部橄榄棕色，下部黄色，带有深橄榄色侧腹。","call":"叫声独特，具体细节未详。","habits":"栖息于湖泊边的广阔芦苇床和临近水域的灌木丛中，偏好高海拔的湿地环境。生活方式与同属其他物种相似，但关于其生态学的具体信息几乎空白。","breeding":"繁殖生态学预计与同属其他黄喉地莺类似，但有关这一罕见墨西哥特有种的繁殖信息极少。","identification":"雄鸟与同域的普通黄喉地莺区别在于无明显的白色或灰色面罩边界，腿色更深。雌鸟较暗，腿色非粉红色，与普通黄喉地莺雌鸟相区别。","protection":"IUCN：VU（易危）","distribution":"繁殖区域集中在墨西哥中部，包括Guanajuato、Michoacán和México州的高海拔湿地。","other":"此物种是墨西哥特有的地方性物种，面临因栖息地丧失而带来的威胁。"},{"name":"贝氏黄喉地莺","english_name":"Belding's Yellowthroat","scientific_name":"Geothlypis beldingi","overview":"贝氏黄喉地莺（英文名：Belding's Yellowthroat，学名：Geothlypis beldingi），是雀形目森莺科黄喉地莺属的鸟类。新世界林莺，仅在墨西哥南部下加利福尼亚半岛繁殖和居住。与黄喉地莺、墨西哥黄喉地莺和巴哈马黄喉地莺关系密切，共同构成超种群，曾被认为同种。","appearance":"体长约14厘米，背部呈橄榄绿色，腹部鲜亮黄色。雄鸟拥有黄色下体、黑色面罩及黄色前冠。雌鸟相似，但无黑面罩，头部橄榄色。金曼亚种（goldmani）雄鸟有淡色腹部和灰前冠，与某些非迁徙的西南部黄喉地莺亚种相似，但分布范围不重叠。","call":"鸣唱响亮，类似'wichety wichety wichety wich'，比黄喉地莺更深沉、饱满，带嗡嗡声。叫声为柔和的'jip'。","habits":"栖息于淡水沼泽和湖边，常有香蒲和硬茎藨草。以昆虫和其他小型无脊椎动物为食，低处觅食。","breeding":"在活香蒲茎上建造杯状巢，使用死香蒲。产卵2-4枚，通常3枚。","identification":"与墨西哥黄喉地莺区别在于分布隔离。与黄喉地莺区别在于体型较大、色彩更鲜艳，面罩延伸至颈背。","protection":"IUCN：VU（易危）。全球种群估计不超过几千只，适宜生境严重碎片化。墨西哥法律将其列为受威胁物种。","distribution":"繁殖于墨西哥下加利福尼亚半岛南部。具体地点包括圣何塞德尔卡波的Estero、圣塔戈、托多桑托斯及Punta San Pedro。","other":"受人类活动和自然灾害影响，如住房开发、农业排水和火灾，导致栖息地破坏。"},{"name":"巴哈马黄喉地莺","english_name":"Bahama Yellowthroat","scientific_name":"Geothlypis rostrata","overview":"巴哈马黄喉地莺（英文名：Bahama Yellowthroat，学名：Geothlypis rostrata），是雀形目森莺科黄喉地莺属的鸟类。行动缓慢，栖息于从沼泽到松树林的浓密植被中。与黄喉地莺相似，但体型更大，结构更健壮，喙部相对较重。","appearance":"雄性巴哈马黄喉地莺具有宽大的黑色面罩，从额头延伸至颈部侧面，上方和后方边缘由狭窄的灰白色带环绕，侧边略带黄色；后冠和颈背为中灰色，微带黄橄榄色，上体呈黄橄榄绿色；喉咙和下体为黄色，腹部略淡，两肋微染橄榄色。雌鸟缺乏雄鸟的头部图案，头顶微染棕色，耳羽灰白，有窄的灰白色眉纹。幼鸟尚未详细描述；一年生秋季比成年稍暗淡，上体稍带棕色，下体更偏肉桂色，雄鸟可能头部图案较不明显。不同亚种在大小、颜色上有细微差异。","call":"歌声响亮，类似'witchity witchity witchit'，与黄喉地莺相似，但音质更丰富，节奏更慢。还有柔和的'whisper-song'，包含短促颤音和喷溅音。常见叫声为尖锐的'tuck'，比黄喉地莺的叫声柔和。","habits":"巴哈马黄喉地莺栖息于密集的干燥或湿润低矮灌木丛，通常比黄喉地莺所选环境更干燥。它们在密集植被或树桩低处筑巢，每次产卵两个。主要以昆虫和其他小型无脊椎动物为食。","breeding":"繁殖期在巴哈马群岛，筑巢于低矮的密集植被或树桩中，每窝产卵两枚。","identification":"与冬季迁徙至此的黄喉地莺相比，巴哈马黄喉地莺体型更大，喙部更重，动作更为迟缓。雄鸟下体黄色面积更广，面罩更大，延至颈背；雌鸟头部带有灰色调，与黄喉地莺不同。","protection":"IUCN：LC（无危）","distribution":"主要分布于巴哈马群岛，包括安德罗斯岛、新普罗维登斯岛、大阿巴科岛、埃利乌瑟拉岛、猫岛等。","other":"已识别三种亚种，分别为G. r. rostrata、G. r. tanneri和G. r. coryi，各自在颜色和大小上有细微差别。"},{"name":"墨西哥黄喉地莺","english_name":"Altamira Yellowthroat","scientific_name":"Geothlypis flavovelata","overview":"墨西哥黄喉地莺（英文名：Altamira Yellowthroat，学名：Geothlypis flavovelata），是雀形目森莺科黄喉地莺属的鸟类，体型约为13厘米，主要分布于墨西哥东部的海湾斜坡地区，偏好密集的芦苇湿地环境。","appearance":"雄鸟具有明亮的黄色头部，黑色面部面具，以及鲜亮的橄榄绿色背部，腹部为明亮的黄色。雌鸟相似，但头部橄榄色，无黑色面具，冠部呈橄榄色。幼鸟头部橄榄色，侧面可能带有灰色调，下体橄榄色逐渐变为腹部和臀部的淡黄色。","call":"其鸣唱为一系列粗糙沙哑的短语，叫声为沙哑的'cheh'或'chrek'声，与黄喉地莺的叫声类似但更沙哑。","habits":"常栖息于含有大量芦苇植被的淡水沼泽，亦可见于池塘和灌溉沟渠中的小型芦苇区。其生态习性与同属物种类似，以昆虫为食。","breeding":"关于繁殖和觅食习性的具体信息较少，但据推测，墨西哥黄喉地莺可能像其他黄喉地莺一样，在低矮植被中筑巢，主要以捕获于密林中的昆虫为食。","identification":"与冬季迁徙至其栖息地的黄喉地莺相比，墨西哥黄喉地莺的下体颜色更为均匀的黄色，而黄喉地莺的腹部为白色。雄鸟的黄色前额带纹是其显著特征。","protection":"IUCN：NT（近危）","distribution":"分布于墨西哥东部的塔毛利帕斯州、圣路易斯波托西州东部及韦拉克鲁斯州北部沿海地区。","other":"由于栖息地丧失，近年来墨西哥黄喉地莺的数量已严重下降，部分群体已消失。"},{"name":"黄喉地莺","english_name":"Common Yellowthroat","scientific_name":"Geothlypis trichas","overview":"黄喉地莺（英文名：Common Yellowthroat，学名：Geothlypis trichas），是雀形目森莺科黄喉地莺属的鸟类。广泛分布于北美的新世界森莺。其繁殖范围自加拿大南部至墨西哥中部，栖息于各种湿生环境中的低矮植被丛中。雄鸟具鲜明的黑脸罩，边界以白色或灰色细线勾勒，雌鸟则呈橄榄褐色，喉部和下腹部黄色，但无黑脸罩。","appearance":"黄喉地莺体型小，背部、翅膀和尾巴呈橄榄色，喉咙和胸部黄色，腹部白色。雄鸟拥有独特的黑色面罩，从颈部两侧延伸至眼睛和前额，上缘由白色或灰色细线界定。雌鸟相似，但下体颜色较淡，缺乏黑面罩。幼鸟外观与成年雌鸟相似，而第一年的雄鸟则有淡化的黑面罩，春季时会加深。","call":"雄鸟的鸣唱声为响亮的‘twichety twichety twichety twich’，叫声为柔和的‘jip’。","habits":"黄喉地莺偏好湿生环境中的浓密低矮植被，如沼泽和其他湿地。它们主要在地面附近的密集灌木丛中活动，寻找昆虫和蜘蛛为食。在迁徙期间，它们会出现在更广泛的栖息地中，包括后院和森林。","breeding":"筑巢于低矮植被中，杯状巢中通常产3-5枚卵，由双亲共同喂养幼鸟。北方种群为夜间迁徙者，冬季迁往繁殖范围南部、中美洲和西印度群岛。","identification":"雄鸟具有显著的黑面罩和黄色下体，而雌鸟和幼鸟则缺乏黑面罩，下体颜色较淡。与黄腹地莺的区别在于后者有明显的黄色眼上纹和眼圈，且全身下体黄色。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美和中美，冬季迁徙至南美西部。","other":"尽管因栖息地丧失导致数量下降，但黄喉地莺仍非常普遍。"},{"name":"纳氏黄喉地莺","english_name":"Hooded Yellowthroat","scientific_name":"Geothlypis nelsoni","overview":"纳氏黄喉地莺（英文名：Hooded Yellowthroat，学名：Geothlypis nelsoni），是雀形目森莺科黄喉地莺属的特有种，仅分布于墨西哥高地，位于伊斯特穆斯德特胡安特佩克以北。这种鸟常居于稠密的半干旱至湿润山地灌木丛或灌木林中。","appearance":"雄性纳氏黄喉地莺身长约为13厘米，体重在10.1到11.8克之间。头部黑色面罩宽大，从额头延伸至眼睛下方并环绕至颈部侧面，上缘和后缘由灰中带点绿色的条纹环绕。上体和两翼橄榄绿较暗淡，喉咙和腹部黄色，腹部颜色略浅，两胁带有橄榄色晕染。雌鸟缺乏雄鸟的面罩特征，头部橄榄色更淡，前额灰白，耳羽亦呈橄榄色。幼鸟全身大致为烟灰色，下体颜色较浅；一年生的换羽细节尚未详述。不同亚种间的差异微小，karlenae亚种的雄鸟前额条纹比指名亚种稍宽，雌鸟胸部色调更橙黄，尾下覆羽青铜黄色。","call":"其鸣唱由一系列‘巫婆般’的音符组成，以升调音符结束，整体音质与黄喉地莺相似，但通常每组音节只有两个（而非三个），并在结尾处有独特的花腔。常见叫声为干燥的‘tchip’或‘tchrrek’声；也会发出柔和的‘tchk’声，类似灰头地莺的叫声，当受刺激时会发出类似鹪鹩的干涩颤音。","habits":"纳氏黄喉地莺全年居住于墨西哥的密集半干旱至湿润山地灌木丛或灌木林中，偏好较为隐蔽的生活环境，但在鸣唱时会占据显眼的枝头。","identification":"不同于大多数黄喉地莺，纳氏黄喉地莺不在沼泽地带活动。相较于黄喉地莺，纳氏黄喉地莺色彩更为深沉，雄鸟具有明显的灰边黑面具。雌鸟虽难以与黄喉地莺区分，但头部的灰白色条纹是辨认的关键。","protection":"IUCN状态未提供。","distribution":"中美洲：墨西哥，主要分布于伊斯特穆斯德特胡安特佩克以北的高地。"},{"name":"啸森莺","english_name":"Whistling Warbler","scientific_name":"Catharopeza bishopi","overview":"啸森莺（英文名：Whistling Warbler，学名：Catharopeza bishopi），是雀形目森莺科啸森莺属的鸟类。中等体型的森莺科鸟类，为圣文森特岛的特有种，生活在山地雨林中。其显著特征包括明亮的白眼环和独特的黑白相间的胸部条纹，整体呈深灰黑色调。由于栖息地破坏和火山活动，该物种面临威胁。","appearance":"啸森莺体长约14.5厘米，重量在13.5至17.5克之间。上体及腹部为暗黑石板灰色，头戴深色帽，拥有鲜明的白色眼环。胸部有宽阔的暗灰色带，将白色上胸与腹部隔开。嘴、腿和脚呈粉红色。雌雄同色，幼鸟则颜色较浅，具褐色冠羽。","call":"啸森莺的鸣唱为一连串响亮的哨音，节奏由快转慢，音量逐渐增大，有时快速连续发出，形成较为杂乱的模式。","habits":"啸森莺栖息于圣文森特岛的山地森林，活动范围从低地至较高海拔的雨林。它们偏好潮湿环境，以昆虫为主食，偶尔摄食植物和蜥蜴。在觅食时，会频繁翘起尾巴。","breeding":"巢筑于低处，呈杯状，已知在7月和4月有繁殖记录。雏鸟在出生数日至一周后离巢，翅膀已发育。","identification":"啸森莺在其分布范围内无相似物种，通过其特有的白眼环、黑白胸部条纹和翘起的尾巴很容易识别。","protection":"IUCN：EN（濒危）","distribution":"啸森莺仅分布在加勒比海的圣文森特岛上，包括Richmond Peak和Grand Bonhomme等地。栖息地范围从300米到600米的海拔高度，更常见于较低海拔的山谷和高地。","other":"啸森莺自1902年火山爆发后，栖息地向更低海拔迁移，目前占据约90平方公里的面积。"},{"name":"铅色林莺","english_name":"Plumbeous Warbler","scientific_name":"Setophaga plumbea","overview":"铅色林莺（英文名：Plumbeous Warbler，学名：Setophaga plumbea），是雀形目森莺科橙尾鸲莺属的鸟类。灰绿色的羽衣，鲜明的白色眉纹和翼斑，使其在蒙特山森林中脱颖而出，偶尔也会出现在干燥灌木丛和红树林中。仅分布于小安的列斯群岛的瓜德罗普岛、高地岛、玛丽加兰特岛和多米尼加。","appearance":"体长约12至14厘米，体重介于8.4至11.3克之间。头部和上体呈灰色，眼上方有断续的白色眉纹，眼下有白色斑点。翅膀上的大覆羽和中覆羽尖端有宽阔的白色（形成两道翼斑），最外侧两对尾羽尖端亦为白色；腹部白色，两胁略带灰色。虹膜深色，喙灰黑色，下颌部暗角质色，腿脚暗灰色。雄雌相似，幼鸟未详述，但首年个体的羽色与成鸟相似，上体灰橄榄色，面部标记和翼斑为淡黄色，下体淡黄白色。","call":"鸣唱简洁而悦耳，可被描述为‘pa-pi-a’或‘de-de-diu’，由一连串悠闲的哨音组成，前三个音符音高相同，有时仅发出前三个音符。叫声包括短促的‘chek’声和响亮的颤音。","habits":"主要以昆虫为食，偶尔食用浆果。觅食时通常在低层林下穿梭，通过捕获方式获取食物。","identification":"与其他潜在相似物种的区别在于，铅色林莺缺乏北美迁徙物种常见的上体和下体条纹。","protection":"IUCN：LC（无危）","distribution":"分布局限于北美的小安的列斯群岛，包括瓜德罗普岛、高地岛、玛丽加兰特岛和多米尼加。"},{"name":"小林莺","english_name":"Elfin Woods Warbler","scientific_name":"Setophaga angelae","overview":"小林莺（英文名：Elfin Woods Warbler，学名：Setophaga angelae），是雀形目森莺科橙尾鸲莺属的鸟类。中等体型的森莺科橙尾鸲莺属鸟类，主要分布在波多黎各的湿润高山矮林中。其独特的黑色冠羽、白色眼圈及两道翼纹使其易于识别。1969年的发现与1972年的正式命名，使之成为20世纪唯一在波多黎各被确认的新物种。","appearance":"小林莺体长约12.5厘米，重量约8.4克，上体主要为黑色，带有白色斑点，下体白色并带有黑色条纹。头部黑色，具不完整的白色眼环，两道明显的白色翼纹，尾羽尖端有白色斑点。幼鸟背部灰绿色，头部及下体黄绿至灰色，喉部及胸部有淡色条纹。","call":"鸣声为一系列短促、快速发出的音调单一而略显单调的音符，音量渐强，以一系列稍低音调的双音节结尾。叫声为单个、短促、金属般的‘chip’声。","habits":"小林莺栖息于中高海拔的湿润森林，偏好波多黎各的Elfin、Podocarpus和Palo Colorado森林类型。它们主要在树冠层捕食昆虫，采用叶间捕食、悬停捕食和空中悬停捕食等技巧。","breeding":"繁殖季节为3月至6月，筑巢于Cecropia peltata的干枯落叶中，通常位于树洞内或藤蔓间。巢呈杯状，由细根、干叶等材料构成，内部衬以纤维和植物残余。雌鸟产卵2-3枚，白色带红棕色斑点。","identification":"与黑白森莺相比，小林莺背部无白色条纹，无白色眉纹，耳羽具有明显的白色斑块。黑白森莺的头纹更为鲜明，耳羽黑色，而小林莺的耳羽为黑色带有白色斑块。","protection":"IUCN：EN（濒危）","distribution":"小林莺仅分布于波多黎各，主要栖息于东部的El Yunque森林和西部Maricao森林的中高海拔地区。","other":"小林莺面临的主要威胁是其栖息地的丧失和退化，尤其是通信设施建设和自然灾难的影响。"},{"name":"尖头林莺","english_name":"Arrowhead Warbler","scientific_name":"Setophaga pharetra","overview":"尖头林莺（英文名：Arrowhead Warbler，学名：Setophaga pharetra），是雀形目森莺科橙尾鸲莺属的鸟类。特有于牙买加的湿润山地森林中。其显著的外部特征为头部及上部带有黑色条纹，腹部呈白色并带有黑色箭头状条纹。","appearance":"体长约12.5至13厘米，体重约9.1至10.5克。头部和背部有黑白相间的条纹，翅膀较暗，大覆羽和中覆羽尖端白色，形成两条白色翼带。尾巴深色，尾羽末端两对有小白色斑点。下体白色，喉部、胸部和两侧有黑色箭头状条纹。虹膜深色，喙黑色，腿为黑褐色。雌雄相似，雌鸟色彩略显暗淡。幼鸟描述不全，但似乎下体无条纹，第一年生个体上部橄榄棕色，有淡黄色条纹，翅膀和尾巴颜色更深，更接近成鸟，下体浅棕黄色，条纹模糊，与非繁殖期白颊林莺的区别在于头部和上部有细淡黄色条纹，翼带不明显，下体颜色统一，无明显眼线和眉纹。","call":"叫声为高音的金属‘tic’声，重复规律。歌声是一系列高音和尖锐的音符，可转录为“sww-sw-swee-sww-sw-swee-sww-sw-swee-swee-swee”。","habits":"栖息于牙买加的亚热带或热带湿润山地森林，以昆虫为食。在树枝、树叶和藤蔓上各个层次觅食，通过采集方式获取食物。","identification":"与白颊林莺和黑白森莺相似，但可通过下体黄色调、春季雄鸟明显的白色颊部，以及头部和上部的条纹细节来区分。","protection":"IUCN：LC（无危）。在牙买加EBA为限制分布物种，局部常见，但无具体种群估计数据。","distribution":"仅限于牙买加。"},{"name":"黑枕威森莺","english_name":"Hooded Warbler","scientific_name":"Setophaga citrina","overview":"黑枕威森莺（英文名：Hooded Warbler，学名：Setophaga citrina），是雀形目森莺科橙尾鸲莺属的鸟类。这种小型迁徙鸟类主要分布于北美的东部，包括加拿大南部至美国东部地区。其最显著的外部特征是成年雄鸟的黑色头罩与黄色脸颊和前额形成鲜明对比。繁殖季节，黑枕威森莺选择混合硬木森林作为栖息地，而冬季则迁徙至中美洲。","appearance":"成年雄性黑枕威森莺上体橄榄绿，下体鲜亮黄色，头部黑色头罩覆盖脸颊和前额，雌鸟和幼鸟颜色较暗淡，缺乏完整的黑色头罩，仅在某些雌鸟中可见黑色头罩的痕迹。雄鸟与雌鸟在第一年和次年(Second Year，SY)的羽毛特征有所不同，尤其是尾羽外侧有明显的白色斑点。","call":"黑枕威森莺的鸣唱由一系列音乐般的音符组成，听起来像是“wheeta wheeta whee-tee-oh”，常被记忆为“红色，红色T恤”或“来树林吧，否则你看不到我”。其叫声为响亮的'chip'声。","habits":"黑枕威森莺主要栖息于具有密集灌木层的成熟阔叶林地带，偏好低矮植被中的昆虫，有时通过飞扑捕食。它们的繁殖地通常位于北美的东部，冬季则迁徙到中美洲。","breeding":"繁殖期间，黑枕威森莺会在灌木较低处筑杯状巢，每窝产3至5枚卵。它们易受到褐头牛鹂的寄生威胁，特别是在森林破碎化严重的地区。","identification":"与黑头威森莺相比，黑枕威森莺尾部有明显的白色斑点。雌鸟与幼鸟与雄鸟在外观上有明显差异，尤其是黑色头罩的缺失或不完整。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美中部、东部和东南部，冬季迁徙至中美洲。","other":"近年来，黑枕威森莺的数量似乎有所增加，这可能与它们适应碎片化栖息地的能力有关。"},{"name":"橙尾鸲莺","english_name":"American Redstart","scientific_name":"Setophaga ruticilla","overview":"橙尾鸲莺（英文名：American Redstart，学名：Setophaga ruticilla），是雀形目森莺科橙尾鸲莺属的鸟类。以其独特的黑色和橙色相间的羽毛而著称。雄鸟拥有亮橙色的翅膀、尾巴和胸侧，与黑色的身体形成鲜明对比，而雌鸟和幼鸟则呈现灰色和橄榄绿色，带有黄色斑块。该物种广泛分布于北美的成熟落叶林中，冬季迁徙至中美洲、西印度群岛和南美洲北部。","appearance":"橙尾鸲莺是一种中等大小的鸟类，总长度约为11到14厘米，翼展介于16到23厘米之间，尾部长而显眼。雄鸟在繁殖季节呈现黑色，翼基、尾基和胸侧有醒目的橙红色斑块；雌鸟和幼鸟的上体呈灰色或橄榄绿色，下体白色或淡黄色，尾羽和翅膀有黄色斑块。雄鸟的体重夏季平均为8.6克，冬季降至7.2克；雌鸟夏季平均体重8.7克，冬季降至6.9克。","call":"其鸣唱是一系列悦耳的‘see’音符组成，叫声则是一种柔和的‘chip’声。","habits":"橙尾鸲莺栖息于开放的森林环境中，尤其偏好靠近水源的成熟落叶林。它们是迁徙性鸟类，繁殖于加拿大南部至美国东部，冬季迁至中美洲、西印度群岛和南美洲北部。昆虫是其主要食物来源，常在树冠下层或灌木丛中觅食。","breeding":"繁殖期间，橙尾鸲莺选择低矮的灌木筑巢，雌鸟孵化2至5枚蛋，孵化期大约10到13天。雏鸟在巢中约9天后离巢，之后可能继续跟随父母长达3周。一岁雄鸟能在首个繁殖季繁殖，但保留类似雌鸟的羽毛，可能影响其繁殖成功率。","identification":"雄鸟与雌鸟和幼鸟在颜色上有明显区别，雄鸟的橙色与黑色组合独一无二。与相似物种比较，橙尾鸲莺的体型较大，尾部较长，且具有明显的橙色或黄色尾部斑点。","protection":"IUCN：LC（无危）","distribution":"繁殖区域覆盖北美，从加拿大西部至加拿大东南部和美国东部。非繁殖季节分布于中美洲、西印度群岛以及南美北部。","other":"橙尾鸲莺的雄鸟在其第一个繁殖季节能够繁殖，但会保留雌鸟般的羽毛，这可能与其较低的繁殖成功率有关。"},{"name":"黑纹背林莺","english_name":"Kirtland's Warbler","scientific_name":"Setophaga kirtlandii","appearance":"成年雄性黑纹背林莺的上身呈蓝灰色，背部和头部有明显的黑色条纹，腹部为鲜明的黄色，侧面带有黑色斑点。雌鸟和幼鸟的羽毛颜色较为暗淡，背部呈褐色。所有个体都具有独特的上下摆动尾巴的行为，以及环绕眼周的白色眼环。雌鸟的背部颜色较浅，不如雄鸟鲜艳。成年雄鸟的喉部、胸部和腹部颜色鲜艳，而雌鸟及幼鸟的这些部位颜色较为暗淡。","call":"黑纹背林莺的鸣唱响亮，通常在枯木顶端或北方针叶栎丛中发出，声音为连续的“chip-chip-chip-too-too-weet-weet”，在良好条件下可传播400米以上。在越冬地，它们不唱歌，而是发出响亮的“chip”声。","habits":"黑纹背林莺夏季栖息于密歇根州北部的年轻短叶松林中，冬季迁徙至巴哈马群岛和附近的特克斯和凯科斯群岛。它们依赖密集的灌木丛作为栖息地，特别是在被放弃的农业地再生后形成的矮林中。在繁殖季节，黑纹背林莺主要以昆虫为食，也会吃一些浆果。","breeding":"繁殖期集中在春季，黑纹背林莺在5月至6月间产卵，每窝通常产4枚蛋。雌鸟负责孵化，孵化期约为14至15天。它们在地面上或靠近地面的树基部筑巢，巢由草、蓝莓和其他植被构成，以提供隐蔽。","identification":"黑纹背林莺与黄喉林莺在巴哈马群岛容易混淆，但可通过前者更灰的背部、尾部摇摆行为和黄色腹部上的黑色条纹加以区分。此外，与加拿大林莺相比，黑纹背林莺的胸腹部条纹更为明显，眼周的黄色也更加突出。","protection":"IUCN：NT（近危）","distribution":"繁殖区位于美国密歇根州北部，非繁殖期则分布于巴哈马群岛。近年来，黑纹背林莺的种群数量有所上升，部分归功于栖息地管理和褐头牛鹂寄生控制。","other":"黑纹背林莺对特定的栖息地高度依赖，尤其是年轻短叶松林，这使得它们容易受到栖息地破坏的影响。为了保护这一物种，实施了多项保护措施，包括栖息地管理、控制褐头牛鹂寄生、年度监测、研究和教育活动。"},{"name":"栗颊林莺","english_name":"Cape May Warbler","scientific_name":"Setophaga tigrina","overview":"栗颊林莺（英文名：Cape May Warbler，学名：Setophaga tigrina），是雀形目森莺科橙尾鸲莺属的鸟类。小型森莺，以其鲜明的栗色脸颊斑和虎纹般的黑色条纹而闻名。繁殖于北美北部森林地带，冬季迁徙至西印度群岛。其独特的外形和生态习性使其成为研究者关注的对象。","appearance":"雄性栗颊林莺在繁殖季节具有醒目的外观，下体黄色带有黑色条纹，栗色脸颊斑和白色翼斑。雌鸟和幼鸟颜色较为暗淡，上体橄榄灰色，下体黄色带灰色条纹，翼上有不明显的白色条纹。所有个体均具有细长而略向下弯的喙。","call":"鸣声高亢，频率变化不大，与栗胸林莺的歌声相似，需经验辨别。","habits":"栖息于北方针叶林，尤其偏好云杉树冠层。繁殖期间，以云杉芽虫为食，冬季则广泛出现在西印度群岛的多种生境中。迁徙时偏好停留在云杉树上。以昆虫为主食，也会吸食花蜜和吃水果。","breeding":"在北方针叶林中营巢繁殖，具体繁殖细节如繁殖成功率等尚不清楚。巢筑于树上，每窝平均产卵数量可能高于其他木莺。","identification":"雄性栗颊林莺的独特外观容易与其他物种区分。雌鸟和幼鸟可能与暗淡的黄腰林莺或棕榈林莺混淆，但后者胸侧条纹限制于两侧，且棕榈林莺有黄色尾下覆羽，而本种没有。","protection":"IUCN：LC（无危）","distribution":"繁殖于加拿大中部至东北部和美国东北部及中北部的北方针叶林。冬季迁徙至西印度群岛。","other":"其种群受云杉芽虫爆发影响，数量随资源丰歉而波动。"},{"name":"蓝林莺","english_name":"Cerulean Warbler","scientific_name":"Setophaga cerulea","overview":"蓝林莺（英文名：Cerulean Warbler，学名：Setophaga cerulea），是雀形目森莺科橙尾鸲莺属的鸟类。冬季则迁徙至南美洲安第斯山脉东坡的哥伦比亚至秘鲁一带。蓝林莺拥有独特的天蓝色外观，雄鸟在繁殖季节展现出深邃的天蓝色上体和白色下体，雌鸟则呈现淡绿蓝色调。该物种面临栖息地丧失的威胁，导致数量急剧下降。","appearance":"蓝林莺是一种小型鸟类，体长约11.5厘米，体重介于8至10.5克之间。雄性蓝林莺上体呈深邃的天蓝色，下体白色，胸部有一条黑色的颈环，背部有暗色条纹。雌鸟上体为淡绿蓝色，下体带有黄色调，具有一条明显的白色眼眉线。所有蓝林莺都有两条白色的翼带和白色的尾下覆羽。雄鸟的背部在所有羽毛上都有条纹，而雌鸟则无。幼鸟的下体可能带有黄色洗染，两性都具有模糊的腹侧条纹。","call":"蓝林莺的鸣声为一系列加速的嗡嗡音节，音调逐渐升高，以响亮的嗡嗡颤音结束。这种鸣唱类似于黑喉蓝林莺，但通常更丰富，分为三个明显部分，且音调比橙胸林莺更低。","habits":"蓝林莺偏好成熟的落叶林，尤其在河流沿岸或干燥的山脊顶部。它们主要在树冠层活动，以昆虫为食，尤其是蝴蝶和蛾子的幼虫。蓝林莺是长途迁徙者，夏季在北美东部繁殖，冬季迁至南美洲安第斯山脉东坡。","breeding":"繁殖期从5月末持续到6月初，蓝林莺在此期间筑巢于成熟森林的树冠层，高度通常超过30米。巢由树皮、草和苔藓构成，使用毛虫丝和蜘蛛丝编织。雌鸟产下3至5枚蛋，孵化期约为12天。幼鸟在巢中保持无能状态约11天，随后离巢。雌鸟负责孵卵，雄鸟则提供食物。","identification":"蓝林莺与橙胸林莺最易混淆，尤其是幼鸟。橙胸林莺的耳罩区域显得较暗，由较浅的超眼纹和较淡的侧面颈部突出。蓝林莺仅有一条明亮的眼眉线。橙胸林莺在所有羽毛上都有较浅的侧背条纹，而蓝林莺从未有过。","protection":"IUCN：NT（近危）","distribution":"繁殖区域位于北美，覆盖加拿大东南部、美国中北部和东北部。非繁殖区域则从哥伦比亚延伸至秘鲁，主要在安第斯山脉东坡的南美洲北部。","other":"蓝林莺是北美地区数量下降最快的候鸟之一，面临严重的栖息地破坏威胁。"},{"name":"北森莺","english_name":"Northern Parula","scientific_name":"Setophaga americana","overview":"北森莺（英文名：Northern Parula，学名：Setophaga americana），是雀形目森莺科橙尾鸲莺属的鸟类。小型的森林莺鸟，广泛分布于北美东部，从加拿大中南部至美国东南部。其别称包括Finch Creeper和Blue Yellow Back Warbler，以其蓝灰、黄、白相间的羽毛著称。繁殖于成熟森林近水区域，冬季则主要移居至墨西哥东部及西印度群岛。","appearance":"体型小，尾部短，喙尖且双色。上体蓝灰色，背部有苔绿色斑块，眼周白色，胸腹部黄色，腹部白色。成年雄鸟具有黑色和赤褐色的胸部带纹；雌鸟及幼鸟颜色较淡，通常缺乏明显的胸带。雄鸟略大于雌鸟。","call":"鸣唱为响亮的颤音，似拉链声，先上升后突然结束；叫声为轻柔的chip声。","habits":"栖息于成熟森林的中上层树冠，偏好湿润环境。繁殖季节在老树丛中筑巢，使用苔藓等材料。以昆虫和蜘蛛为食，迁徙期间可在多种栖息地发现。","breeding":"春季开始繁殖，南方群体最早3月开始，北方群体则于5月。在湿润林地中，利用苔藓或地衣筑巢，每窝产3-7枚卵。雌鸟负责筑巢，主要由植物纤维、动物毛发等构成。幼鸟孵化期12-14天，约10-11天后离巢。","identification":"与热带森莺区别明显，后者胸部清洁黄色或橙色，无白色眼环。雌雄之间，雄鸟更鲜艳，具黑赤胸带。","protection":"IUCN：LC（无危）","distribution":"繁殖区域覆盖加拿大中南部和东南部，美国中部和东部。非繁殖期则主要分布于中美洲，西印度群岛。","other":"在特定条件下会与黄喉森莺杂交，产生Sutton's warbler这一杂交种。"},{"name":"绿背森莺","english_name":"Tropical Parula","scientific_name":"Setophaga pitiayumi","overview":"绿背森莺（英文名：Tropical Parula，学名：Setophaga pitiayumi），是雀形目森莺科橙尾鸲莺属的鸟类。曾被称为森尼特莺、橄榄背莺、皮蒂阿尤米莺等，小型新世界森莺，分布于南美北部至北美的极南端，包括南美北部直至阿根廷北部、中美洲、墨西哥西北部（索诺拉）以及美国南部的得克萨斯州。","appearance":"绿背森莺体型小巧，长度约11厘米，体重介于6.5至8克之间。其上体主要呈现蓝灰色，背部有绿色斑块，翅膀上有两道明显的白色翼带。雄鸟个体的脸部有较深的颜色，胸部呈鲜艳的黄橙色，而雌鸟则颜色较为暗淡，胸腹部黄色较少。喙尖锐，上喙黑色，下喙黄色。成鸟全年羽毛相似，但基本羽衣略显暗淡和绿色。","call":"其鸣唱为高音的嗡嗡颤音，叫声为尖锐的‘tsit’声。","habits":"绿背森莺常见于山地和低山森林，偏好适度干扰和次生林环境，能适应栖息地的碎片化。它们主要在中美洲和南美洲的森林冠层活动，比在地面上听到它们的声音更为常见。它们以昆虫和其他节肢动物为主要食物来源，偶尔也会食用浆果。在某些地区，它们会加入混种觅食群。","breeding":"绿背森莺在树上的苔藓植物簇中筑巢，尤其是西班牙苔藓（Tillandsia usneoides），通常产下两个蛋，由雌鸟主要负责孵化，孵化期为12至14天。在索科罗岛，繁殖季节可能是在夏季月份，到11月时，幼鸟似乎已经离巢。","identification":"与北森莺相似，但绿背森莺缺乏眼圈白纹，胸腹部黄色延伸至腹部上部和两侧，胸腹侧面无栗色和黑色斑点，脸部黑色更多；黄色喉咙与灰脸侧面的边界非常直，不通过颊区或向胸部中心延伸。雄性绿背森莺的终曲音符与北森莺不同，前者为嗡嗡的下降滑音，后者为上升滑音。","protection":"IUCN：LC（无危）","distribution":"绿背森莺分布于中美洲、南美洲以及美国得克萨斯州南部。在中美洲和南美洲，它们广泛分布，包括墨西哥西北部、南美北部直至阿根廷北部，以及特立尼达和多巴哥。在得克萨斯州南部，它们仅限于苔藓森林。","other":"绿背森莺与北森莺关系密切，曾被视为同一物种的一部分。"},{"name":"纹胸林莺","english_name":"Magnolia Warbler","scientific_name":"Setophaga magnolia","overview":"纹胸林莺（英文名：Magnolia Warbler，学名：Setophaga magnolia），是雀形目森莺科橙尾鸲莺属的鸟类。属于北美的木莺科，以鲜明的黑黄相间羽毛和独特的尾羽图案著称，主要在加拿大中部至东南部以及美国东北部和中北部的针叶林中繁殖。这种鸟的命名源于其首次被亚历山大·威尔逊在密西西比州的一棵马格诺利亚树上发现。","appearance":"繁殖期雄性纹胸林莺具有醒目的外观特征：背部灰白，臀部黄色，腹部黄色且带有厚重的黑色条纹。头部呈灰色，带有黑色面罩延伸至喙部，白色翼斑明显。雌鸟和未成熟的个体色彩较为暗淡，头部灰色，胸前有较不明显的条纹，翼斑不那么显著。所有年龄和性别的个体尾羽基部均为白色，尖端黑色。","call":"纹胸林莺的鸣叫特征包括两种不同的歌曲类型，分别用于吸引配偶和标记领地，以及用于警报的呼叫音。","habits":"这种鸟栖息于密集的针叶林中，尤其偏好幼龄生长的林地。它们可以在任何树木覆盖的区域或边缘找到，主要在中美洲和加勒比海地区越冬。迁徙期间，纹胸林莺会出现在各种类型的林地中。","breeding":"繁殖季节，雄鸟先于雌鸟到达繁殖地约两周。雌雄共同筑巢，巢由草、树枝和马尾菌构成，位于地面以上不超过5米的高度。雌鸟通常产3至5枚蛋，独自孵化，孵化期约为两周。雏鸟出生后，雌雄亲鸟共同喂养，直到幼鸟能够在约10天后离巢。","identification":"纹胸林莺与草原绿林莺和黑纹背林莺相似，但可通过尾羽图案、翼斑颜色和胸部条纹的差异来区分。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美，包括加拿大中部至东南部和美国东北部与中北部。非繁殖期主要分布在中美洲和西印度群岛。","other":"纹胸林莺的迁徙路径中，部分个体可能因撞击电视塔而死亡。尽管其栖息地因森林砍伐而有所退化，但总体上纹胸林莺的数量并未受到严重影响。"},{"name":"栗胸林莺","english_name":"Bay-breasted Warbler","scientific_name":"Setophaga castanea","overview":"栗胸林莺（英文名：Bay-breasted Warbler，学名：Setophaga castanea），是雀形目森莺科橙尾鸲莺属的鸟类。属于Parulidae家族。这种鸟在加拿大南部和东南部以及美国东北部的针叶林中繁殖，冬季迁徙至南美西北部。","appearance":"繁殖期雄鸟具有独特的深红棕色头冠和侧面，以及淡黄色颈背，两道明显的白色翼带。雌鸟和秋季的鸟较暗淡，通常会显示出至少一些栗色的侧面。最暗淡的鸟类似白颊林莺和松莺，但有背部条纹，清晰定义的翼带，以及较为干净的黄绿色头部和颈部。非繁殖期雌鸟/幼年雄鸟通常在侧面有淡淡的栗色，头部和颈部呈黄绿色，下部无斑纹。","call":"听其极高音的吱嘎声，类似快速旋转的黑白林莺，非常独特。","habits":"在繁殖季节，栗胸林莺主要以昆虫和蜘蛛为食，特别是在针叶林中。冬季，它们在热带地区食用大量水果。它们在非繁殖季节经常加入多种物种的群落，此时昆虫不如水果占据主导。","breeding":"在成熟的针叶林中筑巢，巢杯状，由植物材料构成，蛛丝常被用作粘合剂。平均一窝产4-7枚带有暗斑的白色蛋。出生时小鸟几乎无毛。","identification":"与栗胁林莺相似，但后者没有到达喉部或头顶的栗色，且有明亮的黄色头顶，黑色面具和白色的颊部和喉咙。与白颊林莺的区别在于后者侧面无栗色痕迹，脚部颜色为黄色而非黑色。","protection":"IUCN：LC（无危）","distribution":"繁殖区主要位于加拿大南部和东南部以及美国东北部的针叶林。非繁殖区跨越至南美西北部，包括中美洲南部和加勒比地区。","other":"在全球范围内，栗胸林莺的估计数量少于1000万只，尽管目前被IUCN列为无危，但其种群正在面临减少，部分原因是昆虫猎物的丧失和全球气候变化。"},{"name":"橙胸林莺","english_name":"Blackburnian Warbler","scientific_name":"Setophaga fusca","overview":"橙胸林莺（英文名：Blackburnian Warbler，学名：Setophaga fusca），是雀形目森莺科橙尾鸲莺属的鸟类。以其火焰般的橙色喉部著称，即使在雾雨中也能闪耀。这种鸟在北美东部繁殖，从加拿大南部到北卡罗来纳州，迁徙至南美北部山区越冬。其独特的三角形黑色颊斑和白色翼斑使其在外形上与众不同。雌鸟和幼鸟的色彩较为柔和，黄色喉部和黑色三角形颊斑是其特征。偏好针叶林或混交林，但在迁徙期间可在各种林地生境中发现。","appearance":"橙胸林莺体型较小，长约11至12厘米，头部具有明显的橙色喉咙，雄鸟在繁殖季节颜色尤为鲜明。黑色的冠和耳部区域形成对比，翼上有白色的斑点。雌鸟和幼鸟的色彩较淡，橙黄色取代了橙色，翼斑变为翼条，腹部白色，侧面带有黑色条纹。所有年龄层都有独特的三角形耳斑和额头中间的浅色条纹。","call":"鸣唱为一系列高音的swi声，通常音调上升，被描述为zip zip zip zip zip zip zip zip，titititi tseeeeee或teetsa teetsa teetsa teetsa。叫声为高音的sip。","habits":"栖息于成熟针叶林，偏好冷杉、白松或云杉林，以及混交林，尤其喜欢铁杉树。主要以昆虫为食，尤其是鳞翅目幼虫。在树冠顶部觅食，有时通过悬停捕食昆虫。冬季迁徙至南美洲的山地森林。","breeding":"繁殖期在5月中旬至6月初，筑巢于针叶树的枝条上，巢由细枝、苔藓、蛛网构成，内衬松针和毛发。每窝产3至5枚白色蛋，孵化和育雏主要由雌鸟承担。","identification":"与其他Setophaga属的莺鸟相比，橙胸林莺的橙色喉咙和脸部图案独一无二。雌鸟和幼鸟可通过黄色眉纹和灰色脸颊的对比，以及黄色喉咙与暗色侧面和背部的差异来识别。仅有的另一种橙喉莺鸟——火喉森莺，头部缺乏黑色条纹，底面白色。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美中部和东南部，包括加拿大和美国东北部、中北部和东部。越冬于哥斯达黎加至玻利维亚的南美山区。","other":"橙胸林莺的种群数量受到南美冬季栖息地丧失的威胁，但根据繁殖鸟类调查数据，近年来数量稳定甚至略有增加。"},{"name":"美洲黄林莺","english_name":"American Yellow Warbler","scientific_name":"Setophaga aestiva","overview":"美洲黄林莺（英文名：American Yellow Warbler，学名：Setophaga aestiva），是雀形目森莺科橙尾鸲莺属的鸟类。亦被称为北美黄林莺，是Setophaga属中最广泛分布的物种，遍布整个北美洲直至墨西哥中部，以及远至南美的北部区域。繁殖季节时，雄鸟展现出引人注目的金黄色外观，而雌鸟和幼鸟则呈现较淡的绿色和黄色。其鸣叫声清脆悦耳，被誉为‘甜美’。","appearance":"美洲黄林莺体长约12-13厘米，翼展可达16-20厘米，体重在9-16克之间，平均寿命约为10年。繁殖季节，雄鸟全身金黄，雌鸟及幼鸟上身绿色偏黄，下身黄色较淡，翅膀和尾巴呈黑橄榄色，带有黄色边缘。雄鸟胸前有少量锈红色条纹，雌鸟色泽稍暗，尤其是在头部。","call":"其鸣唱甜美，可描述为连串的“sweet sweet sweet, I'm so sweet”，但会因地区不同而有所变化。叫声包括柔和或尖锐的“chip”或“ship”。","habits":"栖息于开阔湿润的森林或灌木丛中，偏好柳树生长的环境。在冬季，它们迁徙至中美和南美洲。以昆虫为主要食物来源，包括毛虫、蚊子、甲虫等，也偶尔食用浆果。繁殖季节结束后，它们会迅速迁往南方。","breeding":"在繁殖期，雌雄鸟共同筑巢，通常位于树上，距离地面1至18米。雌鸟负责孵卵，孵化期大约为11至12天。雄鸟会捕食回来喂养雌鸟。幼鸟在孵化后9至12天离巢。褐头牛鹂的卵常常出现在其巢中，导致寄生问题。","identification":"美洲黄林莺与其他森莺科鸟类的区别在于其鲜艳的黄色羽毛，尤其是雄鸟的头部颜色。与金林莺（petechia组）相比，头部的栗色较小，而与红树林莺（erithachorides组）相比，头部无明显的栗色。","protection":"IUCN：LC（无生存危机的物种）","distribution":"繁殖区域覆盖北美至墨西哥高原，非繁殖季节分布于北美南部至亚马逊雨林区域。","other":"持续的森林退化对其构成威胁，但因其广泛分布和数量稳定，目前不属于濒危物种。"},{"name":"黄林莺","english_name":"Mangrove Warbler","scientific_name":"Setophaga petechia","overview":"黄林莺（英文名：Mangrove Warbler，学名：Setophaga petechia），是雀形目森莺科橙尾鸲莺属的鸟类。广泛分布于北美、中美及南美地区，从美国极南部至西印度群岛至中美沿海和南美。其最显著特征为亮丽的黄色羽毛和独特的头部斑纹。","appearance":"黄林莺体长10至18厘米，翼展16至22厘米，体重7至25克，平均约16克，但在美国种群中的繁殖成鸟仅重9至10克。上体绿色带黄，下体黄色较淡，黑色橄榄色的翅膀和尾巴边缘带有黄色，形成不明显的翼带。眼睛、喙暗色，脚部橄榄色至暗橄榄色。夏季雄鸟个体尤为醒目，全身呈明亮的黄色，上体绿金色，胸部和侧腹有淡锈红色条纹，因这些特征得名petechia（肝斑）。雌鸟较雄鸟稍显暗淡，尤其是头部。","call":"鸣唱旋律丰富，可描述为“sweet sweet sweet, I'm so sweet”，但随种群而异。叫声包括柔和或尖锐的‘chip’或‘ship’声，尤其在雄鸟歌唱结束后由雌鸟发出。此外，它们还发出嘶嘶声以防御领域，‘seet’声可能是一种专门的牛鸟警报。","habits":"黄林莺繁殖于北美的温带地区，南至墨西哥中部，偏好湿润的树林或灌木丛生环境，冬季迁徙至中美和南美洲。它们主要以毛虫为食，占饮食的60%，同时也会捕食其他昆虫、蜘蛛和少量浆果。栖息地包括河流边的湿润地带、柳树丛和其他有小树的潮湿地区。非繁殖季节通常成小群体活动，繁殖期间则表现强烈领地性。","breeding":"繁殖季节开始于5月至6月，筑巢于树上，巢呈杯状且坚固。雌雄共同育雏，雌鸟负责筑巢和孵卵，雄鸟负责保卫巢区和觅食。每窝产卵3至6枚，孵化期11天，幼鸟孵化后由双亲喂养约8至9天，随后离巢。热带种群繁殖周期较长，需超过100天。一次繁殖成功率约为55%。","identification":"与金黄林莺和红冠林莺的区别在于头部颜色，夏季雄鸟的头部有锈色帽或面罩。红冠林莺的冠羽更明显，而金黄林莺的头斑范围和色调有所不同。","protection":"IUCN：LC（无危）","distribution":"繁殖区域覆盖整个北美洲，南至墨西哥中部；非繁殖区域扩展至中美洲和南美洲，包括加勒比海岛屿。","other":"黄林莺对人类有益，因其在繁殖季节大量捕食害虫，且其美丽的羽毛和悦耳的歌声吸引了生态旅游。"},{"name":"栗胁林莺","english_name":"Chestnut-sided Warbler","scientific_name":"Setophaga pensylvanica","overview":"栗胁林莺（英文名：Chestnut-sided Warbler，学名：Setophaga pensylvanica），是雀形目森莺科橙尾鸲莺属的鸟类。一种新世界森莺，因人类活动在北美洲大陆上的影响而数量剧增。主要繁殖于加拿大中南部和东南部至美国中北部、东北部和东部地区，冬季迁徙至中美洲至南美北部。繁殖季节时，雄鸟具有鲜明的黄色头顶、黑色眼纹和栗色胁部，雌鸟色彩较为淡雅。","appearance":"雄鸟在繁殖季节展示明亮的黄色头顶、广泛的栗色胁部和坚实的黑色面部标记；背部条纹交错，黄黑相间。雌鸟较为朴素，头顶带绿，面部黑色减少，栗色主要位于上胸部两侧；背部橄榄绿与黑色条纹交织。非繁殖季，雄鸟头部绿色，上体斑点黑色，脸灰，胁部栗色广泛；雌鸟与雄鸟相似，但背部暗纹不明显，胁部栗色减少。首年雄鸟与成年雌鸟相似，但平均胁部栗色较少；首年雌鸟整体最朴素，无下体栗色。","call":"高音哨声，常被描述为'pleased, pleased, pleased to MEECHA'，用于吸引雌鸟和领土防御。","habits":"偏好次生森林，尤其是有大量灌木和幼树的区域。善于在受扰动的环境中生存，如电力线路切割和伐木后的地区。以昆虫为主食，冬季会食用浆果，如Cymbopetalum mayanum的果实。","breeding":"在年轻落叶林再生地带筑巢，通常位于低矮灌木丛中，巢为杯状，由树皮条、杂草茎、草和植物绒毛编织而成。每窝产3-5枚蛋，蛋色为奶油白或淡绿色，带有棕色斑点。繁殖期间，雄鸟会发出强调和非强调结尾的两种歌声。","identification":"与栗胸林莺相比，栗胁林莺的成年雄鸟面颊和头顶颜色较深，非繁殖季羽毛下体纯白色，翼斑和眼环黄色。雌鸟和幼鸟通过纯白下体、绿色上体和黄色翼斑、白色眼环与其它类似物种区分。","protection":"IUCN：LC（无危）","distribution":"繁殖于加拿大中南部和东南部至美国中北部、东北部和东部，冬季迁徙至中美洲至南美北部。","other":"自19世纪末以来，随着次生森林的增加，栗胁林莺的数量显著增长，但自1960年代以来略有下降。"},{"name":"白颊林莺","english_name":"Blackpoll Warbler","scientific_name":"Setophaga striata","overview":"白颊林莺（英文名：Blackpoll Warbler，学名：Setophaga striata），是雀形目森莺科橙尾鸲莺属的鸟类。广泛分布在北美北部森林地带，从阿拉斯加到加拿大大部分地区，南至美国东北部的新英格兰。其显著特征包括黑色顶冠、白色脸颊、以及独特的黑白条纹外观。该物种以非凡的秋季迁徙闻名，能够从美国东海岸直达南美洲，途中跨越大西洋，完成不间断的长途迁飞。","appearance":"白颊林莺体型较小，平均长度14厘米，体重12-13克。成年雄鸟头部顶部全黑，其余部分白色，带有黑色颊纹；上身灰黑色，下身白色，两侧和臀部有明显的黑色条纹，翅膀深色，有两道白色翼斑，尾巴暗色，尾羽基部有白色斑点。腿和脚呈淡橙色至黄色。成年雌鸟颜色较为柔和，上身橄榄灰至橄榄绿，带有黑色条纹，下身淡白色，有黑色条纹，有时带淡黄色调。幼鸟在秋季时颜色较淡，头部和胸部呈柠檬黄色，有模糊的条纹，翅膀上有白色翼斑，下体白色，腿和脚的颜色可能较暗。","call":"白颊林莺的歌声为一系列高音的\"tsi\"重复音符，叫声为细薄的\"sits\"。","habits":"白颊林莺栖息于北方针叶林，夏季常见于海拔较高的山地森林和灌木丛，以及北美东部沿海岛屿的树林中。它们在春季和秋季迁徙期间，会在各种森林环境中停留。它们主要以昆虫为食，偶尔在迁徙和冬季食用浆果。在繁殖季节，它们会筑巢于低矮的针叶树中，每次产卵3-5枚，孵化期约为12天，雏鸟在仅10天左右就离巢。","breeding":"白颊林莺的繁殖期主要集中在夏季，雌雄鸟会在针叶林中选择相对较低的位置筑巢，巢呈杯状。每窝通常产3-5枚蛋，最多可达9枚。孵化期大约为12天，雏鸟在出生后约10天就会离巢，尽管此时还不能很好地飞行。父母双方会继续喂养幼鸟大约两周时间。雌鸟通常会立即开始筑第二个巢，而将照顾离巢幼鸟的任务留给雄鸟。","identification":"白颊林莺在繁殖期雄鸟与黑白森莺有相似的黑白羽毛模式，但可通过完全黑色的顶冠和无颊纹的白色脸颊来区分。在非繁殖期，与栗胸林莺和松莺相似，但可通过下体的条纹、翼斑的差异以及脚底黄色来辨认。","protection":"IUCN：NT（近危）","distribution":"白颊林莺繁殖区位于北美北部，从阿拉斯加至加拿大东部和东南部，以及美国东北部。非繁殖区主要在南美北部和中部。","other":"白颊林莺具有极长的迁徙距离，是新大陆莺鸟中迁徙距离最长的物种之一，这可能是导致它们成为春季最晚出现的莺鸟之一的原因。"},{"name":"黑喉蓝林莺","english_name":"Black-throated Blue Warbler","scientific_name":"Setophaga caerulescens","overview":"黑喉蓝林莺（英文名：Black-throated Blue Warbler，学名：Setophaga caerulescens），是雀形目森莺科橙尾鸲莺属的鸟类。独特的北美森林鸟，以其鲜明的性别差异而闻名。雄鸟拥有深蓝色背部、黑色面部和侧翼以及白色腹部，而雌鸟则呈现橄榄灰色调，带有淡黄色下体。分布于美国东北部和加拿大南部的成熟阔叶林及混合常绿阔叶林，冬季迁徙至加勒比海岛屿。历史上，随着东部北美的森林被欧洲人开垦，其数量可能有所下降，但在20世纪，随着森林的恢复，其种群数量可能已回升。","appearance":"雄性黑喉蓝林莺具有独特的外观，上体为深蓝色，脸部、喉咙和侧翼为黑色，腹部和胸部为白色，翼上有明显的白色斑块。雌鸟为橄榄绿色，下体淡黄色，翼下覆羽和腹下覆羽白色，眼下方有白色的月牙形标记。幼鸟与成年雌鸟相似，但上体带有绿色色调。成年雄鸟和雌鸟的翼上有小的白色斑块，这是识别该物种的关键特征。","call":"黑喉蓝林莺的歌声通常被描述为一系列带有上扬音调的模糊音符，最后以长音的嗡嗡声结束。","habits":"黑喉蓝林莺栖息于成熟阔叶林或混合常绿阔叶林的林下层，偏好山地植被茂密的环境。它们广泛分布于各种森林或灌木丛生的环境中。冬季主要在加勒比海岛屿度过。它们主要以昆虫为食，偶尔在冬季补充种子和浆果。","breeding":"繁殖期一般从五月持续到七月，雄鸟通过歌唱吸引雌鸟。巢建在接近地面的密集灌木中，由雌鸟负责筑巢。繁殖期间，雄鸟会保卫领地并参与喂养后代。","identification":"雄性黑喉蓝林莺的深蓝、黑、白三色搭配在所有鸣禽中独一无二，而雌鸟的橄榄绿色和白色翼斑使其容易与同类中的其他物种区分开来。","protection":"IUCN：LC（无危）","distribution":"繁殖区域位于美国东北部和加拿大东南部的成熟森林地带，非繁殖季节则迁移到巴哈马群岛至南美洲北部的热带森林。","other":"黑喉蓝林莺是北美研究最为深入的迁徙性鸣禽之一，对其种群动态的研究揭示了气候变迁对鸟类生存的影响。"},{"name":"棕榈林莺","english_name":"Palm Warbler","scientific_name":"Setophaga palmarum","overview":"棕榈林莺（英文名：Palm Warbler，学名：Setophaga palmarum），是雀形目森莺科橙尾鸲莺属的鸟类。以其独特的尾部摆动行为而闻名。在繁殖季节展现出锈红色的顶冠。秋季和冬季以淡色眉纹、眼下的暗线、模糊的胸部条纹和鲜艳的黄色臀羽为特征。两个种群——\"西方\"和\"黄色\"——在外观上有所不同，但它们在迁徙期间广泛重叠。繁殖于北方森林中的沼泽和开阔地带，冬季迁至美国南部、加勒比海地区和尤卡坦半岛。","appearance":"棕榈林莺体长约12.5至14.5厘米，背部呈灰褐色至橄榄棕色，明亮的黄色臀羽是其显著特征。下体颜色从黄色到白色不等，胸部和两胁有模糊的棕色条纹。在替代羽毛中，头部顶部呈现锈红色。\"黄色\"亚种整个下体均为黄色；\"西方\"亚种仅臀羽或臀羽和喉部为强烈黄色，与白色或微黄色的胸腹部形成对比。两性相似，但在野外观察时可能难以区分。","call":"发出单调的嗡嗡颤音歌曲，叫声为尖锐的\"chek\"。","habits":"栖息于北方森林的沼泽和开阔地带，冬季迁徙至美国东南部、墨西哥湾沿岸、加勒比海岛屿和中美洲。它们更倾向于地面觅食，有时也会飞起捕食昆虫。主要食物为昆虫和浆果。与大多数森莺相比，它们的冬季分布范围更北，可达美国大西洋沿岸。","breeding":"筑巢于地面或接近地面的开放区域，巢型为开放式的杯状。繁殖期具体细节尚需更多研究，但已知它们会在春季较早返回繁殖地，有时甚至比其他森莺提前两个月。","identification":"与草原绿林莺、栗颊林莺和基本羽毛状态的黄腰林莺区别在于，后者缺乏黄色的臀羽且不持续摆动尾巴。\"西方\"和\"黄色\"亚种在繁殖地分离，但在越冬地混合。","protection":"IUCN：LC（无危）","distribution":"繁殖于加拿大和美国东北部的北方森林沼泽地带。冬季迁徙至美国东南部、墨西哥湾沿岸、加勒比海岛屿和中美洲。在北方最北端的繁殖范围，棕榈林莺的数量在1966年至2015年间有所增加。","other":"棕榈林莺是最早返回其繁殖地的迁徙鸟类之一，有时比其他森莺提前近两个月完成迁徙。"}];
